import type { ProjectDashboardSummary } from '../../lib/dashboard';
import { formatRelative } from '../../lib/dashboard';
import PassRateRing from './PassRateRing';

interface Props {
  summary: ProjectDashboardSummary;
  onJumpToGaps: () => void;
}

export default function SummaryStrip({ summary, onJumpToGaps }: Props) {
  const staleClass = summary.stale ? 'bg-amber-50 border-amber-200' : 'bg-white border-gray-200';

  return (
    <div className="grid grid-cols-2 xl:grid-cols-4 gap-3 sm:gap-4">
      {/* Pass rate */}
      <div className="rounded-2xl border border-gray-200 bg-white p-3 sm:p-5 flex items-center gap-3 min-w-0">
        <div className="shrink-0">
          <PassRateRing passRate={summary.passRate} size={64} stroke={6} />
        </div>
        <div className="min-w-0">
          <div className="text-[10px] sm:text-[11px] uppercase tracking-wide text-gray-400 font-semibold">Pass rate</div>
          {summary.passRate === null ? (
            <div className="text-xs text-gray-500 mt-1">No runs yet</div>
          ) : (
            <div className="text-[11px] sm:text-xs text-gray-500 mt-1 truncate">
              {summary.passedTestCases}/{summary.executedTestCases} executed
            </div>
          )}
        </div>
      </div>

      {/* Test cases */}
      <div className="rounded-2xl border border-gray-200 bg-white p-3 sm:p-5 min-w-0">
        <div className="text-[10px] sm:text-[11px] uppercase tracking-wide text-gray-400 font-semibold">Test cases</div>
        <div className="mt-1 sm:mt-2 text-2xl sm:text-3xl font-bold text-gray-800">{summary.totalTestCases}</div>
        <div className="mt-0.5 sm:mt-1 text-[11px] sm:text-xs text-gray-500 truncate">
          <span className="text-gray-700">{summary.executedTestCases}</span> run
          {' · '}
          <span className={summary.failedTestCases > 0 ? 'text-red-600' : 'text-gray-700'}>
            {summary.failedTestCases}
          </span>{' '}
          failed
        </div>
      </div>

      {/* Features */}
      <div className="rounded-2xl border border-gray-200 bg-white p-3 sm:p-5 min-w-0">
        <div className="text-[10px] sm:text-[11px] uppercase tracking-wide text-gray-400 font-semibold">Features</div>
        <div className="mt-1 sm:mt-2 text-2xl sm:text-3xl font-bold text-gray-800">{summary.totalFeatures}</div>
        <div className="mt-0.5 sm:mt-1 text-[11px] sm:text-xs text-gray-500 truncate">
          <span className="text-gray-700">{summary.featuresWithTests}</span> tested,{' '}
          {summary.featuresWithoutTests > 0 ? (
            <button
              onClick={onJumpToGaps}
              className="text-amber-700 underline-offset-2 hover:underline font-semibold focus:outline-none focus:ring-1 focus:ring-orange-300 rounded"
            >
              {summary.featuresWithoutTests} gap{summary.featuresWithoutTests === 1 ? '' : 's'}
            </button>
          ) : (
            <span className="text-gray-700">0 gaps</span>
          )}
        </div>
      </div>

      {/* Last activity */}
      <div className={`rounded-2xl border p-3 sm:p-5 min-w-0 ${staleClass}`}>
        <div className="text-[10px] sm:text-[11px] uppercase tracking-wide text-gray-400 font-semibold">Last activity</div>
        <div className="mt-1 sm:mt-2 text-sm sm:text-xl font-bold text-gray-800 truncate">
          {summary.lastActivityAt ? formatRelative(summary.lastActivityAt) : 'No activity'}
        </div>
        {summary.stale && (
          <div className="mt-0.5 sm:mt-1 text-[11px] sm:text-xs text-amber-700 font-medium truncate">Stale</div>
        )}
      </div>
    </div>
  );
}
