import { useNavigate } from 'react-router-dom';
import type { ProjectDashboardModule } from '../../lib/dashboard';
import { passRateTone } from '../../lib/dashboard';
import PassRateRing from './PassRateRing';

interface Props {
  projectId: string;
  modules: ProjectDashboardModule[];
  onAddModule: () => void;
}

interface PresenceBadgeProps {
  label: string;
  present: boolean;
}

function PresenceBadge({ label, present }: PresenceBadgeProps) {
  if (present) {
    return (
      <span className="inline-flex items-center gap-1 px-2 py-0.5 text-[10px] font-semibold rounded-full bg-green-50 text-green-700 border border-green-200">
        {label} <span aria-hidden>✓</span>
      </span>
    );
  }
  return (
    <span className="inline-flex items-center gap-1 px-2 py-0.5 text-[10px] font-semibold rounded-full bg-gray-50 text-gray-400 border border-dashed border-gray-200">
      {label}
    </span>
  );
}

export default function ModuleStrip({ projectId, modules, onAddModule }: Props) {
  const navigate = useNavigate();

  return (
    <div>
      <div className="flex items-center justify-between mb-3">
        <h2 className="text-sm font-semibold text-gray-800">Modules ({modules.length})</h2>
      </div>
      {modules.length === 0 ? (
        <div className="flex justify-center">
          <div className="w-full max-w-sm sm:max-w-md rounded-2xl border border-gray-200 bg-white px-6 py-8 text-center shadow-sm">
            <div className="inline-flex items-center justify-center w-10 h-10 rounded-xl bg-orange-100 text-orange-600 text-lg font-bold mb-3">
              M
            </div>
            <h3 className="text-base font-semibold text-gray-800 mb-1">Add your first module</h3>
            <p className="text-xs text-gray-500 mb-5">
              Modules organise testing by functional area. Each module has its own test plan and summary report.
            </p>
            <button
              onClick={onAddModule}
              className="w-full sm:w-auto px-5 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 font-semibold text-sm transition focus:outline-none focus:ring-2 focus:ring-orange-300"
            >
              + Add module
            </button>
          </div>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-3 sm:gap-4">
          {modules.map(mod => {
            const tone = passRateTone(mod.passRate);
            return (
              <button
                key={mod.moduleId}
                onClick={() => navigate(`/project/${projectId}/module/${mod.moduleId}`)}
                className="text-left rounded-2xl border border-gray-200 bg-white p-3 sm:p-5 hover:shadow-sm hover:border-gray-300 transition focus:outline-none focus:ring-2 focus:ring-orange-300 min-w-0"
              >
                <div className="flex items-start gap-3 sm:gap-4">
                  <div className="shrink-0">
                    <PassRateRing passRate={mod.passRate} size={56} stroke={6} />
                  </div>
                  <div className="min-w-0 flex-1">
                    <h3 className="text-sm font-semibold text-gray-800 truncate">{mod.moduleName}</h3>
                    <div className="mt-1 text-[11px] text-gray-500">
                      {mod.featureCount} feature{mod.featureCount !== 1 ? 's' : ''} ·{' '}
                      <span className="text-gray-700">{mod.totalTestCases}</span> tests
                      {mod.failedTestCases > 0 && (
                        <> · <span className="text-red-600 font-semibold">{mod.failedTestCases} failed</span></>
                      )}
                    </div>
                    {mod.passRate === null && (
                      <div className={`mt-1 text-[10px] ${tone.text}`}>No runs yet</div>
                    )}
                  </div>
                </div>
                <div className="mt-3 flex flex-wrap gap-1.5">
                  <PresenceBadge label="Plan" present={mod.hasTestPlan} />
                  <PresenceBadge label="Report" present={mod.hasSummaryReport} />
                  <PresenceBadge label="Comparison" present={mod.hasComparison} />
                </div>
              </button>
            );
          })}
          <button
            onClick={onAddModule}
            className="rounded-2xl border-2 border-dashed border-gray-200 bg-white p-5 flex flex-col items-center justify-center text-gray-500 hover:border-orange-300 hover:text-orange-600 transition focus:outline-none focus:ring-2 focus:ring-orange-300"
          >
            <span className="text-2xl font-bold">+</span>
            <span className="text-xs font-semibold mt-1">Add module</span>
          </button>
        </div>
      )}
    </div>
  );
}
