import { useEffect, useRef, useState } from 'react';

// ─── Building blocks shared across the settings page ───────────────────────────

export function SectionCard({ title, icon, children, action }: { title: string; icon: string; children: React.ReactNode; action?: React.ReactNode }) {
  return (
    <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
      <div className="flex items-center gap-3 px-6 py-4 border-b border-gray-100 bg-gray-50/60">
        <span className="text-xl">{icon}</span>
        <h2 className="text-sm font-semibold text-gray-800 tracking-wide uppercase">{title}</h2>
        {action && <div className="ml-auto">{action}</div>}
      </div>
      <div className="p-6">{children}</div>
    </div>
  );
}

export function Field({ label, hint, children }: { label: string; hint?: string; children: React.ReactNode }) {
  return (
    <div className="flex flex-col gap-1">
      <label className="text-xs font-medium text-gray-600">{label}</label>
      {hint && <p className="text-[11px] text-gray-400 leading-snug">{hint}</p>}
      {children}
    </div>
  );
}

export function TextInput({ value, onChange, placeholder, type = 'text', mono = false }: {
  value: string; onChange: (v: string) => void; placeholder?: string; type?: string; mono?: boolean;
}) {
  return (
    <input
      type={type}
      value={value}
      onChange={e => onChange(e.target.value)}
      placeholder={placeholder}
      className={`w-full px-3 py-2 rounded-lg border border-gray-200 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-orange-300 focus:border-orange-400 transition-all placeholder:text-gray-300 ${mono ? 'font-mono' : ''}`}
    />
  );
}

export function Toggle({ checked, onChange, label }: { checked: boolean; onChange: (v: boolean) => void; label?: string }) {
  return (
    <label className="flex items-center gap-2 cursor-pointer select-none">
      <button
        type="button"
        role="switch"
        aria-checked={checked}
        onClick={() => onChange(!checked)}
        className={`relative w-9 h-5 rounded-full transition-colors duration-200 focus:outline-none focus:ring-2 focus:ring-orange-300 cursor-pointer ${checked ? 'bg-orange-500' : 'bg-gray-200'}`}
      >
        <span className={`absolute top-0.5 left-0.5 w-4 h-4 rounded-full bg-white shadow transition-transform duration-200 ${checked ? 'translate-x-4' : 'translate-x-0'}`} />
      </button>
      {label && <span className="text-xs text-gray-600">{label}</span>}
    </label>
  );
}

export function SegmentedControl<T extends string>({ options, value, onChange }: {
  options: { value: T; label: string; desc?: string }[];
  value: T;
  onChange: (v: T) => void;
}) {
  return (
    <div className="flex flex-wrap gap-2">
      {options.map(opt => (
        <button
          key={opt.value}
          type="button"
          onClick={() => onChange(opt.value)}
          className={`px-3 py-1.5 rounded-lg border text-xs font-medium transition-all duration-150 cursor-pointer ${
            value === opt.value
              ? 'border-orange-400 bg-orange-50 text-orange-700 shadow-sm shadow-orange-100'
              : 'border-gray-200 bg-white text-gray-600 hover:border-gray-300'
          }`}
        >
          {opt.label}
          {opt.desc && <span className="ml-1 text-[10px] text-gray-400 font-normal">({opt.desc})</span>}
        </button>
      ))}
    </div>
  );
}

export function ModelInput({ value, onChange, models, highlighted, placeholder }: { value: string; onChange: (v: string) => void; models: string[]; highlighted?: boolean; placeholder?: string }) {
  const [open, setOpen] = useState(false);
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const filtered = models.filter(m => m.toLowerCase().includes(value.toLowerCase()));
  const inputClass = `w-full px-3 py-2 rounded-lg border text-sm font-mono focus:outline-none focus:ring-2 focus:ring-orange-300 focus:border-orange-400 transition-all placeholder:text-gray-300 ${
    highlighted ? 'border-orange-300 bg-orange-50/40' : 'border-gray-200 bg-white'
  }`;

  return (
    <div className="relative" ref={ref}>
      <input
        type="text"
        value={value}
        onChange={e => { onChange(e.target.value); setOpen(true); }}
        onFocus={() => setOpen(true)}
        placeholder={placeholder ?? 'Model ID'}
        className={inputClass}
      />
      {open && filtered.length > 0 && (
        <div className="absolute top-full mt-1 left-0 right-0 z-50 bg-white border border-gray-200 rounded-xl shadow-xl max-h-48 overflow-y-auto">
          {filtered.map(m => (
            <button
              key={m}
              type="button"
              onMouseDown={() => { onChange(m); setOpen(false); }}
              className={`w-full text-left px-3 py-2 text-xs font-mono hover:bg-orange-50 hover:text-orange-700 transition-colors cursor-pointer ${m === value ? 'bg-orange-50 text-orange-700 font-semibold' : 'text-gray-700'}`}
            >
              {m}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

