export function modelsFor(provider: string): string[] {
  switch (provider) {
    case 'openai': return OPENAI_MODELS;
    case 'bedrock':
    case 'bedrockapi': return BEDROCK_MODELS;
    case 'gh-copilot': return COPILOT_MODELS;
    case 'claudecode': return CLAUDE_CODE_MODELS;
    default: return [];
  }
}
