import { useEffect } from 'react';
import { useStore } from '../store/state';
import { useActivator } from '../store/Context';

interface Props {
  open: boolean;
  initialUrl?: string;
  context: 'module' | 'comparison-old' | 'comparison-new' | 'generic';
  onResult: (result: { xpath: string; url: string }) => void;
  onClose: () => void;
}

export default function ElementPickerModal({ open, initialUrl, context, onResult, onClose }: Props) {
  const activator = useActivator();
  const status = useStore(s => s.pickerStatus);
  const result = useStore(s => s.lastPickerResult);
  const error = useStore(s => s.pickerError);
  const setPickerStatus = useStore(s => s.setPickerStatus);
  const setLastPickerResult = useStore(s => s.setLastPickerResult);
  const setPickerError = useStore(s => s.setPickerError);

  useEffect(() => {
    if (!open) return;
    setPickerStatus('launching');
    setLastPickerResult(null);
    setPickerError(null);
    activator.startPicker({ initialUrl, context });
    return () => {
      activator.cancelPicker();
      setPickerStatus('idle');
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [open]);

  if (!open) return null;

  const handleDone = () => {
    if (result) onResult(result);
    onClose();
  };

  const handlePickAnother = () => {
    setPickerStatus('launching');
    setLastPickerResult(null);
    activator.startPicker({ context });
  };

  const handleCancel = () => {
    activator.cancelPicker();
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50">
      <div className="bg-white rounded-2xl p-6 w-full max-w-lg shadow-xl">
        <h3 className="text-base font-semibold text-gray-800 mb-3">Pick an element</h3>

        {status === 'launching' && <p className="text-sm text-gray-500">Launching browser...</p>}
        {status === 'waiting' && (
          <p className="text-sm text-gray-600">Hover and click the element you want to capture in the browser window. You can navigate freely — the picker stays active.</p>
        )}
        {status === 'picked' && result && (
          <div className="space-y-2">
            <div className="text-sm text-green-700 font-semibold">Element captured</div>
            <div className="text-xs text-gray-500">XPath</div>
            <pre className="text-xs bg-gray-50 border border-gray-200 rounded p-2 overflow-x-auto">{result.xpath}</pre>
            <div className="text-xs text-gray-500">URL</div>
            <pre className="text-xs bg-gray-50 border border-gray-200 rounded p-2 overflow-x-auto">{result.url}</pre>
          </div>
        )}
        {status === 'error' && error && (
          <div className="text-sm text-red-600">Error: {error}</div>
        )}

        <div className="flex gap-2 mt-4 justify-end">
          {status === 'picked' && (
            <button onClick={handlePickAnother} className="px-3 py-1.5 text-xs bg-gray-100 text-gray-700 rounded-md hover:bg-gray-200">
              Pick another
            </button>
          )}
          {status === 'picked' ? (
            <button onClick={handleDone} className="px-3 py-1.5 text-xs bg-orange-500 text-white rounded-md hover:bg-orange-600 font-semibold">
              Done
            </button>
          ) : (
            <button onClick={handleCancel} className="px-3 py-1.5 text-xs bg-gray-100 text-gray-700 rounded-md hover:bg-gray-200">
              Cancel
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
