import { useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useStore } from '../../store/state';
import { useActivator } from '../../store/Context';
import { SuccessIcon, FailedIcon, RunningIcon, PendingIcon } from '../../styles/Icons';

function StatusIcon({ status }: { status: string }) {
  switch (status) {
    case 'passed': return <SuccessIcon className="text-green-500" />;
    case 'failed': return <FailedIcon className="text-red-500" />;
    case 'running': return <RunningIcon className="text-blue-500" />;
    default: return <PendingIcon className="text-gray-400" />;
  }
}

export default function ExecutionHistoryList() {
  const { projectId, moduleId, featureId } = useParams<{
    projectId: string;
    moduleId: string;
    featureId: string;
  }>();
  const navigate = useNavigate();

  const activator = useActivator();
  const setDefectDraft = useStore(s => s.setDefectDraft);
  const [expandedRunId, setExpandedRunId] = useState<string | null>(null);

  const project = useStore(s => s.projects.find(p => p.id === projectId));
  const mod = project?.modules.find(m => m.id === moduleId);
  const feature = mod?.features.find(f => f.id === featureId);

  if (!project || !mod || !feature) {
    return (
      <div className="w-full px-4 py-6">
        <div className="rounded-lg border border-gray-200 bg-white p-6 text-center text-gray-500 text-sm">
          Feature not found
        </div>
      </div>
    );
  }

  const pid = project.id;
  const mid = mod.id;
  const fid = feature.id;
  const runs = [...(feature.testRuns || [])].reverse();

  const openRun = (runId: string) => {
    navigate(`/project/${pid}/module/${mid}/feature/${fid}/tests?runId=${encodeURIComponent(runId)}`);
  };

  const handleDraftBug = (runId: string, testCaseId: string) => {
    setDefectDraft({
      projectId: pid,
      moduleId: mid,
      featureId: fid,
      runId,
      testCaseId,
      status: 'drafting',
    });
    activator.draftDefect(pid, mid, fid, runId, testCaseId);
  };

  return (
    <div className="w-full px-4 py-6">
      {/* Breadcrumb + Back */}
      <div className="flex items-center gap-2 mb-3 text-sm flex-wrap">
        <button
          onClick={() => navigate(`/project/${pid}/module/${mid}`)}
          className="inline-flex items-center gap-1 px-2 py-1 text-xs text-gray-600 hover:text-gray-900 hover:bg-gray-100 rounded-md transition"
          title="Back to Module"
        >
          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
          Back
        </button>
        <span className="text-gray-300">|</span>
        <button onClick={() => navigate('/')} className="text-gray-400 hover:text-gray-700 text-xs">Projects</button>
        <span className="text-gray-300">/</span>
        <button onClick={() => navigate(`/project/${pid}`)} className="text-gray-400 hover:text-gray-700 text-xs">{project.name}</button>
        <span className="text-gray-300">/</span>
        <button onClick={() => navigate(`/project/${pid}/module/${mid}`)} className="text-gray-400 hover:text-gray-700 text-xs">{mod.name}</button>
        <span className="text-gray-300">/</span>
        <button onClick={() => navigate(`/project/${pid}/module/${mid}/feature/${fid}`)} className="text-gray-400 hover:text-gray-700 text-xs">{feature.name}</button>
        <span className="text-gray-300">/</span>
        <span className="font-medium text-gray-800 text-xs">History</span>
      </div>

      <div className="rounded-lg border border-gray-200 bg-white px-4 py-4">
        <h1 className="text-base font-bold text-gray-800 mb-3">Execution History — {feature.name}</h1>

        {runs.length === 0 && (
          <p className="text-xs text-gray-500 py-6 text-center">No execution runs yet.</p>
        )}

        <div className="space-y-2">
          {runs.map(run => {
            const passed = run.testCaseResults.filter(r => r.status === 'passed').length;
            const failed = run.testCaseResults.filter(r => r.status === 'failed').length;
            const total = run.testCaseResults.length;
            const duration = run.testCaseResults.reduce((sum, r) => sum + (r.executionTime || 0), 0);
            const isExpanded = expandedRunId === run.id;
            const hasFailed = failed > 0;
            return (
              <div key={run.id} className="rounded-lg border border-gray-200 bg-white">
                <div className="p-3 flex items-center gap-3">
                  <StatusIcon status={run.status} />
                  <div
                    className="flex-1 min-w-0 cursor-pointer"
                    onClick={() => setExpandedRunId(isExpanded ? null : run.id)}
                  >
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="text-sm font-medium text-gray-800">
                        {run.mode === 'replay' ? 'Replay' : 'AI Run'}
                      </span>
                      <span className="text-[11px] text-gray-400">
                        {new Date(run.startedAt).toLocaleString()}
                      </span>
                    </div>
                    <div className="flex items-center gap-3 text-[11px] mt-0.5">
                      <span className="text-gray-500">{total} tests</span>
                      {passed > 0 && <span className="text-green-600">{passed} passed</span>}
                      {failed > 0 && <span className="text-red-600">{failed} failed</span>}
                      {duration > 0 && <span className="text-gray-400">{(duration / 1000).toFixed(1)}s</span>}
                    </div>
                  </div>
                  <button
                    onClick={() => openRun(run.id)}
                    className="px-2 py-1 text-[11px] font-semibold bg-white text-gray-700 border border-gray-200 rounded hover:bg-gray-50"
                  >
                    Open
                  </button>
                  {hasFailed && (
                    <button
                      onClick={() => setExpandedRunId(isExpanded ? null : run.id)}
                      className="px-2 py-1 text-[11px] font-semibold bg-white text-gray-700 border border-gray-200 rounded hover:bg-gray-50"
                    >
                      {isExpanded ? 'Hide failures' : 'View failures'}
                    </button>
                  )}
                </div>
                {isExpanded && hasFailed && (
                  <div className="border-t border-gray-100 px-3 py-2 space-y-1.5 bg-gray-50">
                    {run.testCaseResults.filter(r => r.status === 'failed').map(tcResult => {
                      const bugFinding = tcResult.findings.find(f => f.type === 'fail' && f.isBug === true);
                      const hasBug = !!bugFinding || !!tcResult.createdJiraKey;
                      const displayFinding = bugFinding ?? tcResult.findings.find(f => f.type === 'fail');
                      return (
                        <div
                          key={tcResult.testCaseId}
                          className="bg-white rounded border border-gray-200 px-3 py-2 flex items-center gap-3"
                        >
                          <FailedIcon className="text-red-500" />
                          <div className="flex-1 min-w-0">
                            <p className="text-xs font-medium text-gray-800 truncate">{tcResult.testCaseTitle}</p>
                            {displayFinding && (
                              <p className="text-[10px] text-red-600 truncate">✗ {displayFinding.message}</p>
                            )}
                            {!hasBug && (
                              <p className="text-[10px] text-gray-400 italic">Execution issue — not flagged as a bug</p>
                            )}
                          </div>
                          {tcResult.createdJiraKey ? (
                            <span className="text-[10px] font-mono text-blue-700 px-2 py-0.5 rounded bg-blue-50 border border-blue-100">
                              {tcResult.createdJiraKey}
                            </span>
                          ) : hasBug ? (
                            <button
                              onClick={() => handleDraftBug(run.id, tcResult.testCaseId)}
                              className="px-2 py-1 text-[11px] font-semibold text-red-700 bg-red-50 border border-red-200 rounded hover:bg-red-100"
                              title="Draft a Jira bug from this failed test case. You will review the draft before anything is posted."
                            >
                              Draft bug
                            </button>
                          ) : null}
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}
