import { useState, useEffect } from 'react';
import type { ResultsExportOptions } from '../../../../activator/types/protocol';
import type { TestRun } from '../../../../activator/types/state';

interface Props {
  initialTitle: string;
  testRuns: TestRun[];
  /** When set, the run picker is hidden and this run is always used. */
  lockedRunId?: string;
  /** When set, only these test cases will be exported (run picker hidden). */
  lockedTestCaseIds?: string[];
  /** Label describing the fixed scope (e.g. "3 test cases from this run"). */
  scopeLabel?: string;
  onCancel: () => void;
  onExport: (format: 'html' | 'pdf', options: ResultsExportOptions) => void;
}

export default function ResultsDialog({ initialTitle, testRuns, lockedRunId, lockedTestCaseIds, scopeLabel, onCancel, onExport }: Props) {
  const [title, setTitle] = useState(initialTitle);
  const [runId, setRunId] = useState<string>(lockedRunId ?? testRuns[testRuns.length - 1]?.id ?? '');
  const [includeSummary, setIncludeSummary] = useState(true);
  const [includeTestCases, setIncludeTestCases] = useState(true);
  const [includeSteps, setIncludeSteps] = useState(true);
  const [includeFindings, setIncludeFindings] = useState(true);
  const [includeErrors, setIncludeErrors] = useState(true);
  const [includeAiReasoning, setIncludeAiReasoning] = useState(false);
  const [screenshotMode, setScreenshotMode] = useState<'all' | 'failures-only' | 'none'>('failures-only');

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') onCancel(); };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [onCancel]);

  const handleExport = () => {
    onExport('html', {
      title,
      runId: runId || undefined,
      testCaseIds: lockedTestCaseIds,
      includeSummary,
      includeTestCases,
      includeSteps: includeTestCases && includeSteps,
      includeFindings: includeTestCases && includeFindings,
      includeErrors,
      includeAiReasoning,
      screenshotMode,
    });
  };

  const Row = ({ label, children }: { label: string; children: React.ReactNode }) => (
    <div className="flex items-center justify-between py-1.5">
      <label className="text-[11px] text-gray-600">{label}</label>
      {children}
    </div>
  );

  const Toggle = ({ checked, onChange }: { checked: boolean; onChange: (v: boolean) => void }) => (
    <button
      type="button"
      role="switch"
      aria-checked={checked}
      onClick={() => onChange(!checked)}
      className={`relative inline-flex h-4 w-7 items-center rounded-full transition-colors ${checked ? 'bg-blue-500' : 'bg-gray-300'}`}
    >
      <span className={`inline-block h-3 w-3 rounded-full bg-white transition-transform ${checked ? 'translate-x-3.5' : 'translate-x-0.5'}`} />
    </button>
  );

  return (
    <div className="fixed inset-0 z-50 bg-black/50 flex items-center justify-center p-4" onClick={onCancel}>
      <div className="w-full max-w-md bg-white rounded-lg shadow-2xl overflow-hidden" onClick={e => e.stopPropagation()}>
        <div className="px-4 py-3 border-b border-gray-200 bg-gradient-to-r from-blue-50 to-indigo-50">
          <h2 className="text-sm font-bold text-gray-800">Export Results</h2>
          <p className="text-[11px] text-gray-500">Tailor the report before export</p>
        </div>

        <div className="px-4 py-3 max-h-[70vh] overflow-y-auto">
          <div className="mb-3">
            <label className="block text-[10px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Title</label>
            <input
              value={title}
              onChange={e => setTitle(e.target.value)}
              className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none focus:ring-1 focus:ring-blue-300"
            />
          </div>

{scopeLabel && (
            <div className="mb-3 px-2 py-1.5 bg-blue-50 border border-blue-100 rounded text-[11px] text-blue-700">
              Scope: {scopeLabel}
            </div>
          )}
          {!lockedRunId && !lockedTestCaseIds && testRuns.length > 1 && (
            <div className="mb-3">
              <label className="block text-[10px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Test Run</label>
              <select
                value={runId}
                onChange={e => setRunId(e.target.value)}
                className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs"
              >
                {testRuns.slice().reverse().map(r => (
                  <option key={r.id} value={r.id}>
                    {new Date(r.startedAt).toLocaleString()} — {r.testCaseResults.length} tests
                  </option>
                ))}
              </select>
            </div>
          )}

          <div className="border-t border-gray-100 pt-2 mb-1">
            <div className="text-[10px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Sections</div>
            <Row label="Summary stats"><Toggle checked={includeSummary} onChange={setIncludeSummary} /></Row>
            <Row label="Test cases"><Toggle checked={includeTestCases} onChange={setIncludeTestCases} /></Row>
            <Row label="Test steps"><Toggle checked={includeSteps} onChange={setIncludeSteps} /></Row>
            <Row label="Findings"><Toggle checked={includeFindings} onChange={setIncludeFindings} /></Row>
            <Row label="Error messages"><Toggle checked={includeErrors} onChange={setIncludeErrors} /></Row>
            <Row label="AI reasoning"><Toggle checked={includeAiReasoning} onChange={setIncludeAiReasoning} /></Row>
          </div>

          <div className="border-t border-gray-100 pt-2">
            <div className="text-[10px] font-semibold text-gray-500 uppercase tracking-wider mb-1">Screenshots</div>
            <div className="flex gap-1">
              {(['all', 'failures-only', 'none'] as const).map(mode => (
                <button
                  key={mode}
                  onClick={() => setScreenshotMode(mode)}
                  className={`flex-1 px-2 py-1 text-[10px] rounded border ${screenshotMode === mode ? 'bg-blue-500 text-white border-blue-500' : 'bg-white text-gray-700 border-gray-200'}`}
                >
                  {mode === 'all' ? 'All' : mode === 'failures-only' ? 'Failures only' : 'None'}
                </button>
              ))}
            </div>
          </div>
        </div>

        <div className="px-4 py-3 border-t border-gray-200 bg-gray-50 flex items-center justify-end gap-2">
          <button onClick={onCancel} className="px-3 py-1.5 text-[11px] bg-white text-gray-700 border border-gray-200 rounded hover:bg-gray-100">Cancel</button>
          <button onClick={handleExport} className="px-3 py-1.5 text-[11px] font-semibold bg-blue-500 text-white rounded hover:bg-blue-600">
            Export HTML
          </button>
        </div>
      </div>
    </div>
  );
}
