import { useEffect, useState } from 'react';
import { useStore } from '../store/state';
import { useActivator } from '../store/Context';

/**
 * Review-and-submit modal for a drafted Jira bug.
 *
 * Flow enforced here:
 *  1. Store enters `drafting` when the user clicks "Draft bug" elsewhere.
 *  2. Activator runs the LLM and broadcasts `defectDrafted` → store becomes `ready`.
 *  3. This modal renders the editable draft. Nothing has been sent to Jira yet.
 *  4. User reviews, edits every field, then clicks "Submit to Jira".
 *  5. An inline confirmation panel appears inside the same modal — the user
 *     must click "Yes, create in Jira" a second time. Only then does the UI
 *     fire `submitDefect`. The backend posts through SecurityGate.
 *  6. On `defectSubmitted`, the modal shows the new Jira key and a Close button.
 *
 * The user can cancel at any time before the second confirmation click — no
 * data leaves the UI unless they explicitly confirm.
 */
export default function DefectDraftModal() {
  const activator = useActivator();
  const draftState = useStore(s => s.defectDraft);
  const setDefectDraft = useStore(s => s.setDefectDraft);
  const updateDefectDraft = useStore(s => s.updateDefectDraft);

  const [summary, setSummary] = useState('');
  const [description, setDescription] = useState('');
  const [projectKey, setProjectKey] = useState('');
  const [priority, setPriority] = useState('');
  const [labels, setLabels] = useState('');
  const [linkedIssueKey, setLinkedIssueKey] = useState('');
  const [confirming, setConfirming] = useState(false);

  // Hydrate the form whenever a new draft arrives.
  useEffect(() => {
    if (!draftState?.draft) return;
    const d = draftState.draft;
    setSummary(d.summary);
    setDescription(d.description);
    setProjectKey(d.projectKey ?? '');
    setPriority(d.priority ?? '');
    setLabels((d.labels ?? []).join(', '));
    setLinkedIssueKey(d.linkedIssueKey ?? '');
    setConfirming(false);
  }, [draftState?.draft]);

  if (!draftState) return null;

  const close = () => setDefectDraft(null);

  const handleSubmit = () => {
    if (!confirming) {
      setConfirming(true);
      return;
    }
    if (!draftState.draft) return;
    if (!projectKey.trim()) {
      updateDefectDraft({ error: 'Jira project key is required' });
      return;
    }
    updateDefectDraft({
      status: 'submitting',
      draft: {
        ...draftState.draft,
        summary: summary.trim(),
        description: description.trim(),
        projectKey: projectKey.trim(),
        priority: priority.trim() || undefined,
        labels: labels.split(',').map(l => l.trim()).filter(Boolean),
        linkedIssueKey: linkedIssueKey.trim() || undefined,
      },
    });
    activator.submitDefect(
      draftState.projectId,
      draftState.moduleId,
      draftState.featureId,
      draftState.runId,
      draftState.testCaseId,
      {
        summary: summary.trim(),
        description: description.trim(),
        issueType: 'Bug',
        priority: priority.trim() || undefined,
        labels: labels.split(',').map(l => l.trim()).filter(Boolean),
        projectKey: projectKey.trim(),
        linkedIssueKey: linkedIssueKey.trim() || undefined,
        reasoning: draftState.draft.reasoning,
      },
    );
  };

  const isReady = draftState.status === 'ready' || draftState.status === 'submitting';
  const isDrafting = draftState.status === 'drafting';
  const isSubmitted = draftState.status === 'submitted';
  const isFailed = draftState.status === 'failed';

  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-3xl max-h-[90vh] overflow-hidden flex flex-col">
        <div className="flex items-center justify-between px-5 py-4 border-b border-gray-100">
          <div>
            <h3 className="text-base font-semibold text-gray-800">Draft Jira Bug</h3>
            <p className="text-xs text-gray-500 mt-0.5">
              Review everything below. Nothing is posted to Jira until you confirm.
            </p>
          </div>
          <button
            onClick={close}
            className="p-1.5 text-gray-400 hover:text-gray-700 rounded hover:bg-gray-100"
            title="Close"
          >
            ✕
          </button>
        </div>

        <div className="flex-1 overflow-y-auto px-5 py-4">
          {isDrafting && (
            <div className="flex items-center gap-3 text-sm text-gray-600 py-6">
              <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-orange-500" />
              Drafting bug from failed run...
            </div>
          )}

          {isFailed && (
            <div className="rounded-lg border border-red-200 bg-red-50 p-3 text-sm text-red-700">
              Failed to draft bug: {draftState.error || 'unknown error'}
            </div>
          )}

          {isSubmitted && draftState.submittedJiraKey && (
            <div className="rounded-lg border border-green-200 bg-green-50 p-4 text-sm text-green-800">
              <p className="font-semibold">Bug created: {draftState.submittedJiraKey}</p>
              <p className="mt-1 text-xs">This test case result is now linked to the new Jira issue.</p>
            </div>
          )}

          {isReady && draftState.draft && (
            <div className="space-y-3">
              {draftState.draft.reasoning && (
                <div className="rounded-lg border border-blue-100 bg-blue-50 p-3 text-xs text-blue-800">
                  <span className="font-semibold">AI reasoning:</span> {draftState.draft.reasoning}
                </div>
              )}

              <div>
                <label className="block text-xs text-gray-500 mb-1">Jira project key <span className="text-red-500">*</span></label>
                <input
                  value={projectKey}
                  onChange={e => setProjectKey(e.target.value)}
                  placeholder="e.g., ABC"
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm font-mono focus:outline-none focus:ring-2 focus:ring-orange-300"
                />
              </div>

              <div>
                <label className="block text-xs text-gray-500 mb-1">Summary</label>
                <input
                  value={summary}
                  onChange={e => setSummary(e.target.value)}
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-300"
                />
              </div>

              <div>
                <label className="block text-xs text-gray-500 mb-1">Description</label>
                <textarea
                  value={description}
                  onChange={e => setDescription(e.target.value)}
                  rows={14}
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm font-mono resize-y focus:outline-none focus:ring-2 focus:ring-orange-300"
                />
              </div>

              <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                <div>
                  <label className="block text-xs text-gray-500 mb-1">Priority</label>
                  <select
                    value={priority}
                    onChange={e => setPriority(e.target.value)}
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm bg-white"
                  >
                    <option value="">(default)</option>
                    <option value="Highest">Highest</option>
                    <option value="High">High</option>
                    <option value="Medium">Medium</option>
                    <option value="Low">Low</option>
                    <option value="Lowest">Lowest</option>
                  </select>
                </div>
                <div>
                  <label className="block text-xs text-gray-500 mb-1">Labels (comma-separated)</label>
                  <input
                    value={labels}
                    onChange={e => setLabels(e.target.value)}
                    placeholder="autoqai, regression"
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-300"
                  />
                </div>
                <div>
                  <label className="block text-xs text-gray-500 mb-1">Link to issue</label>
                  <input
                    value={linkedIssueKey}
                    onChange={e => setLinkedIssueKey(e.target.value)}
                    placeholder="ABC-123"
                    className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm font-mono focus:outline-none focus:ring-2 focus:ring-orange-300"
                  />
                </div>
              </div>

              {draftState.status === 'submitting' && (
                <div className="rounded-lg border border-orange-200 bg-orange-50 p-3 text-sm text-orange-800">
                  Awaiting approval from the security gate...
                </div>
              )}

              {draftState.error && (
                <div className="rounded-lg border border-red-200 bg-red-50 p-3 text-xs text-red-700">
                  {draftState.error}
                </div>
              )}

              {confirming && (
                <div className="rounded-lg border border-amber-200 bg-amber-50 p-3 text-sm text-amber-900">
                  <p className="font-semibold">This will create a new Jira issue in <span className="font-mono">{projectKey || '(none)'}</span>.</p>
                  <p className="text-xs mt-1">Once created, Jira will notify watchers. Do you want to continue?</p>
                </div>
              )}
            </div>
          )}
        </div>

        <div className="flex items-center justify-end gap-2 px-5 py-3 border-t border-gray-100 bg-gray-50">
          {isReady && draftState.draft && draftState.status !== 'submitting' && (
            <>
              {confirming && (
                <button
                  onClick={() => setConfirming(false)}
                  className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-100"
                >
                  Back to editing
                </button>
              )}
              <button
                onClick={close}
                className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-100"
              >
                Cancel
              </button>
              <button
                onClick={handleSubmit}
                disabled={!summary.trim() || !description.trim() || !projectKey.trim()}
                className={`px-4 py-1.5 text-xs font-semibold rounded-lg text-white disabled:opacity-50 ${
                  confirming ? 'bg-red-600 hover:bg-red-700' : 'bg-orange-500 hover:bg-orange-600'
                }`}
              >
                {confirming ? 'Yes, create in Jira' : 'Submit to Jira'}
              </button>
            </>
          )}
          {(isSubmitted || isFailed) && (
            <button
              onClick={close}
              className="px-3 py-1.5 text-xs font-semibold bg-orange-500 text-white rounded-lg hover:bg-orange-600"
            >
              Close
            </button>
          )}
        </div>
      </div>
    </div>
  );
}
