import { useEffect, useMemo, useRef, useState } from 'react';
import { useStore } from '../store/state';
import { useActivator } from '../store/Context';
import type { Fixture, FixtureColumn } from '../../activator/types/state';
import { DeleteIcon, DownloadIcon, EditIcon, PlusCircleIcon, TimesIcon } from '../styles/Icons';

interface Props {
  projectId: string;
  /** When undefined, lists project-scoped artifacts. */
  moduleId?: string;
}

/**
 * Artifact management table (REQUIREMENTS.md §5.1). Works at both Project
 * and Module scope. Uploads are routed through the activator — no direct
 * backend calls. Feature-scoped callers must rewrite to the parent module
 * before mounting this component (per the spec).
 */
export default function ArtifactsPanel({ projectId, moduleId }: Props) {
  const activator = useActivator();
  const fileRef = useRef<HTMLInputElement>(null);

  const fixtures = useStore((s) => s.fixtures);
  const brokenPrompt = useStore((s) => s.brokenConsumersPrompt);
  const setBrokenPrompt = useStore((s) => s.setBrokenConsumersPrompt);

  const [editing, setEditing] = useState<Fixture | null>(null);
  const [dragOver, setDragOver] = useState(false);

  // Request the server list on mount / scope change.
  useEffect(() => {
    activator.listArtifacts(projectId, moduleId);
  }, [activator, projectId, moduleId]);

  const scoped = useMemo(() => {
    return fixtures.filter((f) => {
      if (f.projectId !== projectId) return false;
      if (moduleId) return f.scope === 'module' && f.moduleId === moduleId;
      return f.scope === 'project';
    });
  }, [fixtures, projectId, moduleId]);

  const handleUpload = async (files: FileList | null) => {
    if (!files || files.length === 0) return;
    for (const file of Array.from(files)) {
      const buf = await file.arrayBuffer();
      const base64 = arrayBufferToBase64(buf);
      activator.uploadArtifact(projectId, file.name, base64, moduleId);
    }
  };

  const confirmDelete = (f: Fixture) => {
    activator.deleteArtifact(f.id);
  };

  const proceedDeleteAfterPrompt = () => {
    if (!brokenPrompt) return;
    activator.deleteArtifact(brokenPrompt.fixtureId, true);
    setBrokenPrompt(null);
  };

  return (
    <div className="w-full">
      <div
        className={`rounded-lg border-2 border-dashed p-4 mb-3 text-center transition ${
          dragOver ? 'border-orange-400 bg-orange-50' : 'border-gray-300 bg-gray-50'
        }`}
        onDragOver={(e) => {
          e.preventDefault();
          setDragOver(true);
        }}
        onDragLeave={() => setDragOver(false)}
        onDrop={(e) => {
          e.preventDefault();
          setDragOver(false);
          void handleUpload(e.dataTransfer.files);
        }}
      >
        <p className="text-[11px] text-gray-600 mb-2">
          Drop files here or <strong>click to browse</strong>. CSV and TSV parse columns automatically.
        </p>
        <button
          type="button"
          onClick={() => fileRef.current?.click()}
          className="px-2 py-1 text-[10px] font-semibold bg-orange-500 text-white rounded hover:bg-orange-600 inline-flex items-center gap-1"
        >
          <PlusCircleIcon className="w-3 h-3" /> Upload
        </button>
        <input
          ref={fileRef}
          type="file"
          className="hidden"
          multiple
          onChange={(e) => {
            void handleUpload(e.target.files);
            if (fileRef.current) fileRef.current.value = '';
          }}
        />
      </div>

      {scoped.length === 0 ? (
        <p className="text-[11px] text-gray-400 italic text-center py-6">
          No artifacts in this scope yet.
        </p>
      ) : (
        <div className="overflow-x-auto rounded-lg border border-gray-200 bg-white">
          <table className="w-full text-[11px]">
            <thead>
              <tr className="bg-gray-50 border-b border-gray-200">
                <Th>Name</Th>
                <Th>Columns</Th>
                <Th>Rows</Th>
                <Th>Size</Th>
                <Th>Version</Th>
                <Th>Modified</Th>
                <Th align="right">Actions</Th>
              </tr>
            </thead>
            <tbody>
              {scoped.map((f) => (
                <tr key={f.id} className="border-b border-gray-100 last:border-0">
                  <Td>
                    <div className="font-medium text-gray-800 truncate">{f.filename}</div>
                    {f.uploadedBy && (
                      <div className="text-[9px] text-gray-400">by {f.uploadedBy}</div>
                    )}
                  </Td>
                  <Td>
                    <div className="flex flex-wrap gap-0.5 max-w-48">
                      {f.columns.length === 0 ? (
                        <span className="text-[9px] text-gray-400 italic">unparsed</span>
                      ) : (
                        f.columns.slice(0, 6).map((c) => (
                          <span
                            key={c.name}
                            className={`px-1 py-0.5 text-[9px] rounded ${
                              c.secret
                                ? 'bg-red-100 text-red-700'
                                : 'bg-gray-100 text-gray-600'
                            }`}
                            title={c.secret ? `${c.name} (secret)` : c.name}
                          >
                            {c.name}
                            {c.secret && ' •'}
                          </span>
                        ))
                      )}
                      {f.columns.length > 6 && (
                        <span className="text-[9px] text-gray-400">+{f.columns.length - 6}</span>
                      )}
                    </div>
                  </Td>
                  <Td>{f.rowCount ?? '—'}</Td>
                  <Td>{formatSize(f.size)}</Td>
                  <Td>v{f.version}</Td>
                  <Td>{new Date(f.uploadedAt).toLocaleDateString()}</Td>
                  <Td align="right">
                    <div className="inline-flex items-center gap-0.5">
                      <button
                        type="button"
                        onClick={() => setEditing(f)}
                        className="p-1 text-gray-500 hover:text-gray-800 hover:bg-gray-100 rounded"
                        aria-label={`Edit schema for ${f.filename}`}
                        title="Edit schema"
                      >
                        <EditIcon className="w-3 h-3" />
                      </button>
                      <button
                        type="button"
                        onClick={() => activator.downloadArtifact(f.id)}
                        className="p-1 text-gray-500 hover:text-gray-800 hover:bg-gray-100 rounded"
                        aria-label={`Download ${f.filename}`}
                        title="Download"
                      >
                        <DownloadIcon className="w-3 h-3" />
                      </button>
                      <button
                        type="button"
                        onClick={() => confirmDelete(f)}
                        className="p-1 text-gray-500 hover:text-red-600 hover:bg-red-50 rounded"
                        aria-label={`Delete ${f.filename}`}
                        title="Delete"
                      >
                        <DeleteIcon className="w-3 h-3" />
                      </button>
                    </div>
                  </Td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Schema editor modal */}
      {editing && (
        <SchemaEditor
          fixture={editing}
          onCancel={() => setEditing(null)}
          onSave={(columns, filename) => {
            activator.updateArtifactSchema(editing.id, columns, filename);
            setEditing(null);
          }}
        />
      )}

      {/* Broken-consumers confirmation */}
      {brokenPrompt && (
        <div
          className="fixed inset-0 z-40 flex items-center justify-center bg-black/60"
          role="dialog"
          aria-modal="true"
          aria-labelledby="broken-consumers-title"
          onKeyDown={(e) => {
            if (e.key === 'Escape') setBrokenPrompt(null);
          }}
        >
          <div className="bg-white rounded-lg shadow-xl border border-gray-200 max-w-md w-[92%] p-4">
            <h3 id="broken-consumers-title" className="text-sm font-bold text-red-700 mb-2">
              Fixture is in use
            </h3>
            <p className="text-[11px] text-gray-600 mb-2">
              {brokenPrompt.consumers.length} loop binding(s) currently reference this fixture.
              Deleting will mark every consumer broken and block runs until resolved.
            </p>
            <ul className="text-[10px] text-gray-500 max-h-32 overflow-y-auto mb-3 font-mono">
              {brokenPrompt.consumers.map((c, i) => (
                <li key={i}>
                  project {c.projectId.slice(-6)} / feature {c.featureId.slice(-6)} / testcase {c.testCaseId.slice(-6)}
                </li>
              ))}
            </ul>
            <div className="flex items-center justify-end gap-2">
              <button
                autoFocus
                type="button"
                onClick={() => setBrokenPrompt(null)}
                className="px-3 py-1 text-[11px] bg-gray-100 text-gray-700 rounded hover:bg-gray-200 focus:outline-none focus:ring-2 focus:ring-orange-300"
              >
                Cancel
              </button>
              <button
                type="button"
                onClick={proceedDeleteAfterPrompt}
                className="px-3 py-1 text-[11px] font-semibold bg-red-500 text-white rounded hover:bg-red-600 focus:outline-none focus:ring-2 focus:ring-red-300"
              >
                Delete anyway
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function Th({ children, align }: { children: React.ReactNode; align?: 'right' }) {
  return (
    <th className={`px-2 py-1.5 text-[9px] uppercase tracking-wider text-gray-500 font-semibold ${align === 'right' ? 'text-right' : 'text-left'}`}>
      {children}
    </th>
  );
}

function Td({ children, align }: { children: React.ReactNode; align?: 'right' }) {
  return (
    <td className={`px-2 py-1.5 align-top ${align === 'right' ? 'text-right' : ''}`}>
      {children}
    </td>
  );
}

function SchemaEditor({
  fixture,
  onCancel,
  onSave,
}: {
  fixture: Fixture;
  onCancel: () => void;
  onSave: (columns: FixtureColumn[], filename?: string) => void;
}) {
  const [filename, setFilename] = useState(fixture.filename);
  const [columns, setColumns] = useState<FixtureColumn[]>(fixture.columns);

  const updateCol = (idx: number, patch: Partial<FixtureColumn>) => {
    setColumns((cs) => cs.map((c, i) => (i === idx ? { ...c, ...patch } : c)));
  };

  return (
    <div
      className="fixed inset-0 z-40 flex items-center justify-center bg-black/60"
      role="dialog"
      aria-modal="true"
      aria-labelledby="schema-editor-title"
      onKeyDown={(e) => {
        if (e.key === 'Escape') onCancel();
      }}
    >
      <div className="bg-white rounded-lg shadow-xl border border-gray-200 max-w-lg w-[92%] p-4">
        <div className="flex items-center justify-between mb-2">
          <h3 id="schema-editor-title" className="text-sm font-bold text-gray-800">Edit schema</h3>
          <button
            type="button"
            onClick={onCancel}
            className="p-1 text-gray-500 hover:text-gray-800"
            aria-label="Close"
          >
            <TimesIcon />
          </button>
        </div>
        <label className="block text-[9px] uppercase tracking-wider text-gray-500 font-semibold mb-0.5">
          Filename
        </label>
        <input
          autoFocus
          aria-label="Fixture filename"
          value={filename}
          onChange={(e) => setFilename(e.target.value)}
          className="w-full px-2 py-1 mb-2 border border-gray-200 rounded text-[11px] focus:outline-none focus:ring-1 focus:ring-orange-300"
        />
        <label className="block text-[9px] uppercase tracking-wider text-gray-500 font-semibold mb-0.5">
          Columns
        </label>
        <ul className="space-y-1 max-h-64 overflow-y-auto">
          {columns.length === 0 && (
            <li className="text-[10px] text-gray-400 italic">
              No columns parsed. This file is stored as an opaque blob.
            </li>
          )}
          {columns.map((c, i) => (
            <li key={`${c.name}-${i}`} className="flex items-center gap-1.5 text-[10px]">
              <span className="font-mono text-gray-700 w-28 truncate">{c.name}</span>
              <input
                value={c.label ?? ''}
                onChange={(e) => updateCol(i, { label: e.target.value || undefined })}
                placeholder="label (optional)"
                className="flex-1 px-1.5 py-0.5 border border-gray-200 rounded"
              />
              <select
                value={c.type}
                onChange={(e) => updateCol(i, { type: e.target.value as FixtureColumn['type'] })}
                className="px-1 py-0.5 border border-gray-200 rounded"
              >
                <option value="string">string</option>
                <option value="number">number</option>
                <option value="boolean">boolean</option>
                <option value="date">date</option>
              </select>
              <label className="inline-flex items-center gap-1 text-[9px] text-gray-600">
                <input
                  type="checkbox"
                  checked={!!c.secret}
                  onChange={(e) => updateCol(i, { secret: e.target.checked || undefined })}
                  className="accent-orange-500"
                />
                secret
              </label>
            </li>
          ))}
        </ul>
        <div className="flex items-center justify-end gap-2 mt-3 pt-2 border-t border-gray-100">
          <button
            type="button"
            onClick={onCancel}
            className="px-3 py-1 text-[11px] bg-gray-100 text-gray-700 rounded hover:bg-gray-200"
          >
            Cancel
          </button>
          <button
            type="button"
            onClick={() => onSave(columns, filename !== fixture.filename ? filename : undefined)}
            className="px-3 py-1 text-[11px] font-semibold bg-orange-500 text-white rounded hover:bg-orange-600"
          >
            Save
          </button>
        </div>
      </div>
    </div>
  );
}

function formatSize(bytes: number): string {
  if (bytes < 1024) return `${bytes} B`;
  if (bytes < 1024 * 1024) return `${(bytes / 1024).toFixed(1)} KB`;
  return `${(bytes / 1024 / 1024).toFixed(1)} MB`;
}

function arrayBufferToBase64(buf: ArrayBuffer): string {
  let binary = '';
  const bytes = new Uint8Array(buf);
  const CHUNK = 0x8000;
  for (let i = 0; i < bytes.length; i += CHUNK) {
    binary += String.fromCharCode.apply(null, Array.from(bytes.subarray(i, i + CHUNK)) as number[]);
  }
  return btoa(binary);
}
