import { useEffect, useState, type FunctionComponent, type ReactNode } from 'react';
import { useStore } from './state';
import { AppContext, proxyInstance } from './activatorContext';

export const AppProvider: FunctionComponent<{ children: ReactNode }> = ({ children }) => {
  const [connecting, setConnecting] = useState(true);
  const connected = useStore(s => s.connected);

  useEffect(() => {
    proxyInstance.connect()
      .then(() => {
        useStore.getState().setConnected(true);
        setConnecting(false);
      })
      .catch(() => {
        setConnecting(false);
      });

    return () => proxyInstance.disconnect();
  }, []);

  if (connecting) {
    return (
      <div className="flex items-center justify-center h-screen bg-gray-900 text-white">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-orange-500 mx-auto mb-4" />
          <p>Connecting to activator...</p>
        </div>
      </div>
    );
  }

  if (!connected && !connecting) {
    return (
      <div className="flex items-center justify-center h-screen bg-gray-900 text-white">
        <div className="text-center">
          <p className="text-xl mb-4">Unable to connect to activator</p>
          <p className="text-gray-400 mb-4">Make sure the activator is running on the correct port.</p>
          <button
            onClick={() => {
              setConnecting(true);
              proxyInstance.connect()
                .then(() => {
                  useStore.getState().setConnected(true);
                  setConnecting(false);
                })
                .catch(() => setConnecting(false));
            }}
            className="px-4 py-2 bg-orange-500 text-white rounded hover:bg-orange-600"
          >
            Retry Connection
          </button>
        </div>
      </div>
    );
  }

  return <AppContext.Provider value={proxyInstance}>{children}</AppContext.Provider>;
};

export { useActivator } from './activatorContext';
