import { useState } from 'react';
import { useNavigate, useParams, useLocation } from 'react-router-dom';
import { useStore } from '../../store/state';
import { useActivator } from '../../store/Context';
import MultiSelectAutocomplete from '../../components/inputs/MultiSelectAutocomplete';
import StrategyPicker from '../../components/StrategyPicker';
import { DEFAULT_PROJECT_STRATEGIES } from '../../../activator/engine/strategyCatalog';
import type { JiraTicketRef, Module } from '../../../activator/types/state';

export default function ProjectDetail() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const location = useLocation();
  const activator = useActivator();
  const project = useStore(s => s.projects.find(p => p.id === id));

  // Project editing state
  const [editingProject, setEditingProject] = useState(false);
  const [projectDescription, setProjectDescription] = useState('');
  const [projectStrategies, setProjectStrategies] = useState<string[]>([]);
  const [, setProjectDirty] = useState(false);

  // Module form state — auto-open if ?add=1 is present
  const [showAddModule, setShowAddModule] = useState(() => new URLSearchParams(location.search).get('add') === '1');
  const [editingModuleId, setEditingModuleId] = useState<string | null>(null);
  const [moduleName, setModuleName] = useState('');
  const [moduleDescription, setModuleDescription] = useState('');
  const [modulePageUrl, setModulePageUrl] = useState('');
  const [moduleScope, setModuleScope] = useState('');
  const [moduleTickets, setModuleTickets] = useState<Array<{ value: string; label: string; iconUrl?: string }>>([]);

  if (!project) {
    return (
      <div className="w-full px-4 py-8">
        <div className="rounded-2xl border border-gray-200 bg-white p-8 text-center text-gray-500">
          Project not found
        </div>
      </div>
    );
  }

  // --- Jira search ---
  const searchTickets = async (text: string) => {
    try {
      const response = await fetch('/api/issues/picker?query=' + encodeURIComponent(text)).then(r => r.json());
      return response.map((j: any) => ({ value: j.key, label: `${j.key} - ${j.summaryText}`, iconUrl: j.img }));
    } catch {
      return [];
    }
  };

  // --- Project editing ---
  const startEditProject = () => {
    setProjectDescription(project.description || '');
    setProjectStrategies(project.defaultStrategies ?? []);
    setProjectDirty(false);
    setEditingProject(true);
  };

  const saveProject = () => {
    activator.updateProject({
      id: project.id,
      description: projectDescription.trim(),
      defaultStrategies: projectStrategies.length > 0 ? projectStrategies : undefined,
    });
    setEditingProject(false);
    setProjectDirty(false);
  };

  // --- Module CRUD ---
  const toJiraRefs = (tickets: Array<{ value: string; label: string; iconUrl?: string }>): JiraTicketRef[] =>
    tickets.map(t => ({ key: t.value, summary: t.label.replace(/^[^ ]+ - /, ''), iconUrl: t.iconUrl }));

  const handleAddModule = () => {
    if (!moduleName.trim()) return;
    const jira = toJiraRefs(moduleTickets);
    activator.createModule(project.id, {
      name: moduleName.trim(),
      description: moduleDescription.trim() || undefined,
      pageUrl: modulePageUrl.trim() || undefined,
      scopeSelector: moduleScope.trim() || undefined,
      jiraTickets: jira.length > 0 ? jira : undefined,
    });
    resetModuleForm();
  };

  const startEditModule = (mod: Module) => {
    setEditingModuleId(mod.id);
    setModuleName(mod.name);
    setModuleDescription(mod.description || '');
    setModulePageUrl(mod.pageUrl || '');
    setModuleScope(mod.scopeSelector || '');
    setModuleTickets(
      (mod.jiraTickets || []).map(t => ({ value: t.key, label: `${t.key} - ${t.summary}`, iconUrl: t.iconUrl })),
    );
  };

  const saveEditModule = () => {
    if (!editingModuleId || !moduleName.trim()) return;
    const jira = toJiraRefs(moduleTickets);
    activator.updateModule(project.id, editingModuleId, {
      name: moduleName.trim(),
      description: moduleDescription.trim() || undefined,
      pageUrl: modulePageUrl.trim() || undefined,
      scopeSelector: moduleScope.trim() || undefined,
      jiraTickets: jira.length > 0 ? jira : undefined,
    });
    resetModuleForm();
  };

  const resetModuleForm = () => {
    setShowAddModule(false);
    setEditingModuleId(null);
    setModuleName('');
    setModuleDescription('');
    setModulePageUrl('');
    setModuleScope('');
    setModuleTickets([]);
  };

  const handleDeleteModule = (moduleId: string) => {
    if (confirm('Delete this module and all its features?')) {
      activator.deleteModule(project.id, moduleId);
    }
  };

  // --- Module form ---
  const moduleForm = (
    <div className="rounded-xl border border-gray-200 bg-white p-4 mb-4">
      <h3 className="text-sm font-semibold text-gray-800 mb-3">
        {editingModuleId ? 'Edit Module' : 'Add Module'}
      </h3>
      <div className="space-y-3">
        <div>
          <label className="block text-xs text-gray-500 mb-1">Name *</label>
          <input
            value={moduleName}
            onChange={e => setModuleName(e.target.value)}
            className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-300"
            placeholder="e.g., User Management, Reports, Settings"
            autoFocus
          />
        </div>
        <div>
          <MultiSelectAutocomplete
            label="Jira Epic (optional)"
            onSearch={searchTickets}
            value={moduleTickets}
            onChange={(v: any[]) => setModuleTickets(v)}
          />
        </div>
        <div>
          <label className="block text-xs text-gray-500 mb-1">Description / Module-level prompts</label>
          <textarea
            value={moduleDescription}
            onChange={e => setModuleDescription(e.target.value)}
            className="w-full h-20 px-3 py-2 border border-gray-200 rounded-lg text-sm resize-y focus:outline-none focus:ring-2 focus:ring-orange-300"
            placeholder="Context or instructions specific to this module..."
          />
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
          <div>
            <label className="block text-xs text-gray-500 mb-1">Page URL (optional)</label>
            <input
              value={modulePageUrl}
              onChange={e => setModulePageUrl(e.target.value)}
              className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-300"
              placeholder="https://example.com/users"
            />
          </div>
          <div>
            <label className="block text-xs text-gray-500 mb-1">Scope Selector (optional)</label>
            <input
              value={moduleScope}
              onChange={e => setModuleScope(e.target.value)}
              className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm font-mono focus:outline-none focus:ring-2 focus:ring-orange-300"
              placeholder="#main-content"
            />
          </div>
        </div>
        <div className="flex gap-2">
          <button
            onClick={editingModuleId ? saveEditModule : handleAddModule}
            disabled={!moduleName.trim()}
            className="px-4 py-1.5 text-sm bg-orange-500 text-white rounded-lg hover:bg-orange-600 disabled:opacity-40 font-semibold transition"
          >
            {editingModuleId ? 'Save' : 'Add Module'}
          </button>
          <button
            onClick={resetModuleForm}
            className="px-4 py-1.5 text-sm bg-gray-100 text-gray-600 rounded-lg hover:bg-gray-200 transition"
          >
            Cancel
          </button>
        </div>
      </div>
    </div>
  );

  return (
    <div className="w-full px-4 py-6">
      {/* Header */}
      <div className="rounded-2xl border border-gray-200 bg-white px-5 py-5 mb-5">
        <div className="flex items-center gap-2 mb-3">
          <button
            onClick={() => navigate('/')}
            className="inline-flex items-center gap-1 px-2 py-1 text-xs text-gray-600 hover:text-gray-900 hover:bg-gray-100 rounded-md transition"
            title="Back to Projects"
          >
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
            Back
          </button>
          <span className="text-gray-300">|</span>
          <button onClick={() => navigate('/')} className="text-sm text-gray-400 hover:text-gray-700">Projects</button>
          <span className="text-gray-300">/</span>
          <span className="text-sm font-medium text-gray-800">{project.name}</span>
        </div>
        <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-3">
          <div className="min-w-0">
            <h1 className="text-xl font-bold text-gray-800">{project.name}</h1>
            <p className="text-xs text-gray-400 mt-0.5">{project.category}</p>
            {!editingProject && project.description && (
              <p className="text-sm text-gray-500 mt-2">{project.description}</p>
            )}
          </div>
          <div className="flex items-center gap-2 shrink-0">
            {!editingProject && (
              <>
                <button
                  onClick={() => navigate(`/project/${project.id}/traceability`)}
                  className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-50 transition"
                >
                  Traceability
                </button>
                <button
                  onClick={startEditProject}
                  className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-50 transition"
                >
                  Edit Project
                </button>
              </>
            )}
          </div>
        </div>

        {/* Inline project edit */}
        {editingProject && (
          <div className="mt-4 pt-4 border-t border-gray-100 space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">General Prompts / Instructions</label>
              <textarea
                value={projectDescription}
                onChange={e => { setProjectDescription(e.target.value); setProjectDirty(true); }}
                rows={3}
                className="w-full px-3 py-2 border border-gray-300 rounded-md text-sm resize-y"
                placeholder="General context or instructions that apply to all testing within this project..."
              />
            </div>
            <StrategyPicker
              label="Default test strategies"
              helper="Features inherit these unless they override. Empty = use built-in defaults."
              value={projectStrategies}
              onChange={(v) => { setProjectStrategies(v); setProjectDirty(true); }}
              inheritedFrom={DEFAULT_PROJECT_STRATEGIES as unknown as string[]}
              showResetToDefaults
            />
            <div className="flex gap-2">
              <button onClick={saveProject} className="px-4 py-1.5 text-sm bg-orange-500 text-white rounded-lg hover:bg-orange-600 font-semibold transition">
                Save
              </button>
              <button onClick={() => setEditingProject(false)} className="px-4 py-1.5 text-sm bg-gray-100 text-gray-600 rounded-lg hover:bg-gray-200 transition">
                Cancel
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Modules list */}
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-base font-semibold text-gray-800">Modules ({project.modules.length})</h2>
        {!showAddModule && !editingModuleId && (
          <button
            onClick={() => setShowAddModule(true)}
            className="px-3 py-1.5 text-xs font-semibold bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition"
          >
            + Add Module
          </button>
        )}
      </div>

      {(showAddModule || editingModuleId) && moduleForm}

      {project.modules.length === 0 && !showAddModule && (
        <div className="rounded-2xl border border-gray-200 bg-white p-10 text-center">
          <h3 className="text-lg font-semibold text-gray-800 mb-1">No modules yet</h3>
          <p className="text-sm text-gray-500 mb-4">Add modules to organize your testing by functional areas.</p>
          <button
            onClick={() => setShowAddModule(true)}
            className="px-5 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 font-semibold text-sm transition"
          >
            + Add Module
          </button>
        </div>
      )}

      <div className="space-y-3">
        {project.modules.map(mod => {
          const totalFeatures = mod.features.length;
          const totalTests = mod.features.reduce((sum, f) => sum + f.testCases.length, 0);

          return (
            <div
              key={mod.id}
              className="rounded-xl border border-gray-100 bg-white hover:border-gray-300 hover:shadow-sm transition-all cursor-pointer"
              onClick={() => navigate(`/project/${project.id}/module/${mod.id}`)}
            >
              <div className="p-4 flex items-center justify-between">
                <div className="min-w-0">
                  <h3 className="text-sm font-semibold text-gray-800">{mod.name}</h3>
                  {mod.description && <p className="text-xs text-gray-500 mt-0.5 line-clamp-1">{mod.description}</p>}
                  <div className="flex flex-wrap gap-3 mt-1.5 text-xs text-gray-400">
                    <span>{totalFeatures} feature{totalFeatures !== 1 ? 's' : ''}</span>
                    {totalTests > 0 && <span>{totalTests} tests</span>}
                    {mod.pageUrl && <span className="truncate max-w-48">{mod.pageUrl}</span>}
                    {mod.jiraTickets && mod.jiraTickets.length > 0 && (
                      <span>{mod.jiraTickets.length} Jira ticket{mod.jiraTickets.length > 1 ? 's' : ''}</span>
                    )}
                  </div>
                </div>
                <div className="flex items-center gap-1 ml-3">
                  <button
                    onClick={(e) => { e.stopPropagation(); startEditModule(mod); }}
                    className="p-1.5 text-gray-400 hover:text-blue-500 rounded hover:bg-blue-50 transition"
                    title="Edit"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                  </button>
                  <button
                    onClick={(e) => { e.stopPropagation(); handleDeleteModule(mod.id); }}
                    className="p-1.5 text-gray-400 hover:text-red-500 rounded hover:bg-red-50 transition"
                    title="Delete"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  </button>
                  <svg className="w-4 h-4 text-gray-300 ml-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
