import { useNavigate, useParams } from 'react-router-dom';
import { useStore } from '../../store/state';
import { useActivator } from '../../store/Context';
import FeatureForm, { type FeatureFormValue } from '../workflow-tests/components/FeatureForm';

export default function FeatureDetail() {
  const { projectId, moduleId, featureId } = useParams<{
    projectId: string;
    moduleId: string;
    featureId: string;
  }>();
  const navigate = useNavigate();
  const activator = useActivator();
  const generating = useStore(s => s.generatingTestCases);

  const project = useStore(s => s.projects.find(p => p.id === projectId));
  const mod = project?.modules.find(m => m.id === moduleId);
  const feature = mod?.features.find(f => f.id === featureId);

  if (!project || !mod || !feature) {
    return (
      <div className="w-full px-4 py-6">
        <div className="rounded-lg border border-gray-200 bg-white p-6 text-center text-gray-500 text-sm">
          Feature not found
        </div>
      </div>
    );
  }

  const pid = project.id;
  const mid = mod.id;
  const fid = feature.id;
  const hasTests = feature.testCases.length > 0;
  const hasRuns = (feature.testRuns?.length ?? 0) > 0;
  const featureMode: 'ai' | 'manual' = feature.mode ?? 'ai';
  const isManualMode = featureMode === 'manual';

  const saveFeature = (value: FeatureFormValue) => {
    activator.updateFeature(pid, mid, fid, {
      name: value.name || feature.name,
      description: value.description,
      jiraTickets: value.jiraTickets.length > 0 ? value.jiraTickets : undefined,
      swaggerApis: value.swaggerApis.length > 0 ? value.swaggerApis : undefined,
      strategyOverride: value.strategyOverride,
    });
  };

  const saveAndGenerate = (value: FeatureFormValue) => {
    saveFeature(value);
    activator.generateTestCases(pid, mid, fid, undefined, value.strategyOverride);
    navigate(`/project/${pid}/module/${mid}/feature/${fid}/tests`);
  };

  return (
    <div className="w-full px-4 py-6">
      {/* Breadcrumb + Back */}
      <div className="flex items-center gap-2 mb-3 text-sm flex-wrap">
        <button
          onClick={() => navigate(`/project/${pid}/module/${mid}`)}
          className="inline-flex items-center gap-1 px-2 py-1 text-xs text-gray-600 hover:text-gray-900 hover:bg-gray-100 rounded-md transition cursor-pointer"
          title="Back to Module"
        >
          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
          Back
        </button>
        <span className="text-gray-300">|</span>
        <button onClick={() => navigate('/')} className="text-gray-400 hover:text-gray-700 text-xs cursor-pointer">Projects</button>
        <span className="text-gray-300">/</span>
        <button onClick={() => navigate(`/project/${pid}`)} className="text-gray-400 hover:text-gray-700 text-xs cursor-pointer">{project.name}</button>
        <span className="text-gray-300">/</span>
        <button onClick={() => navigate(`/project/${pid}/module/${mid}`)} className="text-gray-400 hover:text-gray-700 text-xs cursor-pointer">{mod.name}</button>
        <span className="text-gray-300">/</span>
        <span className="font-medium text-gray-800 text-xs">{feature.name}</span>
      </div>

      <div className="rounded-lg border border-gray-200 bg-white px-4 py-4">
        <div className="flex items-center justify-between mb-4 flex-wrap gap-2">
          <div className="flex items-center gap-2">
            <h1 className="text-base font-bold text-gray-800">{feature.name}</h1>
            <span
              className={`inline-flex items-center px-2 py-0.5 text-[10px] font-semibold rounded-md border ${
                isManualMode
                  ? 'border-purple-200 bg-purple-50 text-purple-700'
                  : 'border-orange-200 bg-orange-50 text-orange-700'
              }`}
              title={
                isManualMode
                  ? 'Manual Automation — steps authored declaratively with the selector workbench'
                  : 'AI Automation — the AI drives the browser from screenshots and a11y tree'
              }
            >
              {isManualMode ? 'Manual mode' : 'AI mode'}
            </span>
            {feature.type === 'comparison' && (
              <span className="px-2 py-0.5 rounded-full text-xs font-medium bg-purple-50 text-purple-700 border border-purple-200">
                Comparison
              </span>
            )}
          </div>
          <div className="flex items-center gap-1.5">
            {feature.type === 'comparison' && (
              <button
                onClick={() => navigate(`/project/${pid}/module/${mid}/feature/${fid}/compare`)}
                className="px-3 py-1.5 text-xs font-semibold bg-purple-500 text-white rounded-lg hover:bg-purple-600 transition inline-flex items-center gap-1.5 cursor-pointer"
              >
                Run Comparison
              </button>
            )}
            {hasRuns && (
              <button
                onClick={() => navigate(`/project/${pid}/module/${mid}/feature/${fid}/history`)}
                className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-50 transition inline-flex items-center gap-1.5 cursor-pointer"
                title="View execution history"
              >
                <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                History ({feature.testRuns!.length})
              </button>
            )}
            <button
              onClick={() => navigate(`/project/${pid}/module/${mid}/feature/${fid}/tests`)}
              className="px-3 py-1.5 text-xs font-semibold bg-green-500 text-white rounded-lg hover:bg-green-600 transition flex items-center gap-1.5 cursor-pointer"
              title={isManualMode ? 'Open the manual authoring surface' : 'Open the tests page'}
            >
              <svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z" /></svg>
              {hasTests
                ? `View Tests (${feature.testCases.length})`
                : isManualMode
                  ? 'Author Test Cases'
                  : 'Open Tests Page'}
            </button>
          </div>
        </div>

        <FeatureForm
          initial={{
            name: feature.name,
            description: feature.description,
            jiraTickets: feature.jiraTickets,
            swaggerApis: feature.swaggerApis,
            strategyOverride: feature.strategyOverride,
          }}
          projectDefaultStrategies={project.defaultStrategies}
          submitLabel="Save"
          submitClassName="px-4 py-2 bg-gray-700 text-white rounded-md text-sm font-medium hover:bg-gray-800 transition cursor-pointer"
          onSubmit={saveFeature}
          secondaryAction={{
            label: generating ? 'Generating...' : hasTests ? 'Save & Regenerate Test Cases' : 'Save & Generate Test Cases',
            onSubmit: saveAndGenerate,
            disabled: generating,
          }}
        />
      </div>
    </div>
  );
}
