import { useMemo, useState } from 'react';
import type {
  Fixture,
  LoopBinding,
  ManualStep,
  ResolutionPreset,
  TestCase,
  ValueRef,
} from '../../../../activator/types/state';
import { activeLoopsFor, producersBefore, producerDisplayLabel } from '../../../../activator/engine/referenceHelpers';
import type ActivatorProxy from '../../../store/ActivatorProxy';
import { DeleteIcon, PlusCircleIcon, TimesIcon } from '../../../styles/Icons';
import { MANUAL_ACTION_CATALOG, ALL_MANUAL_ACTIONS, categoryForAction } from './manualActionCatalog';

const PRESETS: ResolutionPreset[] = ['mobile', 'tablet', 'laptop', 'desktop', 'wide'];

/**
 * Browser-side mirror of `hashSandboxedScript` in activator/engine/SecurityGate.ts.
 * Must stay byte-for-byte compatible — sha256 hex of the UTF-8 script body.
 * (SecurityGate uses node:crypto which can't be imported into the UI bundle.)
 */
async function sha256Hex(input: string): Promise<string> {
  const bytes = new TextEncoder().encode(input);
  const digest = await crypto.subtle.digest('SHA-256', bytes);
  return Array.from(new Uint8Array(digest))
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
}

interface Props {
  testCase: TestCase;
  step: ManualStep;
  activator: ActivatorProxy;
  projectId: string;
  featureId: string;
  fixtures: Fixture[];
  onClose: () => void;
  onLaunchPicker: () => void;
}

/**
 * Right-hand authoring panel for a single manual step. Opens when the user
 * clicks a step row. Edits commit immediately through `updateManualStep` —
 * there is no local dirty state or Save button, matching the rest of the app.
 *
 * This is the compact first cut. Still pending: target picker launching the
 * picker workbench, reference-value dropdowns for parameters, sub-ops list UI.
 * Parameters are edited as JSON for now so every tool remains expressible.
 */
export default function StepAuthoringPanel({
  testCase,
  step,
  activator,
  projectId,
  featureId,
  fixtures,
  onClose,
  onLaunchPicker,
}: Props) {
  const patch = (p: Partial<ManualStep>) => {
    const nextToolName = p.toolName ?? step.toolName;
    const touchesArgs = p.toolArgs !== undefined || p.toolName !== undefined;
    // For run_sandboxed_js: keep toolArgs.authoredHash pinned to the live script's sha256.
    // If we don't, SecurityGate will prompt the user on every run (REQUIREMENTS.md §4.10).
    if (nextToolName === 'run_sandboxed_js' && touchesArgs) {
      const nextArgs = { ...(p.toolArgs ?? step.toolArgs ?? {}) } as Record<string, unknown>;
      const script = typeof nextArgs.script === 'string' ? (nextArgs.script as string) : '';
      delete nextArgs.authoredHash;
      const send = (args: Record<string, unknown>) => {
        activator.updateManualStep(projectId, featureId, testCase.id, step.id, {
          ...p,
          toolArgs: args,
        });
      };
      if (!script) {
        send(nextArgs);
        return;
      }
      void sha256Hex(script).then((hash) => send({ ...nextArgs, authoredHash: hash }));
      return;
    }
    activator.updateManualStep(projectId, featureId, testCase.id, step.id, p);
  };

  // Producers (step refs) available for this step — everything that comes
  // before it in the same testcase and is a producer.
  const availableProducers = useMemo(
    () => producersBefore(testCase, step.id),
    [testCase, step.id],
  );

  // CSV columns reachable from this step — union of columns from every
  // fixture bound by a loop whose body contains this step.
  const availableCsvColumns = useMemo(() => {
    const loops = (testCase.loopBindings ?? []) as LoopBinding[];
    const active = activeLoopsFor(testCase, step.id, loops);
    const rows: Array<{ fixture: Fixture; columnName: string; secret: boolean }> = [];
    for (const loop of active) {
      const fixture = fixtures.find((f) => f.id === loop.fixtureId);
      if (!fixture) continue;
      for (const col of fixture.columns) {
        rows.push({ fixture, columnName: col.name, secret: !!col.secret });
      }
    }
    return rows;
  }, [testCase, step.id, fixtures]);

  const guardPresets = new Set<ResolutionPreset>(step.resolutionGuard?.presets ?? []);
  const toggleGuard = (preset: ResolutionPreset) => {
    const next = new Set(guardPresets);
    if (next.has(preset)) next.delete(preset);
    else next.add(preset);
    patch({ resolutionGuard: { presets: Array.from(next) } });
  };

  return (
    <aside
      className="w-full lg:w-80 lg:shrink-0 border-t lg:border-t-0 lg:border-l border-gray-200 bg-white flex flex-col lg:max-h-[calc(100vh-3rem)] lg:sticky lg:top-3 mt-2 lg:mt-0"
      role="complementary"
      aria-label="Step authoring panel"
    >
      {/* Header */}
      <div className="flex items-center justify-between px-3 py-2 border-b border-gray-200 bg-gray-50">
        <div className="min-w-0">
          <div className="text-[9px] uppercase tracking-wider text-gray-500">Edit step</div>
          <div className="text-xs font-semibold text-gray-800 truncate">
            {step.title || step.toolName}
          </div>
        </div>
        <button
          type="button"
          onClick={onClose}
          className="p-1 text-gray-500 hover:text-gray-800 hover:bg-gray-100 rounded shrink-0"
          aria-label="Close step panel"
          title="Close"
        >
          <TimesIcon />
        </button>
      </div>

      <div className="flex-1 overflow-y-auto px-3 py-2 space-y-3 text-[11px]">
        {/* Action */}
        <FieldLabel>Action</FieldLabel>
        <ActionSelector
          value={step.toolName}
          onChange={(name) => patch({ toolName: name })}
        />

        {/* Title */}
        <FieldLabel htmlFor={`title-${step.id}`}>Title</FieldLabel>
        <input
          id={`title-${step.id}`}
          value={step.title ?? ''}
          onChange={(e) => patch({ title: e.target.value || undefined })}
          placeholder="Short label"
          className="w-full px-2 py-1 border border-gray-200 rounded text-[11px] focus:outline-none focus:ring-1 focus:ring-orange-300"
        />

        {/* Description */}
        <FieldLabel htmlFor={`desc-${step.id}`}>Description</FieldLabel>
        <textarea
          id={`desc-${step.id}`}
          value={step.description ?? ''}
          onChange={(e) => patch({ description: e.target.value || undefined })}
          placeholder="What this step does (optional)"
          rows={2}
          className="w-full px-2 py-1 border border-gray-200 rounded text-[11px] resize-y focus:outline-none focus:ring-1 focus:ring-orange-300"
        />

        {/* Expected outcome */}
        <FieldLabel htmlFor={`exp-${step.id}`}>Expected outcome</FieldLabel>
        <textarea
          id={`exp-${step.id}`}
          value={step.expectedOutcome ?? ''}
          onChange={(e) => patch({ expectedOutcome: e.target.value || undefined })}
          placeholder="Used in exports and reports"
          rows={2}
          className="w-full px-2 py-1 border border-gray-200 rounded text-[11px] resize-y focus:outline-none focus:ring-1 focus:ring-orange-300"
        />

        {/* Parameters */}
        <FieldLabel>Parameters</FieldLabel>
        <ParametersEditor
          step={step}
          producers={availableProducers}
          csvColumns={availableCsvColumns}
          onChange={(toolArgs, refs) => patch({ toolArgs, refs })}
        />

        {/* Selectors */}
        <div className="flex items-center justify-between">
          <FieldLabel>Selectors</FieldLabel>
          <button
            type="button"
            onClick={onLaunchPicker}
            className="px-1.5 py-0.5 text-[10px] bg-orange-500 text-white rounded hover:bg-orange-600"
            title="Launch the picker workbench"
          >
            Pick element
          </button>
        </div>
        {step.selectors && step.selectors.length > 0 ? (
          <ul className="space-y-1">
            {step.selectors.map((s, i) => (
              <li
                key={i}
                className="flex items-center gap-1.5 px-1.5 py-1 border border-gray-200 rounded"
              >
                <span className="px-1 py-0.5 text-[9px] font-semibold bg-gray-100 text-gray-600 rounded shrink-0">
                  {s.strategy}
                </span>
                <code className="text-[10px] text-gray-700 truncate flex-1">{s.selector}</code>
                {typeof s.matchCount === 'number' && s.matchCount >= 0 && (
                  <span className="text-[9px] text-gray-400 shrink-0">×{s.matchCount}</span>
                )}
              </li>
            ))}
          </ul>
        ) : (
          <p className="text-[10px] text-gray-400 italic">
            No selectors retained. Click <strong>Pick element</strong> above to open the workbench.
          </p>
        )}

        {/* Resolution guards */}
        <FieldLabel>Run only when resolution is</FieldLabel>
        <div className="flex flex-wrap gap-1" role="group" aria-label="Resolution guard presets">
          {PRESETS.map((p) => {
            const active = guardPresets.has(p);
            return (
              <button
                key={p}
                type="button"
                onClick={() => toggleGuard(p)}
                aria-pressed={active}
                className={`px-1.5 py-0.5 text-[10px] font-medium rounded border transition ${
                  active
                    ? 'bg-blue-100 border-blue-300 text-blue-700'
                    : 'bg-white border-gray-200 text-gray-500 hover:border-gray-300'
                }`}
              >
                {p}
              </button>
            );
          })}
        </div>
        <p className="text-[9px] text-gray-400">
          None selected = always run. Multiple = set membership (any match).
        </p>

        {/* Flags */}
        <FieldLabel>Flags</FieldLabel>
        <div className="space-y-1">
          <Toggle
            label="Producer (captures a value)"
            checked={!!step.isProducer}
            onChange={(v) => patch({ isProducer: v || undefined })}
          />
          <Toggle
            label="Optional (warn on failure, keep going)"
            checked={!!step.optional}
            onChange={(v) => patch({ optional: v || undefined })}
          />
          <Toggle
            label="Enabled"
            checked={step.enabled !== false}
            onChange={(v) => patch({ enabled: v ? true : false })}
          />
        </div>

        {/* Retry */}
        <FieldLabel htmlFor={`retry-${step.id}`}>Retry</FieldLabel>
        <div className="flex items-center gap-1.5">
          <input
            id={`retry-${step.id}`}
            type="number"
            min={0}
            max={10}
            value={step.retryCount ?? 0}
            onChange={(e) => {
              const n = Math.max(0, Math.min(10, Number(e.target.value) || 0));
              patch({ retryCount: n || undefined });
            }}
            className="w-14 px-1.5 py-1 border border-gray-200 rounded text-[11px] focus:outline-none focus:ring-1 focus:ring-orange-300"
            aria-label="Retry count"
          />
          <span className="text-[10px] text-gray-500">×, delay</span>
          <input
            type="number"
            min={0}
            value={step.retryDelayMs ?? 0}
            onChange={(e) => {
              const n = Math.max(0, Number(e.target.value) || 0);
              patch({ retryDelayMs: n || undefined });
            }}
            className="w-16 px-1.5 py-1 border border-gray-200 rounded text-[11px] focus:outline-none focus:ring-1 focus:ring-orange-300"
            aria-label="Retry delay ms"
          />
          <span className="text-[10px] text-gray-500">ms</span>
        </div>

        {/* Group label */}
        <FieldLabel htmlFor={`group-${step.id}`}>Group</FieldLabel>
        <input
          id={`group-${step.id}`}
          value={step.group ?? ''}
          onChange={(e) => patch({ group: e.target.value || undefined })}
          placeholder="Setup / Act / Assert"
          className="w-full px-2 py-1 border border-gray-200 rounded text-[11px] focus:outline-none focus:ring-1 focus:ring-orange-300"
        />

        {/* References panel (REQUIREMENTS.md §5). Visibility only — lists every
            producer + CSV column reachable from this step's scope. Runtime
            captured values live on run results, not on the authored steps. */}
        <FieldLabel>Available references</FieldLabel>
        <div className="rounded border border-gray-200 bg-gray-50/50 p-1.5">
          {availableProducers.length === 0 && availableCsvColumns.length === 0 ? (
            <p className="text-[10px] text-gray-400 italic">
              No producers or CSV columns in scope.
            </p>
          ) : (
            <>
              {availableProducers.length > 0 && (
                <div className="mb-1">
                  <div className="text-[9px] uppercase tracking-wider text-gray-500 font-semibold mb-0.5">
                    Producer steps
                  </div>
                  <ul className="space-y-0.5">
                    {availableProducers.map((p, i) => (
                      <li key={p.id} className="text-[10px] text-gray-700 truncate">
                        {producerDisplayLabel(p, i)}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
              {availableCsvColumns.length > 0 && (
                <div>
                  <div className="text-[9px] uppercase tracking-wider text-gray-500 font-semibold mb-0.5">
                    CSV columns (in scope)
                  </div>
                  <ul className="space-y-0.5">
                    {availableCsvColumns.map((c) => (
                      <li
                        key={`${c.fixture.id}::${c.columnName}`}
                        className="text-[10px] text-gray-700 truncate"
                      >
                        <span className="font-mono">
                          {c.fixture.filename}:{c.columnName}
                        </span>
                        {c.secret && (
                          <span className="ml-1 px-1 py-0.5 text-[8px] font-semibold bg-red-100 text-red-700 rounded">
                            secret
                          </span>
                        )}
                      </li>
                    ))}
                  </ul>
                </div>
              )}
            </>
          )}
        </div>
      </div>
    </aside>
  );
}

function FieldLabel({ children, htmlFor }: { children: React.ReactNode; htmlFor?: string }) {
  return (
    <label
      htmlFor={htmlFor}
      className="block text-[9px] uppercase tracking-wider text-gray-500 font-semibold"
    >
      {children}
    </label>
  );
}

function Toggle({
  label,
  checked,
  onChange,
}: {
  label: string;
  checked: boolean;
  onChange: (v: boolean) => void;
}) {
  return (
    <label className="inline-flex items-center gap-1.5 cursor-pointer text-[11px] text-gray-700">
      <input
        type="checkbox"
        checked={checked}
        onChange={(e) => onChange(e.target.checked)}
        className="accent-orange-500"
      />
      {label}
    </label>
  );
}

/* ============== Action selector ============== */

interface ActionSelectorProps {
  value: string;
  onChange: (name: string) => void;
}

export function ActionSelector({ value, onChange }: ActionSelectorProps) {
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState('');

  const filtered = useMemo(() => {
    const q = query.trim().toLowerCase();
    if (!q) return MANUAL_ACTION_CATALOG;
    return MANUAL_ACTION_CATALOG.map((cat) => ({
      ...cat,
      actions: cat.actions.filter(
        (a) =>
          a.name.toLowerCase().includes(q) ||
          (a.hint && a.hint.toLowerCase().includes(q)),
      ),
    })).filter((cat) => cat.actions.length > 0);
  }, [query]);

  const currentCat = categoryForAction(value);
  const isKnown = ALL_MANUAL_ACTIONS.some((a) => a.name === value);

  return (
    <div className="relative">
      <button
        type="button"
        onClick={() => setOpen((v) => !v)}
        className="w-full px-2 py-1.5 text-left border border-gray-200 rounded hover:border-gray-300 focus:outline-none focus:ring-1 focus:ring-orange-300"
        aria-haspopup="listbox"
        aria-expanded={open}
      >
        <div className="flex items-center justify-between">
          <span className="font-mono text-[11px] text-orange-600 truncate">{value || '(no action)'}</span>
          <span className="text-[9px] text-gray-400 shrink-0">
            {currentCat ?? (isKnown ? '' : 'custom')}
          </span>
        </div>
      </button>

      {open && (
        <div className="absolute z-30 mt-1 w-full bg-white border border-gray-200 rounded-lg shadow-lg overflow-hidden">
          <input
            autoFocus
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            placeholder="Search actions…"
            className="w-full px-2 py-1.5 border-b border-gray-200 text-[11px] focus:outline-none"
            aria-label="Search actions"
          />
          <div className="max-h-72 overflow-y-auto" role="listbox">
            {filtered.length === 0 ? (
              <div className="px-2 py-3 text-[11px] text-gray-400 italic text-center">
                No matches. Type a custom name below.
              </div>
            ) : (
              filtered.map((cat) => (
                <div key={cat.key}>
                  <div className="px-2 py-1 text-[9px] uppercase tracking-wider text-gray-400 bg-gray-50 sticky top-0">
                    {cat.label}
                  </div>
                  {cat.actions.map((a) => {
                    const active = a.name === value;
                    return (
                      <button
                        key={a.name}
                        type="button"
                        role="option"
                        aria-selected={active}
                        onClick={() => {
                          onChange(a.name);
                          setOpen(false);
                          setQuery('');
                        }}
                        className={`block w-full text-left px-2 py-1 border-b border-gray-50 last:border-0 ${
                          active ? 'bg-orange-50' : 'hover:bg-gray-50'
                        }`}
                      >
                        <div className="font-mono text-[11px] text-orange-600 truncate">{a.name}</div>
                        {a.hint && (
                          <div className="text-[9px] text-gray-500 truncate">{a.hint}</div>
                        )}
                      </button>
                    );
                  })}
                </div>
              ))
            )}
          </div>
          <div className="px-2 py-1.5 border-t border-gray-200 bg-gray-50">
            <input
              value={value}
              onChange={(e) => onChange(e.target.value)}
              placeholder="Custom tool name"
              className="w-full px-1.5 py-1 text-[11px] border border-gray-200 rounded focus:outline-none focus:ring-1 focus:ring-orange-300"
              aria-label="Custom tool name"
            />
          </div>
        </div>
      )}
    </div>
  );
}

/* ============== Parameters editor ============== */

type ParamKind = 'literal' | 'producer' | 'csv';

interface CsvColumnChoice {
  fixture: Fixture;
  columnName: string;
  secret: boolean;
}

interface ParametersEditorProps {
  step: ManualStep;
  producers: ManualStep[];
  csvColumns: CsvColumnChoice[];
  onChange: (toolArgs: Record<string, unknown>, refs: Record<string, ValueRef> | undefined) => void;
}

/**
 * Per-parameter editor. Each entry in the step's `toolArgs` becomes a row
 * with a literal/producer/csv selector. Producer and CSV values are tracked
 * in `step.refs` — the step's `toolArgs[key]` carries a sentinel placeholder
 * so replay + export know the param was a reference. We encode the sentinel
 * as `{ __ref: true }` which is never a valid literal.
 *
 * Adding a new parameter is a free-form key + kind chooser below the list.
 * Keys with empty literal values serialize as empty string for replay-safety.
 */
function ParametersEditor({ step, producers, csvColumns, onChange }: ParametersEditorProps) {
  const [newKey, setNewKey] = useState('');

  const entries = useMemo(() => {
    const refs = step.refs ?? {};
    return Object.keys(step.toolArgs ?? {}).map((key) => ({
      key,
      value: step.toolArgs[key],
      ref: refs[key] as ValueRef | undefined,
    }));
  }, [step.toolArgs, step.refs]);

  const writeArg = (key: string, value: unknown, ref?: ValueRef) => {
    const nextArgs = { ...(step.toolArgs ?? {}), [key]: value };
    const nextRefs: Record<string, ValueRef> = { ...(step.refs ?? {}) };
    if (ref) nextRefs[key] = ref;
    else delete nextRefs[key];
    const refsToSend = Object.keys(nextRefs).length > 0 ? nextRefs : undefined;
    onChange(nextArgs, refsToSend);
  };

  const removeArg = (key: string) => {
    const nextArgs = { ...(step.toolArgs ?? {}) };
    delete nextArgs[key];
    const nextRefs: Record<string, ValueRef> = { ...(step.refs ?? {}) };
    delete nextRefs[key];
    const refsToSend = Object.keys(nextRefs).length > 0 ? nextRefs : undefined;
    onChange(nextArgs, refsToSend);
  };

  const addArg = () => {
    const k = newKey.trim();
    if (!k) return;
    if (step.toolArgs && k in step.toolArgs) return;
    writeArg(k, '');
    setNewKey('');
  };

  return (
    <div className="space-y-1.5">
      {entries.length === 0 && (
        <p className="text-[10px] text-gray-400 italic">No parameters. Add one below.</p>
      )}
      {entries.map((entry) => (
        <ParameterRow
          key={entry.key}
          paramKey={entry.key}
          value={entry.value}
          ref={entry.ref}
          producers={producers}
          csvColumns={csvColumns}
          onChange={(value, ref) => writeArg(entry.key, value, ref)}
          onRemove={() => removeArg(entry.key)}
        />
      ))}
      <div className="flex items-center gap-1.5 pt-1 border-t border-gray-100">
        <input
          value={newKey}
          onChange={(e) => setNewKey(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') {
              e.preventDefault();
              addArg();
            }
          }}
          placeholder="new param name"
          className="flex-1 min-w-0 px-1.5 py-0.5 border border-gray-200 rounded text-[10px] focus:outline-none focus:ring-1 focus:ring-orange-300"
          aria-label="New parameter name"
        />
        <button
          type="button"
          onClick={addArg}
          disabled={!newKey.trim()}
          className="px-1.5 py-0.5 text-[10px] font-semibold bg-gray-100 text-gray-700 rounded hover:bg-gray-200 disabled:opacity-40 inline-flex items-center gap-0.5"
        >
          <PlusCircleIcon className="w-3 h-3" /> add
        </button>
      </div>
    </div>
  );
}

interface ParameterRowProps {
  paramKey: string;
  value: unknown;
  ref?: ValueRef;
  producers: ManualStep[];
  csvColumns: CsvColumnChoice[];
  onChange: (value: unknown, ref?: ValueRef) => void;
  onRemove: () => void;
}

const REF_SENTINEL = { __ref: true };

function ParameterRow({
  paramKey,
  value,
  ref,
  producers,
  csvColumns,
  onChange,
  onRemove,
}: ParameterRowProps) {
  const currentKind: ParamKind = ref ? (ref.kind === 'step' ? 'producer' : 'csv') : 'literal';

  const setKind = (kind: ParamKind) => {
    if (kind === currentKind) return;
    if (kind === 'literal') {
      onChange('', undefined);
    } else if (kind === 'producer') {
      if (producers.length === 0) return;
      const first = producers[0];
      onChange(REF_SENTINEL, { kind: 'step', stepId: first.id });
    } else {
      if (csvColumns.length === 0) return;
      const first = csvColumns[0];
      onChange(REF_SENTINEL, { kind: 'csv', fixtureId: first.fixture.id, columnName: first.columnName });
    }
  };

  return (
    <div className="rounded border border-gray-200 bg-white px-1.5 py-1">
      <div className="flex items-center gap-1 mb-1">
        <span className="flex-1 font-mono text-[10px] text-gray-700 truncate">{paramKey}</span>
        <KindChip active={currentKind === 'literal'} onClick={() => setKind('literal')} disabled={false}>
          literal
        </KindChip>
        <KindChip
          active={currentKind === 'producer'}
          onClick={() => setKind('producer')}
          disabled={producers.length === 0}
          title={producers.length === 0 ? 'No producer steps available yet' : 'Reference a prior step'}
        >
          step
        </KindChip>
        <KindChip
          active={currentKind === 'csv'}
          onClick={() => setKind('csv')}
          disabled={csvColumns.length === 0}
          title={csvColumns.length === 0 ? 'No CSV loops bound yet' : 'Reference a CSV column'}
        >
          csv
        </KindChip>
        <button
          type="button"
          onClick={onRemove}
          className="p-0.5 text-gray-400 hover:text-red-600"
          aria-label={`Remove parameter ${paramKey}`}
          title="Remove parameter"
        >
          <DeleteIcon className="w-3 h-3" />
        </button>
      </div>
      {currentKind === 'literal' && (
        <input
          value={typeof value === 'string' ? value : value == null ? '' : String(value)}
          onChange={(e) => onChange(e.target.value, undefined)}
          placeholder="value"
          className="w-full px-1.5 py-0.5 border border-gray-200 rounded text-[10px] focus:outline-none focus:ring-1 focus:ring-orange-300"
          aria-label={`Literal value for ${paramKey}`}
        />
      )}
      {currentKind === 'producer' && ref?.kind === 'step' && (
        <select
          value={ref.stepId}
          onChange={(e) => onChange(REF_SENTINEL, { kind: 'step', stepId: e.target.value })}
          className="w-full px-1.5 py-0.5 border border-gray-200 rounded text-[10px]"
          aria-label={`Producer ref for ${paramKey}`}
        >
          {producers.map((p, i) => (
            <option key={p.id} value={p.id}>
              {producerDisplayLabel(p, i)}
            </option>
          ))}
        </select>
      )}
      {currentKind === 'csv' && ref?.kind === 'csv' && (
        <select
          value={`${ref.fixtureId}::${ref.columnName}`}
          onChange={(e) => {
            const [fixtureId, columnName] = e.target.value.split('::');
            onChange(REF_SENTINEL, { kind: 'csv', fixtureId, columnName });
          }}
          className="w-full px-1.5 py-0.5 border border-gray-200 rounded text-[10px]"
          aria-label={`CSV ref for ${paramKey}`}
        >
          {csvColumns.map((c) => (
            <option key={`${c.fixture.id}::${c.columnName}`} value={`${c.fixture.id}::${c.columnName}`}>
              {c.fixture.filename}:{c.columnName}
              {c.secret ? ' (secret)' : ''}
            </option>
          ))}
        </select>
      )}
    </div>
  );
}

function KindChip({
  children,
  active,
  onClick,
  disabled,
  title,
}: {
  children: React.ReactNode;
  active: boolean;
  onClick: () => void;
  disabled?: boolean;
  title?: string;
}) {
  return (
    <button
      type="button"
      onClick={onClick}
      disabled={disabled}
      title={title}
      aria-pressed={active}
      className={`px-1 py-0.5 text-[9px] font-semibold rounded border transition ${
        active
          ? 'bg-orange-100 border-orange-300 text-orange-700'
          : 'bg-white border-gray-200 text-gray-500 hover:border-gray-300'
      } disabled:opacity-30 disabled:cursor-not-allowed`}
    >
      {children}
    </button>
  );
}
