import type {
  ExecutionStatus,
  Feature,
  JiraTicketRef,
  Module,
  Project,
  TestCase,
  TestCaseRunResult,
  TestFinding,
  TestRun,
} from '../../activator/types/state';

/**
 * A single row in the traceability matrix.
 * Joins: Jira story → feature → test case → latest run → finding(s).
 *
 * Rows are emitted per (jira, feature, test case) triple. Features without
 * Jira tickets surface under a synthetic `__untraced__` Jira key so they
 * remain visible in the matrix.
 */
export interface TraceabilityRow {
  jiraKey: string;              // '__untraced__' when the feature has no tickets
  jiraSummary?: string;
  jiraIconUrl?: string;

  projectId: string;
  projectName: string;
  moduleId: string;
  moduleName: string;
  featureId: string;
  featureName: string;
  featureType: 'functional' | 'comparison';

  testCaseId: string;           // '__no_tests__' when the feature has no test cases
  testCaseTitle: string;
  testCasePriority?: TestCase['priority'];
  testCaseStrategy?: string;

  latestStatus: ExecutionStatus | 'never';
  latestRunAt?: string;
  latestRunId?: string;
  findings: TestFinding[];
}

export interface TraceabilityScope {
  projects: Project[];
  projectId?: string;
  moduleId?: string;
}

/** Find the latest run result for a given test case across all runs of a feature. */
function latestResultFor(runs: TestRun[] | undefined, testCaseId: string): {
  run?: TestRun;
  result?: TestCaseRunResult;
} {
  if (!runs || runs.length === 0) return {};
  // Runs stored oldest-first; walk newest-first.
  for (let i = runs.length - 1; i >= 0; i--) {
    const run = runs[i];
    const result = run.testCaseResults.find(r => r.testCaseId === testCaseId);
    if (result) return { run, result };
  }
  return {};
}

function rowsForFeature(project: Project, mod: Module, feature: Feature): TraceabilityRow[] {
  const tickets: (JiraTicketRef | null)[] =
    feature.jiraTickets && feature.jiraTickets.length > 0 ? feature.jiraTickets : [null];

  const testCases: TestCase[] = feature.testCases;

  const rows: TraceabilityRow[] = [];

  for (const ticket of tickets) {
    const jiraKey = ticket?.key ?? '__untraced__';
    const jiraSummary = ticket?.summary;
    const jiraIconUrl = ticket?.iconUrl;

    const base = {
      jiraKey,
      jiraSummary,
      jiraIconUrl,
      projectId: project.id,
      projectName: project.name,
      moduleId: mod.id,
      moduleName: mod.name,
      featureId: feature.id,
      featureName: feature.name,
      featureType: (feature.type ?? 'functional') as 'functional' | 'comparison',
    };

    if (testCases.length === 0) {
      rows.push({
        ...base,
        testCaseId: '__no_tests__',
        testCaseTitle: '(no test cases)',
        latestStatus: 'never',
        findings: [],
      });
      continue;
    }

    for (const tc of testCases) {
      const { run, result } = latestResultFor(feature.testRuns, tc.id);
      rows.push({
        ...base,
        testCaseId: tc.id,
        testCaseTitle: tc.title,
        testCasePriority: tc.priority,
        testCaseStrategy: tc.strategy,
        latestStatus: result?.status ?? tc.status ?? 'pending',
        latestRunAt: run?.startedAt,
        latestRunId: run?.id,
        findings: result?.findings ?? tc.findings ?? [],
      });
    }
  }

  return rows;
}

/** Build the traceability matrix for the given scope. */
export function buildTraceability(scope: TraceabilityScope): TraceabilityRow[] {
  const projects = scope.projectId
    ? scope.projects.filter(p => p.id === scope.projectId)
    : scope.projects;

  const rows: TraceabilityRow[] = [];
  for (const project of projects) {
    const modules = scope.moduleId
      ? project.modules.filter(m => m.id === scope.moduleId)
      : project.modules;

    for (const mod of modules) {
      for (const feature of mod.features) {
        rows.push(...rowsForFeature(project, mod, feature));
      }
    }
  }
  return rows;
}

export interface TraceabilityCounts {
  total: number;
  passed: number;
  failed: number;
  blocked: number;
  pending: number;
  never: number;
}

export function countByStatus(rows: TraceabilityRow[]): TraceabilityCounts {
  const c: TraceabilityCounts = { total: 0, passed: 0, failed: 0, blocked: 0, pending: 0, never: 0 };
  for (const r of rows) {
    if (r.testCaseId === '__no_tests__') continue;
    c.total++;
    if (r.latestStatus === 'passed') c.passed++;
    else if (r.latestStatus === 'failed') c.failed++;
    else if (r.latestStatus === 'skipped') c.blocked++;
    else if (r.latestStatus === 'never') c.never++;
    else c.pending++;
  }
  return c;
}

/** CSV serializer for download. */
export function rowsToCsv(rows: TraceabilityRow[]): string {
  const header = [
    'Jira Key',
    'Jira Summary',
    'Project',
    'Module',
    'Feature',
    'Feature Type',
    'Test Case',
    'Priority',
    'Strategy',
    'Latest Status',
    'Latest Run At',
    'Findings',
  ];
  const esc = (v: unknown) => {
    if (v === undefined || v === null) return '';
    const s = String(v).replace(/"/g, '""');
    return /[",\n]/.test(s) ? `"${s}"` : s;
  };
  const lines = [header.join(',')];
  for (const r of rows) {
    lines.push(
      [
        r.jiraKey === '__untraced__' ? '' : r.jiraKey,
        r.jiraSummary ?? '',
        r.projectName,
        r.moduleName,
        r.featureName,
        r.featureType,
        r.testCaseId === '__no_tests__' ? '' : r.testCaseTitle,
        r.testCasePriority ?? '',
        r.testCaseStrategy ?? '',
        r.latestStatus,
        r.latestRunAt ?? '',
        r.findings.length,
      ]
        .map(esc)
        .join(','),
    );
  }
  return lines.join('\n');
}

/** Markdown serializer for download. */
export function rowsToMarkdown(rows: TraceabilityRow[], title: string): string {
  const out: string[] = [`# ${title}`, ''];
  if (rows.length === 0) {
    out.push('_No data to display._');
    return out.join('\n');
  }

  const counts = countByStatus(rows);
  out.push(
    `**Total test cases:** ${counts.total}  `,
    `**Passed:** ${counts.passed} · **Failed:** ${counts.failed} · **Pending:** ${counts.pending} · **Never run:** ${counts.never}`,
    '',
    '| Jira | Project | Module | Feature | Test Case | Strategy | Status | Findings |',
    '| --- | --- | --- | --- | --- | --- | --- | --- |',
  );

  for (const r of rows) {
    out.push(
      `| ${r.jiraKey === '__untraced__' ? '—' : r.jiraKey} `
      + `| ${r.projectName} `
      + `| ${r.moduleName} `
      + `| ${r.featureName}${r.featureType === 'comparison' ? ' _(comparison)_' : ''} `
      + `| ${r.testCaseId === '__no_tests__' ? '_(no test cases)_' : r.testCaseTitle} `
      + `| ${r.testCaseStrategy ?? ''} `
      + `| ${r.latestStatus} `
      + `| ${r.findings.length} |`,
    );
  }

  return out.join('\n');
}
