import { useNavigate } from 'react-router-dom';
import type { HighPriorityRiskEntry } from '../../../lib/dashboard';

interface Props {
  projectId: string;
  items: HighPriorityRiskEntry[];
}

export default function HighPriorityRisksTab({ projectId, items }: Props) {
  const navigate = useNavigate();

  if (items.length === 0) {
    return (
      <div className="p-8 text-center">
        <p className="text-sm text-gray-600">All high-priority test cases are passing.</p>
      </div>
    );
  }

  return (
    <ul className="divide-y divide-gray-100">
      {items.map(entry => (
        <li
          key={`${entry.featureId}-${entry.testCaseId}`}
          onClick={() => navigate(`/project/${projectId}/module/${entry.moduleId}/feature/${entry.featureId}/tests`)}
          className="p-3 hover:bg-gray-50 cursor-pointer flex items-center gap-3"
        >
          <div className="flex-1 min-w-0">
            <div className="text-xs font-semibold text-gray-800 truncate">{entry.testCaseTitle}</div>
            <div className="text-[10px] text-gray-400">
              {entry.moduleName} · {entry.featureName}
            </div>
          </div>
          <span
            className={`text-[10px] font-semibold px-2 py-0.5 rounded-full border ${
              entry.latestStatus === 'failed'
                ? 'bg-red-50 text-red-700 border-red-200'
                : 'bg-gray-50 text-gray-500 border-gray-200'
            }`}
          >
            {entry.latestStatus === 'failed' ? 'FAILED' : 'NEVER RUN'}
          </span>
        </li>
      ))}
    </ul>
  );
}
