import { useNavigate, useParams } from 'react-router-dom';
import { useStore } from '../../store/state';
import ArtifactsPanel from '../../components/ArtifactsPanel';

/**
 * Project-scoped or module-scoped artifact management page
 * (REQUIREMENTS.md §5.1). Route: /project/:projectId/artifacts or
 * /project/:projectId/module/:moduleId/artifacts.
 */
export default function ArtifactsPage() {
  const { projectId, moduleId } = useParams<{ projectId: string; moduleId?: string }>();
  const navigate = useNavigate();
  const project = useStore((s) => s.projects.find((p) => p.id === projectId));
  const mod = moduleId ? project?.modules.find((m) => m.id === moduleId) : undefined;

  if (!projectId || !project) {
    return (
      <div className="px-2 py-4">
        <div className="rounded-lg border border-gray-200 bg-white p-6 text-center text-gray-500 text-sm">
          Project not found
        </div>
      </div>
    );
  }
  if (moduleId && !mod) {
    return (
      <div className="px-2 py-4">
        <div className="rounded-lg border border-gray-200 bg-white p-6 text-center text-gray-500 text-sm">
          Module not found
        </div>
      </div>
    );
  }

  return (
    <div className="w-full px-4 py-3">
      <div className="rounded-lg border border-gray-200 bg-white px-3 py-3 mb-3">
        <div className="flex items-center gap-1.5 mb-2 text-[11px] flex-wrap">
          <button onClick={() => navigate('/')} className="text-gray-400 hover:text-gray-700">
            Projects
          </button>
          <span className="text-gray-300">/</span>
          <button
            onClick={() => navigate(`/project/${projectId}`)}
            className="text-gray-400 hover:text-gray-700 truncate max-w-24"
          >
            {project.name}
          </button>
          {mod && (
            <>
              <span className="text-gray-300">/</span>
              <button
                onClick={() => navigate(`/project/${projectId}/module/${mod.id}`)}
                className="text-gray-400 hover:text-gray-700 truncate max-w-24"
              >
                {mod.name}
              </button>
            </>
          )}
          <span className="text-gray-300">/</span>
          <span className="font-medium text-gray-800">Artifacts</span>
        </div>
        <h1 className="text-sm font-bold text-gray-800">
          Artifacts {mod ? `— ${mod.name}` : `— ${project.name}`}
        </h1>
        <p className="text-[10px] text-gray-500 mt-0.5">
          {mod
            ? 'Module-scoped fixtures visible to every feature in this module.'
            : 'Project-scoped fixtures visible to every module and feature in this project.'}
        </p>
      </div>
      <ArtifactsPanel projectId={projectId} moduleId={moduleId} />
    </div>
  );
}
