import { useCallback, useEffect, useRef, useState } from 'react';
import { SearchIcon, TimesIcon } from '../../../styles/Icons';
import ItemList from './ItemList';
import { Item } from './types';

interface PopoverProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: () => void;
    items: Item[];
    selectedKeys: string[];
    onSelectionChange: (keys: string[]) => void;
    onSearch: (query: string) => Promise<Item[]>;
    searchQuery: string;
    onSearchChange: (query: string) => void;
}

const Popover: React.FC<PopoverProps> = ({
    isOpen,
    onClose,
    onSave,
    items,
    selectedKeys,
    onSelectionChange,
    searchQuery,
    onSearchChange,
}) => {
    const [focusedIndex, setFocusedIndex] = useState(-1);
    const searchInputRef = useRef<HTMLInputElement>(null);

    useEffect(() => {
        if (isOpen) {
            searchInputRef.current?.focus();
            setFocusedIndex(-1);
        }
    }, [isOpen]);

    const handleKeyDown = useCallback(
        (e: React.KeyboardEvent) => {
            if (!isOpen) return;

            switch (e.key) {
                case 'Escape':
                    e.preventDefault();
                    onClose();
                    break;
                case 'Enter':
                    e.preventDefault();
                    if (focusedIndex >= 0 && focusedIndex < items.length) {
                        const item = items[focusedIndex];
                        const newSelection = selectedKeys.includes(item.key)
                            ? selectedKeys.filter((k) => k !== item.key)
                            : [...selectedKeys, item.key];
                        onSelectionChange(newSelection);
                    } else {
                        onSave();
                    }
                    break;
                case 'ArrowDown':
                    e.preventDefault();
                    setFocusedIndex((prev) => Math.min(prev + 1, items.length - 1));
                    break;
                case 'ArrowUp':
                    e.preventDefault();
                    setFocusedIndex((prev) => Math.max(prev - 1, -1));
                    break;
                case ' ':
                    if (focusedIndex >= 0 && focusedIndex < items.length) {
                        e.preventDefault();
                        const item = items[focusedIndex];
                        const newSelection = selectedKeys.includes(item.key)
                            ? selectedKeys.filter((k) => k !== item.key)
                            : [...selectedKeys, item.key];
                        onSelectionChange(newSelection);
                    }
                    break;
            }
        },
        [isOpen, focusedIndex, items, selectedKeys, onSelectionChange, onClose, onSave],
    );

    useEffect(() => {
        document.addEventListener('keydown', handleKeyDown as any);
        return () => document.removeEventListener('keydown', handleKeyDown as any);
    }, [handleKeyDown]);

    const handleSearchChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const query = e.target.value;
        onSearchChange(query);
        setFocusedIndex(-1);
    };

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0">
            <div className="fixed inset-0 bg-gray-900 opacity-80" />
            <div className="fixed inset-0 flex items-center justify-center z-500">
                <div className="bg-white rounded-lg shadow-xl w-full max-w-2xl h-5/6 flex flex-col">
                    <div className="flex items-center justify-between p-4 border-b border-gray-200">
                        <h2 className="text-lg font-semibold text-gray-900">Select Items</h2>
                        <button onClick={onClose} className="text-gray-400 hover:text-gray-600 transition-colors cursor-pointer">
                            <TimesIcon />
                        </button>
                    </div>

                    <div className="p-4 border-b border-gray-200">
                        <div className="relative">
                            <SearchIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                            <input
                                ref={searchInputRef}
                                type="text"
                                placeholder="Search items..."
                                value={searchQuery}
                                onChange={handleSearchChange}
                                className="w-full pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                            />
                        </div>
                    </div>

                    <ItemList
                        items={items}
                        selectedKeys={selectedKeys}
                        onSelectionChange={onSelectionChange}
                        focusedIndex={focusedIndex}
                        onFocusChange={setFocusedIndex}
                    />

                    <div className="p-4 border-t border-gray-200 flex justify-end space-x-2">
                        <button onClick={onClose} className="bg-gray-200 text-sm text-gray-700 px-4 py-1.5 rounded-md cursor-pointer">
                            Cancel
                        </button>
                        <button onClick={onSave} className="bg-[#1e2939] text-sm text-white px-4 py-1.5 rounded-md cursor-pointer">
                            Add
                        </button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Popover;
