import { useEffect, useMemo, useRef, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import type { Project } from '../../../activator/types/state';
import { formatRelative } from '../../lib/dashboard';

interface Props {
  projects: Project[];
  selectedProjectId: string | null;
}

export default function ProjectSwitcher({ projects, selectedProjectId }: Props) {
  const navigate = useNavigate();
  const [open, setOpen] = useState(false);
  const [query, setQuery] = useState('');
  const containerRef = useRef<HTMLDivElement>(null);

  const selected = projects.find(p => p.id === selectedProjectId);

  const sorted = useMemo(() => {
    const list = [...projects].sort((a, b) => (a.updatedAt < b.updatedAt ? 1 : -1));
    const q = query.trim().toLowerCase();
    if (!q) return list;
    return list.filter(p =>
      [p.name, p.category, p.description].filter(Boolean).join(' ').toLowerCase().includes(q),
    );
  }, [projects, query]);

  useEffect(() => {
    if (!open) return;
    const onClick = (e: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setOpen(false);
      }
    };
    document.addEventListener('mousedown', onClick);
    return () => document.removeEventListener('mousedown', onClick);
  }, [open]);

  const pick = (id: string) => {
    setOpen(false);
    setQuery('');
    navigate(`/project/${id}`);
  };

  return (
    <div className="relative" ref={containerRef}>
      <button
        onClick={() => setOpen(v => !v)}
        className="inline-flex items-center gap-1.5 px-2.5 py-1.5 text-xs sm:text-sm bg-white border border-gray-200 rounded-lg hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-orange-300 transition max-w-[60vw]"
      >
        <span className="font-semibold text-gray-800 truncate">
          {selected ? selected.name : 'Select project'}
        </span>
        <svg className="w-3.5 h-3.5 text-gray-400 shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
        </svg>
      </button>

      {open && (
        <div className="absolute right-0 mt-2 w-[min(22rem,calc(100vw-1rem))] rounded-2xl border border-gray-200 bg-white shadow-lg z-30">
          <div className="p-2 border-b border-gray-100">
            <input
              autoFocus
              value={query}
              onChange={e => setQuery(e.target.value)}
              placeholder="Search projects..."
              className="w-full px-3 py-2 text-sm border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-orange-300"
            />
          </div>
          <div className="max-h-80 overflow-y-auto py-1">
            {sorted.length === 0 ? (
              <div className="px-4 py-6 text-center text-xs text-gray-400">No projects match</div>
            ) : (
              sorted.map(p => {
                const active = p.id === selectedProjectId;
                return (
                  <button
                    key={p.id}
                    onClick={() => pick(p.id)}
                    className={`w-full text-left px-3 py-2 hover:bg-orange-50 transition ${active ? 'bg-orange-50' : ''}`}
                  >
                    <div className="flex items-center justify-between gap-2">
                      <span className="font-medium text-sm text-gray-800 truncate">{p.name}</span>
                      <span className="text-[10px] text-gray-400 shrink-0">{formatRelative(p.updatedAt)}</span>
                    </div>
                    <div className="text-[11px] text-gray-500">{p.category}</div>
                  </button>
                );
              })
            )}
          </div>
          <div className="border-t border-gray-100 p-2">
            <button
              onClick={() => {
                setOpen(false);
                navigate('/project/new');
              }}
              className="w-full text-left px-3 py-2 text-sm font-semibold text-orange-600 hover:bg-orange-50 rounded-lg transition"
            >
              + New project
            </button>
          </div>
        </div>
      )}
    </div>
  );
}
