import { useMemo, useState } from 'react';
import { useStore } from '../../store/state';
import { useActivator } from '../../store/Context';
import MultiSelectAutocomplete from '../../components/inputs/MultiSelectAutocomplete';

interface Props {
  projectId: string;
  moduleId: string;
}

async function searchTickets(text: string) {
  try {
    const response = await fetch('/api/issues/picker?query=' + encodeURIComponent(text)).then(r => r.json());
    return response.map((j: { key: string; summaryText: string; img?: string }) => ({
      value: j.key,
      label: `${j.key} - ${j.summaryText}`,
      iconUrl: j.img,
    }));
  } catch {
    return [];
  }
}

export default function TestPlanTab({ projectId, moduleId }: Props) {
  const activator = useActivator();
  const mod = useStore(s => s.projects.find(p => p.id === projectId)?.modules.find(m => m.id === moduleId));
  const generating = useStore(s => s.generatingTestPlan);
  const error = useStore(s => s.testPlanError);

  const isGenerating = !!generating && generating.projectId === projectId && generating.moduleId === moduleId;
  const plan = mod?.testPlan;
  const currentVersion = useMemo(
    () => plan?.versions.find(v => v.id === plan.currentVersionId),
    [plan],
  );

  const [includeFeatureTickets, setIncludeFeatureTickets] = useState(true);
  const [adHocTickets, setAdHocTickets] = useState<Array<{ value: string; label: string; iconUrl?: string }>>([]);
  const [notes, setNotes] = useState('');
  const [feedback, setFeedback] = useState('');
  const [selectedVersionId, setSelectedVersionId] = useState<string | undefined>(plan?.currentVersionId);

  const viewVersion = plan?.versions.find(v => v.id === (selectedVersionId ?? plan.currentVersionId));

  const handleGenerate = () => {
    activator.generateTestPlan(projectId, moduleId, {
      includeFeatureTickets,
      adHocJiraKeys: adHocTickets.map(t => t.value),
      userNotes: notes || undefined,
    });
  };

  const handleRefine = () => {
    if (!feedback.trim()) return;
    activator.refineTestPlan(projectId, moduleId, feedback.trim());
    setFeedback('');
  };

  const handleDownload = () => {
    if (!viewVersion) return;
    const blob = new Blob([viewVersion.markdown], { type: 'text/markdown;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `test-plan-${mod?.name || 'module'}-v${viewVersion.versionNumber}.md`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleSetCurrent = (id: string) => {
    activator.setTestPlanCurrentVersion(projectId, moduleId, id);
  };

  const handleDeleteVersion = (id: string) => {
    if (!confirm('Delete this version?')) return;
    activator.deleteTestPlanVersion(projectId, moduleId, id);
  };

  if (!mod) return null;

  if (!plan || plan.versions.length === 0) {
    return (
      <div className="rounded-2xl border border-gray-200 bg-white p-6">
        <h2 className="text-base font-semibold text-gray-800 mb-2">Generate Test Plan</h2>
        <p className="text-sm text-gray-500 mb-4">
          Create a versioned IEEE-829-style test plan for this module from the module description, Jira tickets, and optional notes.
        </p>

        {error && (
          <div className="mb-3 rounded border border-red-200 bg-red-50 px-3 py-2 text-xs text-red-700">{error}</div>
        )}

        <label className="flex items-center gap-2 text-sm text-gray-700 mb-3">
          <input
            type="checkbox"
            checked={includeFeatureTickets}
            onChange={e => setIncludeFeatureTickets(e.target.checked)}
          />
          Include feature-level Jira tickets
        </label>

        <div className="mb-3">
          <MultiSelectAutocomplete
            label="Additional Jira keys (optional)"
            onSearch={searchTickets}
            value={adHocTickets}
            onChange={(v: Array<{ value: string; label: string; iconUrl?: string }>) => setAdHocTickets(v)}
          />
        </div>

        <div className="mb-4">
          <label className="block text-sm font-medium text-gray-700 mb-1">Notes for the generator</label>
          <textarea
            value={notes}
            onChange={e => setNotes(e.target.value)}
            rows={3}
            className="w-full px-3 py-2 border border-gray-300 rounded-md text-sm resize-y"
            placeholder="Any constraints, timelines, or priorities the plan should reflect..."
          />
        </div>

        <button
          onClick={handleGenerate}
          disabled={isGenerating}
          className="px-4 py-2 text-sm bg-orange-500 text-white rounded-lg hover:bg-orange-600 disabled:opacity-60 font-semibold"
        >
          {isGenerating ? 'Generating...' : 'Generate Test Plan'}
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-4">
      {error && (
        <div className="rounded border border-red-200 bg-red-50 px-3 py-2 text-xs text-red-700">{error}</div>
      )}

      <div className="rounded-2xl border border-gray-200 bg-white p-4 flex flex-wrap items-center gap-3">
        <label className="text-xs text-gray-500">Version</label>
        <select
          value={selectedVersionId ?? plan.currentVersionId}
          onChange={e => setSelectedVersionId(e.target.value)}
          className="text-sm border border-gray-300 rounded px-2 py-1"
        >
          {[...plan.versions].reverse().map(v => (
            <option key={v.id} value={v.id}>
              v{v.versionNumber} — {new Date(v.createdAt).toLocaleString()}{v.id === plan.currentVersionId ? ' (current)' : ''}
            </option>
          ))}
        </select>

        {viewVersion && viewVersion.id !== plan.currentVersionId && (
          <button
            onClick={() => handleSetCurrent(viewVersion.id)}
            className="px-2 py-1 text-xs bg-gray-100 text-gray-700 rounded hover:bg-gray-200"
          >
            Make current
          </button>
        )}

        <button
          onClick={handleDownload}
          className="px-2 py-1 text-xs bg-gray-100 text-gray-700 rounded hover:bg-gray-200"
        >
          Download .md
        </button>

        {viewVersion && plan.versions.length > 1 && (
          <button
            onClick={() => handleDeleteVersion(viewVersion.id)}
            className="px-2 py-1 text-xs text-red-600 hover:bg-red-50 rounded"
          >
            Delete version
          </button>
        )}

        <div className="ml-auto text-xs text-gray-400">
          {currentVersion && `Current: v${currentVersion.versionNumber} (${currentVersion.model})`}
        </div>
      </div>

      <div className="rounded-2xl border border-gray-200 bg-white p-5">
        <pre className="whitespace-pre-wrap font-sans text-sm text-gray-800">{viewVersion?.markdown || ''}</pre>
      </div>

      <div className="rounded-2xl border border-gray-200 bg-white p-4">
        <h3 className="text-sm font-semibold text-gray-800 mb-2">Refine with AI</h3>
        <textarea
          value={feedback}
          onChange={e => setFeedback(e.target.value)}
          rows={3}
          className="w-full px-3 py-2 border border-gray-300 rounded-md text-sm resize-y mb-2"
          placeholder="Tighten the scope section, add a risks section, reflect Q3 timeline..."
        />
        <button
          onClick={handleRefine}
          disabled={isGenerating || !feedback.trim()}
          className="px-4 py-2 text-sm bg-orange-500 text-white rounded-lg hover:bg-orange-600 disabled:opacity-60 font-semibold"
        >
          {isGenerating ? 'Refining...' : 'Refine with AI'}
        </button>
      </div>
    </div>
  );
}
