// Fixed catalog of test strategies. Extend here to add new strategies.
// All consumers reference strategies by key.

export type TestStrategyKey =
  | 'equivalence_partitioning'
  | 'boundary_value'
  | 'decision_table'
  | 'state_transition'
  | 'exploratory'
  | 'negative'
  | 'risk_based'
  | 'accessibility'
  | 'cross_browser'
  | 'smoke'
  | 'regression';

export interface TestStrategy {
  key: TestStrategyKey;
  name: string;
  description: string;
  /** Short example shown as a hover tooltip in the strategy picker. */
  example: string;
}

export const STRATEGY_CATALOG: TestStrategy[] = [
  { key: 'equivalence_partitioning', name: 'Equivalence partitioning', description: 'Divide inputs into valid and invalid partitions; pick one representative per partition.', example: 'Age field (18–100): generates 3 cases — valid age (25), under-age (15), over-limit (150). One rep per class instead of testing every value.' },
  { key: 'boundary_value', name: 'Boundary value analysis', description: 'Test values at the edges of allowed ranges — min, max, just-inside, just-outside.', example: 'Password length 8–20 chars: generates cases for 7 (fail), 8 (pass), 20 (pass), 21 (fail). Catches off-by-one bugs.' },
  { key: 'decision_table', name: 'Decision table', description: 'Enumerate combinations of conditions and expected outcomes.', example: 'Checkout with/without coupon × logged-in/guest: generates one case per combination. Useful when multiple flags interact.' },
  { key: 'state_transition', name: 'State transition', description: 'Cover transitions between application states and flag illegal transitions.', example: 'Order flow: Draft → Submitted → Shipped → Delivered. Generates cases for valid paths and illegal jumps like Draft → Delivered.' },
  { key: 'exploratory', name: 'Exploratory / heuristic', description: 'Open-ended probing guided by heuristics and domain intuition.', example: 'Upload form: AI probes unusual file types, very large files, empty files — things not in the spec but likely to break.' },
  { key: 'negative', name: 'Negative / error paths', description: 'Deliberately invalid input and error-path validation.', example: 'Login form: wrong password, blank email, SQL injection string, expired token — verifies proper error messages appear.' },
  { key: 'risk_based', name: 'Risk-based', description: 'Prioritize areas with the highest business or technical risk.', example: 'Payment flow is high-risk: AI generates more cases here than for the low-risk profile-picture upload.' },
  { key: 'accessibility', name: 'Accessibility', description: 'Keyboard navigation, ARIA, contrast, screen-reader semantics.', example: 'Modal dialog: checks it traps focus, has an aria-label, closes on Escape, and all interactive elements are reachable by Tab.' },
  { key: 'cross_browser', name: 'Cross-browser / responsive', description: 'Browser matrix and viewport sizes.', example: 'Navigation menu: generates cases at mobile (375px), tablet (768px), and desktop (1440px) to catch layout breakages.' },
  { key: 'smoke', name: 'Smoke', description: 'Narrow set of high-signal happy paths to prove basic health.', example: 'After deploy: load homepage, log in, create one record, log out — 4 cases that confirm the app is alive before deeper testing.' },
  { key: 'regression', name: 'Regression', description: 'Re-validate previously fixed defects and core flows.', example: 'Known bug: "Save" button disabled after first edit. Generates a case that reproduces the exact scenario to prevent it from recurring.' },
];

export const DEFAULT_PROJECT_STRATEGIES: TestStrategyKey[] = [
  'equivalence_partitioning',
  'boundary_value',
  'negative',
  'smoke',
];

export function isValidStrategyKey(key: string): key is TestStrategyKey {
  return STRATEGY_CATALOG.some(s => s.key === key);
}

export function getStrategies(keys: TestStrategyKey[]): TestStrategy[] {
  return keys.map(k => STRATEGY_CATALOG.find(s => s.key === k)).filter((s): s is TestStrategy => !!s);
}
