import type { ElementInfo, RecordedStep } from '../../../../activator/types/state';
import { SuccessIcon, FailedIcon, RunningIcon, PendingIcon } from '../../../styles/Icons';

interface StepDetailProps {
  step: RecordedStep;
  onClick: () => void;
}

function StepStatusIcon({ success }: { success: boolean }) {
  if (success) return <SuccessIcon className="text-green-500" />;
  return <FailedIcon className="text-red-500" />;
}

/**
 * Human-readable descriptor for the element a step acted on. Prefers
 * name → text → attrName → attrId → tagName, so the UI shows "Submit button"
 * rather than a nested CSS path. Never exposes the raw ref ("e1", "e7") —
 * those are ephemeral and only used for agent ↔ driver communication.
 */
function describeElement(info: ElementInfo | undefined, fallbackSelector: string | undefined): string {
  if (info) {
    const label = info.name || info.text || info.attrName || info.attrId || info.tagName || '';
    const rolePart = info.role && info.role !== info.tagName ? info.role : info.tagName;
    if (label && rolePart) return `"${label}" ${rolePart}`;
    if (label) return `"${label}"`;
    if (rolePart) return rolePart;
  }
  return fallbackSelector || '';
}

/** Derive a readable title from the tool name and args. */
function getStepTitle(step: RecordedStep): string {
  const { toolName, toolArgs, elementInfo } = step;
  const args = toolArgs as Record<string, unknown>;
  const selector = typeof args.selector === 'string' ? args.selector : undefined;
  const element = describeElement(elementInfo, selector);
  const hrefSuffix = elementInfo?.href ? ` → ${elementInfo.href}` : '';

  switch (toolName) {
    case 'browser_click':
      return `Click ${element}${hrefSuffix}`;
    case 'browser_fill':
      return `Fill ${element} with "${args.value || ''}"`;
    case 'browser_navigate':
      return `Navigate to ${args.url || ''}`;
    case 'browser_type':
      return `Type "${args.text || ''}"`;
    case 'browser_press_key':
      return `Press ${args.key || ''}`;
    case 'browser_select_option':
      return `Select "${args.value || args.label || ''}" in ${element}`;
    case 'browser_screenshot':
      return 'Take screenshot';
    case 'browser_snapshot':
      return 'Capture accessibility tree';
    case 'browser_hover':
      return `Hover ${element}`;
    case 'browser_wait_for':
      return `Wait for ${element || args.text || ''}`;
    case 'browser_wait_for_navigation':
      return 'Wait for navigation';
    case 'browser_switch_tab':
      return `Switch to tab ${args.index}`;
    case 'browser_new_tab':
      return `Open new tab${args.url ? `: ${args.url}` : ''}`;
    case 'browser_close_tab':
      return 'Close tab';
    case 'browser_evaluate':
      return 'Execute JavaScript';
    case 'assert_text':
      return `Assert text "${args.expected || ''}" in ${element}`;
    case 'assert_visible':
      return `Assert ${element} visible`;
    case 'assert_url':
      return `Assert URL contains "${args.expected || args.pattern || ''}"`;
    case 'assert_value':
      return `Assert value "${args.expected || ''}" in ${element}`;
    case 'assert_enabled':
      return `Assert ${element} enabled`;
    case 'assert_checked':
      return `Assert ${element} checked`;
    case 'assert_title':
      return `Assert page title contains "${args.expected || ''}"`;
    case 'record_finding':
      return `Finding: ${args.message || ''}`;
    case 'store_artifact':
      return `Store artifact "${args.key || ''}"`;
    case 'store_element':
      return `Capture ${element} as "${args.key || ''}"`;
    case 'browser_check':
      return `Check ${element}`;
    case 'browser_uncheck':
      return `Uncheck ${element}`;
    case 'browser_drag':
      return 'Drag element';
    case 'browser_scroll':
      return 'Scroll page';
    case 'browser_file_upload':
      return 'Upload file';
    case 'browser_handle_dialog':
      return `Handle dialog (${args.action || 'accept'})`;
    case 'browser_reload':
      return 'Reload page';
    case 'wait':
      return `Wait ${args.ms || args.duration || ''}ms`;
    default:
      return toolName.replace(/^browser_/, '').replace(/_/g, ' ');
  }
}

export default function StepDetail({ step, onClick }: StepDetailProps) {
  const title = getStepTitle(step);

  return (
    <div
      className="bg-gray-100 p-2.5 ps-1.5 rounded-md cursor-pointer hover:bg-gray-200 transition-colors"
      onClick={onClick}
    >
      <div className="flex items-center gap-2">
        <StepStatusIcon success={step.result.success} />
        <span className="text-xs text-[#1e2939] flex-1 min-w-0 truncate">{title}</span>
        <span className="text-[10px] text-gray-400 shrink-0">{step.result.duration}ms</span>
      </div>
    </div>
  );
}

export { StepStatusIcon, getStepTitle, SuccessIcon, FailedIcon, RunningIcon, PendingIcon };
