import { useParams } from 'react-router-dom';
import { useStore } from '../../store/state';
import ComparisonView from './ComparisonView';

export default function ModuleComparison() {
  const { projectId, moduleId } = useParams<{ projectId: string; moduleId: string }>();
  const project = useStore(s => s.projects.find(p => p.id === projectId));
  const mod = project?.modules.find(m => m.id === moduleId);

  if (!project || !mod) {
    return (
      <div className="w-full px-4 py-8">
        <div className="rounded-2xl border border-gray-200 bg-white p-8 text-center text-gray-500">Module not found</div>
      </div>
    );
  }

  return (
    <ComparisonView
      scope={{ projectId: project.id, moduleId: mod.id }}
      title={`Compare — ${mod.name}`}
      subtitle={`Module-level comparison · ${project.name}`}
      backTo={`/project/${project.id}/module/${mod.id}`}
    />
  );
}
