import { useState, useEffect } from 'react';
import { useStore } from '../store/state';
import { useActivator } from '../store/Context';
import type { FeedbackResponsePayload } from '../../activator/types/protocol';

/**
 * Modal shown when the AI calls request_user_feedback. Mode drives the form:
 *   - text            → textarea + submit
 *   - approve_reject  → approve / reject buttons + optional comment
 *   - multi_choice    → one button per provided choice
 *   - pick_element    → instructions to use the element picker in the target browser;
 *                       an escape hatch (cancel) is always available so the AI loop
 *                       doesn't get stuck if the user can't fulfil the request.
 *
 * The user can always dismiss the prompt. Dismissal sends `{ cancelled: true }`
 * and the AI tool call returns a successful result with cancelled=true — the AI
 * is expected to handle that and decide whether to retry, ask a different
 * question, or proceed without the input.
 */
export default function FeedbackModal() {
  const feedback = useStore((s) => s.pendingFeedback);
  const activator = useActivator();
  const [text, setText] = useState('');
  const [comment, setComment] = useState('');

  // Reset form whenever a new feedback request arrives.
  useEffect(() => {
    setText('');
    setComment('');
  }, [feedback?.requestId]);

  if (!feedback) return null;

  const respond = (partial: Omit<FeedbackResponsePayload, 'requestId'>) => {
    activator.feedbackResponse({ requestId: feedback.requestId, ...partial });
    useStore.getState().setPendingFeedback(null);
  };

  const handleCancel = () => respond({ cancelled: true });

  return (
    <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50 p-4">
      <div className="bg-gray-800 rounded-lg p-6 max-w-xl w-full border border-gray-600 shadow-xl max-h-[90vh] overflow-y-auto">
        <div className="flex items-start justify-between gap-3 mb-3">
          <div>
            <div className="text-xs uppercase tracking-wider text-blue-400 mb-1">
              AI needs your input{feedback.issuedBy ? ` · ${feedback.issuedBy}` : ''}
            </div>
            <h2 className="text-lg font-semibold text-white leading-snug">{feedback.prompt}</h2>
          </div>
          <button
            onClick={handleCancel}
            className="text-gray-400 hover:text-gray-200 text-xl leading-none cursor-pointer"
            title="Dismiss"
            aria-label="Dismiss"
          >
            ×
          </button>
        </div>

        {feedback.context && (
          <div className="text-sm text-gray-300 whitespace-pre-wrap bg-gray-900/50 rounded p-3 mb-4">
            {feedback.context}
          </div>
        )}

        {feedback.screenshotBase64 && (
          <img
            src={`data:image/png;base64,${feedback.screenshotBase64}`}
            alt="Context screenshot"
            className="max-w-full max-h-64 object-contain rounded border border-gray-700 mb-4"
          />
        )}

        {feedback.mode === 'text' && (
          <div>
            <textarea
              autoFocus
              value={text}
              onChange={(e) => setText(e.target.value)}
              placeholder="Your answer..."
              rows={4}
              className="w-full bg-gray-900 text-white rounded p-3 text-sm border border-gray-700 focus:border-blue-500 outline-none"
            />
            <div className="flex gap-2 justify-end mt-3">
              <button
                onClick={handleCancel}
                className="px-4 py-2 bg-gray-700 text-white rounded hover:bg-gray-600 text-sm cursor-pointer"
              >
                Cancel
              </button>
              <button
                onClick={() => respond({ text })}
                disabled={!text.trim()}
                className="px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600 text-sm disabled:opacity-50 disabled:cursor-not-allowed cursor-pointer"
              >
                Submit
              </button>
            </div>
          </div>
        )}

        {feedback.mode === 'approve_reject' && (
          <div>
            <input
              type="text"
              value={comment}
              onChange={(e) => setComment(e.target.value)}
              placeholder="Optional comment..."
              className="w-full bg-gray-900 text-white rounded p-2 text-sm border border-gray-700 focus:border-blue-500 outline-none mb-3"
            />
            <div className="flex gap-2 justify-end">
              <button
                onClick={handleCancel}
                className="px-4 py-2 bg-gray-700 text-white rounded hover:bg-gray-600 text-sm cursor-pointer"
              >
                Cancel
              </button>
              <button
                onClick={() => respond({ approved: false, comment: comment || undefined })}
                className="px-4 py-2 bg-red-500/90 text-white rounded hover:bg-red-500 text-sm cursor-pointer"
              >
                Reject
              </button>
              <button
                onClick={() => respond({ approved: true, comment: comment || undefined })}
                className="px-4 py-2 bg-green-500/90 text-white rounded hover:bg-green-500 text-sm cursor-pointer"
              >
                Approve
              </button>
            </div>
          </div>
        )}

        {feedback.mode === 'multi_choice' && (
          <div>
            <div className="space-y-2">
              {(feedback.choices ?? []).map((choice) => (
                <button
                  key={choice.id}
                  onClick={() => respond({ choiceId: choice.id })}
                  className="w-full text-left px-4 py-3 bg-gray-900 hover:bg-gray-700 rounded border border-gray-700 text-sm cursor-pointer"
                >
                  <div className="text-white font-medium">{choice.label}</div>
                  {choice.description && (
                    <div className="text-gray-400 text-xs mt-1">{choice.description}</div>
                  )}
                </button>
              ))}
              {(feedback.choices ?? []).length === 0 && (
                <div className="text-gray-400 text-sm italic">No choices were provided.</div>
              )}
            </div>
            <div className="flex justify-end mt-4">
              <button
                onClick={handleCancel}
                className="px-4 py-2 bg-gray-700 text-white rounded hover:bg-gray-600 text-sm cursor-pointer"
              >
                Cancel
              </button>
            </div>
          </div>
        )}

        {feedback.mode === 'pick_element' && (
          <div>
            <div className="bg-gray-900/50 rounded p-3 text-sm text-gray-300 space-y-2 mb-4">
              <div>
                Use the element picker in{' '}
                <span className="text-blue-400 font-mono">
                  {feedback.targetSessionId ?? 'the active browser'}
                </span>{' '}
                to select the element the AI is asking about.
              </div>
              <div className="text-xs text-gray-500">
                (Picker integration with multi-session browsers is landing in the next iteration. For now, open the picker from the comparison view or dismiss to let the AI continue without this input.)
              </div>
            </div>
            <div className="flex justify-end">
              <button
                onClick={handleCancel}
                className="px-4 py-2 bg-gray-700 text-white rounded hover:bg-gray-600 text-sm cursor-pointer"
              >
                Dismiss
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
