import { useMemo, useState } from 'react';
import type { ComparisonRun } from '../../../../activator/types/comparisonPlan';
import { useStore } from '../../../store/state';
import { useActivator } from '../../../store/Context';
import ComparisonDiffDetailModal from './ComparisonDiffDetailModal';

const KIND_LABELS: Record<string, string> = {
  table_diff: 'Table',
  form_diff: 'Form',
  chart_diff: 'Chart',
  section_diff: 'Section',
  style_diff: 'Style',
};

type DiffItem = {
  kind: 'table_diff' | 'form_diff' | 'chart_diff' | 'section_diff' | 'style_diff';
  verdict: 'match' | 'mismatch';
  summary: string;
  artifactKey: string;
};

/**
 * Right-rail panel showing comparison diffs as they are recorded. Diffs stream
 * in live via `comparisonV2DiffRecorded`, so the panel fills up during the run
 * rather than only at state-end. Each diff row is clickable — opens a modal
 * with the full structured breakdown (actual rows/cells/headers that differ).
 */
export default function DiffResultsRail({ run }: { run: ComparisonRun | null }) {
  const liveDiffs = useStore((s) => s.comparisonV2LiveDiffs);
  const activator = useActivator();
  const [detailArtifactKey, setDetailArtifactKey] = useState<string | null>(null);

  // Merge live diffs with final state results so each state shows a single
  // union list. Live diffs take precedence by artifact key.
  const statesView = useMemo(() => {
    if (!run) return [] as Array<{ stateId: string; stateLabel: string; status: string; diffs: DiffItem[]; warnings: string[] }>;
    const seenStateIds = new Set<string>();
    const out: Array<{ stateId: string; stateLabel: string; status: string; diffs: DiffItem[]; warnings: string[] }> = [];
    for (const sr of run.stateResults) {
      seenStateIds.add(sr.stateId);
      const liveForState = liveDiffs[sr.stateId] ?? [];
      const merged: DiffItem[] = [];
      const seenKeys = new Set<string>();
      for (const d of sr.diffs) {
        const key = d.artifactKey || `${d.kind}::${d.summary}`;
        merged.push(d as DiffItem);
        seenKeys.add(key);
      }
      for (const d of liveForState) {
        const key = d.artifactKey || `${d.kind}::${d.summary}`;
        if (!seenKeys.has(key)) merged.push(d);
      }
      out.push({ stateId: sr.stateId, stateLabel: sr.stateLabel, status: sr.status, diffs: merged, warnings: sr.warnings });
    }
    // Live-only states (no result yet) — surface them too so diffs are visible during a state.
    for (const [stateId, diffs] of Object.entries(liveDiffs)) {
      if (seenStateIds.has(stateId)) continue;
      out.push({ stateId, stateLabel: stateId, status: 'running', diffs: diffs as DiffItem[], warnings: [] });
    }
    return out;
  }, [run, liveDiffs]);

  const totalMismatches = statesView.reduce(
    (acc, s) => acc + s.diffs.filter((d) => d.verdict === 'mismatch').length,
    0,
  );

  if (!run) {
    return (
      <div className="rounded-2xl border border-gray-200 bg-white p-4">
        <h3 className="text-sm font-semibold text-gray-800 mb-2">Diffs</h3>
        <p className="text-xs text-gray-400">No run in progress.</p>
      </div>
    );
  }

  const handleDownloadRun = () => {
    activator.downloadComparisonV2Report(run.id);
  };
  const handleDownloadState = (stateId: string) => {
    activator.downloadComparisonV2Report(run.id, stateId);
  };

  return (
    <div className="rounded-2xl border border-gray-200 bg-white p-4 h-full flex flex-col">
      <div className="flex items-center justify-between mb-3">
        <div>
          <h3 className="text-sm font-semibold text-gray-800">Diffs</h3>
          <p className="text-[11px] text-gray-500 mt-0.5">
            {totalMismatches === 0 ? 'No mismatches so far.' : `${totalMismatches} mismatch${totalMismatches === 1 ? '' : 'es'}`}
          </p>
        </div>
        <button
          onClick={handleDownloadRun}
          className="text-[11px] font-semibold text-orange-600 hover:text-orange-700 cursor-pointer"
          title="Download Markdown report for the full run"
        >
          ⤓ Report
        </button>
      </div>

      <div className="space-y-4 overflow-y-auto pr-1" style={{ maxHeight: 'calc(100vh - 260px)' }}>
        {statesView.length === 0 && (
          <p className="text-xs text-gray-400">Diffs will appear here as the AI discovers them.</p>
        )}
        {statesView.map((sr) => (
          <div key={sr.stateId}>
            <div className="flex items-center gap-2 mb-2">
              <span className="text-xs font-semibold text-gray-800 truncate">{sr.stateLabel}</span>
              <span
                className={`inline-block px-1.5 py-0.5 rounded text-[10px] uppercase font-semibold text-white ${
                  sr.status === 'passed' ? 'bg-green-600' : sr.status === 'failed' ? 'bg-red-600' : 'bg-gray-500'
                }`}
              >
                {sr.status}
              </span>
              <button
                onClick={() => handleDownloadState(sr.stateId)}
                className="ml-auto text-[10px] font-semibold text-gray-500 hover:text-orange-700 cursor-pointer"
                title="Download Markdown report for this state"
              >
                ⤓ State
              </button>
            </div>
            {sr.diffs.length === 0 && <p className="text-xs text-gray-400">No diffs recorded.</p>}
            <ul className="space-y-1.5">
              {sr.diffs.map((d, i) => (
                <li
                  key={`${sr.stateId}-${d.artifactKey || i}`}
                  onClick={() => d.artifactKey && setDetailArtifactKey(d.artifactKey)}
                  className={`text-xs border rounded p-2 ${
                    d.verdict === 'match' ? 'border-green-200 bg-green-50/50' : 'border-red-200 bg-red-50/50'
                  } ${d.artifactKey ? 'cursor-pointer hover:border-gray-400' : ''}`}
                  title={d.artifactKey ? 'Click to view exact differences' : undefined}
                >
                  <div className="flex items-center justify-between">
                    <span className="font-semibold text-gray-700">
                      {KIND_LABELS[d.kind] ?? d.kind}
                      <span
                        className={`ml-2 px-1.5 py-0.5 rounded text-[10px] uppercase font-semibold text-white ${
                          d.verdict === 'match' ? 'bg-green-600' : 'bg-red-600'
                        }`}
                      >
                        {d.verdict}
                      </span>
                    </span>
                    <span className="text-[10px] text-gray-400 font-mono truncate ml-2">{d.artifactKey}</span>
                  </div>
                  {d.summary && <p className="text-gray-600 mt-1">{d.summary}</p>}
                </li>
              ))}
            </ul>
            {sr.warnings.length > 0 && (
              <div className="mt-2 text-[11px] text-orange-700 bg-orange-50 rounded p-2">
                {sr.warnings.map((w, i) => (
                  <div key={i}>⚠ {w}</div>
                ))}
              </div>
            )}
          </div>
        ))}
      </div>

      {detailArtifactKey && (
        <ComparisonDiffDetailModal
          artifactKey={detailArtifactKey}
          runId={run.id}
          sideLabels={{
            left: run.plan?.sides[0]?.label || 'left',
            right: run.plan?.sides[1]?.label || 'right',
          }}
          onClose={() => setDetailArtifactKey(null)}
        />
      )}
    </div>
  );
}
