interface CheckboxProps {
    checked: boolean;
    onChange: (checked: boolean) => void;
    onKeyDown?: (e: React.KeyboardEvent) => void;
    focused?: boolean;
}

const Checkbox: React.FC<CheckboxProps> = ({ checked, onChange, onKeyDown, focused }) => {
    return (
        <div
            className={`w-4 h-4 border-2 rounded cursor-pointer flex items-center justify-center transition-colors ${
                checked ? 'bg-blue-500 border-blue-500' : 'border-gray-300 hover:border-gray-400'
            } ${focused ? 'ring-2 ring-blue-200' : ''}`}
            onClick={() => onChange(!checked)}
            onKeyDown={onKeyDown}
            tabIndex={0}
        >
            {checked && (
                <svg className="w-3 h-3 text-white" fill="currentColor" viewBox="0 0 20 20">
                    <path
                        fillRule="evenodd"
                        d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"
                        clipRule="evenodd"
                    />
                </svg>
            )}
        </div>
    );
};

export default Checkbox;
