import { useMemo, useState } from 'react';
import { useStore } from '../../../store/state';
import { useActivator } from '../../../store/Context';
import type {
  ComparisonPlan,
  ComparisonSideConfig,
  ComparisonState,
} from '../../../../activator/types/comparisonPlan';
import BrowserSessionsPanel from './BrowserSessionsPanel';
import DiffResultsRail from './DiffResultsRail';
import ComparisonRunStream from './ComparisonRunStream';
import ComparisonHistoryView from './ComparisonHistoryView';

interface Props {
  projectId: string;
  moduleId: string;
  featureId?: string;
  title: string;
}

type Tab = 'configure' | 'run' | 'history';

/**
 * Plan-based comparison workspace. Covers:
 *   - sides configuration (N browsers, each with URL / credentials / headless / viewport / nav hint)
 *   - states configuration (ordered list of flag / page combinations)
 *   - launch with AI or replay deterministically
 *   - live view: per-state progress and diff results
 *
 * Plans are held in local state for this chunk. Persisting them to the module
 * belongs in a later iteration (needs a protocol + state manager addition).
 */
export default function ComparisonV2View({ projectId, moduleId, featureId, title }: Props) {
  const activator = useActivator();
  const run = useStore((s) => s.comparisonV2Run);
  const stateProgress = useStore((s) => s.comparisonV2StateProgress);
  const runError = useStore((s) => s.comparisonV2RunError);
  const stopping = useStore((s) => s.comparisonV2Stopping);
  const paused = useStore((s) => s.comparisonV2Paused);
  const testCasesByState = useStore((s) => s.comparisonV2TestCasesByState);

  const [plan, setPlan] = useState<ComparisonPlan>(() => makeEmptyPlan(projectId, moduleId, featureId, title));
  const [tab, setTab] = useState<Tab>('configure');
  const [useAI, setUseAI] = useState<boolean>(true);
  const [noteText, setNoteText] = useState('');

  const isRunning = run?.status === 'running' && !stopping;
  const canStart = useMemo(
    () => plan.sides.length >= 2 && plan.sides.every((s) => s.url && s.sessionId && s.label),
    [plan.sides],
  );

  const handleStart = () => {
    if (!canStart || isRunning) return;
    // Clear any previous run's error immediately so the UI doesn't show stale failure text.
    useStore.getState().setComparisonV2RunError(null);
    const toRun: ComparisonPlan = { ...plan, updatedAt: new Date().toISOString() };
    activator.startComparisonV2(toRun, useAI);
    setTab('run');
  };

  const handleStop = () => activator.stopComparisonV2();
  const handlePauseToggle = () => {
    if (paused) activator.resumeComparisonV2();
    else activator.pauseComparisonV2();
  };
  const handleSendNote = () => {
    const msg = noteText.trim();
    if (!msg) return;
    activator.sendComparisonV2Note(msg);
    setNoteText('');
  };

  const updateSide = (idx: number, patch: Partial<ComparisonSideConfig>) => {
    setPlan((p) => ({ ...p, sides: p.sides.map((s, i) => (i === idx ? { ...s, ...patch } : s)) }));
  };
  const addSide = () => {
    setPlan((p) => ({
      ...p,
      sides: [...p.sides, { sessionId: `side_${p.sides.length + 1}`, label: `Side ${p.sides.length + 1}`, url: '' }],
    }));
  };
  const removeSide = (idx: number) => setPlan((p) => ({ ...p, sides: p.sides.filter((_, i) => i !== idx) }));

  const updateState = (idx: number, patch: Partial<ComparisonState>) => {
    setPlan((p) => ({ ...p, states: p.states.map((s, i) => (i === idx ? { ...s, ...patch } : s)) }));
  };
  const addState = () => {
    setPlan((p) => ({
      ...p,
      states: [
        ...p.states,
        { id: `state_${p.states.length + 1}_${Date.now().toString(36)}`, label: `State ${p.states.length + 1}` },
      ],
    }));
  };
  const removeState = (idx: number) => setPlan((p) => ({ ...p, states: p.states.filter((_, i) => i !== idx) }));

  return (
    <div className="w-full">
      {/* Tab strip */}
      <div className="flex items-center gap-1 border-b border-gray-200 mb-4">
        {(['configure', 'run', 'history'] as Tab[]).map((t) => (
          <button
            key={t}
            onClick={() => setTab(t)}
            className={`px-4 py-2 text-sm font-medium border-b-2 -mb-px cursor-pointer transition-colors ${
              tab === t ? 'border-orange-500 text-orange-600' : 'border-transparent text-gray-500 hover:text-gray-700'
            }`}
          >
            {t === 'configure' ? 'Plan' : t === 'run' ? `Run${run ? ` · ${run.status}` : ''}` : 'History'}
          </button>
        ))}
        <div className="flex-1" />
        <div className="flex items-center gap-2 pb-2">
          <label className="inline-flex items-center gap-1.5 text-xs text-gray-600 cursor-pointer">
            <input type="checkbox" checked={useAI} onChange={(e) => setUseAI(e.target.checked)} className="accent-orange-500" />
            Use AI (uncheck to replay saved steps)
          </label>
          {!isRunning && !stopping ? (
            <button
              onClick={handleStart}
              disabled={!canStart}
              className="px-3 py-1.5 text-xs font-semibold bg-orange-500 text-white rounded-lg hover:bg-orange-600 disabled:opacity-50 cursor-pointer"
            >
              {useAI ? 'Start with AI' : 'Replay'}
            </button>
          ) : (
            <>
              {useAI && (
                <button
                  onClick={handlePauseToggle}
                  disabled={stopping}
                  className="px-3 py-1.5 text-xs font-semibold bg-gray-700 text-white rounded-lg hover:bg-gray-800 disabled:opacity-60 cursor-pointer"
                >
                  {paused ? 'Resume' : 'Pause'}
                </button>
              )}
              <button
                onClick={handleStop}
                disabled={stopping}
                className="px-3 py-1.5 text-xs font-semibold bg-red-600 text-white rounded-lg hover:bg-red-700 disabled:opacity-60 cursor-pointer"
              >
                {stopping ? 'Stopping…' : 'Stop'}
              </button>
            </>
          )}
        </div>
      </div>

      {tab === 'configure' && (
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">
          {/* Plan meta */}
          <div className="rounded-2xl border border-gray-200 bg-white p-4">
            <h3 className="text-sm font-semibold text-gray-800 mb-3">Plan</h3>
            <div className="space-y-3">
              <div>
                <label className="block text-xs text-gray-500 mb-1">Title</label>
                <input
                  value={plan.title}
                  onChange={(e) => setPlan((p) => ({ ...p, title: e.target.value }))}
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-300"
                />
              </div>
              <div>
                <label className="block text-xs text-gray-500 mb-1">Acceptance criteria (optional)</label>
                <textarea
                  value={plan.acceptanceCriteria ?? ''}
                  onChange={(e) => setPlan((p) => ({ ...p, acceptanceCriteria: e.target.value }))}
                  rows={3}
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm font-mono focus:outline-none focus:ring-2 focus:ring-orange-300"
                  placeholder="What does &quot;equivalent&quot; mean for this comparison? Key rules for the AI."
                />
              </div>
              <label className="flex items-center gap-2 text-sm text-gray-700 cursor-pointer">
                <input
                  type="checkbox"
                  checked={!!plan.compareStyles}
                  onChange={(e) => setPlan((p) => ({ ...p, compareStyles: e.target.checked }))}
                  className="accent-orange-500"
                />
                Also compare styles (color / font / border / spacing) on key elements
              </label>
              <label className="flex items-center gap-2 text-sm text-gray-700 cursor-pointer">
                <input
                  type="checkbox"
                  checked={!!plan.compareVisuals}
                  onChange={(e) => setPlan((p) => ({ ...p, compareVisuals: e.target.checked }))}
                  className="accent-orange-500"
                />
                Also do visual (screenshot-based) comparison of each component
              </label>
            </div>
          </div>

          {/* Sides */}
          <div className="rounded-2xl border border-gray-200 bg-white p-4">
            <div className="flex items-center justify-between mb-3">
              <h3 className="text-sm font-semibold text-gray-800">Sides</h3>
              <button onClick={addSide} className="text-xs font-semibold text-orange-600 hover:text-orange-700 cursor-pointer">+ Add side</button>
            </div>
            <div className="space-y-3">
              {plan.sides.map((side, idx) => (
                <div key={idx} className="border border-gray-200 rounded-lg p-3 space-y-2">
                  <div className="grid grid-cols-2 gap-2">
                    <LabeledInput label="Session id" value={side.sessionId} onChange={(v) => updateSide(idx, { sessionId: v })} placeholder="old_ui" />
                    <LabeledInput label="Label" value={side.label} onChange={(v) => updateSide(idx, { label: v })} placeholder="Old UI" />
                  </div>
                  <LabeledInput label="URL" value={side.url} onChange={(v) => updateSide(idx, { url: v })} placeholder="https://..." />
                  <LabeledTextarea
                    label="Navigation hint (optional)"
                    value={side.navigationHint ?? ''}
                    onChange={(v) => updateSide(idx, { navigationHint: v })}
                    placeholder={'After login, click Plans > Lifetime Portfolio Value.\nProvide step-by-step instructions if the path is non-obvious.'}
                    rows={3}
                  />
                  <div className="grid grid-cols-2 gap-2">
                    <LabeledInput
                      label="Username (optional)"
                      value={side.credentials?.username ?? ''}
                      onChange={(v) => updateSide(idx, { credentials: { ...side.credentials, username: v } })}
                    />
                    <LabeledInput
                      label="Password (optional)"
                      type="password"
                      value={side.credentials?.password ?? ''}
                      onChange={(v) => updateSide(idx, { credentials: { ...side.credentials, password: v } })}
                    />
                  </div>
                  <div className="flex items-center justify-between">
                    <label className="flex items-center gap-1.5 text-xs text-gray-600 cursor-pointer">
                      <input
                        type="checkbox"
                        checked={!!side.headless}
                        onChange={(e) => updateSide(idx, { headless: e.target.checked })}
                        className="accent-orange-500"
                      />
                      Headless
                    </label>
                    {plan.sides.length > 2 && (
                      <button
                        onClick={() => removeSide(idx)}
                        className="text-xs text-red-600 hover:text-red-700 cursor-pointer"
                      >
                        Remove
                      </button>
                    )}
                  </div>
                </div>
              ))}
              {plan.sides.length < 2 && (
                <p className="text-xs text-gray-400">At least two sides required.</p>
              )}
            </div>
          </div>

          {/* States */}
          <div className="rounded-2xl border border-gray-200 bg-white p-4 xl:col-span-2">
            <div className="flex items-center justify-between mb-3">
              <h3 className="text-sm font-semibold text-gray-800">States</h3>
              <button onClick={addState} className="text-xs font-semibold text-orange-600 hover:text-orange-700 cursor-pointer">+ Add state</button>
            </div>
            {plan.states.length === 0 && (
              <p className="text-xs text-gray-400 mb-2">
                No states defined — a single implicit default state will run. Add states to iterate through feature-flag combinations,
                different pages, or filter settings.
              </p>
            )}
            <div className="space-y-3">
              {plan.states.map((st, idx) => (
                <div key={st.id} className="border border-gray-200 rounded-lg p-3 space-y-2">
                  <div className="grid grid-cols-2 gap-2">
                    <LabeledInput label="Id" value={st.id} onChange={(v) => updateState(idx, { id: v })} />
                    <LabeledInput label="Label" value={st.label} onChange={(v) => updateState(idx, { label: v })} placeholder="Flag X ON" />
                  </div>
                  <div>
                    <label className="block text-xs text-gray-500 mb-1">Setup instructions (what to do before extracting for this state)</label>
                    <textarea
                      value={st.setupInstructions ?? ''}
                      onChange={(e) => updateState(idx, { setupInstructions: e.target.value })}
                      rows={2}
                      className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm font-mono focus:outline-none focus:ring-2 focus:ring-orange-300"
                      placeholder="Turn feature flag X on in Settings, then navigate to the Cashflow page."
                    />
                  </div>
                  <div className="flex items-center justify-between text-xs text-gray-500">
                    <span>{(st.recordedSteps?.length ?? 0)} recorded step(s) · {(st.artifactKeys?.length ?? 0)} artifact(s)</span>
                    <button onClick={() => removeState(idx)} className="text-red-600 hover:text-red-700 cursor-pointer">Remove</button>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {tab === 'run' && (
        <>
          <RunStatusBanner run={run} runError={runError} stopping={stopping} paused={paused} />
          {!run && !runError && (
            <div className="rounded-2xl border border-dashed border-gray-300 bg-gray-50 p-6 text-center text-sm text-gray-500">
              Click <strong className="text-orange-600">Start with AI</strong> on the Plan tab to launch the browsers and begin the
              comparison. Test cases and steps will stream in here as the AI proposes and runs them.
            </div>
          )}
          {run && (
            <div className="grid grid-cols-1 xl:grid-cols-4 gap-4">
              <div className="xl:col-span-3 space-y-4">
                <BrowserSessionsPanel sides={plan.sides} />
                {/* Note input — visible for the whole life of an AI run,
                    including while paused. Gated only on useAI + "a run is
                    active". Replay runs don't consult the LLM so notes are
                    meaningless there. */}
                {run.useAI && run.status === 'running' && !stopping && (
                  <div className="rounded-2xl border border-gray-200 bg-white px-3 py-2">
                    <div className="flex items-end gap-2">
                      <div className="flex-1">
                        <label className="block text-[11px] text-gray-500 mb-0.5">
                          Send a note to the AI {paused ? '(delivered on resume)' : '(delivered on the next turn)'}
                        </label>
                        <textarea
                          value={noteText}
                          onChange={(e) => setNoteText(e.target.value)}
                          onKeyDown={(e) => {
                            // Enter sends; Shift+Enter inserts a newline.
                            if (e.key === 'Enter' && !e.shiftKey) {
                              e.preventDefault();
                              handleSendNote();
                            }
                          }}
                          rows={2}
                          placeholder={'e.g. "The login form is inside the #auth drawer, open it first." — Enter to send, Shift+Enter for newline'}
                          className="w-full px-2 py-1.5 border border-gray-200 rounded-md text-xs font-mono focus:outline-none focus:ring-2 focus:ring-orange-300"
                        />
                      </div>
                      <button
                        onClick={handleSendNote}
                        disabled={!noteText.trim()}
                        className="px-3 py-1.5 text-xs font-semibold bg-gray-700 text-white rounded-md hover:bg-gray-800 disabled:opacity-50 cursor-pointer shrink-0"
                      >
                        Send
                      </button>
                    </div>
                  </div>
                )}
                <ComparisonRunStream
                  plan={plan}
                  testCasesByState={testCasesByState}
                  stateProgress={stateProgress}
                  stateResults={run.stateResults}
                />
              </div>
              <div className="xl:col-span-1">
                <DiffResultsRail run={run} />
              </div>
            </div>
          )}
        </>
      )}

      {tab === 'history' && (
        <ComparisonHistoryView projectId={projectId} moduleId={moduleId} featureId={featureId} />
      )}
    </div>
  );
}

function RunStatusBanner({
  run,
  runError,
  stopping,
  paused,
}: {
  run: import('../../../../activator/types/comparisonPlan').ComparisonRun | null;
  runError: string | null;
  stopping: boolean;
  paused: boolean;
}) {
  if (runError) {
    return (
      <div className="mb-4 rounded-lg border border-red-300 bg-red-50 p-3">
        <div className="text-sm font-semibold text-red-800">Comparison failed</div>
        <div className="text-xs text-red-700 mt-1 whitespace-pre-wrap font-mono">{runError}</div>
        <div className="text-xs text-red-700 mt-2">
          Check the activator log for more context, fix the issue in the plan, then click <strong>Start with AI</strong> again.
        </div>
      </div>
    );
  }
  if (!run) return null;

  const effectiveStatus = stopping ? 'stopping' : paused ? 'paused' : run.status;
  const colour =
    effectiveStatus === 'running'
      ? 'border-orange-300 bg-orange-50 text-orange-800'
      : effectiveStatus === 'stopping'
        ? 'border-yellow-300 bg-yellow-50 text-yellow-800'
        : effectiveStatus === 'paused'
          ? 'border-blue-300 bg-blue-50 text-blue-800'
          : effectiveStatus === 'passed'
            ? 'border-green-300 bg-green-50 text-green-800'
            : effectiveStatus === 'failed'
              ? 'border-red-300 bg-red-50 text-red-800'
              : 'border-gray-300 bg-gray-50 text-gray-700';
  return (
    <div className={`mb-4 rounded-lg border p-3 ${colour}`}>
      <div className="flex items-center justify-between">
        <div className="text-sm font-semibold capitalize">Comparison {effectiveStatus}</div>
        <div className="text-[11px] font-mono opacity-75">run {run.id}</div>
      </div>
      {effectiveStatus === 'running' && (
        <div className="text-xs mt-1 opacity-90">
          AI is driving the browsers — authenticating, navigating, extracting, diffing. Test cases and steps stream in below as they happen.
        </div>
      )}
      {effectiveStatus === 'paused' && (
        <div className="text-xs mt-1 opacity-90">
          Paused at the next yield point. Click Resume to continue, or send a note to the AI and it will be picked up on resume.
        </div>
      )}
      {effectiveStatus === 'stopping' && (
        <div className="text-xs mt-1 opacity-90">
          Stopping the run — closing browsers, cancelling pending feedback, and aborting the AI loop.
        </div>
      )}
    </div>
  );
}

function LabeledInput({
  label,
  value,
  onChange,
  placeholder,
  type = 'text',
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  placeholder?: string;
  type?: 'text' | 'password';
}) {
  return (
    <div>
      <label className="block text-xs text-gray-500 mb-1">{label}</label>
      <input
        type={type}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-300"
      />
    </div>
  );
}

function LabeledTextarea({
  label,
  value,
  onChange,
  placeholder,
  rows = 3,
}: {
  label: string;
  value: string;
  onChange: (v: string) => void;
  placeholder?: string;
  rows?: number;
}) {
  return (
    <div>
      <label className="block text-xs text-gray-500 mb-1">{label}</label>
      <textarea
        value={value}
        onChange={(e) => onChange(e.target.value)}
        placeholder={placeholder}
        rows={rows}
        className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-300 resize-y"
      />
    </div>
  );
}

function makeEmptyPlan(projectId: string, moduleId: string, featureId: string | undefined, title: string): ComparisonPlan {
  const now = new Date().toISOString();
  return {
    id: `plan_${Date.now().toString(36)}_${Math.random().toString(36).slice(2, 6)}`,
    projectId,
    moduleId,
    featureId,
    title,
    sides: [
      { sessionId: 'old_ui', label: 'Old UI', url: '' },
      { sessionId: 'new_ui', label: 'New UI', url: '' },
    ],
    states: [],
    compareStyles: false,
    createdAt: now,
    updatedAt: now,
  };
}
