import type { TestCase } from '../../../../activator/types/state';
import type ActivatorProxy from '../../../store/ActivatorProxy';
import { PlayCircleIcon, StopIcon } from '../../../styles/Icons';
import TestCaseCard from './TestCaseCard';
import EditTestCaseForm from './EditTestCaseForm';

interface TestGroupProps {
  groupId: string;
  groupName: string;
  tests: TestCase[];
  activator: ActivatorProxy;
  projectId: string;
  featureId: string;
  useAI: boolean;
  editingId: string | null;
  onEdit: (tc: TestCase) => void;
  onSaveEdit: (title: string, description: string, priority: 'high' | 'medium' | 'low', strategy: string | undefined) => void;
  onCancelEdit: () => void;
  onDelete: (id: string) => void;
}

export default function TestGroup({
  groupName,
  tests,
  activator,
  projectId,
  featureId,
  useAI,
  editingId,
  onEdit,
  onSaveEdit,
  onCancelEdit,
  onDelete,
}: TestGroupProps) {
  const isRunning = tests.some(tc => tc.status === 'running' || tc.status === 'paused');

  const handleRunGroup = () => {
    activator.runTestCases(projectId, featureId, tests.map(tc => tc.id), useAI || undefined);
  };

  const handleStop = () => {
    activator.stopExecution();
  };

  return (
    <div>
      {/* Group header */}
      <div className="bg-white rounded-lg shadow-sm border border-gray-200 flex items-center gap-2 mb-2 px-3 py-2.5">
        {isRunning ? (
          <button className="text-red-600 cursor-pointer" onClick={handleStop}>
            <StopIcon />
          </button>
        ) : (
          <button className="text-blue-600 cursor-pointer" onClick={handleRunGroup}>
            <PlayCircleIcon />
          </button>
        )}
        <h2 className="text-sm font-semibold text-[#1e2939] flex items-center gap-2 justify-between w-full">
          <span className="flex items-center gap-2">
            {groupName}
          </span>
          <span className="text-xs font-medium text-gray-500">{tests.length} testcases</span>
        </h2>
      </div>

      {/* Test cases in the group */}
      {tests.map(tc =>
        editingId === tc.id ? (
          <EditTestCaseForm
            key={tc.id}
            initialTitle={tc.title}
            initialDescription={tc.description}
            initialPriority={tc.priority}
            initialStrategy={tc.strategy}
            onSave={onSaveEdit}
            onCancel={onCancelEdit}
          />
        ) : (
          <TestCaseCard
            key={tc.id}
            testCase={tc}
            activator={activator}
            projectId={projectId}
            featureId={featureId}
            showRunButton={false}
            useAI={useAI}
            onEdit={onEdit}
            onDelete={onDelete}
          />
        )
      )}
    </div>
  );
}
