import classnames from 'classnames';
import type { ComparisonStep } from '../../../../activator/types/comparisonPlan';
import { SuccessIcon, FailedIcon, RunningIcon } from '../../../styles/Icons';

interface Props {
  step: ComparisonStep;
  /** Optional 1-based number to show before the title (e.g. "3. Click ..."). */
  index?: number;
  onClick: () => void;
}

const COMMON_BADGE = 'common';

/**
 * Mirrors the test-execution `StepDetail` row: status icon + human-readable
 * one-line title + optional session badge + duration. NO raw JSON, NO args
 * dump. Click opens a modal with the full breakdown.
 */
export default function ComparisonStepRow({ step, index, onClick }: Props) {
  const title = getComparisonStepTitle(step);
  const sessionBadge = step.sessionId ?? COMMON_BADGE;
  const isCommon = sessionBadge === COMMON_BADGE;

  return (
    <div
      className="bg-gray-100 p-2.5 ps-1.5 rounded-md cursor-pointer hover:bg-gray-200 transition-colors"
      onClick={onClick}
    >
      <div className="flex items-center gap-2">
        <StepStatusIcon status={step.status} />
        <span
          className={classnames(
            'shrink-0 text-[10px] uppercase font-semibold tracking-wide px-1.5 py-0.5 rounded font-mono',
            isCommon ? 'bg-gray-200 text-gray-600' : 'bg-blue-100 text-blue-700',
          )}
          title={isCommon ? 'Session-independent tool' : `Browser session: ${sessionBadge}`}
        >
          {sessionBadge}
        </span>
        <span className="text-xs text-[#1e2939] flex-1 min-w-0 truncate">
          {index ? `${index}. ${title}` : title}
        </span>
        {typeof step.durationMs === 'number' && (
          <span className="text-[10px] text-gray-400 shrink-0">{formatDuration(step.durationMs)}</span>
        )}
      </div>
    </div>
  );
}

export function StepStatusIcon({ status }: { status: ComparisonStep['status'] }) {
  if (status === 'running') return <RunningIcon className="text-orange-500 animate-pulse" />;
  if (status === 'failed') return <FailedIcon className="text-red-500" />;
  return <SuccessIcon className="text-green-500" />;
}

/**
 * One-line, human-readable title for a comparison step. Mirrors the
 * test-execution `getStepTitle` style — element-name where possible, no raw
 * selectors, no JSON. Adds comparison-specific tools on top.
 */
export function getComparisonStepTitle(step: ComparisonStep): string {
  const args = step.toolArgs as Record<string, unknown>;
  const toolName = step.toolName;
  const elementInfo = (args.__elementInfo as ElementInfoLike | undefined);
  const selector = typeof args.selector === 'string' ? (args.selector as string) : undefined;
  const element = describeElement(elementInfo, selector);

  switch (toolName) {
    // ===== Comparison-specific tools =====
    case 'propose_test_case':
      return `New test case: "${(args.title as string) ?? 'Untitled'}"`;
    case 'finish_test_case': {
      const status = (args.status as string) ?? 'passed';
      const summary = (args.summary as string) ?? '';
      return summary ? `Finish test case (${status}): ${summary}` : `Finish test case (${status})`;
    }
    case 'extract_table':
      return `Extract table → "${(args.artifactKey as string) ?? ''}"`;
    case 'compare_tables':
      return `Compare tables: "${(args.leftArtifactKey as string) ?? ''}" vs "${(args.rightArtifactKey as string) ?? ''}"`;
    case 'extract_form':
      return `Extract form → "${(args.artifactKey as string) ?? ''}"`;
    case 'compare_forms':
      return `Compare forms: "${(args.leftArtifactKey as string) ?? ''}" vs "${(args.rightArtifactKey as string) ?? ''}"`;
    case 'extract_chart':
      return `Extract chart → "${(args.artifactKey as string) ?? ''}"`;
    case 'compare_charts':
      return `Compare charts: "${(args.leftArtifactKey as string) ?? ''}" vs "${(args.rightArtifactKey as string) ?? ''}"`;
    case 'extract_section':
      return `Extract section → "${(args.artifactKey as string) ?? ''}"`;
    case 'compare_sections':
      return `Compare sections: "${(args.leftArtifactKey as string) ?? ''}" vs "${(args.rightArtifactKey as string) ?? ''}"`;
    case 'extract_style':
      return `Extract styles → "${(args.artifactKey as string) ?? ''}"`;
    case 'compare_styles':
      return `Compare styles: "${(args.leftArtifactKey as string) ?? ''}" vs "${(args.rightArtifactKey as string) ?? ''}"`;
    case 'request_user_feedback': {
      const mode = (args.mode as string) ?? 'text';
      const prompt = (args.prompt as string) ?? '';
      const trimmed = prompt.length > 60 ? prompt.slice(0, 60) + '…' : prompt;
      return `Ask user (${mode}): ${trimmed}`;
    }
    case 'browser_launch_session':
      return `Launch session "${(args.id as string) ?? ''}"`;
    case 'browser_switch_session':
      return `Switch to session "${(args.id as string) ?? ''}"`;
    case 'browser_close_session':
      return `Close session "${(args.id as string) ?? ''}"`;
    case 'browser_sessions':
      return 'List browser sessions';

    // ===== Reused from regular execution =====
    case 'browser_click':
      return `Click ${element}`;
    case 'browser_fill':
      return `Fill ${element} with "${(args.value as string) ?? ''}"`;
    case 'browser_navigate':
      return `Navigate to ${(args.url as string) ?? ''}`;
    case 'browser_navigate_back':
      return 'Navigate back';
    case 'browser_navigate_forward':
      return 'Navigate forward';
    case 'browser_type':
      return `Type "${(args.text as string) ?? ''}"`;
    case 'browser_press_key':
      return `Press ${(args.key as string) ?? ''}`;
    case 'browser_select_option':
      return `Select "${(args.value as string) ?? (args.label as string) ?? ''}" in ${element}`;
    case 'browser_screenshot':
      return 'Take screenshot';
    case 'browser_snapshot':
      return 'Capture accessibility tree';
    case 'browser_hover':
      return `Hover ${element}`;
    case 'browser_wait_for':
      return `Wait for ${element || (args.text as string) || ''}`;
    case 'browser_switch_tab':
      return `Switch to tab ${args.index}`;
    case 'browser_new_tab':
      return `Open new tab${args.url ? `: ${args.url}` : ''}`;
    case 'browser_close_tab':
      return 'Close tab';
    case 'browser_evaluate':
      return 'Execute JavaScript';
    case 'browser_reload':
      return 'Reload page';
    case 'browser_check':
      return `Check ${element}`;
    case 'browser_uncheck':
      return `Uncheck ${element}`;

    default:
      return toolName.replace(/^browser_/, '').replace(/_/g, ' ');
  }
}

interface ElementInfoLike {
  role?: string;
  name?: string;
  text?: string;
  tagName?: string;
  attrId?: string;
  attrName?: string;
  href?: string;
}

function describeElement(info: ElementInfoLike | undefined, fallbackSelector: string | undefined): string {
  if (info) {
    const label = info.name || info.text || info.attrName || info.attrId || info.tagName || '';
    const rolePart = info.role && info.role !== info.tagName ? info.role : info.tagName;
    if (label && rolePart) return `"${label}" ${rolePart}`;
    if (label) return `"${label}"`;
    if (rolePart) return rolePart;
  }
  return fallbackSelector || '';
}

function formatDuration(ms: number): string {
  if (ms < 1000) return `${ms}ms`;
  return `${(ms / 1000).toFixed(2)}s`;
}
