import { useMemo, useState } from 'react';
import { useStore } from '../../store/state';
import { useActivator } from '../../store/Context';

interface Props {
  projectId: string;
  moduleId: string;
}

export default function SummaryReportTab({ projectId, moduleId }: Props) {
  const activator = useActivator();
  const project = useStore(s => s.projects.find(p => p.id === projectId));
  const mod = project?.modules.find(m => m.id === moduleId);
  const generating = useStore(s => s.generatingSummaryReport);
  const error = useStore(s => s.summaryReportError);

  const [selectedFeatureIds, setSelectedFeatureIds] = useState<string[]>([]);
  const [currentVersionId, setCurrentVersionId] = useState<string | null>(null);

  const report = mod?.summaryReport;

  const activeVersion = useMemo(() => {
    if (!report) return null;
    const id = currentVersionId ?? report.currentVersionId;
    return report.versions.find(v => v.id === id) ?? null;
  }, [report, currentVersionId]);

  const isGenerating =
    generating?.projectId === projectId && generating?.moduleId === moduleId;

  if (!mod) return null;

  const toggleFeature = (id: string) =>
    setSelectedFeatureIds(prev => (prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]));

  const handleGenerate = () => {
    activator.generateSummaryReport(projectId, moduleId, {
      featureIds: selectedFeatureIds.length > 0 ? selectedFeatureIds : undefined,
    });
  };

  const handleDownload = () => {
    if (!activeVersion) return;
    const blob = new Blob([activeVersion.markdown], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `summary-${mod.name.replace(/\s+/g, '_')}-v${activeVersion.versionNumber}.md`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleDelete = () => {
    if (!activeVersion) return;
    if (!confirm(`Delete version ${activeVersion.versionNumber}?`)) return;
    activator.deleteSummaryReportVersion(projectId, moduleId, activeVersion.id);
    setCurrentVersionId(null);
  };

  return (
    <div className="space-y-4">
      {/* Generate form */}
      <div className="rounded-2xl border border-gray-200 bg-white p-5">
        <h3 className="text-sm font-semibold text-gray-800 mb-3">Generate Summary Report</h3>
        <p className="text-xs text-gray-500 mb-3">
          Aggregates execution overview, per-feature results, comparison findings, and a traceability matrix into a
          downloadable Markdown report. Leave features unchecked to include all.
        </p>

        <div className="mb-3">
          <label className="block text-xs text-gray-500 mb-1">Features to include (optional)</label>
          <div className="flex flex-wrap gap-2">
            {mod.features.length === 0 && <span className="text-xs text-gray-400">No features</span>}
            {mod.features.map(f => (
              <label
                key={f.id}
                className={`inline-flex items-center gap-1.5 px-2 py-1 rounded-full text-xs cursor-pointer border ${
                  selectedFeatureIds.includes(f.id)
                    ? 'bg-orange-50 border-orange-300 text-orange-700'
                    : 'bg-white border-gray-200 text-gray-700 hover:border-gray-300'
                }`}
              >
                <input
                  type="checkbox"
                  checked={selectedFeatureIds.includes(f.id)}
                  onChange={() => toggleFeature(f.id)}
                  className="accent-orange-500"
                />
                {f.name}
              </label>
            ))}
          </div>
        </div>

        <button
          onClick={handleGenerate}
          disabled={isGenerating || mod.features.length === 0}
          className="px-4 py-1.5 text-sm font-semibold bg-orange-500 text-white rounded-lg hover:bg-orange-600 disabled:opacity-50"
        >
          {isGenerating ? 'Generating...' : report ? 'Generate new version' : 'Generate Summary Report'}
        </button>

        {error && <p className="text-xs text-red-600 mt-2">Error: {error}</p>}
      </div>

      {/* Versions */}
      {report && (
        <div className="rounded-2xl border border-gray-200 bg-white p-5">
          <div className="flex items-center justify-between mb-3 flex-wrap gap-2">
            <div className="flex items-center gap-2">
              <label className="text-xs text-gray-500">Version</label>
              <select
                value={activeVersion?.id ?? report.currentVersionId}
                onChange={e => setCurrentVersionId(e.target.value)}
                className="px-2 py-1 text-xs border border-gray-200 rounded-lg bg-white"
              >
                {report.versions
                  .slice()
                  .sort((a, b) => b.versionNumber - a.versionNumber)
                  .map(v => (
                    <option key={v.id} value={v.id}>
                      v{v.versionNumber} — {new Date(v.createdAt).toLocaleString()}
                    </option>
                  ))}
              </select>
            </div>
            <div className="flex items-center gap-2">
              <button
                onClick={handleDownload}
                className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-50"
              >
                Download .md
              </button>
              <button
                onClick={handleDelete}
                className="px-3 py-1.5 text-xs font-semibold bg-white text-red-600 border border-red-200 rounded-lg hover:bg-red-50"
              >
                Delete version
              </button>
            </div>
          </div>

          {activeVersion && (
            <pre className="text-xs bg-gray-50 border border-gray-200 rounded-lg p-4 whitespace-pre-wrap overflow-x-auto max-h-[70vh]">
              {activeVersion.markdown}
            </pre>
          )}
        </div>
      )}

      {!report && !isGenerating && (
        <div className="rounded-2xl border border-dashed border-gray-200 bg-white p-6 text-center">
          <p className="text-sm text-gray-500">No summary report yet. Generate one after running test cases.</p>
        </div>
      )}
    </div>
  );
}
