import { useEffect, useRef, useState } from 'react';
import type { RecordedStep, NetworkRequestSummary, ConsoleMessageSummary, TestFinding } from '../../../../activator/types/state';
import type { ServerMessage } from '../../../../activator/types/protocol';
import { useActivator } from '../../../store/Context';

interface StepDetailModalProps {
  step: RecordedStep;
  findings?: TestFinding[];
  /**
   * When supplied, the modal lazy-loads heavy per-step data (screenshot,
   * network, console) from the per-run folder on disk. Not needed for steps
   * from the currently running test case — those already have the data in
   * memory. Required for steps from historical runs.
   */
  runContext?: { runId: string; testCaseId: string };
  onClose: () => void;
}

type TabId = 'details' | 'network' | 'console' | 'screenshot';

function NetworkRequestCard({ req }: { req: NetworkRequestSummary }) {
  const [expanded, setExpanded] = useState(false);

  const methodColor =
    req.method === 'GET' ? 'bg-green-100 text-green-700' :
    req.method === 'POST' ? 'bg-blue-100 text-blue-700' :
    req.method === 'PUT' ? 'bg-yellow-100 text-yellow-700' :
    req.method === 'PATCH' ? 'bg-orange-100 text-orange-700' :
    req.method === 'DELETE' ? 'bg-red-100 text-red-700' :
    'bg-gray-100 text-gray-700';

  const statusColor =
    req.failed ? 'text-red-600' :
    !req.status ? 'text-gray-400' :
    req.status >= 500 ? 'text-red-600' :
    req.status >= 400 ? 'text-orange-600' :
    req.status >= 300 ? 'text-yellow-600' :
    'text-green-600';

  return (
    <div className="border border-gray-200 rounded-lg overflow-hidden mb-1.5">
      <div
        className={`flex items-center gap-2 px-3 py-2 cursor-pointer hover:bg-gray-50 ${expanded ? 'bg-gray-50' : ''}`}
        onClick={() => setExpanded(!expanded)}
      >
        <span className={`px-2 py-0.5 rounded text-[10px] font-bold ${methodColor}`}>{req.method}</span>
        <span className={`text-xs font-semibold ${statusColor}`}>
          {req.failed ? 'FAILED' : req.status || '...'}
        </span>
        {req.resourceType && req.resourceType !== 'other' && (
          <span className="text-[10px] text-gray-400 bg-gray-100 px-1.5 rounded">{req.resourceType}</span>
        )}
        {req.duration != null && (
          <span className="text-[10px] text-gray-400">{req.duration}ms</span>
        )}
        <svg className={`w-3 h-3 text-gray-400 ml-auto transition-transform ${expanded ? 'rotate-90' : ''}`} fill="currentColor" viewBox="0 0 20 20">
          <path fillRule="evenodd" d="M7.21 5.23a.75.75 0 011.06-.02l3.85 4.25a.75.75 0 010 1.02l-3.85 4.25a.75.75 0 11-1.08-1.04l3.35-3.71-3.35-3.71a.75.75 0 01.02-1.06z" clipRule="evenodd" />
        </svg>
      </div>
      <div className="px-3 pb-1 text-[11px] text-gray-500 font-mono break-all">{req.url}</div>

      {req.failureReason && (
        <div className="px-3 pb-2 text-xs text-red-600">{req.failureReason}</div>
      )}

      {expanded && (
        <div className="border-t border-gray-200 px-3 py-2 space-y-3">
          {/* Request Headers */}
          {req.requestHeaders && Object.keys(req.requestHeaders).length > 0 && (
            <div>
              <h4 className="text-[10px] font-semibold text-gray-500 uppercase mb-1">Request Headers</h4>
              <div className="bg-gray-50 rounded p-2 text-[11px] font-mono space-y-0.5 max-h-40 overflow-y-auto">
                {Object.entries(req.requestHeaders).map(([key, val]) => (
                  <div key={key} className="flex">
                    <span className="text-blue-600 shrink-0">{key}: </span>
                    <span className="text-gray-700 break-all ml-1">{val}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Request Body */}
          {req.requestBody != null && (
            <div>
              <h4 className="text-[10px] font-semibold text-gray-500 uppercase mb-1">Request Body</h4>
              <pre className="bg-gray-50 rounded p-2 text-[11px] font-mono whitespace-pre-wrap break-all max-h-48 overflow-y-auto text-gray-700">
                {typeof req.requestBody === 'string' ? req.requestBody : JSON.stringify(req.requestBody, null, 2)}
              </pre>
            </div>
          )}

          {/* Response Headers */}
          {req.responseHeaders && Object.keys(req.responseHeaders).length > 0 && (
            <div>
              <h4 className="text-[10px] font-semibold text-gray-500 uppercase mb-1">Response Headers</h4>
              <div className="bg-gray-50 rounded p-2 text-[11px] font-mono space-y-0.5 max-h-40 overflow-y-auto">
                {Object.entries(req.responseHeaders).map(([key, val]) => (
                  <div key={key} className="flex">
                    <span className="text-purple-600 shrink-0">{key}: </span>
                    <span className="text-gray-700 break-all ml-1">{val}</span>
                  </div>
                ))}
              </div>
            </div>
          )}

          {/* Response Body */}
          {req.responseBody != null && (
            <div>
              <h4 className="text-[10px] font-semibold text-gray-500 uppercase mb-1">Response Body</h4>
              <pre className="bg-gray-50 rounded p-2 text-[11px] font-mono whitespace-pre-wrap break-all max-h-64 overflow-y-auto text-gray-700">
                {typeof req.responseBody === 'string' ? req.responseBody : JSON.stringify(req.responseBody, null, 2)}
              </pre>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function ConsoleMessageCard({ msg }: { msg: ConsoleMessageSummary }) {
  const bgColor =
    msg.type === 'error' ? 'bg-red-50 border-red-200' :
    msg.type === 'warn' ? 'bg-yellow-50 border-yellow-200' :
    msg.type === 'info' ? 'bg-blue-50 border-blue-200' :
    msg.type === 'debug' ? 'bg-gray-100 border-gray-200' :
    'bg-gray-50 border-gray-200';

  const badgeColor =
    msg.type === 'error' ? 'bg-red-100 text-red-700' :
    msg.type === 'warn' ? 'bg-yellow-100 text-yellow-700' :
    msg.type === 'info' ? 'bg-blue-100 text-blue-700' :
    msg.type === 'debug' ? 'bg-gray-200 text-gray-600' :
    'bg-gray-200 text-gray-600';

  return (
    <div className={`rounded-lg border p-2.5 ${bgColor}`}>
      <div className="flex items-start gap-2">
        <span className={`px-1.5 py-0.5 rounded text-[10px] font-bold uppercase shrink-0 ${badgeColor}`}>
          {msg.type}
        </span>
        <div className="flex-1 min-w-0">
          <p className="text-xs text-gray-800 break-all">{msg.text}</p>
          {(msg.url || msg.lineNumber != null) && (
            <p className="text-[10px] text-gray-400 mt-0.5 font-mono truncate">
              {msg.url}{msg.lineNumber != null ? `:${msg.lineNumber}` : ''}
            </p>
          )}
        </div>
      </div>
    </div>
  );
}

export default function StepDetailModal({ step, findings = [], runContext, onClose }: StepDetailModalProps) {
  const stepFindings = findings.filter(f => f.stepId === step.id);
  const [activeTab, setActiveTab] = useState<TabId>('details');
  const [heavy, setHeavy] = useState<{
    screenshotBefore?: string;
    screenshotAfter?: string;
    networkRequests?: NetworkRequestSummary[];
    consoleMessages?: ConsoleMessageSummary[];
  } | null>(null);
  const requestIdRef = useRef<string | null>(null);
  const proxy = useActivator();

  useEffect(() => {
    if (!runContext || !proxy) return;
    const needs =
      !step.screenshotAfter && !step.screenshotBefore &&
      (!step.networkRequests || step.networkRequests.length === 0) &&
      (!step.consoleMessages || step.consoleMessages.length === 0);
    if (!needs) return;

    const rid = `step_heavy_${step.id}_${Date.now()}`;
    requestIdRef.current = rid;

    const unsubscribe = proxy.subscribe((msg: ServerMessage) => {
      if (msg.type === 'stepHeavyDataLoaded' && msg.data.requestId === rid) {
        setHeavy({
          screenshotBefore: msg.data.screenshotBefore,
          screenshotAfter: msg.data.screenshotAfter,
          networkRequests: msg.data.networkRequests,
          consoleMessages: msg.data.consoleMessages,
        });
      }
    });

    proxy.loadStepHeavyData(runContext.runId, runContext.testCaseId, step.id, rid);
    return () => { unsubscribe(); };
  }, [runContext, proxy, step.id, step.screenshotAfter, step.screenshotBefore, step.networkRequests, step.consoleMessages]);

  const networkRequests = heavy?.networkRequests ?? step.networkRequests ?? [];
  const consoleMessages = heavy?.consoleMessages ?? step.consoleMessages ?? [];
  const screenshotAfter = heavy?.screenshotAfter ?? step.screenshotAfter;

  const handleBackdropClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) onClose();
  };

  const tabs: { id: TabId; label: string; count?: number }[] = [
    { id: 'details', label: 'Details', count: stepFindings.length || undefined },
    { id: 'network', label: 'Network', count: networkRequests.length },
    { id: 'console', label: 'Console', count: consoleMessages.length },
    { id: 'screenshot', label: 'Screenshot' },
  ];

  return (
    <div className="fixed inset-0 bg-[rgba(0,0,0,0.5)] flex items-end z-50" onClick={handleBackdropClick}>
      <div className="bg-white rounded-t-2xl shadow-xl w-full min-h-[65vh] max-h-[65vh] animate-slide-up overflow-hidden flex flex-col">
        {/* Drag handle + header */}
        <div className="sticky top-0 bg-white border-b border-gray-200 px-4 py-3 shrink-0">
          <div className="w-12 h-1 bg-gray-300 rounded-full mx-auto mb-2" />
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <span className={`w-2.5 h-2.5 rounded-full ${step.result.success ? 'bg-green-500' : 'bg-red-500'}`} />
              <h2 className="text-sm font-semibold text-gray-800">
                Step {step.index + 1}: {step.toolName}
              </h2>
              <span className="text-xs text-gray-400">{step.result.duration}ms</span>
            </div>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-600 p-1">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>

          {/* Tab bar */}
          <div className="flex gap-1 mt-2">
            {tabs.map(tab => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id)}
                className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors ${
                  activeTab === tab.id
                    ? 'bg-[#1e2939] text-white'
                    : 'text-gray-500 hover:bg-gray-100'
                }`}
              >
                {tab.label}
                {tab.count != null && tab.count > 0 && (
                  <span className={`ml-1 px-1.5 py-0.5 rounded-full text-[10px] ${
                    activeTab === tab.id ? 'bg-white/20' : 'bg-gray-200'
                  }`}>
                    {tab.count}
                  </span>
                )}
              </button>
            ))}
          </div>
        </div>

        {/* Tab content */}
        <div className="flex-1 overflow-y-auto p-4">
          {activeTab === 'details' && (
            <div className="space-y-4">
              {stepFindings.length > 0 && (
                <div>
                  <h3 className="text-xs font-semibold text-gray-500 uppercase mb-1">Findings</h3>
                  <div className="space-y-1.5">
                    {stepFindings.map(f => {
                      const styles =
                        f.type === 'fail' ? { bg: 'bg-red-50', border: 'border-red-200', text: 'text-red-700', icon: '✗' } :
                        f.type === 'pass' ? { bg: 'bg-green-50', border: 'border-green-200', text: 'text-green-700', icon: '✓' } :
                        f.type === 'warning' ? { bg: 'bg-yellow-50', border: 'border-yellow-200', text: 'text-yellow-700', icon: '!' } :
                        { bg: 'bg-gray-50', border: 'border-gray-200', text: 'text-gray-600', icon: 'i' };
                      return (
                        <div key={f.id} className={`rounded-lg border p-3 flex items-start gap-2 ${styles.bg} ${styles.border}`}>
                          <span className={`shrink-0 font-bold text-sm ${styles.text}`}>{styles.icon}</span>
                          <p className={`text-xs wrap-break-word flex-1 ${styles.text}`}>{f.message}</p>
                        </div>
                      );
                    })}
                  </div>
                </div>
              )}

              {step.aiReasoning && (
                <div>
                  <h3 className="text-xs font-semibold text-gray-500 uppercase mb-1">AI Reasoning</h3>
                  <p className="text-sm text-gray-700 bg-blue-50 rounded-lg p-3 border border-blue-100">
                    {step.aiReasoning}
                  </p>
                </div>
              )}

              <div>
                <h3 className="text-xs font-semibold text-gray-500 uppercase mb-1">Arguments</h3>
                <pre className="text-xs text-gray-700 font-mono whitespace-pre-wrap break-all bg-gray-50 rounded-lg p-3 border border-gray-200">
                  {JSON.stringify(step.toolArgs, null, 2)}
                </pre>
              </div>

              <div>
                <h3 className="text-xs font-semibold text-gray-500 uppercase mb-1">Result</h3>
                <div className={`rounded-lg p-3 border text-sm ${
                  step.result.success ? 'bg-green-50 border-green-200' : 'bg-red-50 border-red-200'
                }`}>
                  <span className={`font-semibold ${step.result.success ? 'text-green-700' : 'text-red-700'}`}>
                    {step.result.success ? 'Success' : 'Failed'}
                  </span>
                  {step.result.error && <p className="text-red-600 text-xs mt-1">{step.result.error}</p>}
                  {step.result.data != null && (
                    <pre className="mt-2 text-xs font-mono whitespace-pre-wrap break-all text-gray-600">
                      {typeof step.result.data === 'string' ? step.result.data : JSON.stringify(step.result.data, null, 2)}
                    </pre>
                  )}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'network' && (
            <div>
              {networkRequests.length === 0 ? (
                <p className="text-sm text-gray-400 text-center py-4">No network requests captured</p>
              ) : (
                <div>
                  {networkRequests.map((req, i) => (
                    <NetworkRequestCard key={i} req={req} />
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'console' && (
            <div>
              {consoleMessages.length === 0 ? (
                <p className="text-sm text-gray-400 text-center py-4">No console messages captured</p>
              ) : (
                <div className="space-y-1.5">
                  {consoleMessages.map((msg, i) => (
                    <ConsoleMessageCard key={i} msg={msg} />
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'screenshot' && (
            <div>
              {screenshotAfter ? (
                <img
                  src={`data:image/png;base64,${screenshotAfter}`}
                  alt="After step"
                  className="w-full rounded-lg border border-gray-200"
                />
              ) : (
                <p className="text-sm text-gray-400 text-center py-4">No screenshot captured</p>
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
