import { modelsFor, ModelInput } from './controls';

// Keep this in sync with LLMTaskJsonKey in activator/config/appConfig.ts.
export type TaskKey =
  | 'vision'
  | 'testCaseGeneration'
  | 'testPlanGeneration'
  | 'featureClassification'
  | 'stepExecution'
  | 'comparison'
  | 'codeGeneration'
  | 'documentation'
  | 'summaryReportGeneration'
  | 'defectDrafting';

export interface TaskBinding {
  provider: string;
  model: string;
  temperature: number;
  maxTokens: number;
}

interface TaskRowMeta {
  key: TaskKey;
  label: string;
  description: string;
}

const TASK_ROWS: TaskRowMeta[] = [
  { key: 'vision',                  label: 'Vision',              description: 'Analyzes screenshots and understands current UI state during execution.' },
  { key: 'testCaseGeneration',      label: 'Test Generation',     description: 'Generates high-level test cases from requirements and feature descriptions.' },
  { key: 'testPlanGeneration',      label: 'Test Plan',           description: 'Produces the module-level test plan from linked Jira tickets and features.' },
  { key: 'featureClassification',   label: 'Feature Classifier',  description: 'Tags a feature with test strategies based on its description and scope.' },
  { key: 'stepExecution',           label: 'Step Execution',      description: 'Decides the next browser action during live AI-driven test execution.' },
  { key: 'comparison',              label: 'Comparison',          description: 'Analyses old vs. new UI screenshots to detect visual and functional regressions.' },
  { key: 'codeGeneration',          label: 'Code Generation',     description: 'Generates Playwright / Selenium automation scripts from recorded test executions.' },
  { key: 'documentation',           label: 'Documentation',       description: 'Writes test reports, summaries, and traceability documents.' },
  { key: 'summaryReportGeneration', label: 'Summary Report',      description: 'Builds a human-readable summary of a completed test run.' },
  { key: 'defectDrafting',          label: 'Defect Drafting',     description: 'Drafts a Jira bug report from a failing test case.' },
];

const PROVIDER_OPTIONS: Array<{ value: string; label: string }> = [
  { value: 'openai', label: 'OpenAI' },
  { value: 'bedrock', label: 'Bedrock SDK' },
  { value: 'bedrockapi', label: 'Bedrock API' },
  { value: 'gh-copilot', label: 'GitHub Copilot' },
  { value: 'claudecode', label: 'Claude Code' },
];

type BindingField = keyof TaskBinding;

interface Props {
  /** Resolved (merged) task bindings — what the activator would actually use. */
  merged: Record<TaskKey, TaskBinding>;
  /** Default bindings from config.json. */
  defaults: Record<TaskKey, TaskBinding>;
  /** Override patch for the currently-selected profile. Empty when viewing default. */
  profilePatch: Partial<Record<TaskKey, Partial<TaskBinding>>>;
  /** "default" means we edit defaults; any other name means we edit the named profile's patch. */
  editingProfile: string;
  /** Update a single field. Routed to defaults or to the active profile's patch based on `editingProfile`. */
  onChange: (task: TaskKey, field: BindingField, value: string | number) => void;
  /** Reset an override (profile view only). No-op when viewing default. */
  onResetOverride: (task: TaskKey, field: BindingField) => void;
}

function isOverridden(patch: Partial<TaskBinding> | undefined, field: BindingField): boolean {
  return !!patch && patch[field] !== undefined;
}

export default function TasksTable({ merged, defaults, profilePatch, editingProfile, onChange, onResetOverride }: Props) {
  const viewingProfile = editingProfile !== 'default';

  return (
    <div className="overflow-x-auto rounded-xl border border-gray-100">
      <table className="w-full text-xs">
        <thead>
          <tr className="bg-gray-50 border-b border-gray-100">
            <th className="text-left px-4 py-2.5 font-semibold text-gray-600 w-44">Task</th>
            <th className="text-left px-3 py-2.5 font-semibold text-gray-600 w-40">Provider</th>
            <th className="text-left px-3 py-2.5 font-semibold text-gray-600">Model</th>
            <th className="text-left px-3 py-2.5 font-semibold text-gray-600 w-24">Temp</th>
            <th className="text-left px-3 py-2.5 font-semibold text-gray-600 w-28">Max tokens</th>
          </tr>
        </thead>
        <tbody>
          {TASK_ROWS.map((row, i) => {
            const m = merged[row.key];
            const d = defaults[row.key];
            const patch = profilePatch[row.key];

            const providerOverridden = viewingProfile && isOverridden(patch, 'provider');
            const modelOverridden    = viewingProfile && isOverridden(patch, 'model');
            const tempOverridden     = viewingProfile && isOverridden(patch, 'temperature');
            const maxOverridden      = viewingProfile && isOverridden(patch, 'maxTokens');

            return (
              <tr key={row.key} className={`border-b border-gray-50 ${i % 2 === 0 ? 'bg-white' : 'bg-gray-50/40'} hover:bg-orange-50/20 transition-colors align-top`}>
                <td className="px-4 py-2.5">
                  <div className="font-semibold text-gray-800">{row.label}</div>
                  <div className="text-[10px] text-gray-400 leading-snug mt-0.5 max-w-xs">{row.description}</div>
                </td>

                {/* Provider */}
                <td className="px-3 py-2.5">
                  <div className="flex items-center gap-1">
                    <select
                      value={m.provider}
                      onChange={e => onChange(row.key, 'provider', e.target.value)}
                      className={`flex-1 px-2 py-1.5 rounded-lg border text-xs focus:outline-none focus:ring-2 focus:ring-orange-300 transition-all cursor-pointer ${
                        providerOverridden ? 'border-orange-300 bg-orange-50/40' : 'border-gray-200 bg-white'
                      }`}
                    >
                      {PROVIDER_OPTIONS.map(p => (
                        <option key={p.value} value={p.value}>{p.label}</option>
                      ))}
                    </select>
                    {providerOverridden && (
                      <ResetBtn
                        title={`Reset to default (${d.provider})`}
                        onClick={() => onResetOverride(row.key, 'provider')}
                      />
                    )}
                  </div>
                </td>

                {/* Model */}
                <td className="px-3 py-2.5">
                  <div className="flex items-center gap-1">
                    <div className="flex-1">
                      <ModelInput
                        value={m.model}
                        onChange={v => onChange(row.key, 'model', v)}
                        models={modelsFor(m.provider)}
                        highlighted={modelOverridden}
                        placeholder={m.provider === 'gh-copilot' || m.provider === 'claudecode' ? 'blank = CLI default' : 'Model ID'}
                      />
                    </div>
                    {modelOverridden && (
                      <ResetBtn
                        title={`Reset to default (${d.model})`}
                        onClick={() => onResetOverride(row.key, 'model')}
                      />
                    )}
                  </div>
                </td>

                {/* Temperature */}
                <td className="px-3 py-2.5">
                  <div className="flex items-center gap-1">
                    <input
                      type="number"
                      min="0"
                      max="2"
                      step="0.05"
                      value={m.temperature}
                      onChange={e => onChange(row.key, 'temperature', parseFloat(e.target.value))}
                      className={`flex-1 w-full px-2 py-1.5 rounded-lg border text-xs font-mono focus:outline-none focus:ring-2 focus:ring-orange-300 transition-all ${
                        tempOverridden ? 'border-orange-300 bg-orange-50/40' : 'border-gray-200 bg-white'
                      }`}
                    />
                    {tempOverridden && (
                      <ResetBtn
                        title={`Reset to default (${d.temperature})`}
                        onClick={() => onResetOverride(row.key, 'temperature')}
                      />
                    )}
                  </div>
                </td>

                {/* Max tokens */}
                <td className="px-3 py-2.5">
                  <div className="flex items-center gap-1">
                    <input
                      type="number"
                      min="256"
                      max="200000"
                      step="256"
                      value={m.maxTokens}
                      onChange={e => onChange(row.key, 'maxTokens', parseInt(e.target.value, 10))}
                      className={`flex-1 w-full px-2 py-1.5 rounded-lg border text-xs font-mono focus:outline-none focus:ring-2 focus:ring-orange-300 transition-all ${
                        maxOverridden ? 'border-orange-300 bg-orange-50/40' : 'border-gray-200 bg-white'
                      }`}
                    />
                    {maxOverridden && (
                      <ResetBtn
                        title={`Reset to default (${d.maxTokens})`}
                        onClick={() => onResetOverride(row.key, 'maxTokens')}
                      />
                    )}
                  </div>
                </td>
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

function ResetBtn({ onClick, title }: { onClick: () => void; title: string }) {
  return (
    <button
      type="button"
      onClick={onClick}
      title={title}
      className="shrink-0 w-6 h-6 flex items-center justify-center rounded-md text-orange-600 hover:bg-orange-100 transition-colors cursor-pointer"
      aria-label="Reset to default"
    >
      ↺
    </button>
  );
}
