/**
 * Static catalog of MCP tool names, grouped for the manual-mode action selector.
 * Mirrors `activator/tools/schemas/*.ts`. Kept hand-rolled (rather than imported)
 * so the UI bundle doesn't pull in the activator tool runtime. When a new tool
 * ships in the activator schemas, add its name here — the authoring UI is the
 * only consumer.
 */
export interface ManualActionCategory {
  key: string;
  label: string;
  actions: ManualAction[];
}

export interface ManualAction {
  name: string;
  /** Short hint displayed under the name in the searchable list. */
  hint?: string;
}

