/** Flat list (for quick lookup) of every action in the catalog. */
export const ALL_MANUAL_ACTIONS: ManualAction[] = MANUAL_ACTION_CATALOG.flatMap(
  (c) => c.actions,
);

/** Find the category label for an action name, or undefined. */
export function categoryForAction(name: string): string | undefined {
  for (const cat of MANUAL_ACTION_CATALOG) {
    if (cat.actions.some((a) => a.name === name)) return cat.label;
  }
  return undefined;
}
