import { useState } from 'react';

interface Props {
  profiles: string[];               // names (excluding "default")
  activeProfile: string | null;     // null when "default" is active
  editingProfile: string;           // "default" or a profile name — which one the table edits
  onEdit: (name: string) => void;   // switch which profile the task table edits
  onActivate: (name: string | null) => void; // set activeProfile (the one the runtime uses)
  onCreate: (name: string) => void;
  onRename: (oldName: string, newName: string) => void;
  onDelete: (name: string) => void;
}

/**
 * Profile chip bar. The "active" pill marks which profile the runtime
 * applies. The currently-edited profile is visually selected (orange
 * outline) — those two can differ so the user can tweak a profile
 * without it being live.
 */
export default function ProfileBar({ profiles, activeProfile, editingProfile, onEdit, onActivate, onCreate, onRename, onDelete }: Props) {
  const [creating, setCreating] = useState(false);
  const [newName, setNewName] = useState('');
  const [renaming, setRenaming] = useState<string | null>(null);
  const [renameValue, setRenameValue] = useState('');

  const chips: Array<{ name: string; isDefault: boolean }> = [
    { name: 'default', isDefault: true },
    ...profiles.map(name => ({ name, isDefault: false })),
  ];

  const commitCreate = () => {
    const trimmed = newName.trim();
    if (!trimmed || trimmed === 'default') { setCreating(false); setNewName(''); return; }
    if (profiles.includes(trimmed)) { setCreating(false); setNewName(''); return; }
    onCreate(trimmed);
    setCreating(false);
    setNewName('');
  };

  const commitRename = () => {
    if (!renaming) return;
    const trimmed = renameValue.trim();
    if (!trimmed || trimmed === renaming || trimmed === 'default' || profiles.includes(trimmed)) {
      setRenaming(null); setRenameValue(''); return;
    }
    onRename(renaming, trimmed);
    setRenaming(null);
    setRenameValue('');
  };

  return (
    <div className="flex flex-wrap items-center gap-2">
      <div className="flex flex-wrap items-center gap-2 flex-1">
        {chips.map(c => {
          const isEditing = editingProfile === c.name;
          const isActive = (c.isDefault && activeProfile === null) || (!c.isDefault && activeProfile === c.name);

          if (renaming === c.name) {
            return (
              <input
                key={c.name}
                autoFocus
                value={renameValue}
                onChange={e => setRenameValue(e.target.value)}
                onKeyDown={e => {
                  if (e.key === 'Enter') commitRename();
                  if (e.key === 'Escape') { setRenaming(null); setRenameValue(''); }
                }}
                onBlur={commitRename}
                className="px-3 py-1.5 rounded-lg border border-orange-400 bg-orange-50 text-xs font-semibold text-orange-700 focus:outline-none focus:ring-2 focus:ring-orange-300"
              />
            );
          }

          return (
            <button
              key={c.name}
              type="button"
              onClick={() => onEdit(c.name)}
              onDoubleClick={() => {
                if (!c.isDefault) { setRenaming(c.name); setRenameValue(c.name); }
              }}
              title={c.isDefault ? 'Default — the baseline every profile inherits from' : 'Double-click to rename'}
              className={`px-3 py-1.5 rounded-lg border text-xs font-semibold transition-all cursor-pointer ${
                isEditing
                  ? 'border-orange-500 bg-orange-100 text-orange-800 shadow-sm shadow-orange-100'
                  : 'border-gray-200 bg-white text-gray-600 hover:border-gray-300'
              }`}
            >
              {c.name}
              {isActive && (
                <span className="ml-2 inline-flex items-center px-1.5 py-0.5 rounded-full bg-green-100 text-green-700 text-[9px] font-bold uppercase tracking-wide">
                  live
                </span>
              )}
            </button>
          );
        })}

        {creating ? (
          <input
            autoFocus
            value={newName}
            onChange={e => setNewName(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter') commitCreate();
              if (e.key === 'Escape') { setCreating(false); setNewName(''); }
            }}
            onBlur={commitCreate}
            placeholder="profile name…"
            className="px-3 py-1.5 rounded-lg border border-orange-400 bg-orange-50 text-xs font-semibold text-orange-700 focus:outline-none focus:ring-2 focus:ring-orange-300 w-44"
          />
        ) : (
          <button
            type="button"
            onClick={() => setCreating(true)}
            className="px-3 py-1.5 rounded-lg border border-dashed border-gray-300 text-xs font-semibold text-gray-500 hover:border-orange-300 hover:text-orange-600 transition-all cursor-pointer"
          >
            + New profile
          </button>
        )}
      </div>

      {/* Actions for the profile being edited */}
      <div className="flex items-center gap-2">
        <label className="flex items-center gap-2 text-[11px] text-gray-500">
          <span>Active at runtime:</span>
          <select
            value={activeProfile ?? ''}
            onChange={e => onActivate(e.target.value === '' ? null : e.target.value)}
            className="px-2 py-1 rounded-md border border-gray-200 text-xs bg-white focus:outline-none focus:ring-2 focus:ring-orange-300 cursor-pointer"
          >
            <option value="">default</option>
            {profiles.map(p => <option key={p} value={p}>{p}</option>)}
          </select>
        </label>
        {editingProfile !== 'default' && (
          <button
            type="button"
            onClick={() => {
              if (confirm(`Delete profile "${editingProfile}"?`)) onDelete(editingProfile);
            }}
            className="px-2 py-1 rounded-md text-[11px] text-red-600 hover:bg-red-50 border border-red-100 transition-colors cursor-pointer"
          >
            Delete
          </button>
        )}
      </div>
    </div>
  );
}
