import { useCallback, useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Field, SectionCard, SegmentedControl, TextInput, Toggle } from './controls';
import ProfileBar from './ProfileBar';
import TasksTable, { type TaskBinding, type TaskKey } from './TasksTable';

// ─── Types mirroring the on-disk config.json (profile-aware shape) ───────────

type BrowserDriver = 'playwright' | 'selenium';
type ScreenshotMode = 'always' | 'on-failure' | 'off';

interface Viewport { width: number; height: number }

interface RawConfig {
  ports: { activator: number; activatorApi: number; backend: number };
  browser: {
    driver: BrowserDriver;
    type: string;
    headless: boolean;
    cdpPort: number;
    viewport: Viewport;
    extensionPath: string | null;
    userDataDir: string | null;
    launchUrl: string | null;
  };
  resolutions: Record<'mobile' | 'tablet' | 'laptop' | 'desktop' | 'wide', Viewport>;
  llm: {
    providers: {
      openai?: Record<string, unknown>;
      bedrock: { region: string };
      bedrockapi: { region: string; anthropicVersion: string };
      ghCopilot: { cwd: string; logLevel: string; oneShotTimeoutMs: number; sessionTimeoutMs: number; clientName: string };
      claudeCode: { cwd: string; oneShotTimeoutMs: number; sessionTimeoutMs: number };
    };
    tasks: {
      default: Record<TaskKey, TaskBinding>;
      profiles: Record<string, Partial<Record<TaskKey, Partial<TaskBinding>>>>;
      activeProfile: string | null;
    };
  };
  execution: {
    screenshotMode: ScreenshotMode;
    passiveFindings: { captureWarnings: boolean; failOnFinding: boolean };
  };
  logging: { logPrompts: boolean; debugLog: boolean };
  cache: { enabled: boolean; useCached: boolean };
  cost: { usdToInr: number };
  integrations: { jira: { baseUrl: string | null }; swaggerUrls: string[] };
  devMode: boolean;
}

// ─── Fields whose changes require a restart to take effect ────────────────────

const RESTART_REQUIRED_KEYS = ['ports', 'browser.driver', 'cache', 'logging.debugLog', 'devMode'] as const;

// ─── Helpers ──────────────────────────────────────────────────────────────────

function mergeBindings(
  defaults: Record<TaskKey, TaskBinding>,
  patch: Partial<Record<TaskKey, Partial<TaskBinding>>> | undefined,
): Record<TaskKey, TaskBinding> {
  const out = {} as Record<TaskKey, TaskBinding>;
  for (const key of Object.keys(defaults) as TaskKey[]) {
    out[key] = { ...defaults[key], ...(patch?.[key] ?? {}) };
  }
  return out;
}

/**
 * Normalize a config read from the API. If the JSON still uses the legacy
 * flat `tasks: { vision: {...}, ... }` shape, wrap it into the profile-aware
 * shape so the rest of the UI can assume one form.
 */
function normalizeConfig(raw: unknown): RawConfig {
  const cfg = raw as RawConfig;
  const tasksUnknown = cfg.llm.tasks as unknown;
  if (tasksUnknown && typeof tasksUnknown === 'object' && !('default' in tasksUnknown)) {
    // Legacy flat shape — wrap it.
    cfg.llm.tasks = {
      default: tasksUnknown as Record<TaskKey, TaskBinding>,
      profiles: {},
      activeProfile: null,
    };
  } else {
    const t = cfg.llm.tasks as Partial<RawConfig['llm']['tasks']>;
    if (!t.profiles) t.profiles = {};
    if (!('activeProfile' in t)) t.activeProfile = null;
  }
  return cfg;
}

type ReadinessReason = 'config-missing' | 'missing-credential';

interface Props {
  /** When true the user cannot navigate away — first-run setup mode. */
  firstRun?: boolean;
  /** Why the readiness check blocked the user, if at all. */
  readinessReason?: ReadinessReason | null;
  /** Env keys that were detected missing for providers in use. */
  missingKeys?: string[];
}

export default function SettingsPage({ firstRun = false, readinessReason = null, missingKeys = [] }: Props) {
  const navigate = useNavigate();

  const [envValues, setEnvValues] = useState<Record<string, string>>({});
  const [config, setConfig] = useState<RawConfig | null>(null);
  const [editingProfile, setEditingProfile] = useState<string>('default');

  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [savedAt, setSavedAt] = useState<number | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [dirtyFields, setDirtyFields] = useState<Set<string>>(new Set());

  // Load both env secrets and the config document in parallel on mount.
  useEffect(() => {
    let cancelled = false;
    Promise.all([
      fetch('/api/env').then(r => r.json()).catch(() => ({ values: {} })),
      fetch('/api/config').then(r => r.json()).catch(() => ({ config: null })),
    ]).then(([envRes, cfgRes]: [{ values: Record<string, string> }, { config: unknown; error?: string }]) => {
      if (cancelled) return;
      setEnvValues(envRes.values ?? {});
      if (cfgRes?.config) {
        setConfig(normalizeConfig(cfgRes.config));
      } else if (cfgRes?.error) {
        setError(`Failed to load config.json: ${cfgRes.error}`);
      }
      setLoading(false);
    }).catch(err => {
      if (cancelled) return;
      setError(err instanceof Error ? err.message : 'Failed to load settings');
      setLoading(false);
    });
    return () => { cancelled = true; };
  }, []);

  // ─── Env secret editors ──────────────────────────────────────────────────────
  const envStr = useCallback((k: string, d = '') => envValues[k] ?? d, [envValues]);
  const setEnv = useCallback((k: string, v: string) => {
    setEnvValues(prev => ({ ...prev, [k]: v }));
    setSavedAt(null);
  }, []);

  // ─── Config editors (typed mutators) ─────────────────────────────────────────
  const markDirty = useCallback((key: string) => {
    setSavedAt(null);
    setDirtyFields(prev => new Set(prev).add(key));
  }, []);

  const patchConfig = useCallback(<K extends keyof RawConfig>(path: K, value: RawConfig[K]) => {
    setConfig(prev => prev ? { ...prev, [path]: value } : prev);
    markDirty(String(path));
  }, [markDirty]);

  const patchBrowser = useCallback((updater: (b: RawConfig['browser']) => RawConfig['browser']) => {
    setConfig(prev => prev ? { ...prev, browser: updater(prev.browser) } : prev);
    markDirty('browser');
  }, [markDirty]);

  const patchResolution = useCallback((key: keyof RawConfig['resolutions'], axis: 'width' | 'height', value: number) => {
    setConfig(prev => prev ? {
      ...prev,
      resolutions: { ...prev.resolutions, [key]: { ...prev.resolutions[key], [axis]: value } },
    } : prev);
    markDirty(`resolutions.${key}`);
  }, [markDirty]);

  const patchExecution = useCallback((updater: (e: RawConfig['execution']) => RawConfig['execution']) => {
    setConfig(prev => prev ? { ...prev, execution: updater(prev.execution) } : prev);
    markDirty('execution');
  }, [markDirty]);

  const patchPorts = useCallback((k: keyof RawConfig['ports'], value: number) => {
    setConfig(prev => prev ? { ...prev, ports: { ...prev.ports, [k]: value } } : prev);
    markDirty('ports');
  }, [markDirty]);

  const patchCache = useCallback((k: keyof RawConfig['cache'], value: boolean) => {
    setConfig(prev => prev ? { ...prev, cache: { ...prev.cache, [k]: value } } : prev);
    markDirty('cache');
  }, [markDirty]);

  const patchLogging = useCallback((k: keyof RawConfig['logging'], value: boolean) => {
    setConfig(prev => prev ? { ...prev, logging: { ...prev.logging, [k]: value } } : prev);
    markDirty(`logging.${k}`);
  }, [markDirty]);

  const patchJiraBase = useCallback((value: string) => {
    setConfig(prev => prev ? { ...prev, integrations: { ...prev.integrations, jira: { baseUrl: value || null } } } : prev);
    markDirty('integrations.jira');
  }, [markDirty]);

  const patchSwagger = useCallback((value: string) => {
    const list = value.split(',').map(s => s.trim()).filter(Boolean);
    setConfig(prev => prev ? { ...prev, integrations: { ...prev.integrations, swaggerUrls: list } } : prev);
    markDirty('integrations.swaggerUrls');
  }, [markDirty]);

  // ─── Profile CRUD ────────────────────────────────────────────────────────────
  const createProfile = useCallback((name: string) => {
    setConfig(prev => {
      if (!prev) return prev;
      if (name in prev.llm.tasks.profiles || name === 'default') return prev;
      return {
        ...prev,
        llm: {
          ...prev.llm,
          tasks: {
            ...prev.llm.tasks,
            profiles: { ...prev.llm.tasks.profiles, [name]: {} },
          },
        },
      };
    });
    setEditingProfile(name);
    markDirty('llm.tasks.profiles');
  }, [markDirty]);

  const renameProfile = useCallback((oldName: string, newName: string) => {
    setConfig(prev => {
      if (!prev) return prev;
      const profiles = { ...prev.llm.tasks.profiles };
      if (!(oldName in profiles) || newName in profiles || newName === 'default') return prev;
      profiles[newName] = profiles[oldName];
      delete profiles[oldName];
      const nextActive = prev.llm.tasks.activeProfile === oldName ? newName : prev.llm.tasks.activeProfile;
      return { ...prev, llm: { ...prev.llm, tasks: { ...prev.llm.tasks, profiles, activeProfile: nextActive } } };
    });
    if (editingProfile === oldName) setEditingProfile(newName);
    markDirty('llm.tasks.profiles');
  }, [editingProfile, markDirty]);

  const deleteProfile = useCallback((name: string) => {
    setConfig(prev => {
      if (!prev) return prev;
      const profiles = { ...prev.llm.tasks.profiles };
      delete profiles[name];
      const nextActive = prev.llm.tasks.activeProfile === name ? null : prev.llm.tasks.activeProfile;
      return { ...prev, llm: { ...prev.llm, tasks: { ...prev.llm.tasks, profiles, activeProfile: nextActive } } };
    });
    if (editingProfile === name) setEditingProfile('default');
    markDirty('llm.tasks.profiles');
  }, [editingProfile, markDirty]);

  const activateProfile = useCallback((name: string | null) => {
    setConfig(prev => prev ? {
      ...prev,
      llm: { ...prev.llm, tasks: { ...prev.llm.tasks, activeProfile: name } },
    } : prev);
    markDirty('llm.tasks.activeProfile');
  }, [markDirty]);

  // ─── Task-table edits ────────────────────────────────────────────────────────
  const handleTaskChange = useCallback((task: TaskKey, field: keyof TaskBinding, value: string | number) => {
    setConfig(prev => {
      if (!prev) return prev;
      if (editingProfile === 'default') {
        const currentDefault = prev.llm.tasks.default[task];
        const nextDefault = { ...prev.llm.tasks.default, [task]: { ...currentDefault, [field]: value } };
        return { ...prev, llm: { ...prev.llm, tasks: { ...prev.llm.tasks, default: nextDefault } } };
      }
      // Writing into a profile — only record the override if the value
      // diverges from the current default. This keeps the JSON tidy and
      // lets the user "set to default" by simply retyping the default value.
      const defaultVal = prev.llm.tasks.default[task][field];
      const existingPatch = prev.llm.tasks.profiles[editingProfile]?.[task] ?? {};
      let nextTaskPatch: Partial<TaskBinding> = { ...existingPatch };
      if (value === defaultVal) {
        delete (nextTaskPatch as Record<string, unknown>)[field];
      } else {
        (nextTaskPatch as Record<string, unknown>)[field] = value;
      }
      const nextProfilePatch = { ...(prev.llm.tasks.profiles[editingProfile] ?? {}), [task]: nextTaskPatch };
      // Clean up empty task patches so the JSON stays minimal.
      if (Object.keys(nextTaskPatch).length === 0) delete (nextProfilePatch as Record<string, unknown>)[task];
      const nextProfiles = { ...prev.llm.tasks.profiles, [editingProfile]: nextProfilePatch };
      return { ...prev, llm: { ...prev.llm, tasks: { ...prev.llm.tasks, profiles: nextProfiles } } };
    });
    markDirty(`llm.tasks.${editingProfile}.${task}.${field}`);
  }, [editingProfile, markDirty]);

  const handleResetOverride = useCallback((task: TaskKey, field: keyof TaskBinding) => {
    if (editingProfile === 'default') return;
    setConfig(prev => {
      if (!prev) return prev;
      const existingPatch = prev.llm.tasks.profiles[editingProfile]?.[task];
      if (!existingPatch || existingPatch[field] === undefined) return prev;
      const nextTaskPatch = { ...existingPatch };
      delete (nextTaskPatch as Record<string, unknown>)[field];
      const nextProfilePatch = { ...(prev.llm.tasks.profiles[editingProfile] ?? {}) };
      if (Object.keys(nextTaskPatch).length === 0) {
        delete (nextProfilePatch as Record<string, unknown>)[task];
      } else {
        (nextProfilePatch as Record<string, unknown>)[task] = nextTaskPatch;
      }
      const nextProfiles = { ...prev.llm.tasks.profiles, [editingProfile]: nextProfilePatch };
      return { ...prev, llm: { ...prev.llm, tasks: { ...prev.llm.tasks, profiles: nextProfiles } } };
    });
    markDirty(`llm.tasks.${editingProfile}.${task}.${field}`);
  }, [editingProfile, markDirty]);

  // ─── Derived values ──────────────────────────────────────────────────────────
  const merged = useMemo(() => {
    if (!config) return null;
    const patch = editingProfile === 'default' ? undefined : config.llm.tasks.profiles[editingProfile];
    return mergeBindings(config.llm.tasks.default, patch);
  }, [config, editingProfile]);

  const needsRestart = useMemo(() => {
    for (const key of dirtyFields) {
      for (const marker of RESTART_REQUIRED_KEYS) {
        if (key.startsWith(marker)) return true;
      }
    }
    return false;
  }, [dirtyFields]);

  // ─── Save ────────────────────────────────────────────────────────────────────
  const handleSave = async () => {
    if (!config) return;
    setSaving(true);
    setError(null);
    try {
      const [envRes, cfgRes] = await Promise.all([
        fetch('/api/env', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ values: envValues }),
        }),
        fetch('/api/config', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ config }),
        }),
      ]);
      const envData = await envRes.json().catch(() => ({}));
      const cfgData = await cfgRes.json().catch(() => ({}));
      if (!envRes.ok) throw new Error(envData.error || 'Failed to save secrets');
      if (!cfgRes.ok) throw new Error(cfgData.error || 'Failed to save config.json');
      setSavedAt(Date.now());
      setDirtyFields(new Set());
      if (firstRun) {
        // Re-check readiness; only leave the page if the server now reports ready.
        try {
          const r = await fetch('/api/readiness').then(res => res.json());
          if (r?.ready) setTimeout(() => navigate('/'), 1200);
        } catch { /* stay on settings */ }
      }
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Save failed');
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="flex flex-col items-center gap-3 text-gray-400">
          <div className="w-8 h-8 border-2 border-orange-400 border-t-transparent rounded-full animate-spin" />
          <span className="text-sm">Loading configuration…</span>
        </div>
      </div>
    );
  }

  if (!config) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-12">
        <div className="p-6 bg-red-50 border border-red-200 rounded-xl text-red-700">
          <p className="font-semibold mb-2">Could not load configuration</p>
          <p className="text-sm">{error ?? 'config.json is missing or unreadable. Ensure it exists at the repo root or at AUTOQAI_CONFIG_PATH.'}</p>
        </div>
      </div>
    );
  }

  const driver = config.browser.driver;
  const screenshotMode = config.execution.screenshotMode;

  const browserTypes = driver === 'playwright' ? ['chromium', 'firefox', 'webkit'] : ['chrome', 'firefox', 'edge'];

  const profiles = Object.keys(config.llm.tasks.profiles);

  return (
    <div className="max-w-5xl mx-auto px-4 py-8 space-y-6">

      {/* Header */}
      <div className="flex items-start justify-between gap-4">
        <div>
          {firstRun ? (
            <>
              <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-orange-100 text-orange-700 text-xs font-semibold mb-3">
                <span className="w-2 h-2 rounded-full bg-orange-500 animate-pulse" />
                {readinessReason === 'config-missing' ? 'Configuration required' : readinessReason === 'missing-credential' ? 'Credentials required' : 'First-time setup'}
              </div>
              <h1 className="text-2xl font-bold text-gray-900">Configure AutoQAI</h1>
              <p className="text-sm text-gray-500 mt-1">
                {readinessReason === 'config-missing'
                  ? 'config.json is missing or could not be parsed. Review the values below and save to create it.'
                  : readinessReason === 'missing-credential'
                  ? `Missing credentials for providers currently in use: ${missingKeys.join(', ')}. Fill them in the LLM Provider Credentials section and save.`
                  : 'Set up your credentials and runtime preferences before you start testing.'}
              </p>
            </>
          ) : (
            <>
              <h1 className="text-2xl font-bold text-gray-900">Settings</h1>
              <p className="text-sm text-gray-500 mt-1">
                Runtime configuration is stored in <code className="text-xs bg-gray-100 px-1.5 py-0.5 rounded font-mono">config.json</code>; secrets stay in <code className="text-xs bg-gray-100 px-1.5 py-0.5 rounded font-mono">.env</code>. Most changes apply live; a few require a restart.
              </p>
            </>
          )}
        </div>
        <div className="flex items-center gap-3 shrink-0">
          {!firstRun && (
            <button
              type="button"
              onClick={() => navigate(-1)}
              className="px-4 py-2 text-sm text-gray-600 bg-gray-100 rounded-lg hover:bg-gray-200 transition-colors cursor-pointer"
            >
              Cancel
            </button>
          )}
          <button
            type="button"
            onClick={handleSave}
            disabled={saving}
            className="flex items-center gap-2 px-5 py-2 bg-orange-500 text-white text-sm font-semibold rounded-lg hover:bg-orange-600 disabled:opacity-60 transition-all shadow-sm shadow-orange-200 cursor-pointer"
          >
            {saving ? (
              <>
                <span className="w-4 h-4 border-2 border-white/40 border-t-white rounded-full animate-spin" />
                Saving…
              </>
            ) : savedAt ? (
              <>
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" /></svg>
                Saved
              </>
            ) : 'Save configuration'}
          </button>
        </div>
      </div>

      {error && (
        <div className="flex items-center gap-3 px-4 py-3 bg-red-50 border border-red-200 rounded-xl text-sm text-red-700">
          <svg className="w-4 h-4 shrink-0" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><circle cx="12" cy="12" r="10"/><path strokeLinecap="round" d="M12 8v4m0 4h.01"/></svg>
          {error}
        </div>
      )}

      {savedAt !== null && (
        <div className="flex items-start gap-3 px-4 py-3 bg-emerald-50 border border-emerald-200 rounded-xl text-sm text-emerald-800">
          <svg className="w-4 h-4 shrink-0 mt-0.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" /></svg>
          <div>
            <p className="font-semibold">{firstRun ? 'Configuration saved. Redirecting…' : 'Configuration saved.'}</p>
            {needsRestart
              ? <p className="text-emerald-700 mt-0.5">Some changes (ports, browser driver, cache mode, dev mode, file logging) require an activator + backend restart. Other changes are already live.</p>
              : <p className="text-emerald-700 mt-0.5">Changes are live — no restart needed.</p>}
          </div>
        </div>
      )}

      {/* ── LLM PROFILES + TASKS ── */}
      <SectionCard title="LLM Profiles" icon="🧠">
        <div className="space-y-5">
          <p className="text-[11px] text-gray-400 -mt-1">
            Each profile is a set of <b>overrides</b> on top of <span className="text-gray-700 font-semibold">default</span>. The profile marked <span className="text-green-700 font-semibold">live</span> is what the activator actually uses; click a chip to edit that profile without making it live.
          </p>
          <ProfileBar
            profiles={profiles}
            activeProfile={config.llm.tasks.activeProfile}
            editingProfile={editingProfile}
            onEdit={setEditingProfile}
            onActivate={activateProfile}
            onCreate={createProfile}
            onRename={renameProfile}
            onDelete={deleteProfile}
          />
          {merged && (
            <TasksTable
              merged={merged}
              defaults={config.llm.tasks.default}
              profilePatch={editingProfile === 'default' ? {} : (config.llm.tasks.profiles[editingProfile] ?? {})}
              editingProfile={editingProfile}
              onChange={handleTaskChange}
              onResetOverride={handleResetOverride}
            />
          )}
          {editingProfile !== 'default' && (
            <p className="text-[11px] text-gray-400">
              Tip: any value you type that equals the default is NOT recorded as an override — the cell simply "inherits" again. Use the <span className="text-orange-600 font-semibold">↺</span> button to explicitly clear an override.
            </p>
          )}
        </div>
      </SectionCard>

      {/* ── LLM Provider Credentials (secrets, in .env) ── */}
      <SectionCard title="LLM Provider Credentials" icon="🔑" action={<span className="text-[10px] font-medium text-gray-400 uppercase tracking-wide">stored in .env</span>}>
        <div className="space-y-6">
          <div className="space-y-3">
            <SubHeader>OpenAI</SubHeader>
            <Field label="API key" hint="Used when any task's provider is set to 'openai'.">
              <TextInput value={envStr('OPENAI_API_KEY')} onChange={v => setEnv('OPENAI_API_KEY', v)} placeholder="sk-…" type="password" mono />
            </Field>
          </div>

          <div className="space-y-3">
            <SubHeader>AWS Bedrock (SDK)</SubHeader>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <Field label="Access key ID">
                <TextInput value={envStr('AWS_ACCESS_KEY_ID')} onChange={v => setEnv('AWS_ACCESS_KEY_ID', v)} placeholder="AKIA…" mono />
              </Field>
              <Field label="Secret access key">
                <TextInput value={envStr('AWS_SECRET_ACCESS_KEY')} onChange={v => setEnv('AWS_SECRET_ACCESS_KEY', v)} placeholder="…" type="password" mono />
              </Field>
            </div>
            <Field label="Region" hint="Non-secret — edited in the provider settings below.">
              <input
                value={config.llm.providers.bedrock.region}
                onChange={e => setConfig(prev => prev ? { ...prev, llm: { ...prev.llm, providers: { ...prev.llm.providers, bedrock: { region: e.target.value } } } } : prev)}
                className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-orange-300 font-mono"
              />
            </Field>
          </div>

          <div className="space-y-3">
            <SubHeader>AWS Bedrock (REST API)</SubHeader>
            <Field label="API key">
              <TextInput value={envStr('BED_ROCK_API_KEY')} onChange={v => setEnv('BED_ROCK_API_KEY', v)} placeholder="…" type="password" mono />
            </Field>
          </div>

          <div className="space-y-3">
            <SubHeader>GitHub Copilot / Claude Code</SubHeader>
            <p className="text-[11px] text-gray-400">Authenticate the CLIs out-of-band (<code>copilot auth login</code> / <code>claude auth</code>). Tokens are not stored here.</p>
          </div>
        </div>
      </SectionCard>

      {/* ── Browser Driver ── */}
      <SectionCard title="Browser Driver" icon="🌐">
        <div className="space-y-5">
          <Field label="Driver" hint="Playwright is recommended. Selenium requires a ChromeDriver or WebDriver binary on PATH. (Change requires restart.)">
            <SegmentedControl<BrowserDriver>
              value={driver}
              onChange={v => patchBrowser(b => ({ ...b, driver: v, type: (v === 'playwright' ? 'chromium' : 'chrome') }))}
              options={[
                { value: 'playwright', label: 'Playwright', desc: 'recommended' },
                { value: 'selenium', label: 'Selenium' },
              ]}
            />
          </Field>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <Field label="Browser type" hint={driver === 'playwright' ? 'chromium · firefox · webkit' : 'chrome · firefox · edge'}>
              <select
                value={config.browser.type}
                onChange={e => patchBrowser(b => ({ ...b, type: e.target.value }))}
                className="w-full px-3 py-2 rounded-lg border border-gray-200 text-sm bg-white focus:outline-none focus:ring-2 focus:ring-orange-300 transition-all cursor-pointer"
              >
                {browserTypes.map(b => <option key={b}>{b}</option>)}
              </select>
            </Field>
            {driver === 'selenium' && (
              <Field label="CDP port" hint="Chrome DevTools Protocol port used by SeleniumDriver for network/console tracking.">
                <TextInput
                  value={String(config.browser.cdpPort)}
                  onChange={v => patchBrowser(b => ({ ...b, cdpPort: parseInt(v, 10) || 0 }))}
                  placeholder="10112"
                  mono
                />
              </Field>
            )}
            <Field label="Viewport width">
              <TextInput value={String(config.browser.viewport.width)} onChange={v => patchBrowser(b => ({ ...b, viewport: { ...b.viewport, width: parseInt(v, 10) || 0 } }))} mono />
            </Field>
            <Field label="Viewport height">
              <TextInput value={String(config.browser.viewport.height)} onChange={v => patchBrowser(b => ({ ...b, viewport: { ...b.viewport, height: parseInt(v, 10) || 0 } }))} mono />
            </Field>
          </div>

          <Field label="Run headless by default">
            <Toggle
              checked={config.browser.headless}
              onChange={v => patchBrowser(b => ({ ...b, headless: v }))}
              label="Headless mode (user can override per run)"
            />
          </Field>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <Field label="Initial launch URL" hint="Opened automatically on browser launch. Overridden by the LAUNCH_URL env var or --launchUrl: CLI flag.">
              <TextInput value={config.browser.launchUrl ?? ''} onChange={v => patchBrowser(b => ({ ...b, launchUrl: v || null }))} placeholder="https://…" mono />
            </Field>
            <Field label="User data dir" hint="Persistent browser profile directory (optional).">
              <TextInput value={config.browser.userDataDir ?? ''} onChange={v => patchBrowser(b => ({ ...b, userDataDir: v || null }))} placeholder="" mono />
            </Field>
          </div>
        </div>
      </SectionCard>

      {/* ── Ports ── */}
      <SectionCard title="Ports" icon="🔌" action={<RestartHint />}>
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
          <Field label="Activator (WS)" hint="WebSocket server used by the UI.">
            <TextInput value={String(config.ports.activator)} onChange={v => patchPorts('activator', parseInt(v, 10) || 0)} mono />
          </Field>
          <Field label="Activator API (HTTP)" hint="REST endpoints for 3rd-party integrations.">
            <TextInput value={String(config.ports.activatorApi)} onChange={v => patchPorts('activatorApi', parseInt(v, 10) || 0)} mono />
          </Field>
          <Field label="Backend" hint="Jira + Swagger + static UI host.">
            <TextInput value={String(config.ports.backend)} onChange={v => patchPorts('backend', parseInt(v, 10) || 0)} mono />
          </Field>
        </div>
      </SectionCard>

      {/* ── Resolution Presets ── */}
      <SectionCard title="Resolution Presets" icon="📐">
        <p className="text-[11px] text-gray-400 mb-4">Pixel dimensions for each named preset used in manual automation step guards.</p>
        <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-5 gap-3">
          {(Object.keys(config.resolutions) as Array<keyof RawConfig['resolutions']>).map(preset => (
            <div key={preset} className="space-y-1">
              <label className="text-xs font-medium text-gray-600 capitalize">{preset}</label>
              <div className="flex gap-1">
                <input
                  type="number"
                  value={config.resolutions[preset].width}
                  onChange={e => patchResolution(preset, 'width', parseInt(e.target.value, 10) || 0)}
                  className="w-full px-2 py-1.5 rounded-lg border border-gray-200 text-xs font-mono bg-white focus:outline-none focus:ring-2 focus:ring-orange-300"
                />
                <span className="self-center text-gray-300">×</span>
                <input
                  type="number"
                  value={config.resolutions[preset].height}
                  onChange={e => patchResolution(preset, 'height', parseInt(e.target.value, 10) || 0)}
                  className="w-full px-2 py-1.5 rounded-lg border border-gray-200 text-xs font-mono bg-white focus:outline-none focus:ring-2 focus:ring-orange-300"
                />
              </div>
            </div>
          ))}
        </div>
      </SectionCard>

      {/* ── Execution Settings ── */}
      <SectionCard title="Execution Settings" icon="⚙️">
        <div className="space-y-5">
          <Field label="Screenshot capture mode" hint="Controls when screenshots are captured during test execution and replay.">
            <SegmentedControl<ScreenshotMode>
              value={screenshotMode}
              onChange={v => patchExecution(e => ({ ...e, screenshotMode: v }))}
              options={[
                { value: 'always',     label: 'Always',     desc: 'best for debugging' },
                { value: 'on-failure', label: 'On failure',  desc: 'faster replays' },
                { value: 'off',        label: 'Off',         desc: 'smallest footprint' },
              ]}
            />
          </Field>

          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <Field label="Passive findings">
              <div className="space-y-2">
                <Toggle
                  checked={config.execution.passiveFindings.captureWarnings}
                  onChange={v => patchExecution(e => ({ ...e, passiveFindings: { ...e.passiveFindings, captureWarnings: v } }))}
                  label="Capture console.warn as findings"
                />
                <Toggle
                  checked={config.execution.passiveFindings.failOnFinding}
                  onChange={v => patchExecution(e => ({ ...e, passiveFindings: { ...e.passiveFindings, failOnFinding: v } }))}
                  label="Fail test case on any passive finding"
                />
              </div>
            </Field>
          </div>
        </div>
      </SectionCard>

      {/* ── Jira Integration (mixed: base URL in JSON, credentials in .env) ── */}
      <SectionCard title="Jira Integration" icon="🐛">
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
          <Field label="Jira domain" hint="e.g. your-domain.atlassian.net (config.json)">
            <TextInput value={config.integrations.jira.baseUrl ?? ''} onChange={v => patchJiraBase(v)} placeholder="your-domain.atlassian.net" mono />
          </Field>
          <Field label="Email" hint=".env">
            <TextInput value={envStr('JIRA_EMAIL')} onChange={v => setEnv('JIRA_EMAIL', v)} placeholder="you@example.com" />
          </Field>
          <Field label="API token" hint=".env — create at id.atlassian.com → Security → API tokens">
            <TextInput value={envStr('JIRA_API_TOKEN')} onChange={v => setEnv('JIRA_API_TOKEN', v)} placeholder="…" type="password" mono />
          </Field>
        </div>
      </SectionCard>

      {/* ── Swagger ── */}
      <SectionCard title="Swagger / API Specs" icon="📄">
        <Field label="Swagger URLs" hint="Comma-separated list. Used for API endpoint selection in feature forms.">
          <TextInput
            value={config.integrations.swaggerUrls.join(', ')}
            onChange={patchSwagger}
            placeholder="https://petstore.swagger.io/v2/swagger.json, https://…"
            mono
          />
        </Field>
      </SectionCard>

      {/* ── General / Developer ── */}
      <SectionCard title="General" icon="🛠️">
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-x-8 gap-y-4">
          <Field label="Logging & debug">
            <div className="space-y-2">
              <Toggle checked={config.logging.logPrompts} onChange={v => patchLogging('logPrompts', v)} label="Log LLM prompts to console" />
              <Toggle checked={config.logging.debugLog} onChange={v => patchLogging('debugLog', v)} label="Write debug log file on startup (restart required)" />
              <Toggle checked={config.devMode} onChange={v => patchConfig('devMode', v)} label="Dev mode (restart required)" />
            </div>
          </Field>

          <Field label="Response caching" hint="Disk-cached LLM responses for faster dev iterations. (Restart required.)">
            <div className="space-y-2">
              <Toggle checked={config.cache.enabled} onChange={v => patchCache('enabled', v)} label="Cache LLM responses to disk" />
              <Toggle checked={config.cache.useCached} onChange={v => patchCache('useCached', v)} label="Use cached responses instead of calling LLM" />
            </div>
          </Field>

          <Field label="Currency conversion" hint="Approximate INR per 1 USD — used for cost display in the UI.">
            <TextInput value={String(config.cost.usdToInr)} onChange={v => setConfig(prev => prev ? { ...prev, cost: { usdToInr: parseFloat(v) || 0 } } : prev)} mono />
          </Field>
        </div>
      </SectionCard>

      {/* Bottom save bar */}
      <div className="sticky bottom-4 flex justify-end">
        <button
          type="button"
          onClick={handleSave}
          disabled={saving}
          className="flex items-center gap-2 px-6 py-3 bg-orange-500 text-white text-sm font-semibold rounded-xl hover:bg-orange-600 disabled:opacity-60 transition-all shadow-lg shadow-orange-200 cursor-pointer"
        >
          {saving ? (
            <>
              <span className="w-4 h-4 border-2 border-white/40 border-t-white rounded-full animate-spin" />
              Saving…
            </>
          ) : savedAt ? (
            <>
              <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" /></svg>
              Saved
            </>
          ) : 'Save configuration'}
        </button>
      </div>

    </div>
  );
}

function SubHeader({ children }: { children: React.ReactNode }) {
  return (
    <div className="flex items-center gap-2">
      <span className="text-xs font-semibold text-gray-700 uppercase tracking-wide">{children}</span>
      <span className="h-px flex-1 bg-gray-100" />
    </div>
  );
}

function RestartHint() {
  return (
    <span className="text-[10px] font-medium text-amber-600 bg-amber-50 border border-amber-100 px-2 py-0.5 rounded-full uppercase tracking-wide">
      Restart required
    </span>
  );
}
