import { useNavigate } from 'react-router-dom';
import { useActivator } from '../../../store/Context';
import { useStore } from '../../../store/state';
import type { FailedCaseEntry } from '../../../lib/dashboard';
import { formatRelative } from '../../../lib/dashboard';

interface Props {
  projectId: string;
  items: FailedCaseEntry[];
}

export default function FailedCasesTab({ projectId, items }: Props) {
  const navigate = useNavigate();
  const activator = useActivator();
  const setDefectDraft = useStore(s => s.setDefectDraft);

  if (items.length === 0) {
    return (
      <div className="p-8 text-center">
        <div className="text-green-600 text-2xl mb-1">✓</div>
        <p className="text-sm text-gray-600">No failed test cases in this project.</p>
      </div>
    );
  }

  const handleDraft = (e: React.MouseEvent, entry: FailedCaseEntry) => {
    e.stopPropagation();
    setDefectDraft({
      projectId: entry.projectId,
      moduleId: entry.moduleId,
      featureId: entry.featureId,
      runId: entry.runId,
      testCaseId: entry.testCaseId,
      status: 'drafting',
    });
    activator.draftDefect(entry.projectId, entry.moduleId, entry.featureId, entry.runId, entry.testCaseId);
  };

  const openRun = (entry: FailedCaseEntry) => {
    navigate(
      `/project/${entry.projectId}/module/${entry.moduleId}/feature/${entry.featureId}/history`,
    );
  };

  return (
    <div>
      <ul className="divide-y divide-gray-100">
        {items.map(entry => (
          <li
            key={`${entry.runId}-${entry.testCaseId}`}
            onClick={() => openRun(entry)}
            className="p-3 hover:bg-gray-50 cursor-pointer flex items-start gap-2 sm:gap-3"
          >
            <div className="flex-1 min-w-0">
              <div className="text-xs font-semibold text-gray-800 truncate">{entry.testCaseTitle}</div>
              <div className="text-[10px] text-gray-400 truncate">{entry.featureName}</div>
              {entry.failureMessage && (
                <p className="text-[11px] text-red-600 truncate mt-0.5">✗ {entry.failureMessage}</p>
              )}
              <div className="text-[10px] text-gray-400 mt-0.5">{formatRelative(entry.startedAt)}</div>
            </div>
            {entry.createdJiraKey ? (
              <span className="text-[10px] font-mono text-blue-700 px-2 py-0.5 rounded bg-blue-50 border border-blue-100 shrink-0">
                {entry.createdJiraKey}
              </span>
            ) : (
              <button
                onClick={e => handleDraft(e, entry)}
                className="px-2 py-1 text-[10px] font-semibold text-red-700 bg-red-50 border border-red-200 rounded hover:bg-red-100 shrink-0 focus:outline-none focus:ring-2 focus:ring-red-300"
              >
                Draft bug
              </button>
            )}
          </li>
        ))}
      </ul>
      <div className="border-t border-gray-100 p-2 text-center">
        <button
          onClick={() => navigate(`/project/${projectId}/traceability`)}
          className="text-xs font-semibold text-orange-600 hover:text-orange-700"
        >
          View all in Traceability →
        </button>
      </div>
    </div>
  );
}
