import classnames from 'classnames';
import { useEffect, useRef, useState } from 'react';
import type {
    ComparisonPlan,
    ComparisonState,
    ComparisonStateResult,
    ComparisonStep,
    ComparisonTestCase,
} from '../../../../activator/types/comparisonPlan';
import ComparisonStepDetailModal from './ComparisonStepDetailModal';
import ComparisonStepRow, { StepStatusIcon } from './ComparisonStepRow';

interface Props {
    plan: ComparisonPlan;
    /** Per-state list of AI-proposed test cases (live + completed). */
    testCasesByState: Record<string, ComparisonTestCase[]>;
    /** Per-state running/completed status flags from the engine. */
    stateProgress: Record<string, { label: string; status: 'running' | 'completed' }>;
    /** Final diffs per state, populated as each state completes. */
    stateResults: ComparisonStateResult[];
}

/**
 * Live test-execution-style stream for the comparison Run tab.
 *
 * Mirrors the regular test-execution UI: state sections contain test-case
 * cards (expand/collapse via chevron), each test case lists its steps as
 * single-line rows showing status + human-readable title + duration. Click
 * a step row to open a bottom-sheet modal with arguments, result, and
 * screenshot — never dump JSON inline. This keeps the page scannable even
 * when a run produces hundreds of steps.
 */
export default function ComparisonRunStream({ plan, testCasesByState, stateProgress, stateResults }: Props) {
    const [selectedStep, setSelectedStep] = useState<ComparisonStep | null>(null);

    const states: ComparisonState[] = plan.states.length > 0 ? plan.states : [{ id: 'default', label: 'Default' } as ComparisonState];

    return (
        <>
            <div className="space-y-4">
                {states.map((st) => {
                    const testCases = testCasesByState[st.id] ?? [];
                    const progress = stateProgress[st.id];
                    const result = stateResults.find((r) => r.stateId === st.id);
                    const matchCount = result ? result.diffs.filter((d) => d.verdict === 'match').length : 0;
                    const mismatchCount = result ? result.diffs.filter((d) => d.verdict === 'mismatch').length : 0;
                    return (
                        <StateSection
                            key={st.id}
                            stateLabel={st.label}
                            stateStatus={progress?.status ?? (result ? 'completed' : 'pending')}
                            testCases={testCases}
                            matchCount={matchCount}
                            mismatchCount={mismatchCount}
                            warnings={result?.warnings ?? []}
                            onStepClick={setSelectedStep}
                        />
                    );
                })}
                {states.every((st) => (testCasesByState[st.id]?.length ?? 0) === 0) && (
                    <div className="rounded-2xl border border-dashed border-gray-300 bg-gray-50 p-6 text-center text-sm text-gray-500">
                        The AI has not proposed any test cases yet. Browser sessions are launching and the AI is surveying each side — the
                        first test case usually appears within a few seconds.
                    </div>
                )}
            </div>

            {selectedStep && <ComparisonStepDetailModal step={selectedStep} onClose={() => setSelectedStep(null)} />}
        </>
    );
}

function StateSection({
    stateLabel,
    stateStatus,
    testCases,
    matchCount,
    mismatchCount,
    warnings,
    onStepClick,
}: {
    stateLabel: string;
    stateStatus: 'pending' | 'running' | 'completed';
    testCases: ComparisonTestCase[];
    matchCount: number;
    mismatchCount: number;
    warnings: string[];
    onStepClick: (step: ComparisonStep) => void;
}) {
    return (
        <section className="rounded-2xl border border-gray-200 bg-white overflow-hidden">
            <header
                className={classnames(
                    'flex items-center justify-between gap-3 px-4 py-2.5 border-b',
                    stateStatus === 'completed'
                        ? 'bg-green-50/60 border-green-200'
                        : stateStatus === 'running'
                          ? 'bg-orange-50/60 border-orange-200'
                          : 'bg-gray-50 border-gray-200',
                )}
            >
                <div className="flex items-center gap-2 min-w-0">
                    <span
                        className={classnames(
                            'inline-block w-2 h-2 rounded-full',
                            stateStatus === 'completed'
                                ? 'bg-green-500'
                                : stateStatus === 'running'
                                  ? 'bg-orange-500 animate-pulse'
                                  : 'bg-gray-300',
                        )}
                    />
                    <h3 className="text-sm font-semibold text-gray-800 truncate">{stateLabel}</h3>
                    <span className="text-[10px] uppercase font-semibold tracking-wide text-gray-500">{stateStatus}</span>
                </div>
                <div className="flex items-center gap-3 text-xs">
                    {matchCount > 0 && (
                        <span className="inline-flex items-center gap-1 text-green-700">
                            <span className="inline-block w-1.5 h-1.5 rounded-full bg-green-600" />
                            {matchCount} match
                        </span>
                    )}
                    {mismatchCount > 0 && (
                        <span className="inline-flex items-center gap-1 text-red-700">
                            <span className="inline-block w-1.5 h-1.5 rounded-full bg-red-600" />
                            {mismatchCount} mismatch
                        </span>
                    )}
                    <span className="text-gray-500">
                        {testCases.length} test case{testCases.length === 1 ? '' : 's'}
                    </span>
                </div>
            </header>
            <TestCaseScrollList testCases={testCases} onStepClick={onStepClick} />
            {warnings.length > 0 && (
                <div className="px-4 py-2 bg-orange-50 border-t border-orange-200 text-[11px] text-orange-700 space-y-0.5">
                    {warnings.map((w, i) => (
                        <div key={i}>⚠ {w}</div>
                    ))}
                </div>
            )}
        </section>
    );
}

/**
 * The scrollable list of test cases for one state. Keeps the scroll pinned to
 * the bottom while the user is already at the bottom — new test cases and
 * steps appear in view without the user chasing them. The moment the user
 * scrolls up to inspect earlier activity, stickiness disengages so we don't
 * yank them back down.
 */
function TestCaseScrollList({ testCases, onStepClick }: { testCases: ComparisonTestCase[]; onStepClick: (step: ComparisonStep) => void }) {
    const ref = useRef<HTMLDivElement | null>(null);
    const stickyRef = useRef(true);

    // Fingerprint of everything that grows as the run progresses — new cases,
    // new steps under existing cases, status flips. Triggers the stick-to-bottom
    // effect on each change.
    const activityStamp = testCases.map((tc) => `${tc.id}:${tc.status}:${tc.steps.length}`).join('|');

    const handleScroll = () => {
        const el = ref.current;
        if (!el) return;
        const distanceFromBottom = el.scrollHeight - el.scrollTop - el.clientHeight;
        stickyRef.current = distanceFromBottom < 32;
    };

    useEffect(() => {
        const el = ref.current;
        if (!el) return;
        if (stickyRef.current) el.scrollTop = el.scrollHeight;
    }, [activityStamp]);

    return (
        <div
            ref={ref}
            onScroll={handleScroll}
            className="divide-y divide-gray-100 overflow-y-auto"
            style={{ maxHeight: 'calc(100vh - 230px)', height: 'calc(100vh - 230px)' }}
        >
            {testCases.map((tc) => (
                <TestCaseCard key={tc.id} testCase={tc} onStepClick={onStepClick} />
            ))}
            {testCases.length === 0 && <p className="px-4 py-3 text-xs text-gray-400">No test cases yet for this state.</p>}
        </div>
    );
}

const TC_STATUS_BADGE: Record<ComparisonTestCase['status'], string> = {
    pending: 'bg-gray-200 text-gray-700',
    running: 'bg-orange-100 text-orange-700',
    passed: 'bg-green-100 text-green-700',
    failed: 'bg-red-100 text-red-700',
    skipped: 'bg-gray-100 text-gray-500',
};

function TestCaseCard({ testCase, onStepClick }: { testCase: ComparisonTestCase; onStepClick: (step: ComparisonStep) => void }) {
    // Auto-expand running and failed cases so the user sees activity / problems
    // immediately. Passed/skipped cases collapse — click to open.
    const [expanded, setExpanded] = useState<boolean>(testCase.status === 'running' || testCase.status === 'failed');
    const prevStatusRef = useRef<ComparisonTestCase['status']>(testCase.status);

    // When the test case transitions FROM running TO a terminal status, auto-collapse.
    // User can still click to expand again. `failed` cases auto-open and stay open
    // so issues are visible. Manual toggling is preserved — we only react to a
    // status transition event, not every render.
    useEffect(() => {
        const prev = prevStatusRef.current;
        if (prev !== testCase.status) {
            if (prev === 'running' && testCase.status === 'failed') {
                setExpanded(true);
            } else if (prev === 'running' && (testCase.status === 'passed' || testCase.status === 'skipped')) {
                setExpanded(false);
            }
            prevStatusRef.current = testCase.status;
        }
    }, [testCase.status]);

    return (
        <div className="px-4 py-3">
            <button
                type="button"
                onClick={() => setExpanded((v) => !v)}
                className="w-full flex items-center justify-between gap-3 text-left cursor-pointer group"
            >
                <div className="flex items-center gap-2 min-w-0 flex-1">
                    <TestCaseStatusDot status={testCase.status} />
                    <span className="text-sm font-semibold text-gray-800 truncate group-hover:text-orange-700 transition-colors">
                        {testCase.title}
                    </span>
                    <span
                        className={classnames(
                            'shrink-0 text-[10px] uppercase font-semibold tracking-wide px-1.5 py-0.5 rounded',
                            TC_STATUS_BADGE[testCase.status],
                        )}
                    >
                        {testCase.status}
                    </span>
                    <span className="shrink-0 text-[10px] text-gray-400">
                        {testCase.steps.length} step{testCase.steps.length === 1 ? '' : 's'}
                    </span>
                </div>
                <span className="text-xs text-gray-400 shrink-0">{expanded ? '▾' : '▸'}</span>
            </button>

            {/* Description / summary surface in the collapsed row footer too — they
          are short by contract (one or two lines) so they don't blow up the row. */}
            {testCase.description && <p className="text-xs text-gray-600 mt-1 ml-5">{testCase.description}</p>}
            {testCase.summary && testCase.status !== 'running' && (
                <p className="text-xs text-gray-500 italic mt-0.5 ml-5">{testCase.summary}</p>
            )}

            {expanded && testCase.steps.length > 0 && (
                <div className="mt-3 ml-5 space-y-1">
                    {testCase.steps.map((step, idx) => (
                        <ComparisonStepRow key={step.id} step={step} index={idx + 1} onClick={() => onStepClick(step)} />
                    ))}
                </div>
            )}
            {expanded && testCase.steps.length === 0 && (
                <p className="mt-3 ml-5 text-[11px] text-gray-400">Waiting for the AI to issue the first tool call...</p>
            )}
        </div>
    );
}

function TestCaseStatusDot({ status }: { status: ComparisonTestCase['status'] }) {
    if (status === 'running') return <StepStatusIcon status="running" />;
    if (status === 'failed') return <StepStatusIcon status="failed" />;
    if (status === 'passed') return <StepStatusIcon status="passed" />;
    // pending / skipped — neutral dot
    return <span className={classnames('inline-block w-2.5 h-2.5 rounded-full', status === 'skipped' ? 'bg-gray-400' : 'bg-gray-300')} />;
}
