import { useState } from 'react';
import { STRATEGY_CATALOG, type TestStrategy } from '../../../../activator/engine/strategyCatalog';

interface EditTestCaseFormProps {
  initialTitle: string;
  initialDescription: string;
  initialPriority: 'high' | 'medium' | 'low';
  initialStrategy?: string;
  onSave: (title: string, description: string, priority: 'high' | 'medium' | 'low', strategy: string | undefined) => void;
  onCancel: () => void;
}

export default function EditTestCaseForm({
  initialTitle,
  initialDescription,
  initialPriority,
  initialStrategy,
  onSave,
  onCancel,
}: EditTestCaseFormProps) {
  const [title, setTitle] = useState(initialTitle);
  const [description, setDescription] = useState(initialDescription);
  const [priority, setPriority] = useState(initialPriority);
  const [strategy, setStrategy] = useState(initialStrategy ?? '');

  return (
    <div className="bg-white rounded-lg border-2 border-orange-200 p-3 mb-1.5">
      <div className="space-y-2">
        <input
          value={title}
          onChange={e => setTitle(e.target.value)}
          className="w-full px-2 py-1.5 border border-gray-200 rounded text-xs focus:outline-none focus:ring-1 focus:ring-orange-300"
          autoFocus
        />
        <textarea
          value={description}
          onChange={e => setDescription(e.target.value)}
          className="w-full h-16 px-2 py-1.5 border border-gray-200 rounded text-xs resize-y focus:outline-none focus:ring-1 focus:ring-orange-300"
        />
        <div className="flex items-center gap-2 flex-wrap">
          <select
            value={priority}
            onChange={e => setPriority(e.target.value as 'high' | 'medium' | 'low')}
            className="px-2 py-1 border border-gray-200 rounded text-[11px]"
          >
            <option value="high">High</option>
            <option value="medium">Medium</option>
            <option value="low">Low</option>
          </select>
          <select
            value={strategy}
            onChange={e => setStrategy(e.target.value)}
            className="px-2 py-1 border border-gray-200 rounded text-[11px] flex-1 min-w-0"
          >
            <option value="">No strategy</option>
            {STRATEGY_CATALOG.map((s: TestStrategy) => (
              <option key={s.key} value={s.key}>{s.name}</option>
            ))}
          </select>
          <button
            onClick={() => onSave(title, description, priority, strategy || undefined)}
            disabled={!title.trim()}
            className="px-3 py-1 text-[11px] bg-orange-500 text-white rounded hover:bg-orange-600 disabled:opacity-40 font-medium"
          >
            Save
          </button>
          <button
            onClick={onCancel}
            className="px-3 py-1 text-[11px] bg-gray-100 text-gray-600 rounded hover:bg-gray-200"
          >
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
}
