import { useEffect, useRef } from 'react';
import Checkbox from '../Checkbox';
import { Item } from './types';

interface ItemListProps {
    items: Item[];
    selectedKeys: string[];
    onSelectionChange: (keys: string[]) => void;
    focusedIndex: number;
    onFocusChange: (index: number) => void;
}

const ItemList: React.FC<ItemListProps> = ({ items, selectedKeys, onSelectionChange, focusedIndex }) => {
    const itemRefs = useRef<(HTMLDivElement | null)[]>([]);

    useEffect(() => {
        if (focusedIndex >= 0 && focusedIndex < items.length) {
            itemRefs.current[focusedIndex]?.scrollIntoView({
                behavior: 'smooth',
                block: 'nearest',
            });
        }
    }, [focusedIndex, items.length]);

    const handleSelectionToggle = (key: string) => {
        const newSelection = selectedKeys.includes(key) ? selectedKeys.filter((k) => k !== key) : [...selectedKeys, key];
        onSelectionChange(newSelection);
    };

    const handleItemKeyDown = (e: React.KeyboardEvent, key: string) => {
        if (e.key === ' ') {
            e.preventDefault();
            handleSelectionToggle(key);
        }
    };

    return (
        <div className="flex-1 overflow-y-auto">
            {items.map((item, index) => (
                <div
                    key={item.key}
                    ref={(el: HTMLDivElement) => {
                        itemRefs.current[index] = el;
                    }}
                    className={`p-3 border-b border-gray-200 cursor-pointer hover:bg-gray-50 transition-colors ${
                        focusedIndex === index ? 'bg-blue-50' : ''
                    }`}
                    onClick={() => handleSelectionToggle(item.key)}
                    onKeyDown={(e) => handleItemKeyDown(e, item.key)}
                    tabIndex={0}
                >
                    <div className="flex items-start space-x-3">
                        <Checkbox
                            checked={selectedKeys.includes(item.key)}
                            onChange={() => handleSelectionToggle(item.key)}
                            focused={focusedIndex === index}
                        />
                        <div className="flex-1 min-w-0">
                            <div className="flex items-center space-x-2 mb-1">
                                <ActionBadge action={item.action} />
                                <VersionBadge version={item.version} />
                                <h3 className="text-sm font-medium text-gray-900 truncate">{item.summary}</h3>
                            </div>
                            <p className="text-sm text-gray-600 line-clamp-1 mb-1">{item.path}</p>
                            <p className="text-xs text-gray-500 line-clamp-2">{item.description}</p>
                        </div>
                    </div>
                </div>
            ))}
        </div>
    );
};

export default ItemList;

interface ActionBadgeProps {
    action: string;
}

const ActionBadge: React.FC<ActionBadgeProps> = ({ action }) => {
    const getActionColor = (action: string) => {
        switch (action) {
            case 'GET':
                return 'bg-green-100 text-green-800';
            case 'POST':
                return 'bg-blue-100 text-blue-800';
            case 'PUT':
                return 'bg-yellow-100 text-yellow-800';
            case 'PATCH':
                return 'bg-orange-100 text-orange-800';
            case 'DELETE':
                return 'bg-red-100 text-red-800';
            default:
                return 'bg-gray-100 text-gray-800';
        }
    };

    return <span className={`px-2 py-1 rounded text-xs font-medium ${getActionColor(action)}`}>{action}</span>;
};

interface VersionBadgeProps {
    version: string;
}

const VersionBadge: React.FC<VersionBadgeProps> = ({ version }) => {
    return <span className="px-2 py-1 rounded text-xs font-medium bg-purple-100 text-purple-800">v{version}</span>;
};
