import { useEffect, useMemo, useState } from 'react';
import { useStore } from '../store/state';
import { useActivator } from '../store/Context';
import type { ComparisonCriteria } from '../../activator/types/state';

/**
 * Prompts the user when the feature classifier thinks a freshly-
 * created or updated feature should switch to `type: 'comparison'`.
 *
 * Presents:
 *   - the classifier reasoning and confidence
 *   - the proposed old / new URLs extracted from the description (editable)
 *   - Accept → updates the feature with type=comparison + a minimal
 *     comparisonConfig seeded from the extracted URLs
 *   - Dismiss → clears the pending state without mutating anything
 */
export default function FeatureClassificationModal() {
  const activator = useActivator();
  const pending = useStore(s => s.pendingClassification);
  const setPending = useStore(s => s.setPendingClassification);
  const projects = useStore(s => s.projects);

  const feature = useMemo(() => {
    if (!pending) return null;
    const p = projects.find(x => x.id === pending.projectId);
    const m = p?.modules.find(x => x.id === pending.moduleId);
    return m?.features.find(x => x.id === pending.featureId) ?? null;
  }, [pending, projects]);

  const [oldUrl, setOldUrl] = useState('');
  const [newUrl, setNewUrl] = useState('');

  useEffect(() => {
    if (pending) {
      setOldUrl(pending.classification.extractedOldUrl ?? '');
      setNewUrl(pending.classification.extractedNewUrl ?? '');
    }
  }, [pending]);

  if (!pending || !feature) return null;

  const dismiss = () => {
    setPending(null);
  };

  const accept = () => {
    const criteria: ComparisonCriteria[] = ['fields', 'labels', 'data', 'functionality'];
    activator.updateFeature(pending.projectId, pending.moduleId, pending.featureId, {
      type: 'comparison',
      comparisonConfig: (oldUrl.trim() && newUrl.trim())
        ? {
            oldUrl: oldUrl.trim(),
            newUrl: newUrl.trim(),
            scope: 'full_page',
            criteria,
          }
        : undefined,
    });
    dismiss();
  };

  const confidencePct = Math.round(pending.classification.confidence * 100);

  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-xl overflow-hidden">
        <div className="px-5 py-4 border-b border-gray-100">
          <h3 className="text-base font-semibold text-gray-800">Is this a comparison feature?</h3>
          <p className="text-xs text-gray-500 mt-0.5">
            The classifier thinks <span className="font-semibold text-gray-700">{feature.name}</span> looks like a screen-to-screen diff.
          </p>
        </div>
        <div className="px-5 py-4 space-y-3">
          <div className="rounded-lg border border-blue-100 bg-blue-50 p-3 text-xs text-blue-900">
            <div className="font-semibold mb-1">Classifier confidence: {confidencePct}%</div>
            <div>{pending.classification.reasoning}</div>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
            <div>
              <label className="block text-xs text-gray-500 mb-1">Old URL (baseline)</label>
              <input
                value={oldUrl}
                onChange={e => setOldUrl(e.target.value)}
                placeholder="https://old.example.com/..."
                className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-300"
              />
            </div>
            <div>
              <label className="block text-xs text-gray-500 mb-1">New URL (to compare)</label>
              <input
                value={newUrl}
                onChange={e => setNewUrl(e.target.value)}
                placeholder="https://new.example.com/..."
                className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-300"
              />
            </div>
          </div>
          <p className="text-[11px] text-gray-400">
            Leave URLs blank if you would rather configure the comparison later.
          </p>
        </div>
        <div className="flex items-center justify-end gap-2 px-5 py-3 border-t border-gray-100 bg-gray-50">
          <button
            onClick={dismiss}
            className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-100"
          >
            Keep as functional
          </button>
          <button
            onClick={accept}
            className="px-4 py-1.5 text-xs font-semibold bg-orange-500 text-white rounded-lg hover:bg-orange-600"
          >
            Switch to comparison
          </button>
        </div>
      </div>
    </div>
  );
}
