import { useEffect, useMemo, useState } from 'react';
import { useStore } from '../../../store/state';
import { useActivator } from '../../../store/Context';
import type { ComparisonRun, ComparisonRunSummary } from '../../../../activator/types/comparisonPlan';

interface Props {
  projectId: string;
  moduleId: string;
  featureId?: string;
}

/**
 * Scoped history of past comparison runs. Shows up to 20 per scope (module,
 * or feature when featureId is present). Entries can be opened for a detailed
 * read-only view, downloaded as Markdown, or deleted with confirmation.
 */
export default function ComparisonHistoryView({ projectId, moduleId, featureId }: Props) {
  const scopeKey = `${projectId}:${moduleId}:${featureId ?? ''}`;
  const scopedHistory = useStore((s) => s.comparisonV2HistoryByScope[scopeKey]);
  const projects = useStore((s) => s.projects);
  const loadedRuns = useStore((s) => s.comparisonV2LoadedRuns);
  const activator = useActivator();
  const [expandedRunId, setExpandedRunId] = useState<string | null>(null);
  const [confirmDeleteId, setConfirmDeleteId] = useState<string | null>(null);

  // Prefer the live scope cache; fall back to whatever is embedded in the
  // state-synced project/module/feature so the list appears on first mount
  // without waiting for a dedicated broadcast.
  const history: ComparisonRunSummary[] = useMemo(() => {
    if (scopedHistory) return scopedHistory;
    const project = projects.find((p) => p.id === projectId);
    const mod = project?.modules.find((m) => m.id === moduleId);
    if (featureId) {
      const feature = mod?.features.find((f) => f.id === featureId);
      return feature?.comparisonHistory ?? [];
    }
    return mod?.comparisonHistory ?? [];
  }, [scopedHistory, projects, projectId, moduleId, featureId]);

  useEffect(() => {
    if (!expandedRunId) return;
    if (loadedRuns[expandedRunId]) return;
    const requestId = `cmpload_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`;
    activator.loadComparisonV2RunDetail(requestId, expandedRunId);
  }, [expandedRunId, loadedRuns, activator]);

  const handleDelete = (runId: string) => {
    if (confirmDeleteId !== runId) {
      setConfirmDeleteId(runId);
      return;
    }
    activator.deleteComparisonV2Run(projectId, moduleId, featureId, runId);
    setConfirmDeleteId(null);
    if (expandedRunId === runId) setExpandedRunId(null);
  };

  if (history.length === 0) {
    return (
      <div className="rounded-2xl border border-dashed border-gray-300 bg-gray-50 p-6 text-center text-sm text-gray-500">
        No past comparison runs. Once you run a comparison, the last 20 runs for this scope show up here for review and download.
      </div>
    );
  }

  return (
    <div className="space-y-3">
      <p className="text-xs text-gray-500">
        Last {history.length} comparison run{history.length === 1 ? '' : 's'} for this {featureId ? 'feature' : 'module'}. The oldest
        rolls off automatically when the 20-run cap is hit.
      </p>
      {history.map((entry) => {
        const expanded = expandedRunId === entry.id;
        const detail = loadedRuns[entry.id];
        return (
          <div key={entry.id} className="rounded-2xl border border-gray-200 bg-white overflow-hidden">
            <button
              type="button"
              onClick={() => setExpandedRunId(expanded ? null : entry.id)}
              className="w-full flex items-center justify-between gap-3 px-4 py-3 cursor-pointer hover:bg-gray-50 text-left"
            >
              <div className="flex items-center gap-3 min-w-0">
                <span
                  className={`px-1.5 py-0.5 rounded text-[10px] uppercase font-semibold text-white ${
                    entry.status === 'passed' ? 'bg-green-600' : entry.status === 'failed' ? 'bg-red-600' : 'bg-gray-500'
                  }`}
                >
                  {entry.status}
                </span>
                <div className="min-w-0">
                  <p className="text-sm font-semibold text-gray-800 truncate">{entry.planTitle || entry.planId}</p>
                  <p className="text-[11px] text-gray-500 truncate">
                    {new Date(entry.startedAt).toLocaleString()} · {entry.totalStates} state{entry.totalStates === 1 ? '' : 's'} ·{' '}
                    {entry.totalTestCases} test case{entry.totalTestCases === 1 ? '' : 's'} · {entry.mismatchCount} mismatch
                    {entry.mismatchCount === 1 ? '' : 'es'}
                    {entry.sideLabels.length > 0 && <> · {entry.sideLabels.join(' vs ')}</>}
                  </p>
                </div>
              </div>
              <div className="flex items-center gap-2 shrink-0">
                <span
                  onClick={(e) => {
                    e.stopPropagation();
                    activator.downloadComparisonV2Report(entry.id);
                  }}
                  className="text-[11px] font-semibold text-orange-600 hover:text-orange-700 cursor-pointer"
                  title="Download Markdown report"
                >
                  ⤓ Report
                </span>
                <span
                  onClick={(e) => {
                    e.stopPropagation();
                    handleDelete(entry.id);
                  }}
                  className={`text-[11px] font-semibold cursor-pointer ${
                    confirmDeleteId === entry.id ? 'text-red-800 underline' : 'text-red-600 hover:text-red-700'
                  }`}
                  title={confirmDeleteId === entry.id ? 'Click again to confirm' : 'Delete this run'}
                >
                  {confirmDeleteId === entry.id ? 'Confirm delete' : 'Delete'}
                </span>
                <span className="text-xs text-gray-400">{expanded ? '▾' : '▸'}</span>
              </div>
            </button>
            {expanded && (
              <div className="px-4 pb-4 border-t border-gray-100">
                {!detail && <p className="text-xs text-gray-500 mt-3">Loading run details…</p>}
                {detail && <RunDetail run={detail} />}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

function RunDetail({ run }: { run: ComparisonRun }) {
  return (
    <div className="space-y-3 pt-3 text-xs">
      {run.stateResults.map((sr) => (
        <div key={sr.stateId} className="border border-gray-200 rounded-lg p-3">
          <div className="flex items-center gap-2 mb-2">
            <span className="text-sm font-semibold text-gray-800">{sr.stateLabel}</span>
            <span
              className={`px-1.5 py-0.5 rounded text-[10px] uppercase font-semibold text-white ${
                sr.status === 'passed' ? 'bg-green-600' : sr.status === 'failed' ? 'bg-red-600' : 'bg-gray-500'
              }`}
            >
              {sr.status}
            </span>
            <span className="text-[11px] text-gray-500">
              {sr.testCases.length} test case{sr.testCases.length === 1 ? '' : 's'} · {sr.diffs.length} diff
              {sr.diffs.length === 1 ? '' : 's'}
            </span>
          </div>
          {sr.diffs.length > 0 && (
            <div className="space-y-1">
              {sr.diffs.map((d, i) => (
                <div
                  key={`${sr.stateId}-${i}`}
                  className={`rounded border px-2 py-1.5 ${
                    d.verdict === 'match' ? 'border-green-200 bg-green-50/50' : 'border-red-200 bg-red-50/50'
                  }`}
                >
                  <span className="font-semibold">{d.kind.replace('_diff', '')}</span> — {d.summary}
                </div>
              ))}
            </div>
          )}
          {sr.testCases.length > 0 && (
            <details className="mt-2">
              <summary className="cursor-pointer text-gray-600 hover:text-gray-800">Test cases</summary>
              <ul className="mt-1.5 space-y-1 ml-3">
                {sr.testCases.map((tc) => (
                  <li key={tc.id}>
                    <span
                      className={`px-1 py-0.5 rounded text-[10px] uppercase ${
                        tc.status === 'passed'
                          ? 'bg-green-100 text-green-700'
                          : tc.status === 'failed'
                            ? 'bg-red-100 text-red-700'
                            : 'bg-gray-100 text-gray-600'
                      }`}
                    >
                      {tc.status}
                    </span>{' '}
                    {tc.title}
                    {tc.summary && <span className="text-gray-500 ml-2">— {tc.summary}</span>}
                  </li>
                ))}
              </ul>
            </details>
          )}
        </div>
      ))}
    </div>
  );
}
