import { createContext, useContext } from 'react';
import ActivatorProxy from './ActivatorProxy';
import { handleServerMessage } from './messageHandler';

/**
 * The singleton proxy instance and its React context live in this plain .ts
 * file (not .tsx) so `@vitejs/plugin-react`'s fast-refresh boundary detector
 * does not see a mixed component/non-component export in the same module,
 * which is the condition that triggers the `$RefreshSig$ is not defined`
 * runtime error with vite 8 + plugin-react 6.
 */
export const proxyInstance = new ActivatorProxy(handleServerMessage);

export const AppContext = createContext<ActivatorProxy>(null!);

export const useActivator = (): ActivatorProxy => useContext(AppContext);
