import { useEffect, useMemo, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useStore } from '../../store/state';
import { buildProjectDashboard } from '../../lib/dashboard';
import DashboardHeader from './DashboardHeader';
import DashboardEmpty from './DashboardEmpty';
import SummaryStrip from './SummaryStrip';
import ModuleStrip from './ModuleStrip';
import AttentionPanel from './AttentionPanel';
import ActivityFeed from './ActivityFeed';
import NoModulesGuide from './NoModulesGuide';

export default function Dashboard() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();

  const projects = useStore(s => s.projects);
  const comparisons = useStore(s => s.comparisons);
  const session = useStore(s => s.session);

  const sortedProjects = useMemo(
    () => [...projects].sort((a, b) => (a.updatedAt < b.updatedAt ? 1 : -1)),
    [projects],
  );

  const resolvedId = id ?? sortedProjects[0]?.id ?? null;
  const selected = sortedProjects.find(p => p.id === resolvedId) ?? null;

  const [initialAttentionTab, setInitialAttentionTab] = useState<'failed' | 'gaps' | 'risks' | undefined>();

  useEffect(() => {
    if (!id && sortedProjects.length > 0) {
      navigate(`/project/${sortedProjects[0].id}`, { replace: true });
    }
  }, [id, sortedProjects, navigate]);

  const dashboard = useMemo(() => {
    if (!selected) return null;
    return buildProjectDashboard(selected, comparisons, session);
  }, [selected, comparisons, session]);

  if (projects.length === 0) return <DashboardEmpty />;
  if (!selected || !dashboard) return null;

  const jumpToGaps = () => {
    setInitialAttentionTab('gaps');
    document.getElementById('dashboard-attention')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  };

  return (
    <div className="w-full px-2 sm:px-4 py-3 sm:py-6">
      <DashboardHeader
        projects={sortedProjects}
        selected={selected}
        browserConnected={session.browserConnected}
      />

      {dashboard.summary.totalModules === 0 ? (
        <NoModulesGuide projectId={selected.id} projectName={selected.name} />
      ) : (
        <>
          <div className="mb-4 sm:mb-5">
            <SummaryStrip summary={dashboard.summary} onJumpToGaps={jumpToGaps} />
          </div>

          <div className="mb-4 sm:mb-5">
            <ModuleStrip
              projectId={selected.id}
              modules={dashboard.modules}
              onAddModule={() => navigate(`/project/${selected.id}/manage?add=1`)}
            />
          </div>

          <div className="grid grid-cols-1 xl:grid-cols-3 gap-4 sm:gap-5">
            <div className="xl:col-span-2 min-w-0">
              <AttentionPanel
                projectId={selected.id}
                attention={dashboard.attention}
                initialTab={initialAttentionTab}
              />
            </div>
            <div className="min-w-0">
              <ActivityFeed
                projectId={selected.id}
                activity={dashboard.activity}
                live={dashboard.live}
                projectName={selected.name}
              />
            </div>
          </div>
        </>
      )}
    </div>
  );
}
