import classNames from 'classnames';
import React, { KeyboardEvent, useCallback, useEffect, useLayoutEffect, useRef, useState } from 'react';
import { createPortal } from 'react-dom';

type Item<T> = {
    iconUrl?: string;
    value: T;
    label: string;
};

type PopoverPlacement = 'bottom-left' | 'bottom-right' | 'top-left' | 'top-right';

type MultiSelectAutocompleteProps<T> = {
    onChange: (items: Item<T>[]) => void;
    onSearch: (text: string) => Promise<Item<T>[]>;
    placeholder?: string;
    value: Item<T>[];
    id?: string;
    disabled?: boolean;
    maxSelectedItems?: number;
    placement?: PopoverPlacement;
    label?: string;
};

function isEqualValue<T>(a: T, b: T): boolean {
    try {
        return JSON.stringify(a) === JSON.stringify(b);
    } catch {
        return a === b;
    }
}

function valueExists<T>(arr: Item<T>[], value: T) {
    return arr.some((item) => isEqualValue(item.value, value));
}

function getNextIndex(current: number, max: number, direction: 1 | -1 = 1): number {
    if (max === 0) return -1;
    let next = current + direction;
    if (next >= max) next = 0;
    if (next < 0) next = max - 1;
    return next;
}

function useClickOutside(ref: React.RefObject<HTMLElement>, handler: (evt: MouseEvent | TouchEvent) => void, attached = true) {
    useEffect(() => {
        if (!attached) return;
        const listener = (event: MouseEvent | TouchEvent) => {
            if (!ref.current || ref.current.contains(event.target as Node)) return;
            handler(event);
        };
        document.addEventListener('mousedown', listener);
        document.addEventListener('touchstart', listener);
        return () => {
            document.removeEventListener('mousedown', listener);
            document.removeEventListener('touchstart', listener);
        };
    }, [ref, handler, attached]);
}

function useWindowResize(handler: () => void, active = true) {
    useEffect(() => {
        if (!active) return;
        window.addEventListener('resize', handler);
        return () => {
            window.removeEventListener('resize', handler);
        };
    }, [handler, active]);
}

type PopoverProps = {
    anchorRect: DOMRect | null;
    visible: boolean;
    children: React.ReactNode;
};

const Popover: React.FC<PopoverProps> = ({ anchorRect, visible, children }) => {
    const el = useRef<HTMLDivElement>(null);
    const [position, setPosition] = useState<{ top: number; left: number }>({
        top: 0,
        left: 0,
    });

    const calcPosition = useCallback(() => {
        if (!anchorRect || !el.current) return;
        const viewportW = window.innerWidth;
        const viewportH = window.innerHeight;
        const popoverRect = el.current.getBoundingClientRect();

        const spaces = {
            bottom: viewportH - anchorRect.bottom,
            top: anchorRect.top,
            left: anchorRect.left,
            right: viewportW - anchorRect.right,
        };

        let top = 0,
            left = 0;

        if (spaces.bottom >= popoverRect.height) {
            // place bottom
            top = anchorRect.bottom + window.scrollY;
            if (spaces.right >= popoverRect.width) {
                left = anchorRect.left + window.scrollX;
            } else if (spaces.left >= popoverRect.width) {
                left = anchorRect.right - popoverRect.width + window.scrollX;
            } else {
                left = anchorRect.left + window.scrollX;
            }
        } else if (spaces.top >= popoverRect.height) {
            // place top
            top = anchorRect.top - popoverRect.height + window.scrollY;
            if (spaces.right >= popoverRect.width) {
                left = anchorRect.left + window.scrollX;
            } else if (spaces.left >= popoverRect.width) {
                left = anchorRect.right - popoverRect.width + window.scrollX;
            } else {
                left = anchorRect.left + window.scrollX;
            }
        } else {
            // fallback bottom-left
            top = anchorRect.bottom + window.scrollY;
            left = anchorRect.left + window.scrollX;
        }
        setPosition({ top, left });
    }, [anchorRect]);

    useLayoutEffect(() => {
        if (visible) {
            calcPosition();
        }
    }, [visible, calcPosition]);

    useWindowResize(() => {
        if (visible) {
            calcPosition();
        }
    }, visible);

    const portalRoot = document.body;

    if (!visible) return null;
    return createPortal(
        <div
            ref={el}
            className="absolute z-[5000] max-h-[300px] overflow-y-auto bg-white dark:bg-gray-800 rounded-[6px] border border-gray-300 shadow-lg"
            style={{
                top: position.top,
                left: position.left,
                minWidth: anchorRect?.width ?? 200,
            }}
            role="listbox"
            tabIndex={-1}
        >
            {children}
        </div>,
        portalRoot,
    );
};

const RemoveIcon: React.FC<{ onClick: () => void }> = ({ onClick }) => (
    <button
        type="button"
        onClick={onClick}
        className="ml-1 text-gray-500 dark:text-gray-300 hover:text-gray-700 dark:hover:text-gray-200 focus:outline-none focus:ring-1 focus:ring-gray-400 rounded cursor-pointer"
        aria-label="Remove item"
    >
        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" viewBox="0 0 20 20" fill="currentColor" aria-hidden="true">
            <path
                fillRule="evenodd"
                d="M6.293 6.293a1 1 0 011.414 0L10 8.586l2.293-2.293a1 1 0 111.414 1.414L11.414 10l2.293 2.293a1 1 0 01-1.414 1.414L10 11.414l-2.293 2.293a1 1 0 01-1.414-1.414L8.586 10 6.293 7.707a1 1 0 010-1.414z"
                clipRule="evenodd"
            />
        </svg>
    </button>
);

const Tag = <T extends any>({ item, onRemove }: { item: Item<T>; onRemove: () => void }) => (
    <div className="flex items-center bg-blue-100 dark:bg-gray-900 text-blue-800 dark:text-blue-100 rounded px-2 py-0.5 mr-2 mb-1 select-none text-sm">
        {!!item.iconUrl && <img src={item.iconUrl} className="size-5 me-2" />}
        <span className="truncate max-w-xs">{item.label}</span>
        <RemoveIcon onClick={onRemove} />
    </div>
);

function normalizeItems<T>(remote: Item<T>[], localItems: Item<T>[]): Item<T>[] {
    if (localItems.length === 0) return remote;
    const unique = remote.filter((i) => !valueExists(localItems, i.value));
    return unique;
}

function MultiSelectAutocomplete<T>({
    onChange,
    onSearch,
    placeholder,
    value,
    id,
    disabled = false,
    maxSelectedItems,
    label,
}: MultiSelectAutocompleteProps<T>) {
    const ctrlRef = useRef<HTMLDivElement>(null!);
    const inputRef = useRef<HTMLInputElement>(null);
    const [inputValue, setInputValue] = useState('');
    const [focusedIndex, setFocusedIndex] = useState(-1);
    const [open, setOpen] = useState(false);
    const [searchResult, setSearchResult] = useState<Item<T>[]>([]);
    const [loading, setLoading] = useState(false);
    const focusedItemRef = useRef<HTMLElement | null>(null);

    const mergedSelected = value || [];

    const canSelectMore = maxSelectedItems === undefined || mergedSelected.length < maxSelectedItems;

    const displayedItems = normalizeItems(searchResult, mergedSelected);

    const onOutsideClick = useCallback(() => {
        setOpen(false);
        setFocusedIndex(-1);
    }, []);

    useClickOutside(
        ctrlRef,
        () => {
            onOutsideClick();
        },
        open,
    );

    useEffect(() => {
        if (!open) {
            setInputValue('');
            setSearchResult([]);
            setFocusedIndex(-1);
        }
    }, [open]);

    useEffect(() => {
        if (!open) return;
        let active = true;
        const query = inputValue.trim();
        if (query === '') {
            setSearchResult([]);
            setLoading(false);
            return;
        }
        setLoading(true);
        onSearch(query)
            .then((res) => {
                if (!active) return;
                setSearchResult(res);
                setLoading(false);
                setFocusedIndex(res.length > 0 ? 0 : -1);
            })
            .catch(() => {
                if (!active) return;
                setSearchResult([]);
                setLoading(false);
                setFocusedIndex(-1);
            });
        return () => {
            active = false;
        };
    }, [inputValue, onSearch, open]);

    const onKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
        if (!open) {
            if (e.key === 'ArrowDown' || e.key === 'ArrowUp' || e.key === 'Enter') {
                e.preventDefault();
                setOpen(true);
            }
            return;
        }
        if (e.key === 'ArrowDown') {
            e.preventDefault();
            if (displayedItems.length === 0) return;
            setFocusedIndex((idx) => getNextIndex(idx, displayedItems.length, 1));
        } else if (e.key === 'ArrowUp') {
            e.preventDefault();
            if (displayedItems.length === 0) return;
            setFocusedIndex((idx) => getNextIndex(idx, displayedItems.length, -1));
        } else if (e.key === 'Enter' || e.key === 'Tab') {
            if (focusedIndex >= 0 && focusedIndex < displayedItems.length) {
                e.preventDefault();
                selectItem(displayedItems[focusedIndex]);
            } else if (e.key === 'Enter' && displayedItems.length === 1 && focusedIndex === -1) {
                e.preventDefault();
                selectItem(displayedItems[0]);
            }
        } else if (e.key === 'Backspace') {
            if (inputValue === '' && mergedSelected.length > 0) {
                // remove last item on backspace
                e.preventDefault();
                removeItem(mergedSelected[mergedSelected.length - 1]);
            }
        } else if (e.key === 'Escape') {
            setOpen(false);
            setFocusedIndex(-1);
        }
    };

    const selectItem = (item: Item<T>) => {
        if (disabled) return;
        if (!canSelectMore) return;
        if (valueExists(mergedSelected, item.value)) return;
        const updated = [...mergedSelected, item];
        onChange(updated);
        setInputValue('');
        setFocusedIndex(-1);
    };

    const removeItem = (item: Item<T>) => {
        if (disabled) return;
        const updated = mergedSelected.filter((v) => !isEqualValue(v.value, item.value));
        onChange(updated);
    };

    useEffect(() => {
        if (focusedItemRef.current && focusedItemRef.current.scrollIntoView && open) {
            focusedItemRef.current.scrollIntoView({
                block: 'nearest',
            });
        }
    }, [focusedIndex, open]);

    const listboxId = id ? `${id}-listbox` : undefined;
    const inputId = id ? `${id}-input` : undefined;

    return (
        <div className="mb-4">
            <label className="mb-1.5 block text-sm font-small text-gray-700">{label}</label>
            <div
                ref={ctrlRef}
                className={classNames(
                    'relative border border-gray-300 rounded px-2 py-1 flex flex-wrap items-center min-h-[38px] gap-1 cursor-text',
                    disabled ? 'bg-gray-100 dark:bg-gray-700 cursor-not-allowed' : 'bg-white dark:bg-gray-800',
                    'focus-within:ring-2 focus-within:ring-blue-500 focus-within:outline-none',
                )}
                onClick={() => {
                    if (!disabled) {
                        setOpen(true);
                        inputRef.current?.focus();
                    }
                }}
                aria-haspopup="listbox"
                aria-owns={listboxId}
                aria-expanded={open}
                role="combobox"
                tabIndex={-1}
                id={id}
            >
                {mergedSelected.map((item) => (
                    <Tag key={JSON.stringify(item.value)} item={item} onRemove={() => removeItem(item)} />
                ))}

                <input
                    ref={inputRef}
                    id={inputId}
                    className={classNames(
                        'flex-grow min-w-[100px] border-none outline-none bg-transparent p-0 m-0 text-gray-900 dark:text-gray-200',
                        disabled && 'cursor-not-allowed',
                    )}
                    disabled={disabled || !canSelectMore}
                    placeholder={mergedSelected.length === 0 ? placeholder : undefined}
                    value={inputValue}
                    onChange={(e) => {
                        setInputValue(e.target.value);
                        setOpen(true);
                    }}
                    onKeyDown={onKeyDown}
                    aria-autocomplete="list"
                    aria-controls={listboxId}
                    aria-activedescendant={focusedIndex >= 0 && displayedItems[focusedIndex] ? `${id}-option-${focusedIndex}` : undefined}
                    spellCheck={false}
                    autoComplete="off"
                    role="textbox"
                    autoCorrect="off"
                    autoCapitalize="off"
                />
            </div>

            <Popover anchorRect={ctrlRef.current?.getBoundingClientRect() ?? null} visible={open && (displayedItems.length > 0 || loading)}>
                <ul
                    id={listboxId}
                    role="listbox"
                    className="max-h-72 overflow-auto"
                    style={{ outline: 'none' }}
                    tabIndex={-1}
                    aria-multiselectable="true"
                >
                    {loading && (
                        <li className="p-2 text-center text-gray-500 text-sm select-none" aria-live="polite">
                            Searching...
                        </li>
                    )}
                    {!loading && displayedItems.length === 0 && (
                        <li className="p-2 text-center text-gray-400 text-sm select-none" aria-live="polite">
                            No results
                        </li>
                    )}
                    {!loading &&
                        displayedItems.map((item, idx) => (
                            <li
                                key={JSON.stringify(item.value)}
                                id={`${id}-option-${idx}`}
                                role="option"
                                aria-selected={focusedIndex === idx}
                                ref={(el) => {
                                    if (focusedIndex === idx) {
                                        focusedItemRef.current = el;
                                    }
                                    if (focusedIndex !== idx && focusedItemRef.current === el) {
                                        focusedItemRef.current = null;
                                    }
                                }}
                                onMouseEnter={() => setFocusedIndex(idx)}
                                onMouseDown={(e) => {
                                    e.preventDefault();
                                    selectItem(item);
                                }}
                                className={classNames(
                                    'cursor-pointer px-3 py-2 truncate flex',
                                    focusedIndex === idx ? 'bg-blue-600 text-white' : 'text-gray-900 dark:text-gray-200 hover:bg-blue-100',
                                )}
                            >
                                {!!item.iconUrl && <img src={item.iconUrl} className="size-5 me-2" />}
                                <span>{item.label}</span>
                            </li>
                        ))}
                </ul>
            </Popover>
        </div>
    );
}

export default MultiSelectAutocomplete;
