import { useCallback, useEffect, useState } from 'react';
import MultiSelectAutocomplete from '../../../components/inputs/MultiSelectAutocomplete';
import SwaggerMultiSelectDropdown from '../../../components/inputs/swagger-multiselect';
import InputWrapper from '../../../components/inputs/InputWrapper';
import StrategyPicker from '../../../components/StrategyPicker';
import type { FeatureMode, JiraTicketRef, SwaggerApiRef } from '../../../../activator/types/state';

export interface FeatureFormValue {
  name: string;
  description: string;
  jiraTickets: JiraTicketRef[];
  swaggerApis: SwaggerApiRef[];
  strategyOverride?: string[];
  mode?: FeatureMode;
}

interface FeatureFormProps {
  initial?: Partial<FeatureFormValue>;
  showNameField?: boolean;
  /** Show the AI-vs-Manual mode picker. Creation forms should enable this; edit forms should hide it. */
  showModeField?: boolean;
  submitLabel: string;
  submitClassName?: string;
  onSubmit: (value: FeatureFormValue) => void;
  onCancel?: () => void;
  onDirtyChange?: (dirty: boolean) => void;
  /** Project default strategies — shown as inherited hint when feature has no override. */
  projectDefaultStrategies?: string[];
  secondaryAction?: {
    label: string;
    onSubmit: (value: FeatureFormValue) => void;
    disabled?: boolean;
    className?: string;
  };
  tertiaryAction?: {
    label: string;
    onSubmit: (value: FeatureFormValue) => void;
    disabled?: boolean;
    className?: string;
  };
}

type TicketOption = { value: string; label: string; iconUrl?: string };

export default function FeatureForm({
  initial,
  showNameField = true,
  showModeField = false,
  submitLabel,
  submitClassName,
  onSubmit,
  onCancel,
  onDirtyChange,
  projectDefaultStrategies,
  secondaryAction,
  tertiaryAction,
}: FeatureFormProps) {
  const seedStrategies = (override?: string[]) =>
    (override && override.length > 0) ? override : (projectDefaultStrategies || []);

  const [name, setName] = useState(initial?.name || '');
  const [description, setDescription] = useState(initial?.description || '');
  const [mode, setMode] = useState<FeatureMode>(initial?.mode ?? 'ai');
  const [tickets, setTickets] = useState<TicketOption[]>(
    (initial?.jiraTickets || []).map(t => ({
      value: t.key,
      label: `${t.key} - ${t.summary}`,
      iconUrl: t.iconUrl,
    })),
  );
  const [swaggerApis, setSwaggerApis] = useState<SwaggerApiRef[]>(initial?.swaggerApis || []);
  const [strategyOverride, setStrategyOverride] = useState<string[]>(seedStrategies(initial?.strategyOverride));
  const [apiList, setApiList] = useState<any[]>();
  const [dirty, setDirty] = useState(false);

  const markDirty = () => {
    if (!dirty) {
      setDirty(true);
      onDirtyChange?.(true);
    }
  };

  useEffect(() => {
    setName(initial?.name || '');
    setDescription(initial?.description || '');
    setTickets(
      (initial?.jiraTickets || []).map(t => ({
        value: t.key,
        label: `${t.key} - ${t.summary}`,
        iconUrl: t.iconUrl,
      })),
    );
    setSwaggerApis(initial?.swaggerApis || []);
    setStrategyOverride(seedStrategies(initial?.strategyOverride));
    setDirty(false);
    onDirtyChange?.(false);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [initial?.name, initial?.description]);

  const loadApis = useCallback(async () => {
    const list = await fetch('/api/swagger/picker').then(r => r.json()).catch(() => []);
    setApiList(list);
    return list;
  }, []);

  useEffect(() => { loadApis(); }, [loadApis]);

  const searchApis = useCallback(async (searchText: string) => {
    let list = apiList;
    if (!list) list = await loadApis();
    if (!list?.length) return [];
    const q = searchText?.toLowerCase();
    return list.filter(
      (s: any) =>
        s.summary?.toLowerCase().includes(q) ||
        s.description?.toLowerCase().includes(q) ||
        s.path?.toLowerCase().includes(q),
    );
  }, [apiList, loadApis]);

  const searchTickets = async (text: string) => {
    try {
      const response = await fetch('/api/issues/picker?query=' + encodeURIComponent(text)).then(r => r.json());
      return response.map((j: any) => ({ value: j.key, label: `${j.key} - ${j.summaryText}`, iconUrl: j.img }));
    } catch {
      return [];
    }
  };

  const buildValue = (): FeatureFormValue => ({
    name: name.trim(),
    description: description.trim(),
    jiraTickets: tickets.map(t => ({
      key: t.value,
      summary: t.label.replace(/^[^ ]+ - /, ''),
      iconUrl: t.iconUrl,
    })),
    swaggerApis,
    strategyOverride: strategyOverride.length > 0 ? strategyOverride : undefined,
    mode: showModeField ? mode : undefined,
  });

  const handleSubmit = () => onSubmit(buildValue());
  const handleSecondary = () => secondaryAction?.onSubmit(buildValue());
  const handleTertiary = () => tertiaryAction?.onSubmit(buildValue());

  const canSubmit = showNameField ? name.trim().length > 0 : true;

  return (
    <div className="space-y-4">
      {showNameField && (
        <div>
          <label className="block text-xs text-gray-500 mb-1">Name *</label>
          <input
            value={name}
            onChange={e => { setName(e.target.value); markDirty(); }}
            className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-300"
            placeholder="e.g., User Registration, Login, Password Reset"
            autoFocus
          />
        </div>
      )}

      {showModeField && (
        <div>
          <label className="block text-xs text-gray-500 mb-1">Authoring mode *</label>
          <div className="grid grid-cols-2 gap-2" role="radiogroup" aria-label="Feature authoring mode">
            <button
              type="button"
              role="radio"
              aria-checked={mode === 'ai'}
              onClick={() => { setMode('ai'); markDirty(); }}
              className={`text-left px-3 py-2 rounded-lg border transition ${
                mode === 'ai'
                  ? 'border-orange-400 bg-orange-50 ring-2 ring-orange-200'
                  : 'border-gray-200 bg-white hover:border-gray-300'
              }`}
            >
              <div className="text-sm font-semibold text-gray-800">AI Automation</div>
              <div className="text-[11px] text-gray-500 mt-0.5">The AI generates test cases and drives the browser from live screenshots + a11y tree.</div>
            </button>
            <button
              type="button"
              role="radio"
              aria-checked={mode === 'manual'}
              onClick={() => { setMode('manual'); markDirty(); }}
              className={`text-left px-3 py-2 rounded-lg border transition ${
                mode === 'manual'
                  ? 'border-orange-400 bg-orange-50 ring-2 ring-orange-200'
                  : 'border-gray-200 bg-white hover:border-gray-300'
              }`}
            >
              <div className="text-sm font-semibold text-gray-800">Manual Automation</div>
              <div className="text-[11px] text-gray-500 mt-0.5">You author each step declaratively with the element picker + selector workbench, CSV loops, guards.</div>
            </button>
          </div>
          <div className="text-[11px] text-gray-400 mt-1">Mode is fixed at creation. You can convert later from the feature settings, but it archives existing testcases.</div>
        </div>
      )}

      <div>
        <MultiSelectAutocomplete
          label="Jira Stories / Tasks / Bugs"
          onSearch={searchTickets}
          value={tickets}
          onChange={(v: any[]) => { setTickets(v); markDirty(); }}
        />
      </div>

      <InputWrapper label="API Endpoints (Swagger)">
        <SwaggerMultiSelectDropdown
          onSearch={searchApis}
          allItems={apiList || []}
          value={swaggerApis.map(a => a.key)}
          placeholder="Select API endpoints for field-level validations"
          onChange={(keys) => {
            const items = (apiList || []).filter((i: any) => keys.includes(i.key));
            setSwaggerApis(items.map((i: any) => ({ key: i.key, method: i.action || '', path: i.path || '', summary: i.summary })));
            markDirty();
          }}
        />
      </InputWrapper>

      <div>
        <label className="block text-sm font-medium text-gray-700 mb-1">
          Description / Test Scenarios
        </label>
        <textarea
          value={description}
          onChange={e => { setDescription(e.target.value); markDirty(); }}
          rows={5}
          className="w-full px-3 py-2 border border-gray-300 rounded-md text-sm resize-y"
          placeholder="Describe the specific scenarios to test, expected behaviors, edge cases, validation rules..."
        />
      </div>

      <StrategyPicker
        label="Strategy override (optional)"
        helper="Leave empty to inherit from the project defaults. Select to pin a specific subset on this feature."
        value={strategyOverride}
        onChange={(v) => { setStrategyOverride(v); markDirty(); }}
        inheritedFrom={projectDefaultStrategies}
      />

      <div className="flex flex-wrap gap-2 pt-2 border-t border-gray-100">
        <button
          onClick={handleSubmit}
          disabled={!canSubmit}
          className={submitClassName || 'px-4 py-2 bg-orange-500 text-white rounded-md text-sm font-medium hover:bg-orange-600 disabled:opacity-40 transition cursor-pointer'}
        >
          {submitLabel}
        </button>
        {onCancel && (
          <button
            onClick={onCancel}
            className="px-4 py-2 bg-gray-100 text-gray-600 rounded-md text-sm font-medium hover:bg-gray-200 transition cursor-pointer"
          >
            Cancel
          </button>
        )}
        {secondaryAction && (
          <button
            onClick={handleSecondary}
            disabled={secondaryAction.disabled}
            className={secondaryAction.className || 'px-4 py-2 bg-orange-500 text-white rounded-md text-sm font-medium hover:bg-orange-600 disabled:opacity-40 transition cursor-pointer'}
          >
            {secondaryAction.label}
          </button>
        )}
        {tertiaryAction && (
          <button
            onClick={handleTertiary}
            disabled={tertiaryAction.disabled || !canSubmit}
            className={tertiaryAction.className || 'px-4 py-2 bg-white text-gray-700 border border-gray-200 rounded-md text-sm font-medium hover:bg-gray-50 disabled:opacity-40 transition cursor-pointer'}
          >
            {tertiaryAction.label}
          </button>
        )}
      </div>
    </div>
  );
}
