import { useState } from 'react';
import StrategyPicker from './StrategyPicker';

interface Props {
  open: boolean;
  title?: string;
  subtitle?: string;
  initialStrategies: string[];
  inheritedFrom?: string[];
  confirmLabel?: string;
  onCancel: () => void;
  onConfirm: (strategies: string[]) => void;
}

export default function StrategyChooserDialog({
  open,
  title = 'Choose strategies for this generation',
  subtitle = 'Tweak without saving — the changes only apply to this one run.',
  initialStrategies,
  inheritedFrom,
  confirmLabel = 'Generate',
  onCancel,
  onConfirm,
}: Props) {
  const [strategies, setStrategies] = useState<string[]>(initialStrategies);

  if (!open) return null;

  return (
    <div className="fixed inset-0 bg-black/40 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-2xl shadow-xl w-full max-w-2xl max-h-[90vh] flex flex-col overflow-hidden">
        <div className="px-5 py-4 border-b border-gray-100">
          <h3 className="text-base font-semibold text-gray-800">{title}</h3>
          {subtitle && <p className="text-xs text-gray-500 mt-0.5">{subtitle}</p>}
        </div>
        <div className="flex-1 min-h-0 overflow-y-auto overflow-x-hidden px-5 py-4">
          <StrategyPicker
            value={strategies}
            onChange={setStrategies}
            inheritedFrom={inheritedFrom}
          />
        </div>
        <div className="flex items-center justify-end gap-2 px-5 py-3 border-t border-gray-100 bg-gray-50">
          <button
            onClick={onCancel}
            className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-100 cursor-pointer"
          >
            Cancel
          </button>
          <button
            onClick={() => onConfirm(strategies)}
            disabled={strategies.length === 0}
            className="px-4 py-1.5 text-xs font-semibold bg-orange-500 text-white rounded-lg hover:bg-orange-600 disabled:opacity-50 cursor-pointer"
          >
            {confirmLabel}
          </button>
        </div>
      </div>
    </div>
  );
}
