import { passRateTone } from '../../lib/dashboard';

interface Props {
  passRate: number | null;
  size?: number;
  stroke?: number;
  label?: string;
}

export default function PassRateRing({ passRate, size = 88, stroke = 8, label }: Props) {
  const tone = passRateTone(passRate);
  const radius = (size - stroke) / 2;
  const circ = 2 * Math.PI * radius;
  const pct = passRate === null ? 0 : Math.max(0, Math.min(1, passRate));
  const offset = circ * (1 - pct);

  const ringColor =
    passRate === null
      ? '#e5e7eb'
      : passRate >= 0.8
        ? '#16a34a'
        : passRate >= 0.5
          ? '#d97706'
          : '#dc2626';

  const text = passRate === null ? '—' : `${Math.round(pct * 100)}%`;

  return (
    <div className={`relative inline-flex items-center justify-center rounded-full ${tone.bg}`} style={{ width: size, height: size }}>
      <svg width={size} height={size} className="-rotate-90">
        <circle cx={size / 2} cy={size / 2} r={radius} stroke="#f3f4f6" strokeWidth={stroke} fill="none" />
        <circle
          cx={size / 2}
          cy={size / 2}
          r={radius}
          stroke={ringColor}
          strokeWidth={stroke}
          strokeLinecap="round"
          strokeDasharray={circ}
          strokeDashoffset={offset}
          fill="none"
        />
      </svg>
      <div className="absolute inset-0 flex flex-col items-center justify-center">
        <span className={`text-lg font-bold ${tone.text}`}>{text}</span>
        {label && <span className="text-[10px] uppercase tracking-wide text-gray-400">{label}</span>}
      </div>
    </div>
  );
}
