import { useState } from 'react';
import type { Fixture, LoopBinding, ManualStep, TestCase } from '../../../../activator/types/state';
import type ActivatorProxy from '../../../store/ActivatorProxy';
import { DeleteIcon, PlusCircleIcon } from '../../../styles/Icons';

interface Props {
  testCase: TestCase;
  fixtures: Fixture[];
  activator: ActivatorProxy;
  projectId: string;
  featureId: string;
}

/**
 * Loop-binding authoring (REQUIREMENTS.md §5.1). A loop binds a contiguous
 * range of steps to exactly one fixture. Outer loops multiply with inner
 * loops. We intentionally allow any range combination — overlap validation
 * is a runtime concern handled by the executor.
 */
export default function LoopBindingsPanel({
  testCase,
  fixtures,
  activator,
  projectId,
  featureId,
}: Props) {
  const [adding, setAdding] = useState(false);

  const steps = testCase.manualSteps ?? [];
  const loops = testCase.loopBindings ?? [];

  if (steps.length === 0) {
    return null;
  }

  const removeBinding = (id: string) => {
    activator.deleteLoopBinding(projectId, featureId, testCase.id, id);
  };

  return (
    <div className="border-t border-gray-100 bg-white px-3 py-2">
      <div className="flex items-center justify-between mb-1.5">
        <h4 className="text-[9px] uppercase tracking-wider text-gray-500 font-semibold">
          Loops ({loops.filter((l) => l.fixtureId).length})
        </h4>
        <button
          type="button"
          onClick={() => setAdding(true)}
          className="px-1.5 py-0.5 text-[9px] font-medium text-gray-600 border border-dashed border-gray-300 rounded hover:bg-gray-50"
        >
          <PlusCircleIcon className="w-3 h-3 inline-block mr-0.5" /> add loop
        </button>
      </div>
      {loops.filter((l) => l.fixtureId).length === 0 && !adding && (
        <p className="text-[10px] text-gray-400 italic">
          Bind a range of steps to a fixture to run them once per row.
        </p>
      )}
      <ul className="space-y-1">
        {loops.filter((l) => l.fixtureId).map((binding) => (
          <li key={binding.id}>
            <LoopRow
              binding={binding}
              steps={steps}
              fixtures={fixtures}
              onChange={(next) =>
                activator.bindLoop(projectId, featureId, testCase.id, next)
              }
              onRemove={() => removeBinding(binding.id)}
            />
          </li>
        ))}
      </ul>
      {adding && (
        <LoopAddForm
          steps={steps}
          fixtures={fixtures}
          onCancel={() => setAdding(false)}
          onCommit={(binding) => {
            activator.bindLoop(projectId, featureId, testCase.id, binding);
            setAdding(false);
          }}
        />
      )}
    </div>
  );
}

function LoopRow({
  binding,
  steps,
  fixtures,
  onChange,
  onRemove,
}: {
  binding: LoopBinding;
  steps: ManualStep[];
  fixtures: Fixture[];
  onChange: (next: LoopBinding) => void;
  onRemove: () => void;
}) {
  const fixture = fixtures.find((f) => f.id === binding.fixtureId);
  return (
    <div className="rounded border border-gray-200 bg-gray-50/70 px-2 py-1 text-[10px]">
      <div className="flex flex-wrap items-center gap-1.5">
        <span className="font-mono text-gray-500">loop</span>
        <StepSelect
          value={binding.fromStepId}
          steps={steps}
          onChange={(id) => onChange({ ...binding, fromStepId: id })}
          ariaLabel="First step in loop"
        />
        <span className="text-gray-400">→</span>
        <StepSelect
          value={binding.toStepId}
          steps={steps}
          onChange={(id) => onChange({ ...binding, toStepId: id })}
          ariaLabel="Last step in loop"
        />
        <select
          value={binding.fixtureId}
          onChange={(e) => onChange({ ...binding, fixtureId: e.target.value })}
          className="px-1 py-0.5 border border-gray-200 rounded text-[10px] flex-1 min-w-0"
          aria-label="Fixture"
        >
          {fixtures.map((f) => (
            <option key={f.id} value={f.id}>
              {f.filename}
            </option>
          ))}
        </select>
        <button
          type="button"
          onClick={onRemove}
          className="p-0.5 text-gray-400 hover:text-red-600"
          aria-label="Remove loop"
          title="Remove loop"
        >
          <DeleteIcon className="w-3 h-3" />
        </button>
      </div>
      <div className="flex flex-wrap items-center gap-1.5 mt-1">
        <input
          value={binding.rowFilter ?? ''}
          onChange={(e) => onChange({ ...binding, rowFilter: e.target.value || undefined })}
          placeholder={`Row filter (optional, e.g. ${fixture?.columns[0]?.name ?? 'col'} == "x")`}
          className="flex-1 min-w-0 px-1.5 py-0.5 border border-gray-200 rounded text-[10px]"
          aria-label="Row filter"
        />
        <label className="inline-flex items-center gap-1 text-[9px] text-gray-600 whitespace-nowrap">
          <input
            type="checkbox"
            checked={!!binding.stopOnFirstRowFailure}
            onChange={(e) =>
              onChange({ ...binding, stopOnFirstRowFailure: e.target.checked || undefined })
            }
            className="accent-orange-500"
          />
          stop on first row failure
        </label>
      </div>
    </div>
  );
}

function LoopAddForm({
  steps,
  fixtures,
  onCancel,
  onCommit,
}: {
  steps: ManualStep[];
  fixtures: Fixture[];
  onCancel: () => void;
  onCommit: (binding: LoopBinding) => void;
}) {
  const [fromId, setFromId] = useState(steps[0]?.id ?? '');
  const [toId, setToId] = useState(steps[steps.length - 1]?.id ?? '');
  const [fixtureId, setFixtureId] = useState(fixtures[0]?.id ?? '');

  const canCommit = fromId && toId && fixtureId;

  return (
    <div className="mt-2 rounded border border-gray-200 bg-white p-2">
      <div className="text-[9px] uppercase tracking-wider text-gray-500 font-semibold mb-1">
        New loop
      </div>
      <div className="flex flex-wrap items-center gap-1.5 mb-1.5">
        <StepSelect value={fromId} steps={steps} onChange={setFromId} ariaLabel="From step" />
        <span className="text-[10px] text-gray-400">→</span>
        <StepSelect value={toId} steps={steps} onChange={setToId} ariaLabel="To step" />
        <select
          value={fixtureId}
          onChange={(e) => setFixtureId(e.target.value)}
          className="px-1 py-0.5 border border-gray-200 rounded text-[10px] flex-1 min-w-0"
          aria-label="Fixture"
        >
          {fixtures.length === 0 ? (
            <option value="">No fixtures available</option>
          ) : (
            fixtures.map((f) => (
              <option key={f.id} value={f.id}>
                {f.filename}
              </option>
            ))
          )}
        </select>
      </div>
      <div className="flex items-center gap-1.5">
        <button
          type="button"
          disabled={!canCommit}
          onClick={() => {
            onCommit({
              id: `loop_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
              fixtureId,
              fromStepId: fromId,
              toStepId: toId,
            });
          }}
          className="px-2 py-0.5 text-[10px] font-semibold bg-orange-500 text-white rounded hover:bg-orange-600 disabled:opacity-40"
        >
          Create
        </button>
        <button
          type="button"
          onClick={onCancel}
          className="px-2 py-0.5 text-[10px] bg-gray-100 text-gray-600 rounded hover:bg-gray-200"
        >
          Cancel
        </button>
      </div>
    </div>
  );
}

function StepSelect({
  value,
  steps,
  onChange,
  ariaLabel,
}: {
  value: string;
  steps: ManualStep[];
  onChange: (id: string) => void;
  ariaLabel: string;
}) {
  return (
    <select
      value={value}
      onChange={(e) => onChange(e.target.value)}
      className="px-1 py-0.5 border border-gray-200 rounded text-[10px] max-w-[35%] truncate"
      aria-label={ariaLabel}
    >
      {steps.map((s, i) => (
        <option key={s.id} value={s.id}>
          {i + 1}. {s.title || s.toolName}
        </option>
      ))}
    </select>
  );
}
