import { useParams } from 'react-router-dom';
import { useStore } from '../../store/state';
import TraceabilityMatrix from './TraceabilityMatrix';

export default function ProjectTraceability() {
  const { projectId } = useParams<{ projectId: string }>();
  const project = useStore(s => s.projects.find(p => p.id === projectId));

  if (!project) {
    return (
      <div className="w-full px-4 py-8">
        <div className="rounded-2xl border border-gray-200 bg-white p-8 text-center text-gray-500">Project not found</div>
      </div>
    );
  }

  return (
    <TraceabilityMatrix
      projectId={project.id}
      title={`Traceability — ${project.name}`}
      subtitle="Jira story → Feature → Test case → Latest run → Findings"
      backTo={`/project/${project.id}`}
    />
  );
}
