import { useEffect, useState } from 'react';
import type { ProjectDashboard } from '../../lib/dashboard';
import FailedCasesTab from './attention/FailedCasesTab';
import CoverageGapsTab from './attention/CoverageGapsTab';
import HighPriorityRisksTab from './attention/HighPriorityRisksTab';

type TabKey = 'failed' | 'gaps' | 'risks';

interface Props {
  projectId: string;
  attention: ProjectDashboard['attention'];
  initialTab?: TabKey;
}

function pickDefault(attention: ProjectDashboard['attention']): TabKey {
  if (attention.failedCases.length > 0) return 'failed';
  if (attention.coverageGaps.length > 0) return 'gaps';
  if (attention.highPriorityRisks.length > 0) return 'risks';
  return 'failed';
}

export default function AttentionPanel({ projectId, attention, initialTab }: Props) {
  const [tab, setTab] = useState<TabKey>(initialTab ?? pickDefault(attention));

  useEffect(() => {
    if (initialTab) setTab(initialTab);
  }, [initialTab]);

  const tabs: Array<{ key: TabKey; shortLabel: string; longLabel: string; count: number }> = [
    { key: 'failed', shortLabel: 'Failed', longLabel: 'Failed test cases', count: attention.failedCases.length },
    { key: 'gaps', shortLabel: 'Gaps', longLabel: 'Coverage gaps', count: attention.coverageGaps.length },
    {
      key: 'risks',
      shortLabel: 'High-priority',
      longLabel: 'High-priority test cases without a passing run',
      count: attention.highPriorityRisks.length,
    },
  ];

  return (
    <div id="dashboard-attention" className="rounded-2xl border border-gray-200 bg-white overflow-hidden">
      <div className="flex items-center border-b border-gray-200 overflow-x-auto">
        {tabs.map(t => {
          const active = tab === t.key;
          return (
            <button
              key={t.key}
              onClick={() => setTab(t.key)}
              className={`px-3 sm:px-4 py-2.5 sm:py-3 text-[11px] sm:text-xs font-semibold whitespace-nowrap transition border-b-2 focus:outline-none ${
                active
                  ? 'border-orange-500 text-orange-600'
                  : 'border-transparent text-gray-500 hover:text-gray-800'
              }`}
              title={t.longLabel}
            >
              <span className="md:hidden">{t.shortLabel}</span>
              <span className="hidden md:inline">{t.longLabel}</span>
              <span
                className={`ml-1.5 sm:ml-2 px-1.5 py-0.5 rounded-full text-[10px] ${
                  active ? 'bg-orange-100 text-orange-700' : 'bg-gray-100 text-gray-500'
                }`}
              >
                {t.count}
              </span>
            </button>
          );
        })}
      </div>
      {tab === 'failed' && <FailedCasesTab projectId={projectId} items={attention.failedCases} />}
      {tab === 'gaps' && <CoverageGapsTab projectId={projectId} items={attention.coverageGaps} />}
      {tab === 'risks' && <HighPriorityRisksTab projectId={projectId} items={attention.highPriorityRisks} />}
    </div>
  );
}
