import { useEffect, useRef, useState } from 'react';
import { STRATEGY_CATALOG, DEFAULT_PROJECT_STRATEGIES } from '../../activator/engine/strategyCatalog';

interface TooltipProps {
  children: React.ReactNode;
  visible: boolean;
  wide?: boolean;
}

function Tooltip({ children, visible, wide = false }: TooltipProps) {
  return (
    <div
      className={`
        absolute left-6 top-1/2 -translate-y-1/2 z-50
        ${wide ? 'w-80' : 'w-64'}
        rounded-xl border border-gray-100 bg-white shadow-xl ring-1 ring-black/5
        p-3 text-[11px] text-gray-600 leading-relaxed
        pointer-events-none select-none
        transition-all duration-200 ease-out
        ${visible ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-1'}
      `}
    >
      {/* Arrow */}
      <div className="absolute -left-1.5 top-1/2 -translate-y-1/2 w-3 h-3 bg-white border-l border-t border-gray-100 -rotate-45 shadow-[-1px_-1px_0_0_rgb(243,244,246)]" />
      {children}
    </div>
  );
}

interface Props {
  label?: string;
  helper?: string;
  value: string[];
  onChange: (next: string[]) => void;
  inheritedFrom?: string[];
  showResetToDefaults?: boolean;
}

/**
 * Shared multi-select for the fixed test strategy catalog. Referenced by:
 *  - project settings form (defaultStrategies)
 *  - feature form (strategyOverride)
 *  - test-case generation dialog (strategiesOverride — per-run)
 */
export default function StrategyPicker({
  label = 'Test strategies',
  helper,
  value,
  onChange,
  inheritedFrom,
  showResetToDefaults,
}: Props) {
  const [activeTooltip, setActiveTooltip] = useState<string | null>(null);
  const hideTimer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const show = (key: string) => {
    if (hideTimer.current) clearTimeout(hideTimer.current);
    setActiveTooltip(key);
  };

  const hide = () => {
    hideTimer.current = setTimeout(() => setActiveTooltip(null), 80);
  };

  useEffect(() => () => { if (hideTimer.current) clearTimeout(hideTimer.current); }, []);

  const toggle = (key: string) => {
    onChange(value.includes(key) ? value.filter(k => k !== key) : [...value, key]);
  };

  return (
    <div>
      <div className="flex items-center justify-between mb-1">
        <div className="flex items-center gap-1.5">
          <label className="block text-xs text-gray-500">{label}</label>

          {/* Label-level tooltip — what does strategy override do? */}
          <div className="relative inline-flex items-center">
            <button
              type="button"
              className={`
                w-4 h-4 rounded-full text-[10px] font-bold flex items-center justify-center
                transition-all duration-150 focus:outline-none focus:ring-2 focus:ring-orange-300
                ${activeTooltip === '__label__'
                  ? 'bg-orange-500 text-white shadow-md shadow-orange-200'
                  : 'bg-gray-200 text-gray-500 hover:bg-orange-100 hover:text-orange-600'}
              `}
              onMouseEnter={() => show('__label__')}
              onMouseLeave={hide}
              onFocus={() => show('__label__')}
              onBlur={hide}
              aria-label="What is strategy override?"
            >
              ?
            </button>
            <Tooltip visible={activeTooltip === '__label__'} wide>
              <p className="font-semibold text-gray-800 mb-1.5 text-[12px]">What is Strategy override?</p>
              <p className="text-gray-600">
                Each feature inherits the project-level strategies by default. Selecting strategies here
                {' '}<span className="font-semibold text-orange-600">overrides</span>{' '}
                those defaults for this feature only — the AI generates test cases using exactly these strategies.
              </p>
              <div className="mt-2 rounded-lg bg-orange-50 border border-orange-100 px-2.5 py-2">
                <span className="font-semibold text-orange-700">Example:</span>
                <span className="text-gray-600"> Project default is Smoke + Negative. Your Payment feature can override to add Security + Boundary Value without affecting any other feature.</span>
              </div>
              <p className="mt-2 text-gray-400 italic">Leave empty to inherit from project defaults.</p>
            </Tooltip>
          </div>
        </div>

        {showResetToDefaults && (
          <button
            type="button"
            onClick={() => onChange(DEFAULT_PROJECT_STRATEGIES as unknown as string[])}
            className="text-[11px] text-orange-600 hover:text-orange-700 transition-colors"
          >
            Reset to defaults
          </button>
        )}
      </div>

      {helper && <p className="text-[11px] text-gray-400 mb-2">{helper}</p>}

      <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
        {STRATEGY_CATALOG.map(s => (
          <label
            key={s.key}
            className={`
              flex items-start gap-2 p-2 rounded-lg border cursor-pointer
              transition-all duration-150
              ${value.includes(s.key)
                ? 'border-orange-400 bg-orange-50 shadow-sm shadow-orange-100'
                : 'border-gray-200 bg-white hover:border-gray-300 hover:shadow-sm'}
            `}
          >
            <input
              type="checkbox"
              checked={value.includes(s.key)}
              onChange={() => toggle(s.key)}
              className="accent-orange-500 mt-0.5"
            />
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-1">
                <span className="text-xs font-semibold text-gray-800">{s.name}</span>

                {/* Per-item tooltip — concrete example */}
                <div className="relative inline-flex items-center shrink-0">
                  <button
                    type="button"
                    className={`
                      w-3.5 h-3.5 rounded-full text-[9px] font-bold flex items-center justify-center
                      transition-all duration-150 focus:outline-none
                      ${activeTooltip === s.key
                        ? 'bg-orange-400 text-white shadow-sm shadow-orange-200 scale-110'
                        : 'bg-gray-100 text-gray-400 hover:bg-orange-100 hover:text-orange-500 hover:scale-110'}
                    `}
                    onMouseEnter={() => show(s.key)}
                    onMouseLeave={hide}
                    onFocus={() => show(s.key)}
                    onBlur={hide}
                    onClick={e => e.preventDefault()}
                    aria-label={`Example for ${s.name}`}
                  >
                    ?
                  </button>
                  <Tooltip visible={activeTooltip === s.key}>
                    <p className="font-semibold text-gray-800 mb-1 text-[12px]">{s.name}</p>
                    <p className="text-gray-600">{s.example}</p>
                  </Tooltip>
                </div>
              </div>
              <p className="text-[11px] text-gray-500 leading-snug">{s.description}</p>
            </div>
          </label>
        ))}
      </div>

      {inheritedFrom && inheritedFrom.length > 0 && value.length === 0 && (
        <p className="mt-2 text-[11px] text-gray-400">
          Using inherited defaults: {inheritedFrom.join(', ')}
        </p>
      )}
    </div>
  );
}
