import { create } from 'zustand';
import type { AppState, ElementTreeNode, ExecutionStatus, Feature, Fixture, Module, Project, RecordedStep, SelectorCandidate, TestCase } from '../../activator/types/state';
import type { DefectDraftPayload, FeedbackRequestPayload } from '../../activator/types/protocol';
import type { ComparisonRun, ComparisonRunSummary, ComparisonStateResult, ComparisonStep, ComparisonTestCase } from '../../activator/types/comparisonPlan';

export interface DefectDraftState {
  projectId: string;
  moduleId: string;
  featureId: string;
  runId: string;
  testCaseId: string;
  status: 'drafting' | 'ready' | 'submitting' | 'submitted' | 'failed';
  draft?: DefectDraftPayload;
  error?: string;
  submittedJiraKey?: string;
}

export interface ApprovalRequest {
  requestId: string;
  toolName: string;
  description: string;
  target: string;
  reason: string;
}

export interface SecurityWarningItem {
  toolName: string;
  target: string;
  reason: string;
  autoApproveSource: string;
}

interface UIState extends AppState {
  // UI-specific state
  connected: boolean;
  generatingTestCases: boolean;
  generatingTestPlan: { projectId: string; moduleId: string } | null;
  testPlanError: string | null;
  generatingSummaryReport: { projectId: string; moduleId: string } | null;
  summaryReportError: string | null;
  defectDraft: DefectDraftState | null;
  pendingClassification: {
    projectId: string;
    moduleId: string;
    featureId: string;
    classification: import('../../activator/types/state').FeatureClassification;
  } | null;
  pickerStatus: 'idle' | 'launching' | 'waiting' | 'picked' | 'cancelled' | 'error';
  lastPickerResult: {
    sessionId?: string;
    xpath: string;
    url: string;
    candidates?: SelectorCandidate[];
    tree?: ElementTreeNode;
  } | null;
  pickerError: string | null;
  fixtures: Fixture[];
  brokenConsumersPrompt: {
    fixtureId: string;
    consumers: Array<{ projectId: string; featureId: string; testCaseId: string; stepId?: string }>;
  } | null;
  proposedManualSteps: Array<{
    projectId: string;
    featureId: string;
    testCaseId: string;
    step: import('../../activator/types/state').ManualStep;
    source: 'nl' | 'refine';
  }>;
  lastScreenshot: string | null;
  pendingApproval: ApprovalRequest | null;
  pendingFeedback: FeedbackRequestPayload | null;
  /** In-flight / recently completed v2 comparison run, keyed by runId. */
  comparisonV2Run: ComparisonRun | null;
  /** Per-state progress updates arriving during a v2 run. */
  comparisonV2StateProgress: Record<string, { label: string; status: 'running' | 'completed' }>;
  /** Any run-level error surfaced from the activator (launch failure, unhandled exception). */
  comparisonV2RunError: string | null;
  /** True when the user has clicked Stop and the engine is winding down. Cleared when the run completes. */
  comparisonV2Stopping: boolean;
  /** True while the engine is paused. Flipped by `comparisonV2Paused` / `comparisonV2Resumed`. */
  comparisonV2Paused: boolean;
  /**
   * Live diffs broadcast as each compare_* tool finishes — keyed by stateId.
   * The per-state list is additive during the run; at state-completion the
   * stateResults on `comparisonV2Run` subsumes them, but during the run this
   * lets the Diffs panel fill up as the AI discovers mismatches.
   */
  comparisonV2LiveDiffs: Record<string, Array<{ kind: 'table_diff' | 'form_diff' | 'chart_diff' | 'section_diff' | 'style_diff'; verdict: 'match' | 'mismatch'; summary: string; artifactKey: string }>>;
  /**
   * Per-scope comparison history summaries. Key is `${projectId}:${moduleId}:${featureId ?? ''}`.
   * Populated on `comparisonV2HistoryUpdated`, and lazily on state sync via `refreshComparisonV2History`.
   */
  comparisonV2HistoryByScope: Record<string, ComparisonRunSummary[]>;
  /** When the user opens a past run, the loaded detail is cached here keyed by runId. */
  comparisonV2LoadedRuns: Record<string, ComparisonRun>;
  /**
   * Live, per-state list of AI-proposed test cases. Streamed in via
   * `comparisonV2TestCaseProposed` / `comparisonV2StepExecuted` so the UI
   * shows test cases and their steps the moment the AI emits them — without
   * waiting for the state-completed message that arrives at the end.
   */
  comparisonV2TestCasesByState: Record<string, ComparisonTestCase[]>;
  manualPause: {
    projectId: string;
    featureId: string;
    testCaseId: string;
    stepId: string;
    message?: string;
  } | null;
  securityWarnings: SecurityWarningItem[];
  generatedCode: { framework: string; code: string } | null;
  liveTokenUsage: Array<{ purpose: string; model: string; inputTokens: number; outputTokens: number; cost: number; calls: number }> | null;

  // Actions — state sync
  setFullState: (state: AppState) => void;
  setConnected: (connected: boolean) => void;
  setGeneratingTestCases: (generating: boolean) => void;
  setGeneratingTestPlan: (v: { projectId: string; moduleId: string } | null) => void;
  setTestPlanError: (err: string | null) => void;
  setGeneratingSummaryReport: (v: { projectId: string; moduleId: string } | null) => void;
  setSummaryReportError: (err: string | null) => void;
  setDefectDraft: (state: DefectDraftState | null) => void;
  updateDefectDraft: (patch: Partial<DefectDraftState>) => void;
  setPendingClassification: (v: UIState['pendingClassification']) => void;
  setPickerStatus: (s: 'idle' | 'launching' | 'waiting' | 'picked' | 'cancelled' | 'error') => void;
  setLastPickerResult: (r: UIState['lastPickerResult']) => void;
  setPickerError: (err: string | null) => void;
  setFixtures: (fixtures: Fixture[]) => void;
  upsertFixture: (fixture: Fixture) => void;
  removeFixture: (fixtureId: string) => void;
  setBrokenConsumersPrompt: (p: UIState['brokenConsumersPrompt']) => void;
  addProposedManualStep: (p: UIState['proposedManualSteps'][number]) => void;
  clearProposedManualStep: (testCaseId: string) => void;
  setLastScreenshot: (screenshot: string | null) => void;
  setPendingApproval: (request: ApprovalRequest | null) => void;
  setPendingFeedback: (request: FeedbackRequestPayload | null) => void;
  setComparisonV2Run: (run: ComparisonRun | null) => void;
  setComparisonV2StateProgress: (stateId: string, update: { label: string; status: 'running' | 'completed' } | null) => void;
  appendComparisonV2StateResult: (runId: string, stateId: string, result: ComparisonStateResult) => void;
  setComparisonV2RunError: (msg: string | null) => void;
  setComparisonV2Stopping: (stopping: boolean) => void;
  setComparisonV2Paused: (paused: boolean) => void;
  appendComparisonV2LiveDiff: (stateId: string, diff: UIState['comparisonV2LiveDiffs'][string][number]) => void;
  setComparisonV2History: (scopeKey: string, history: ComparisonRunSummary[]) => void;
  setComparisonV2LoadedRun: (runId: string, run: ComparisonRun | null) => void;
  resetComparisonV2LiveStreams: () => void;
  appendComparisonV2TestCase: (stateId: string, testCase: ComparisonTestCase) => void;
  patchComparisonV2TestCase: (stateId: string, testCaseId: string, patch: Partial<ComparisonTestCase>) => void;
  appendOrReplaceComparisonV2Step: (stateId: string, testCaseId: string, step: ComparisonStep) => void;
  setManualPause: (pause: UIState['manualPause']) => void;
  addSecurityWarning: (warning: SecurityWarningItem) => void;
  setGeneratedCode: (code: { framework: string; code: string } | null) => void;
  setLiveTokenUsage: (usage: Array<{ purpose: string; model: string; inputTokens: number; outputTokens: number; cost: number; calls: number }> | null) => void;

  // Project updates
  addProject: (project: Project) => void;
  updateProject: (project: Project) => void;
  removeProject: (id: string) => void;

  // Module updates
  addModule: (projectId: string, module: Module) => void;
  updateModule: (projectId: string, module: Module) => void;
  removeModule: (projectId: string, moduleId: string) => void;

  // Feature updates
  addFeature: (projectId: string, moduleId: string, feature: Feature) => void;
  updateFeature: (projectId: string, moduleId: string, feature: Feature) => void;
  removeFeature: (projectId: string, moduleId: string, featureId: string) => void;

  // Test case updates
  setTestCases: (projectId: string, featureId: string, testCases: TestCase[]) => void;
  setTestCaseStatus: (projectId: string, featureId: string, testCaseId: string, status: ExecutionStatus) => void;

  // Live execution updates (driven by targeted `stepExecuted` messages so UI
  // stays in sync with the activator without waiting for the throttled full
  // state sync).
  appendLiveStep: (projectId: string, featureId: string, testCaseId: string, step: RecordedStep) => void;
}

// Helper to update a feature's test cases inside the nested structure
function updateFeatureTestCases(
  projects: Project[],
  projectId: string,
  featureId: string,
  updater: (testCases: TestCase[]) => TestCase[],
): Project[] {
  return projects.map(p => {
    if (p.id !== projectId) return p;
    return {
      ...p,
      modules: p.modules.map(m => ({
        ...m,
        features: m.features.map(f => {
          if (f.id !== featureId) return f;
          return { ...f, testCases: updater(f.testCases) };
        }),
      })),
    };
  });
}

export const useStore = create<UIState>((set) => ({
  // Initial state
  projects: [],
  get workflows() { return this.projects; },
  session: {
    browserConnected: false,
    activeBrowserDriver: 'playwright' as const,
  },
  comparisons: [],
  connected: false,
  generatingTestCases: false,
  generatingTestPlan: null,
  testPlanError: null,
  generatingSummaryReport: null,
  summaryReportError: null,
  defectDraft: null,
  pendingClassification: null,
  pickerStatus: 'idle',
  lastPickerResult: null,
  pickerError: null,
  fixtures: [],
  brokenConsumersPrompt: null,
  proposedManualSteps: [],
  lastScreenshot: null,
  pendingApproval: null,
  pendingFeedback: null,
  comparisonV2Run: null,
  comparisonV2StateProgress: {},
  comparisonV2RunError: null,
  comparisonV2Stopping: false,
  comparisonV2Paused: false,
  comparisonV2LiveDiffs: {},
  comparisonV2HistoryByScope: {},
  comparisonV2LoadedRuns: {},
  comparisonV2TestCasesByState: {},
  manualPause: null,
  securityWarnings: [],
  generatedCode: null,
  liveTokenUsage: null,

  // Full state sync from activator
  setFullState: (state) => set({
    projects: state.projects || state.workflows || [],
    session: state.session,
    comparisons: state.comparisons,
  }),

  setConnected: (connected) => set({ connected }),
  setGeneratingTestCases: (generating) => set({ generatingTestCases: generating }),
  setGeneratingTestPlan: (v) => set({ generatingTestPlan: v }),
  setTestPlanError: (err) => set({ testPlanError: err }),
  setGeneratingSummaryReport: (v) => set({ generatingSummaryReport: v }),
  setSummaryReportError: (err) => set({ summaryReportError: err }),
  setDefectDraft: (state) => set({ defectDraft: state }),
  updateDefectDraft: (patch) => set((s) => (s.defectDraft ? { defectDraft: { ...s.defectDraft, ...patch } } : s)),
  setPendingClassification: (v) => set({ pendingClassification: v }),
  setPickerStatus: (s) => set({ pickerStatus: s }),
  setLastPickerResult: (r) => set({ lastPickerResult: r }),
  setPickerError: (err) => set({ pickerError: err }),
  setFixtures: (fixtures) => set({ fixtures }),
  upsertFixture: (fixture) =>
    set((s) => {
      const idx = s.fixtures.findIndex((f) => f.id === fixture.id);
      if (idx >= 0) {
        const next = s.fixtures.slice();
        next[idx] = fixture;
        return { fixtures: next };
      }
      return { fixtures: [...s.fixtures, fixture] };
    }),
  removeFixture: (fixtureId) => set((s) => ({ fixtures: s.fixtures.filter((f) => f.id !== fixtureId) })),
  setBrokenConsumersPrompt: (p) => set({ brokenConsumersPrompt: p }),
  addProposedManualStep: (p) =>
    set((s) => ({
      proposedManualSteps: [
        ...s.proposedManualSteps.filter((x) => x.testCaseId !== p.testCaseId),
        p,
      ],
    })),
  clearProposedManualStep: (testCaseId) =>
    set((s) => ({ proposedManualSteps: s.proposedManualSteps.filter((p) => p.testCaseId !== testCaseId) })),
  setLastScreenshot: (screenshot) => set({ lastScreenshot: screenshot }),
  setPendingApproval: (request) => set({ pendingApproval: request }),
  setPendingFeedback: (request) => set({ pendingFeedback: request }),
  setComparisonV2Run: (run) => set({ comparisonV2Run: run }),
  setComparisonV2StateProgress: (stateId, update) =>
    set((s) => {
      const next = { ...s.comparisonV2StateProgress };
      if (update === null) delete next[stateId];
      else next[stateId] = update;
      return { comparisonV2StateProgress: next };
    }),
  appendComparisonV2StateResult: (runId, stateId, result) =>
    set((s) => {
      if (!s.comparisonV2Run || s.comparisonV2Run.id !== runId) return s;
      const existingIdx = s.comparisonV2Run.stateResults.findIndex((r) => r.stateId === stateId);
      const nextResults = existingIdx >= 0
        ? s.comparisonV2Run.stateResults.map((r, i) => (i === existingIdx ? result : r))
        : [...s.comparisonV2Run.stateResults, result];
      return { comparisonV2Run: { ...s.comparisonV2Run, stateResults: nextResults } };
    }),
  setComparisonV2RunError: (msg) => set({ comparisonV2RunError: msg }),
  setComparisonV2Stopping: (stopping) => set({ comparisonV2Stopping: stopping }),
  setComparisonV2Paused: (paused) => set({ comparisonV2Paused: paused }),
  appendComparisonV2LiveDiff: (stateId, diff) =>
    set((s) => {
      const existing = s.comparisonV2LiveDiffs[stateId] ?? [];
      // De-dup by artifact key so repeat broadcasts (if the engine ever resends) do not stack.
      if (diff.artifactKey && existing.some((d) => d.artifactKey === diff.artifactKey)) return s;
      return {
        comparisonV2LiveDiffs: { ...s.comparisonV2LiveDiffs, [stateId]: [...existing, diff] },
      };
    }),
  setComparisonV2History: (scopeKey, history) =>
    set((s) => ({ comparisonV2HistoryByScope: { ...s.comparisonV2HistoryByScope, [scopeKey]: history } })),
  setComparisonV2LoadedRun: (runId, run) =>
    set((s) => {
      const next = { ...s.comparisonV2LoadedRuns };
      if (run === null) delete next[runId];
      else next[runId] = run;
      return { comparisonV2LoadedRuns: next };
    }),
  resetComparisonV2LiveStreams: () =>
    set({
      comparisonV2TestCasesByState: {},
      comparisonV2StateProgress: {},
      comparisonV2Stopping: false,
      comparisonV2Paused: false,
      comparisonV2LiveDiffs: {},
    }),
  appendComparisonV2TestCase: (stateId, testCase) =>
    set((s) => {
      const existing = s.comparisonV2TestCasesByState[stateId] ?? [];
      // De-dup if the test case is already present (the engine may resend after replays).
      if (existing.some((tc) => tc.id === testCase.id)) return s;
      return {
        comparisonV2TestCasesByState: {
          ...s.comparisonV2TestCasesByState,
          [stateId]: [...existing, { ...testCase, steps: testCase.steps ? [...testCase.steps] : [] }],
        },
      };
    }),
  patchComparisonV2TestCase: (stateId, testCaseId, patch) =>
    set((s) => {
      const list = s.comparisonV2TestCasesByState[stateId];
      if (!list) return s;
      const next = list.map((tc) => (tc.id === testCaseId ? { ...tc, ...patch } : tc));
      return {
        comparisonV2TestCasesByState: { ...s.comparisonV2TestCasesByState, [stateId]: next },
      };
    }),
  appendOrReplaceComparisonV2Step: (stateId, testCaseId, step) =>
    set((s) => {
      const list = s.comparisonV2TestCasesByState[stateId];
      if (!list) return s;
      const next = list.map((tc) => {
        if (tc.id !== testCaseId) return tc;
        const idx = tc.steps.findIndex((existing) => existing.id === step.id);
        const steps = idx >= 0
          ? tc.steps.map((existing, i) => (i === idx ? step : existing))
          : [...tc.steps, step];
        return { ...tc, steps };
      });
      return {
        comparisonV2TestCasesByState: { ...s.comparisonV2TestCasesByState, [stateId]: next },
      };
    }),
  setManualPause: (pause) => set({ manualPause: pause }),
  addSecurityWarning: (warning) => set((s) => ({ securityWarnings: [...s.securityWarnings, warning] })),
  setGeneratedCode: (code) => set({ generatedCode: code }),
  setLiveTokenUsage: (usage) => set({ liveTokenUsage: usage }),

  // Project CRUD
  addProject: (project) => set((s) => ({ projects: [...s.projects, project] })),
  updateProject: (project) => set((s) => ({
    projects: s.projects.map(p => p.id === project.id ? project : p),
  })),
  removeProject: (id) => set((s) => ({
    projects: s.projects.filter(p => p.id !== id),
  })),

  // Module CRUD
  addModule: (projectId, module) => set((s) => ({
    projects: s.projects.map(p =>
      p.id === projectId ? { ...p, modules: [...p.modules, module] } : p
    ),
  })),
  updateModule: (projectId, module) => set((s) => ({
    projects: s.projects.map(p =>
      p.id === projectId
        ? { ...p, modules: p.modules.map(m => m.id === module.id ? module : m) }
        : p
    ),
  })),
  removeModule: (projectId, moduleId) => set((s) => ({
    projects: s.projects.map(p =>
      p.id === projectId
        ? { ...p, modules: p.modules.filter(m => m.id !== moduleId) }
        : p
    ),
  })),

  // Feature CRUD
  addFeature: (projectId, moduleId, feature) => set((s) => ({
    projects: s.projects.map(p =>
      p.id === projectId
        ? {
            ...p,
            modules: p.modules.map(m =>
              m.id === moduleId ? { ...m, features: [...m.features, feature] } : m
            ),
          }
        : p
    ),
  })),
  updateFeature: (projectId, moduleId, feature) => set((s) => ({
    projects: s.projects.map(p =>
      p.id === projectId
        ? {
            ...p,
            modules: p.modules.map(m =>
              m.id === moduleId
                ? { ...m, features: m.features.map(f => f.id === feature.id ? feature : f) }
                : m
            ),
          }
        : p
    ),
  })),
  removeFeature: (projectId, moduleId, featureId) => set((s) => ({
    projects: s.projects.map(p =>
      p.id === projectId
        ? {
            ...p,
            modules: p.modules.map(m =>
              m.id === moduleId
                ? { ...m, features: m.features.filter(f => f.id !== featureId) }
                : m
            ),
          }
        : p
    ),
  })),

  // Test cases
  setTestCases: (projectId, featureId, testCases) => set((s) => ({
    projects: updateFeatureTestCases(s.projects, projectId, featureId, () => testCases),
  })),

  setTestCaseStatus: (projectId, featureId, testCaseId, status) => set((s) => ({
    projects: updateFeatureTestCases(s.projects, projectId, featureId, (tcs) =>
      tcs.map(tc => tc.id === testCaseId ? { ...tc, status } : tc)
    ),
  })),

  appendLiveStep: (projectId, featureId, testCaseId, step) => set((s) => ({
    projects: updateFeatureTestCases(s.projects, projectId, featureId, (tcs) =>
      tcs.map(tc => {
        if (tc.id !== testCaseId) return tc;
        const existing = tc.liveSteps || [];
        // De-dup by step id in case both stateSync and stepExecuted deliver it.
        if (existing.some(e => e.id === step.id)) return tc;
        return { ...tc, liveSteps: [...existing, step] };
      })
    ),
  })),

}));
