import { useEffect, useRef, useState } from 'react';
import { useStore } from '../../../store/state';
import type { ElementTreeNode, SelectorCandidate } from '../../../../activator/types/state';
import type ActivatorProxy from '../../../store/ActivatorProxy';
import { TimesIcon } from '../../../styles/Icons';

interface Props {
  activator: ActivatorProxy;
  initialSelectors?: SelectorCandidate[];
  onClose: () => void;
  onCommit: (retained: SelectorCandidate[]) => void;
}

/**
 * Selector workbench modal (REQUIREMENTS.md §3). Renders:
 *  - Element tree on the left, reselect by clicking a node.
 *  - Candidate list on the right with strategy label, editable selector,
 *    live match count, stability rank, retain checkbox.
 *  - A retain list at the bottom showing the selected primary+fallbacks in
 *    priority order. Click a retained entry to promote/demote.
 *
 * Listens directly to `pickerResult` / `selectorValidated` via the Zustand
 * store (pickerResult already flows through the store; selectorValidated is
 * subscribed locally via addEventListener on the websocket through the
 * activator proxy — for v1 we just re-run validateSelector and optimistically
 * update a match count when the user hits Validate).
 *
 * The picker must already be started before this modal opens. When the user
 * commits retained selectors, we call activator.cancelPicker() to tear down.
 */
export default function SelectorWorkbenchModal({
  activator,
  initialSelectors,
  onClose,
  onCommit,
}: Props) {
  const pickerStatus = useStore((s) => s.pickerStatus);
  const result = useStore((s) => s.lastPickerResult);
  const pickerError = useStore((s) => s.pickerError);

  const [candidates, setCandidates] = useState<SelectorCandidate[]>([]);
  const [retained, setRetained] = useState<SelectorCandidate[]>(initialSelectors ?? []);
  const cancelBtnRef = useRef<HTMLButtonElement>(null);

  // When a new pickerResult arrives, adopt its candidates verbatim.
  useEffect(() => {
    if (result?.candidates) {
      setCandidates(result.candidates);
    }
  }, [result]);

  // Subscribe locally to `selectorValidated` — the global messageHandler
  // intentionally no-ops this so each open workbench updates its own candidate
  // list in place with the echoed matchCount + valid flag.
  useEffect(() => {
    const unsubscribe = activator.subscribe((message) => {
      if (message.type !== 'selectorValidated') return;
      const { sessionId, candidate } = message.data;
      if (result?.sessionId && sessionId !== result.sessionId) return;
      setCandidates((list) =>
        list.map((c) =>
          c.strategy === candidate.strategy && c.selector === candidate.selector
            ? { ...c, matchCount: candidate.matchCount, valid: candidate.valid }
            : c,
        ),
      );
    });
    return unsubscribe;
  }, [activator, result?.sessionId]);

  const reselect = (xpath: string) => {
    if (!result?.sessionId) return;
    activator.reselectPickerNode(result.sessionId, xpath);
  };

  const validate = (candidate: SelectorCandidate) => {
    if (!result?.sessionId) return;
    activator.validateSelector(result.sessionId, candidate);
  };

  const editSelector = (index: number, value: string) => {
    setCandidates((list) => list.map((c, i) => (i === index ? { ...c, selector: value } : c)));
  };

  const toggleRetain = (candidate: SelectorCandidate) => {
    setRetained((list) => {
      const idx = list.findIndex((c) => c.selector === candidate.selector && c.strategy === candidate.strategy);
      if (idx >= 0) return list.filter((_, i) => i !== idx);
      return [...list, candidate];
    });
  };

  const moveRetained = (index: number, dir: -1 | 1) => {
    setRetained((list) => {
      const target = index + dir;
      if (target < 0 || target >= list.length) return list;
      const next = list.slice();
      const [item] = next.splice(index, 1);
      next.splice(target, 0, item);
      return next;
    });
  };

  const commit = () => {
    onCommit(retained);
    activator.cancelPicker();
    onClose();
  };

  const cancel = () => {
    activator.cancelPicker();
    onClose();
  };

  // Initial focus + Escape to close (WCAG 2.1.2 / 2.4.3).
  useEffect(() => {
    cancelBtnRef.current?.focus();
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        e.stopPropagation();
        cancel();
      }
    };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60" role="dialog" aria-modal="true" aria-labelledby="selector-workbench-title">
      <div className="bg-white rounded-lg shadow-2xl border border-gray-200 w-[95%] max-w-5xl max-h-[92vh] flex flex-col">
        {/* Header */}
        <div className="flex items-center justify-between px-4 py-2 border-b border-gray-200 bg-gray-50">
          <div>
            <h2 id="selector-workbench-title" className="text-sm font-bold text-gray-800">
              Selector Workbench
            </h2>
            <p className="text-[10px] text-gray-500">
              {pickerStatus === 'picked'
                ? result?.url ?? ''
                : pickerStatus === 'waiting'
                ? 'Click an element in the browser…'
                : pickerStatus === 'launching'
                ? 'Launching picker…'
                : pickerStatus === 'error'
                ? pickerError ?? 'Picker error'
                : 'Idle'}
            </p>
          </div>
          <div className="flex items-center gap-1.5">
            <button
              ref={cancelBtnRef}
              type="button"
              onClick={cancel}
              className="px-2 py-1 text-[11px] bg-gray-100 text-gray-700 rounded hover:bg-gray-200 focus:outline-none focus:ring-2 focus:ring-orange-300"
            >
              Cancel
            </button>
            <button
              type="button"
              onClick={commit}
              disabled={retained.length === 0}
              className="px-2 py-1 text-[11px] font-semibold bg-orange-500 text-white rounded hover:bg-orange-600 disabled:opacity-40"
            >
              Retain {retained.length} selector{retained.length === 1 ? '' : 's'}
            </button>
            <button
              type="button"
              onClick={cancel}
              className="p-1 text-gray-500 hover:text-gray-800"
              aria-label="Close workbench"
              title="Close"
            >
              <TimesIcon />
            </button>
          </div>
        </div>

        {/* Body */}
        <div className="flex-1 overflow-hidden flex">
          {/* Tree */}
          <div className="w-1/3 border-r border-gray-200 overflow-y-auto p-2 text-[11px] bg-gray-50/40">
            <h3 className="text-[9px] uppercase tracking-wider text-gray-500 font-semibold mb-1">
              Element tree
            </h3>
            {result?.tree ? (
              <TreeNode node={result.tree} onReselect={reselect} />
            ) : (
              <p className="text-[10px] text-gray-400 italic">
                Pick an element in the browser to populate the tree.
              </p>
            )}
          </div>

          {/* Candidates */}
          <div className="flex-1 overflow-y-auto p-2">
            <h3 className="text-[9px] uppercase tracking-wider text-gray-500 font-semibold mb-1">
              Candidate selectors
            </h3>
            {candidates.length === 0 ? (
              <p className="text-[10px] text-gray-400 italic">
                No candidates yet. Pick an element first.
              </p>
            ) : (
              <ul className="space-y-1">
                {candidates.map((c, i) => {
                  const isRetained = retained.some(
                    (r) => r.selector === c.selector && r.strategy === c.strategy,
                  );
                  const matchCountDisplay =
                    typeof c.matchCount === 'number' && c.matchCount >= 0 ? `×${c.matchCount}` : '—';
                  return (
                    <li
                      key={`${c.strategy}::${c.selector}::${i}`}
                      className={`rounded border p-1.5 ${
                        isRetained ? 'border-orange-300 bg-orange-50/60' : 'border-gray-200 bg-white'
                      }`}
                    >
                      <div className="flex items-center gap-1.5 mb-1">
                        <input
                          type="checkbox"
                          checked={isRetained}
                          onChange={() => toggleRetain(c)}
                          className="accent-orange-500"
                          aria-label={`Retain ${c.strategy} selector`}
                        />
                        <span className="px-1 py-0.5 text-[9px] font-semibold bg-gray-100 text-gray-700 rounded">
                          {c.strategy}
                        </span>
                        <span className="text-[9px] text-gray-400 ml-auto">
                          rank {c.stabilityRank ?? '?'} · {matchCountDisplay}
                          {c.valid === false && <span className="text-red-600 ml-1">invalid</span>}
                        </span>
                      </div>
                      <div className="flex items-center gap-1">
                        <input
                          value={c.selector}
                          onChange={(e) => editSelector(i, e.target.value)}
                          className="flex-1 min-w-0 px-1.5 py-0.5 border border-gray-200 rounded text-[10px] font-mono focus:outline-none focus:ring-1 focus:ring-orange-300"
                          aria-label={`${c.strategy} selector value`}
                        />
                        <button
                          type="button"
                          onClick={() => validate(c)}
                          className="px-1.5 py-0.5 text-[9px] bg-blue-500 text-white rounded hover:bg-blue-600"
                        >
                          Validate
                        </button>
                      </div>
                    </li>
                  );
                })}
              </ul>
            )}
          </div>
        </div>

        {/* Retained footer */}
        {retained.length > 0 && (
          <div className="border-t border-gray-200 bg-white px-3 py-2 max-h-32 overflow-y-auto">
            <h3 className="text-[9px] uppercase tracking-wider text-gray-500 font-semibold mb-1">
              Retained (primary first)
            </h3>
            <ol className="space-y-0.5">
              {retained.map((r, i) => (
                <li
                  key={`${r.strategy}::${r.selector}::${i}`}
                  className="flex items-center gap-1.5 text-[10px]"
                >
                  <span className="w-4 text-right text-gray-400">{i + 1}.</span>
                  <span className="px-1 py-0.5 text-[9px] bg-gray-100 text-gray-700 rounded shrink-0">
                    {r.strategy}
                  </span>
                  <code className="font-mono truncate flex-1 text-gray-700">{r.selector}</code>
                  <button
                    type="button"
                    onClick={() => moveRetained(i, -1)}
                    disabled={i === 0}
                    className="p-0.5 text-gray-400 hover:text-gray-800 disabled:opacity-30"
                    aria-label="Move retained up"
                  >
                    ↑
                  </button>
                  <button
                    type="button"
                    onClick={() => moveRetained(i, 1)}
                    disabled={i === retained.length - 1}
                    className="p-0.5 text-gray-400 hover:text-gray-800 disabled:opacity-30"
                    aria-label="Move retained down"
                  >
                    ↓
                  </button>
                  <button
                    type="button"
                    onClick={() => toggleRetain(r)}
                    className="p-0.5 text-gray-400 hover:text-red-600"
                    aria-label="Remove retained"
                  >
                    ×
                  </button>
                </li>
              ))}
            </ol>
          </div>
        )}
      </div>
    </div>
  );
}

function TreeNode({
  node,
  onReselect,
  depth = 0,
}: {
  node: ElementTreeNode;
  onReselect: (xpath: string) => void;
  depth?: number;
}) {
  const indent = { paddingLeft: depth * 10 };
  const label = `${node.tag}${node.role ? ` [${node.role}]` : ''}${node.name ? ` "${node.name}"` : ''}`;
  return (
    <div>
      <button
        type="button"
        onClick={() => onReselect(node.xpath)}
        style={indent}
        className={`block w-full text-left truncate text-[10px] py-0.5 rounded hover:bg-gray-100 ${
          node.picked ? 'bg-orange-100 text-orange-700 font-semibold' : 'text-gray-700'
        }`}
        title={node.xpath}
      >
        {label}
      </button>
      {node.children?.map((child, i) => (
        <TreeNode key={`${child.xpath}-${i}`} node={child} onReselect={onReselect} depth={depth + 1} />
      ))}
    </div>
  );
}
