import type { ServerMessage } from '../../activator/types/protocol';
import { useStore } from './state';

/**
 * Handles all messages from the activator WebSocket.
 * Updates the Zustand store accordingly.
 *
 * IMPORTANT: The activator's state subscription broadcasts `stateSync` on every
 * state mutation. This means CRUD messages (projectCreated, moduleCreated, etc.)
 * are redundant — the full state has already been synced by the time they arrive.
 * We intentionally ignore CRUD messages to avoid double-applying state changes.
 * Only non-state messages (UI-specific events) are handled individually.
 */
export function handleServerMessage(message: ServerMessage): void {
  const store = useStore.getState();

  switch (message.type) {
    // Full state sync — authoritative, replaces everything
    case 'stateSync':
      store.setFullState(message.data);
      store.setConnected(true);
      break;

    // CRUD messages are intentionally ignored — stateSync already applied the change.
    // These are kept in the protocol for potential future use (e.g., multi-tab optimistic UI)
    // but the current architecture makes them redundant.
    case 'projectCreated':
    case 'projectUpdated':
    case 'projectDeleted':
    case 'workflowCreated':
    case 'workflowUpdated':
    case 'workflowDeleted':
    case 'moduleCreated':
    case 'moduleUpdated':
    case 'moduleDeleted':
    case 'featureCreated':
    case 'featureUpdated':
    case 'featureDeleted':
    case 'testCaseUpdated':
      // No-op: handled by stateSync
      break;

    // Test case generation result — stateSync handles the data,
    // but we also need to clear the generating flag
    case 'testCasesGenerated':
      store.setGeneratingTestCases(false);
      break;

    // Execution events — these carry UI-specific info not in stateSync
    case 'executionStarted':
      // Flip the test case to running immediately so the UI lights up without
      // waiting for the throttled stateSync broadcast.
      store.setTestCaseStatus(
        message.data.projectId,
        message.data.featureId,
        message.data.testCaseId,
        'running',
      );
      break;

    case 'stepExecuted':
      // Apply the step incrementally. The activator throttles full stateSync
      // broadcasts (see activator/index.ts), so relying solely on stateSync
      // caused the UI to lag well behind the live execution. Targeted
      // stepExecuted messages keep the step list in sync in real time.
      store.appendLiveStep(
        message.data.projectId,
        message.data.featureId,
        message.data.testCaseId,
        message.data.step,
      );
      break;

    case 'executionPaused':
      if (message.data.screenshot) {
        store.setLastScreenshot(message.data.screenshot);
      }
      break;

    case 'executionResumed':
      // stateSync handles the status change
      break;

    case 'executionCompleted':
      // stateSync handles the status change. Clear live token usage.
      store.setLiveTokenUsage(null);
      break;

    case 'generatingTestCases':
      store.setGeneratingTestCases(message.data.status === 'started');
      break;

    case 'browserStatus':
      // Handled through stateSync
      break;

    case 'testPlanGenerating':
      if (message.data.status === 'started') {
        store.setGeneratingTestPlan({ projectId: message.data.projectId, moduleId: message.data.moduleId });
        store.setTestPlanError(null);
      } else if (message.data.status === 'failed') {
        store.setGeneratingTestPlan(null);
        store.setTestPlanError(message.data.error || 'Failed to generate test plan');
      } else {
        store.setGeneratingTestPlan(null);
      }
      break;

    case 'testPlanUpdated':
    case 'summaryReportUpdated':
    case 'summaryReportReady':
      // Handled via stateSync
      break;

    case 'featureClassified': {
      // stateSync already applied the classification to feature state.
      // If the classifier suggests switching to 'comparison' with enough
      // confidence, surface a confirmation modal so the user can accept.
      const { projectId, moduleId, featureId, classification } = message.data;
      const fresh = useStore.getState();
      const project = fresh.projects.find(p => p.id === projectId);
      const feature = project?.modules.find(m => m.id === moduleId)?.features.find(f => f.id === featureId);
      const currentType = feature?.type ?? 'functional';
      if (
        classification.type === 'comparison'
        && currentType !== 'comparison'
        && classification.confidence >= 0.6
      ) {
        store.setPendingClassification({ projectId, moduleId, featureId, classification });
      }
      break;
    }

    case 'defectDrafting':
      if (message.data.status === 'failed') {
        store.updateDefectDraft({ status: 'failed', error: message.data.error });
      }
      // 'started' and 'completed' are handled by defectDrafted below.
      break;

    case 'defectDrafted':
      store.setDefectDraft({
        projectId: message.data.projectId,
        moduleId: message.data.moduleId,
        featureId: message.data.featureId,
        runId: message.data.runId,
        testCaseId: message.data.testCaseId,
        status: 'ready',
        draft: message.data.draft,
      });
      break;

    case 'defectSubmitted':
      store.updateDefectDraft({ status: 'submitted', submittedJiraKey: message.data.jiraKey });
      break;

    case 'summaryReportGenerating':
      if (message.data.status === 'started') {
        store.setGeneratingSummaryReport({ projectId: message.data.projectId, moduleId: message.data.moduleId });
        store.setSummaryReportError(null);
      } else if (message.data.status === 'failed') {
        store.setGeneratingSummaryReport(null);
        store.setSummaryReportError(message.data.error || 'Failed to generate summary report');
      } else {
        store.setGeneratingSummaryReport(null);
      }
      break;

    case 'pickerStarted':
      store.setPickerStatus('launching');
      store.setPickerError(null);
      store.setLastPickerResult(null);
      break;

    case 'pickerWaiting':
      store.setPickerStatus('waiting');
      break;

    case 'pickerResult':
      store.setPickerStatus('picked');
      store.setLastPickerResult({
        sessionId: message.data.sessionId,
        xpath: message.data.xpath,
        url: message.data.url,
        candidates: message.data.candidates,
        tree: message.data.tree,
      });
      break;

    case 'pickerCancelled':
      store.setPickerStatus('cancelled');
      break;

    case 'pickerError':
      store.setPickerStatus('error');
      store.setPickerError(message.data.message);
      break;

    case 'screenshot':
      store.setLastScreenshot(message.data.base64);
      break;

    case 'approvalRequired':
      store.setPendingApproval({
        requestId: message.data.requestId,
        toolName: message.data.toolName,
        description: message.data.description,
        target: message.data.target,
        reason: message.data.reason,
      });
      break;

    case 'feedbackRequest':
      // AI paused and wants input. The FeedbackModal subscribes and renders.
      store.setPendingFeedback(message.data);
      break;

    // ===== Comparison v2 run lifecycle =====
    case 'comparisonV2Started':
      // Seed a fresh run object; clear any previous error and live streams.
      store.setComparisonV2RunError(null);
      store.resetComparisonV2LiveStreams();
      store.setComparisonV2Run({
        id: message.data.runId,
        planId: message.data.planId,
        projectId: message.data.projectId,
        moduleId: message.data.moduleId,
        featureId: message.data.featureId,
        useAI: message.data.useAI,
        status: 'running',
        stateResults: [],
        startedAt: new Date().toISOString(),
        artifactSessionId: message.data.runId,
      });
      break;
    case 'comparisonV2StateStarted':
      store.setComparisonV2StateProgress(message.data.stateId, { label: message.data.label, status: 'running' });
      break;
    case 'comparisonV2StateCompleted':
      store.appendComparisonV2StateResult(message.data.runId, message.data.stateId, message.data.result);
      store.setComparisonV2StateProgress(message.data.stateId, { label: message.data.result.stateLabel, status: 'completed' });
      break;
    case 'comparisonV2Completed':
      store.setComparisonV2Run(message.data.run);
      store.setComparisonV2Stopping(false);
      break;
    case 'comparisonV2Stopping':
      store.setComparisonV2Stopping(true);
      break;
    case 'comparisonV2TestCaseProposed':
      store.appendComparisonV2TestCase(message.data.stateId, message.data.testCase);
      break;
    case 'comparisonV2TestCaseStatusChanged':
      store.patchComparisonV2TestCase(message.data.stateId, message.data.testCaseId, {
        status: message.data.status,
        summary: message.data.summary,
        completedAt: message.data.completedAt,
      });
      break;
    case 'comparisonV2StepExecuted':
      store.appendOrReplaceComparisonV2Step(message.data.stateId, message.data.testCaseId, message.data.step);
      break;
    case 'comparisonV2DiffRecorded':
      store.appendComparisonV2LiveDiff(message.data.stateId, message.data.diff);
      break;
    case 'comparisonV2Paused':
      store.setComparisonV2Paused(true);
      break;
    case 'comparisonV2Resumed':
      store.setComparisonV2Paused(false);
      break;
    case 'comparisonV2HistoryUpdated': {
      const scopeKey = `${message.data.projectId}:${message.data.moduleId}:${message.data.featureId ?? ''}`;
      store.setComparisonV2History(scopeKey, message.data.history);
      break;
    }
    case 'comparisonV2RunDetailLoaded':
      if (message.data.run) store.setComparisonV2LoadedRun(message.data.runId, message.data.run);
      break;
    case 'comparisonV2ReportReady': {
      const { filename, contentBase64, mimeType } = message.data;
      const bin = atob(contentBase64);
      const bytes = Uint8Array.from(bin, (c) => c.charCodeAt(0));
      const blob = new Blob([bytes], { type: mimeType });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      break;
    }

    case 'securityWarning':
      store.addSecurityWarning({
        toolName: message.data.toolName,
        target: message.data.target,
        reason: message.data.reason,
        autoApproveSource: message.data.autoApproveSource,
      });
      break;

    case 'tokenUsageUpdate':
      store.setLiveTokenUsage(message.data.breakdown);
      break;

    case 'codeGenerated':
      store.setGeneratedCode({ framework: message.data.framework, code: message.data.code });
      break;

    case 'exportReady': {
      const { filename, contentBase64 } = message.data;
      const bin = atob(contentBase64);
      const html = new TextDecoder('utf-8').decode(
        Uint8Array.from(bin, c => c.charCodeAt(0)),
      );
      const blob = new Blob([html], { type: 'text/html;charset=utf-8' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      break;
    }

    // ===== Manual Automation authoring — redundant with stateSync =====
    case 'manualStepAdded':
    case 'manualStepUpdated':
    case 'manualStepDeleted':
    case 'manualStepsReordered':
    case 'loopBound':
    case 'loopBindingDeleted':
      // State already re-synced via stateSync. No-op.
      break;

    // HITL pause broadcast — authoring UI can subscribe directly if it wants
    // a modal; for now we just log so the console confirms the executor waited.
    case 'manualPauseRequired':
      store.setManualPause(message.data);
      break;

    // Fixture broadcasts — fixtures are NOT part of AppState (per REQUIREMENTS.md
    // Fixture store gotcha), so we maintain a separate list in the UI store.
    case 'artifactList':
      store.setFixtures(message.data.fixtures);
      break;
    case 'artifactUploaded':
      store.upsertFixture(message.data.fixture);
      break;
    case 'artifactUpdated':
      store.upsertFixture(message.data.fixture);
      break;
    case 'artifactDeleted':
      store.removeFixture(message.data.fixtureId);
      break;
    case 'artifactBrokenConsumers':
      store.setBrokenConsumersPrompt({
        fixtureId: message.data.fixtureId,
        consumers: message.data.consumers,
      });
      break;
    case 'artifactDownloadReady': {
      const { filename, mimeType, contentBase64 } = message.data;
      const bin = atob(contentBase64);
      const bytes = Uint8Array.from(bin, (c) => c.charCodeAt(0));
      const blob = new Blob([bytes], { type: mimeType || 'application/octet-stream' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      break;
    }

    // NL-proposed / AI-refine results. Consumed by the authoring panel.
    case 'manualStepProposed':
      store.addProposedManualStep(message.data);
      break;

    // selectorValidated is consumed by the selector workbench via a local
    // subscription (not through Zustand) — no-op here.
    case 'selectorValidated':
      break;

    case 'error':
      console.error('[Activator Error]:', message.data.message, message.data.context);
      // Surface comparison-run errors in the Run tab so silent launch failures
      // (bad driver config, port conflict, missing auth) become visible.
      if (message.data.context === 'comparisonV2') {
        store.setComparisonV2RunError(message.data.message);
      }
      break;

    default:
      console.warn('[WS] Unhandled message type:', (message as { type: string }).type);
  }
}
