import { useEffect, useMemo, useRef, useState } from 'react';
import type { RecordedStep, TestCase } from '../../../../activator/types/state';
import type ActivatorProxy from '../../../store/ActivatorProxy';
import { RunIcon, StopIcon, ChevronDownIcon, ChevronRightIcon } from '../../../styles/Icons';
import StepDetail from './StepDetail';
import StepDetailModal from './StepDetailModal';
import ExecutionControls from './ExecutionControls';

interface TestCaseCardProps {
  testCase: TestCase;
  activator: ActivatorProxy;
  projectId: string;
  featureId: string;
  showRunButton: boolean;
  useAI: boolean;
  onEdit: (tc: TestCase) => void;
  onDelete: (id: string) => void;
}

function getStatusTextColor(status: string): string {
  switch (status) {
    case 'passed': return 'text-green-500';
    case 'failed': return 'text-red-500';
    case 'running': return 'text-blue-500';
    case 'paused': return 'text-orange-500';
    case 'skipped': return 'text-yellow-500';
    default: return 'text-gray-500';
  }
}

/** Aggregate counts from all steps */
function getStepCounts(steps: RecordedStep[]) {
  let networkCount = 0;
  let consoleErrorCount = 0;
  let consoleWarnCount = 0;
  let consoleLogCount = 0;
  let screenshotCount = 0;
  for (const s of steps) {
    networkCount += s.networkRequests.length;
    for (const m of s.consoleMessages) {
      if (m.type === 'error') consoleErrorCount++;
      else if (m.type === 'warn') consoleWarnCount++;
      else consoleLogCount++;
    }
    if (s.screenshotAfter) screenshotCount++;
  }
  return { networkCount, consoleErrorCount, consoleWarnCount, consoleLogCount, screenshotCount };
}

export default function TestCaseCard({
  testCase: tc,
  activator,
  projectId,
  featureId,
  showRunButton,
  useAI,
  onEdit,
  onDelete,
}: TestCaseCardProps) {
  const [stepsOpen, setStepsOpen] = useState(false);
  const [selectedStep, setSelectedStep] = useState<RecordedStep | null>(null);
  const isRunning = tc.status === 'running';
  const isPaused = tc.status === 'paused';
  const isActive = isRunning || isPaused;
  const hasSteps = tc.steps && tc.steps.length > 0;
  const liveSteps = tc.liveSteps || [];
  const counts = useMemo(() => getStepCounts(liveSteps), [liveSteps]);
  const lastStepRef = useRef<HTMLDivElement>(null);

  // Auto-expand when running
  useEffect(() => {
    if (isActive) setStepsOpen(true);
  }, [isActive]);

  // Auto-scroll to latest step during execution
  useEffect(() => {
    if (isActive && lastStepRef.current) {
      lastStepRef.current.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    }
  }, [liveSteps.length, isActive]);

  const handleRun = (e: React.MouseEvent) => {
    e.stopPropagation();
    activator.runTestCase(projectId, featureId, tc.id);
  };

  const handleReplay = (e: React.MouseEvent) => {
    e.stopPropagation();
    activator.replayTestCase(projectId, featureId, tc.id);
  };

  const handleStop = (e: React.MouseEvent) => {
    e.stopPropagation();
    activator.stopExecution();
  };

  return (
    <div className="bg-white rounded-lg shadow-sm border border-gray-200 p-3 mb-2">
      {/* Header row */}
      <div className="flex gap-1.5 items-center">
        {/* Run/Stop button */}
        {!isActive && showRunButton && (
          <button
            className={`cursor-pointer ${getStatusTextColor(tc.status)}`}
            onClick={hasSteps && !useAI ? handleReplay : handleRun}
            title={hasSteps && !useAI ? 'Replay saved steps' : 'Run with AI'}
          >
            <RunIcon />
          </button>
        )}
        {isActive && (
          <button className="text-red-600 cursor-pointer" onClick={handleStop}>
            <StopIcon />
          </button>
        )}

        {/* Title + meta */}
        <span className="text-[12.5px] text-[#1e2939] flex-1 min-w-0">
          <span className="cursor-pointer hover:underline" onClick={() => setStepsOpen(o => !o)}>
            {tc.title}
          </span>
          <div className="flex items-center gap-1.5 mt-0.5 flex-wrap">
            {hasSteps && (
              <span className="text-[10px] text-gray-500">{tc.steps.length} steps</span>
            )}
            {liveSteps.length > 0 && (
              <>
                <span className="text-[10px] text-gray-400">&middot;</span>
                <span className="text-[10px] text-blue-500">{liveSteps.length} executed</span>
              </>
            )}
            {counts.networkCount > 0 && (
              <>
                <span className="text-[10px] text-gray-400">&middot;</span>
                <span className="text-[10px] text-blue-500">{counts.networkCount} network</span>
              </>
            )}
            {counts.consoleErrorCount > 0 && (
              <>
                <span className="text-[10px] text-gray-400">&middot;</span>
                <span className="text-[10px] text-red-500">{counts.consoleErrorCount} errors</span>
              </>
            )}
            {counts.consoleWarnCount > 0 && (
              <>
                <span className="text-[10px] text-gray-400">&middot;</span>
                <span className="text-[10px] text-yellow-500">{counts.consoleWarnCount} warnings</span>
              </>
            )}
            {counts.consoleLogCount > 0 && (
              <>
                <span className="text-[10px] text-gray-400">&middot;</span>
                <span className="text-[10px] text-gray-500">{counts.consoleLogCount} logs</span>
              </>
            )}
            {counts.screenshotCount > 0 && (
              <>
                <span className="text-[10px] text-gray-400">&middot;</span>
                <span className="text-[10px] text-purple-500">{counts.screenshotCount} screenshots</span>
              </>
            )}
            {tc.findings.length > 0 && (
              <>
                <span className="text-[10px] text-gray-400">&middot;</span>
                <span className={`text-[10px] ${tc.findings.some(f => f.type === 'fail') ? 'text-red-500' : 'text-green-500'}`}>
                  {tc.findings.length} findings
                </span>
              </>
            )}
            {tc.executionTime != null && (
              <>
                <span className="text-[10px] text-gray-400">&middot;</span>
                <span className="text-[10px] text-gray-500">{(tc.executionTime / 1000).toFixed(1)}s</span>
              </>
            )}
            <span className="text-[10px] text-gray-400">&middot;</span>
            <button
              className="text-[10px] text-gray-500 cursor-pointer underline underline-offset-2 decoration-dotted decoration-gray-400"
              onClick={() => onEdit(tc)}
            >
              Edit
            </button>
            <span className="text-[10px] text-gray-400">&middot;</span>
            <button
              className="text-[10px] text-gray-500 cursor-pointer underline underline-offset-2 decoration-dotted decoration-gray-400"
              onClick={() => onDelete(tc.id)}
            >
              Delete
            </button>
          </div>
        </span>

        {/* Expand/collapse chevron */}
        <span className="flex items-center cursor-pointer select-none" onClick={() => setStepsOpen(o => !o)}>
          {stepsOpen || isActive ? (
            <ChevronDownIcon className="w-4 h-4 ml-1 text-gray-400" />
          ) : (
            <ChevronRightIcon className="w-4 h-4 ml-1 text-gray-400" />
          )}
        </span>
      </div>

      {/* Execution controls (inline when paused) */}
      {isActive && (
        <div className="mt-2">
          <ExecutionControls activator={activator} isRunning={isRunning} isPaused={isPaused} />
        </div>
      )}

      {/* Expanded steps list */}
      {(stepsOpen || isActive) && (
        <div className="flex flex-col gap-1.5 mt-2">
          {/* During execution: show live recorded steps */}
          {liveSteps.length > 0 && liveSteps.map((step, idx) => (
            <div key={step.id} ref={idx === liveSteps.length - 1 ? lastStepRef : undefined}>
              <StepDetail
                step={step}
                onClick={() => setSelectedStep(step)}
              />
            </div>
          ))}
          {/* When not executing: show saved steps as simple list */}
          {liveSteps.length === 0 && hasSteps && tc.steps.map((step, idx) => (
            <div key={idx} className="bg-gray-100 p-2 ps-1.5 rounded-md">
              <div className="flex items-center gap-2">
                <span className="text-[10px] text-gray-400 w-4 text-right">{idx + 1}</span>
                <span className="text-xs text-[#1e2939]">{step.toolName}</span>
                <span className="text-[10px] text-gray-400 truncate flex-1">
                  {JSON.stringify(step.toolArgs).substring(0, 60)}
                </span>
              </div>
            </div>
          ))}
          {liveSteps.length === 0 && !hasSteps && !isActive && (
            <div className="text-xs text-gray-400">No steps yet</div>
          )}
          {isRunning && (
            <div className={`flex items-center gap-2 p-2 text-xs ${useAI || !hasSteps ? 'text-blue-500' : 'text-green-600'}`}>
              <div className={`animate-spin rounded-full h-3 w-3 border-b-2 ${useAI || !hasSteps ? 'border-blue-500' : 'border-green-500'}`} />
              {useAI || !hasSteps ? 'AI is deciding next action...' : 'Replaying saved steps...'}
            </div>
          )}
        </div>
      )}

      {/* Test-case level findings (no stepId) */}
      {(stepsOpen || isActive) && tc.findings.some(f => !f.stepId) && (
        <div className="mt-2 pt-2 border-t border-gray-100">
          {tc.findings.filter(f => !f.stepId).map(f => (
            <div key={f.id} className={`text-xs py-0.5 flex items-start gap-1.5 ${
              f.type === 'fail' ? 'text-red-600' :
              f.type === 'pass' ? 'text-green-600' :
              f.type === 'warning' ? 'text-yellow-600' : 'text-gray-500'
            }`}>
              <span className="shrink-0 font-bold">
                {f.type === 'fail' ? '✗' : f.type === 'pass' ? '✓' : f.type === 'warning' ? '!' : 'i'}
              </span>
              <span>{f.message}</span>
            </div>
          ))}
        </div>
      )}

      {/* Step detail modal (bottom sheet) */}
      {selectedStep && (
        <StepDetailModal step={selectedStep} findings={tc.findings} onClose={() => setSelectedStep(null)} />
      )}
    </div>
  );
}
