import { useNavigate } from 'react-router-dom';
import type { ComparisonScope } from '../../../activator/types/state';
import ComparisonV2View from './v2/ComparisonV2View';

interface Props {
  scope: ComparisonScope;
  title: string;
  subtitle: string;
  backTo: string;
}

/**
 * Page shell for the side-by-side comparison feature. The body is the
 * plan-based multi-session workspace — launching two (or more) browsers,
 * iterating through states, and producing deterministic diffs.
 */
export default function ComparisonView({ scope, title, subtitle, backTo }: Props) {
  const navigate = useNavigate();

  return (
    <div className="w-full px-2 sm:px-4 py-3 sm:py-6 max-w-[1800px] mx-auto">
      {/* Top-left back button */}
      <div className="flex items-center gap-2 mb-3">
        <button
          onClick={() => navigate(backTo)}
          className="inline-flex items-center gap-1 px-2 py-1 text-xs text-gray-600 hover:text-gray-900 hover:bg-gray-100 rounded-md transition cursor-pointer"
          title="Back"
        >
          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" />
          </svg>
          Back
        </button>
      </div>

      {/* Header */}
      <div className="mb-4 min-w-0">
        <h1 className="text-base sm:text-xl font-bold text-gray-800 truncate">{title}</h1>
        <p className="text-xs sm:text-sm text-gray-500 mt-1 truncate">{subtitle}</p>
      </div>

      <ComparisonV2View
        projectId={scope.projectId}
        moduleId={scope.moduleId ?? ''}
        featureId={scope.featureId}
        title={title}
      />
    </div>
  );
}
