import type { ComparisonStep } from '../../../../activator/types/comparisonPlan';
import { getComparisonStepTitle } from './ComparisonStepRow';

interface Props {
  step: ComparisonStep;
  onClose: () => void;
}

const COMMON_BADGE = 'common';

/**
 * Bottom-sheet modal mirroring the test-execution `StepDetailModal` style:
 * sticky header, body with Arguments / Result / Screenshot sections.
 *
 * Comparison steps don't capture per-step network or console traces (those
 * belong to the per-test-case BrowserDriver instances and aren't exposed via
 * the comparison engine), so this modal omits those tabs and just stacks
 * the sections vertically — same look, simpler payload.
 */
export default function ComparisonStepDetailModal({ step, onClose }: Props) {
  const title = getComparisonStepTitle(step);
  const sessionBadge = step.sessionId ?? COMMON_BADGE;
  const cleanArgs = stripBookkeepingKeys(step.toolArgs);
  const hasArgs = Object.keys(cleanArgs).length > 0;
  const resultData = unwrapResultData(step.result);

  const handleBackdropClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) onClose();
  };

  return (
    <div className="fixed inset-0 bg-[rgba(0,0,0,0.5)] flex items-end z-50" onClick={handleBackdropClick}>
      <div className="bg-white rounded-t-2xl shadow-xl w-full min-h-[55vh] max-h-[80vh] animate-slide-up overflow-hidden flex flex-col">
        <div className="sticky top-0 bg-white border-b border-gray-200 px-4 py-3 shrink-0">
          <div className="w-12 h-1 bg-gray-300 rounded-full mx-auto mb-2" />
          <div className="flex items-center justify-between gap-2">
            <div className="flex items-center gap-2 min-w-0">
              <span
                className={`w-2.5 h-2.5 rounded-full shrink-0 ${
                  step.status === 'failed' ? 'bg-red-500' : step.status === 'running' ? 'bg-orange-500 animate-pulse' : 'bg-green-500'
                }`}
              />
              <h2 className="text-sm font-semibold text-gray-800 truncate">{title}</h2>
              <span className="text-xs text-gray-400 shrink-0">{step.toolName}</span>
              {typeof step.durationMs === 'number' && (
                <span className="text-xs text-gray-400 shrink-0">· {step.durationMs}ms</span>
              )}
            </div>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-600 p-1 cursor-pointer shrink-0">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4">
          <div className="flex items-center gap-2 text-xs text-gray-600">
            <span className="font-semibold text-gray-500 uppercase text-[10px]">Session</span>
            <span className="font-mono px-1.5 py-0.5 rounded bg-gray-100">{sessionBadge}</span>
          </div>

          {step.error && (
            <div>
              <h3 className="text-xs font-semibold text-gray-500 uppercase mb-1">Error</h3>
              <pre className="text-xs text-red-700 font-mono whitespace-pre-wrap break-all bg-red-50 rounded-lg p-3 border border-red-200">
                {step.error}
              </pre>
            </div>
          )}

          {hasArgs && (
            <div>
              <h3 className="text-xs font-semibold text-gray-500 uppercase mb-1">Arguments</h3>
              <pre className="text-xs text-gray-700 font-mono whitespace-pre-wrap break-all bg-gray-50 rounded-lg p-3 border border-gray-200">
                {JSON.stringify(cleanArgs, null, 2)}
              </pre>
            </div>
          )}

          <div>
            <h3 className="text-xs font-semibold text-gray-500 uppercase mb-1">Result</h3>
            <div
              className={`rounded-lg p-3 border text-sm ${
                step.status === 'failed' ? 'bg-red-50 border-red-200' : 'bg-green-50 border-green-200'
              }`}
            >
              <span
                className={`font-semibold capitalize ${step.status === 'failed' ? 'text-red-700' : 'text-green-700'}`}
              >
                {step.status}
              </span>
              {resultData !== undefined && resultData !== null && (
                <pre className="mt-2 text-xs font-mono whitespace-pre-wrap break-all text-gray-600">
                  {typeof resultData === 'string' ? resultData : JSON.stringify(resultData, null, 2)}
                </pre>
              )}
            </div>
          </div>

          {step.screenshotBase64 && (
            <div>
              <h3 className="text-xs font-semibold text-gray-500 uppercase mb-1">Screenshot</h3>
              <img
                src={`data:image/png;base64,${step.screenshotBase64}`}
                alt={`${step.toolName} screenshot`}
                className="w-full rounded-lg border border-gray-200"
              />
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

function stripBookkeepingKeys(args: Record<string, unknown>): Record<string, unknown> {
  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(args)) {
    if (k === '__selectorFallbacks' || k === '__elementInfo') continue;
    out[k] = v;
  }
  return out;
}

/**
 * The engine wraps tool results as `{ success, data }` before broadcasting.
 * Unwrap to surface just the inner payload in the modal — saves a confusing
 * `success: true` line above the actual data the AI cared about.
 */
function unwrapResultData(result: unknown): unknown {
  if (!result || typeof result !== 'object') return result;
  const r = result as { success?: unknown; data?: unknown; error?: unknown };
  if ('data' in r) return r.data;
  return result;
}
