import { useStore } from '../store/state';
import { useActivator } from '../store/Context';

/**
 * Modal dialog shown when the AI requests an external operation
 * that requires user approval (HTTP request, file write, shell command).
 */
export default function ApprovalDialog() {
  const approval = useStore(s => s.pendingApproval);
  const activator = useActivator();

  if (!approval) return null;

  const handleApprove = () => {
    activator.approvalResponse(approval.requestId, true);
    useStore.getState().setPendingApproval(null);
  };

  const handleDeny = () => {
    activator.approvalResponse(approval.requestId, false);
    useStore.getState().setPendingApproval(null);
  };

  const toolLabels: Record<string, string> = {
    http_request: 'HTTP Request',
    write_file: 'File Write',
    run_command: 'Shell Command',
  };

  return (
    <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-50">
      <div className="bg-gray-800 rounded-lg p-6 max-w-lg w-full mx-4 border border-gray-600 shadow-xl">
        <div className="flex items-center gap-2 mb-4">
          <span className="text-yellow-400 text-xl">!</span>
          <h2 className="text-lg font-semibold text-white">Approval Required</h2>
        </div>

        <p className="text-gray-300 text-sm mb-3">
          The AI wants to perform an external operation that requires your approval:
        </p>

        <div className="bg-gray-900 rounded p-4 mb-4 space-y-2">
          <div className="flex gap-2">
            <span className="text-gray-500 text-xs w-16 flex-shrink-0">Tool:</span>
            <span className="text-orange-400 text-sm font-medium">{toolLabels[approval.toolName] || approval.toolName}</span>
          </div>
          <div className="flex gap-2">
            <span className="text-gray-500 text-xs w-16 flex-shrink-0">Target:</span>
            <span className="text-white text-sm font-mono break-all">{approval.target}</span>
          </div>
          <div className="flex gap-2">
            <span className="text-gray-500 text-xs w-16 flex-shrink-0">Reason:</span>
            <span className="text-gray-300 text-sm">{approval.reason}</span>
          </div>
        </div>

        <p className="text-gray-500 text-xs mb-4">
          This action will be automatically denied in 60 seconds if no response is given.
        </p>

        <div className="flex gap-3 justify-end">
          <button
            onClick={handleDeny}
            className="px-4 py-2 bg-gray-700 text-white rounded hover:bg-gray-600 text-sm"
          >
            Deny
          </button>
          <button
            onClick={handleApprove}
            className="px-4 py-2 bg-orange-500 text-white rounded hover:bg-orange-600 text-sm"
          >
            Approve
          </button>
        </div>
      </div>
    </div>
  );
}
