import { useEffect } from 'react';

interface Props {
  framework: string;
  code: string;
  onClose: () => void;
}

const FRAMEWORK_META: Record<string, { label: string; ext: string; filename: string }> = {
  'plain-text':        { label: 'Plain text (deterministic)', ext: 'txt',  filename: 'testcases.txt' },
  'playwright-ts':     { label: 'Playwright (TypeScript)',    ext: 'ts',   filename: 'generated.spec.ts' },
  'playwright-java':   { label: 'Playwright (Java)',          ext: 'java', filename: 'GeneratedTests.java' },
  'playwright-csharp': { label: 'Playwright (C#)',            ext: 'cs',   filename: 'GeneratedTests.cs' },
  'selenium-ts':       { label: 'Selenium (TypeScript)',      ext: 'ts',   filename: 'generated.selenium.spec.ts' },
  'selenium-java':     { label: 'Selenium (Java)',            ext: 'java', filename: 'GeneratedSeleniumTests.java' },
  'selenium-csharp':   { label: 'Selenium (C#)',              ext: 'cs',   filename: 'GeneratedSeleniumTests.cs' },
};

export default function CodeModal({ framework, code, onClose }: Props) {
  const meta = FRAMEWORK_META[framework] || { label: framework, ext: 'txt', filename: 'generated.txt' };

  useEffect(() => {
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
    window.addEventListener('keydown', onKey);
    return () => window.removeEventListener('keydown', onKey);
  }, [onClose]);

  const handleCopy = () => navigator.clipboard.writeText(code);

  const handleDownload = () => {
    const blob = new Blob([code], { type: 'text/plain;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = meta.filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return (
    <div className="fixed inset-0 z-50 bg-black/50 flex items-stretch justify-center p-3" onClick={onClose}>
      <div
        className="w-full max-w-none bg-white rounded-lg shadow-2xl flex flex-col overflow-hidden"
        onClick={e => e.stopPropagation()}
      >
        <div className="flex items-center justify-between px-4 py-2.5 border-b border-gray-200 bg-gradient-to-r from-purple-50 to-blue-50">
          <div className="min-w-0">
            <h2 className="text-sm font-bold text-gray-800 truncate">Generated Code</h2>
            <p className="text-[11px] text-gray-500 truncate">{meta.label}</p>
          </div>
          <div className="flex items-center gap-2 shrink-0">
            <button
              onClick={handleCopy}
              className="px-3 py-1.5 text-[11px] font-semibold bg-white text-gray-700 border border-gray-200 rounded hover:bg-gray-50"
            >
              Copy
            </button>
            <button
              onClick={handleDownload}
              className="px-3 py-1.5 text-[11px] font-semibold bg-purple-500 text-white rounded hover:bg-purple-600"
            >
              Download
            </button>
            <button
              onClick={onClose}
              className="px-3 py-1.5 text-[11px] font-semibold bg-gray-100 text-gray-700 rounded hover:bg-gray-200"
            >
              Close
            </button>
          </div>
        </div>
        <pre className="flex-1 overflow-auto p-4 text-[12px] leading-relaxed font-mono text-gray-800 bg-gray-50 whitespace-pre m-0">
          {code}
        </pre>
      </div>
    </div>
  );
}
