import type {
  ComparisonResult,
  ExecutionStatus,
  Feature,
  Module,
  Project,
  SessionState,
  TestCase,
  TestCaseRunResult,
  TestRun,
} from '../../activator/types/state';

export interface ProjectDashboardSummary {
  totalTestCases: number;
  executedTestCases: number;
  passedTestCases: number;
  failedTestCases: number;
  passRate: number | null;
  totalFeatures: number;
  featuresWithTests: number;
  featuresWithoutTests: number;
  totalModules: number;
  lastActivityAt: string | null;
  stale: boolean;
}

export interface ProjectDashboardModule {
  moduleId: string;
  moduleName: string;
  totalTestCases: number;
  passedTestCases: number;
  failedTestCases: number;
  passRate: number | null;
  featureCount: number;
  hasTestPlan: boolean;
  hasSummaryReport: boolean;
  hasComparison: boolean;
}

export interface FailedCaseEntry {
  projectId: string;
  moduleId: string;
  featureId: string;
  featureName: string;
  runId: string;
  testCaseId: string;
  testCaseTitle: string;
  failureMessage: string | null;
  startedAt: string;
  createdJiraKey?: string;
}

export interface CoverageGapEntry {
  moduleId: string;
  moduleName: string;
  featureId: string;
  featureName: string;
  kind: 'no_test_cases' | 'no_runs';
}

export interface HighPriorityRiskEntry {
  moduleId: string;
  moduleName: string;
  featureId: string;
  featureName: string;
  testCaseId: string;
  testCaseTitle: string;
  latestStatus: 'never' | 'failed';
}

export type ActivityEntry =
  | {
      kind: 'run';
      runId: string;
      featureId: string;
      featureName: string;
      moduleId: string;
      mode: 'ai' | 'replay' | 'manual';
      status: ExecutionStatus;
      passed: number;
      failed: number;
      startedAt: string;
    }
  | {
      kind: 'comparison';
      comparisonId: string;
      moduleId?: string;
      featureId?: string;
      scopeLabel: string;
      status: ExecutionStatus;
      findingsCount: number;
      startedAt: string;
    };

export interface ProjectDashboard {
  project: Project;
  summary: ProjectDashboardSummary;
  modules: ProjectDashboardModule[];
  attention: {
    failedCases: FailedCaseEntry[];
    coverageGaps: CoverageGapEntry[];
    highPriorityRisks: HighPriorityRiskEntry[];
  };
  activity: ActivityEntry[];
  live: {
    executionInFlight?: { featureId: string; testCaseId: string };
    comparisonInFlight?: { moduleId?: string; featureId?: string };
  };
}

const SEVEN_DAYS_MS = 7 * 24 * 60 * 60 * 1000;
const FAILED_CAP = 15;
const ACTIVITY_CAP = 10;

function latestResultFor(
  runs: TestRun[] | undefined,
  testCaseId: string,
): { run?: TestRun; result?: TestCaseRunResult } {
  if (!runs || runs.length === 0) return {};
  for (let i = runs.length - 1; i >= 0; i--) {
    const run = runs[i];
    const result = run.testCaseResults.find(r => r.testCaseId === testCaseId);
    if (result) return { run, result };
  }
  return {};
}

function firstBugFinding(result: TestCaseRunResult): string | null {
  const bug = result.findings.find(f => f.type === 'fail' && f.isBug === true);
  return bug?.message ?? null;
}

function hasBugFinding(result: TestCaseRunResult): boolean {
  return result.findings.some(f => f.type === 'fail' && f.isBug === true);
}

function moduleHasComparison(mod: Module): boolean {
  if (mod.comparisonConfig) return true;
  return mod.features.some(f => f.type === 'comparison');
}

function collectFeatureCases(feature: Feature): {
  cases: TestCase[];
  runs: TestRun[] | undefined;
} {
  return { cases: feature.testCases, runs: feature.testRuns };
}

export function buildProjectDashboard(
  project: Project,
  comparisons: ComparisonResult[],
  session: SessionState,
): ProjectDashboard {
  let totalTestCases = 0;
  let executedTestCases = 0;
  let passedTestCases = 0;
  let failedTestCases = 0;
  let totalFeatures = 0;
  let featuresWithTests = 0;
  let lastActivityAt: string | null = null;

  const modules: ProjectDashboardModule[] = [];
  const failedCases: FailedCaseEntry[] = [];
  const coverageGaps: CoverageGapEntry[] = [];
  const highPriorityRisks: HighPriorityRiskEntry[] = [];
  const activity: ActivityEntry[] = [];

  const trackActivity = (iso: string | undefined) => {
    if (!iso) return;
    if (!lastActivityAt || iso > lastActivityAt) lastActivityAt = iso;
  };

  for (const mod of project.modules) {
    let modTotal = 0;
    let modPassed = 0;
    let modFailed = 0;

    for (const feature of mod.features) {
      totalFeatures++;
      const { cases, runs } = collectFeatureCases(feature);

      if (cases.length === 0) {
        coverageGaps.push({
          moduleId: mod.id,
          moduleName: mod.name,
          featureId: feature.id,
          featureName: feature.name,
          kind: 'no_test_cases',
        });
      } else {
        featuresWithTests++;

        const hasAnyRun = (runs?.length ?? 0) > 0;
        const allPendingOrSkipped = cases.every(
          c => c.status === 'pending' || c.status === 'skipped',
        );
        if (!hasAnyRun && allPendingOrSkipped) {
          coverageGaps.push({
            moduleId: mod.id,
            moduleName: mod.name,
            featureId: feature.id,
            featureName: feature.name,
            kind: 'no_runs',
          });
        }
      }

      // Runs → activity feed + last activity
      if (runs) {
        for (const run of runs) {
          trackActivity(run.startedAt);
          const passedInRun = run.testCaseResults.filter(r => r.status === 'passed').length;
          const failedInRun = run.testCaseResults.filter(r => r.status === 'failed').length;
          activity.push({
            kind: 'run',
            runId: run.id,
            featureId: feature.id,
            featureName: feature.name,
            moduleId: mod.id,
            mode: run.mode,
            status: run.status,
            passed: passedInRun,
            failed: failedInRun,
            startedAt: run.startedAt,
          });
        }
      }

      // Per-test-case rollup via latest run
      for (const tc of cases) {
        totalTestCases++;
        modTotal++;

        const { run, result } = latestResultFor(runs, tc.id);
        const latestStatus: ExecutionStatus | 'never' = result?.status ?? 'never';

        if (result && run) {
          executedTestCases++;
          if (result.status === 'passed') {
            passedTestCases++;
            modPassed++;
          } else if (result.status === 'failed') {
            failedTestCases++;
            modFailed++;

            // Only surface in the attention list if the AI flagged an actual
            // product defect, or a Jira bug has already been drafted for it.
            // Intermediate selector/retry noise stays out of the nag list.
            if (hasBugFinding(result) || result.createdJiraKey) {
              failedCases.push({
                projectId: project.id,
                moduleId: mod.id,
                featureId: feature.id,
                featureName: feature.name,
                runId: run.id,
                testCaseId: tc.id,
                testCaseTitle: tc.title,
                failureMessage: firstBugFinding(result),
                startedAt: run.startedAt,
                createdJiraKey: result.createdJiraKey,
              });
            }
          }
        }

        if (tc.priority === 'high') {
          if (latestStatus === 'failed' || latestStatus === 'never') {
            highPriorityRisks.push({
              moduleId: mod.id,
              moduleName: mod.name,
              featureId: feature.id,
              featureName: feature.name,
              testCaseId: tc.id,
              testCaseTitle: tc.title,
              latestStatus: latestStatus === 'failed' ? 'failed' : 'never',
            });
          }
        }
      }
    }

    const modExecuted = modPassed + modFailed;
    modules.push({
      moduleId: mod.id,
      moduleName: mod.name,
      totalTestCases: modTotal,
      passedTestCases: modPassed,
      failedTestCases: modFailed,
      passRate: modExecuted > 0 ? modPassed / modExecuted : null,
      featureCount: mod.features.length,
      hasTestPlan: !!mod.testPlan,
      hasSummaryReport: !!mod.summaryReport,
      hasComparison: moduleHasComparison(mod),
    });
  }

  // Comparisons for this project
  for (const cmp of comparisons) {
    if (cmp.scope?.projectId !== project.id) continue;
    trackActivity(cmp.startedAt);
    const modName = cmp.scope.moduleId
      ? project.modules.find(m => m.id === cmp.scope.moduleId)?.name
      : undefined;
    const scopeLabel = modName ? `Module — ${modName}` : 'Project';
    activity.push({
      kind: 'comparison',
      comparisonId: cmp.id,
      moduleId: cmp.scope.moduleId,
      featureId: cmp.scope.featureId,
      scopeLabel,
      status: cmp.status,
      findingsCount: cmp.findings?.length ?? 0,
      startedAt: cmp.startedAt,
    });
  }

  // Sort activity newest first, cap
  activity.sort((a, b) => (a.startedAt < b.startedAt ? 1 : -1));
  const activityCapped = activity.slice(0, ACTIVITY_CAP);

  // Sort failed cases newest first, cap
  failedCases.sort((a, b) => (a.startedAt < b.startedAt ? 1 : -1));
  const failedCapped = failedCases.slice(0, FAILED_CAP);

  const passRate = executedTestCases > 0 ? passedTestCases / executedTestCases : null;
  const stale =
    lastActivityAt !== null &&
    Date.now() - Date.parse(lastActivityAt) > SEVEN_DAYS_MS &&
    totalTestCases > executedTestCases;

  const live: ProjectDashboard['live'] = {};
  if (session.activeExecution && session.activeExecution.projectId === project.id) {
    live.executionInFlight = {
      featureId: session.activeExecution.featureId,
      testCaseId: session.activeExecution.testCaseId,
    };
  }
  if (session.activeComparison && session.activeComparison.projectId === project.id) {
    live.comparisonInFlight = {
      moduleId: session.activeComparison.moduleId,
      featureId: session.activeComparison.featureId,
    };
  }

  return {
    project,
    summary: {
      totalTestCases,
      executedTestCases,
      passedTestCases,
      failedTestCases,
      passRate,
      totalFeatures,
      featuresWithTests,
      featuresWithoutTests: totalFeatures - featuresWithTests,
      totalModules: project.modules.length,
      lastActivityAt,
      stale,
    },
    modules,
    attention: {
      failedCases: failedCapped,
      coverageGaps,
      highPriorityRisks,
    },
    activity: activityCapped,
    live,
  };
}

export function formatRelative(iso: string | null | undefined): string {
  if (!iso) return 'never';
  const then = Date.parse(iso);
  if (Number.isNaN(then)) return 'never';
  const diff = Date.now() - then;
  if (diff < 0) return 'just now';
  const sec = Math.floor(diff / 1000);
  if (sec < 45) return 'just now';
  const min = Math.floor(sec / 60);
  if (min < 2) return 'a minute ago';
  if (min < 60) return `${min} minutes ago`;
  const hr = Math.floor(min / 60);
  if (hr < 2) return 'an hour ago';
  if (hr < 24) return `${hr} hours ago`;
  const day = Math.floor(hr / 24);
  if (day < 2) return 'yesterday';
  if (day < 30) return `${day} days ago`;
  const mo = Math.floor(day / 30);
  if (mo < 2) return 'a month ago';
  if (mo < 12) return `${mo} months ago`;
  const yr = Math.floor(day / 365);
  return yr < 2 ? 'a year ago' : `${yr} years ago`;
}

export interface PassRateTone {
  text: string;
  ring: string;
  bg: string;
}

export function passRateTone(passRate: number | null): PassRateTone {
  if (passRate === null) {
    return { text: 'text-gray-400', ring: 'ring-gray-200', bg: 'bg-gray-50' };
  }
  if (passRate >= 0.8) {
    return { text: 'text-green-600', ring: 'ring-green-200', bg: 'bg-green-50' };
  }
  if (passRate >= 0.5) {
    return { text: 'text-amber-600', ring: 'ring-amber-200', bg: 'bg-amber-50' };
  }
  return { text: 'text-red-600', ring: 'ring-red-200', bg: 'bg-red-50' };
}
