import { useMemo, useState } from 'react';
import type { Fixture, TestCase, ManualStep, ResolutionPreset, LoopBinding, DriverLoopBinding } from '../../../../activator/types/state';
import { findBrokenRefs } from '../../../../activator/engine/referenceHelpers';
import { useStore } from '../../../store/state';
import type ActivatorProxy from '../../../store/ActivatorProxy';
import { ChevronDownIcon, ChevronRightIcon, DeleteIcon, EditIcon, PlusCircleIcon } from '../../../styles/Icons';
import StepAuthoringPanel, { ActionSelector } from './StepAuthoringPanel';
import LoopBindingsPanel from './LoopBindingsPanel';

interface Props {
  testCases: TestCase[];
  activator: ActivatorProxy;
  projectId: string;
  moduleId: string;
  featureId: string;
  fixtures: Fixture[];
  onEdit: (tc: TestCase) => void;
  onDelete: (testCaseId: string) => void;
  onUpdateTestCase: (
    testCaseId: string,
    patch: { dependsOnTestCaseId?: string | null; driverLoop?: DriverLoopBinding | null },
  ) => void;
  onPickForStep: (testCaseId: string, stepId: string) => void;
  onRefineWithAI: (tc: TestCase, stepIds: string[]) => void;
}

interface SelectedStep {
  testCaseId: string;
  stepId: string;
}

/**
 * Manual-mode testcase list. Renders the authoring surface for features whose
 * mode === 'manual'. This is the compact first cut: testcase expand/collapse,
 * per-step row showing toolName + title + producer/guard badges, add/delete/
 * reorder via up-down buttons.
 *
 * Later Phase 6 chunks layer on the right-hand step authoring panel, the
 * selector workbench, loop binding UI, and the references side panel.
 */
export default function ManualTestCaseList({
  testCases,
  activator,
  projectId,
  moduleId,
  featureId,
  fixtures,
  onEdit,
  onDelete,
  onUpdateTestCase,
  onPickForStep,
  onRefineWithAI,
}: Props) {
  const [expanded, setExpanded] = useState<Set<string>>(new Set());
  const [selected, setSelected] = useState<SelectedStep | null>(null);

  const toggle = (id: string) => {
    setExpanded((s) => {
      const next = new Set(s);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      return next;
    });
  };

  // Resolve the currently-selected step freshly on each render so panel edits
  // reflect through stateSync without local caching.
  const selectedView = useMemo(() => {
    if (!selected) return null;
    const tc = testCases.find((t) => t.id === selected.testCaseId);
    if (!tc) return null;
    const step = tc.manualSteps?.find((s) => s.id === selected.stepId);
    if (!step) return null;
    return { tc, step };
  }, [selected, testCases]);

  // Clear selection if the underlying step vanished (deleted upstream).
  if (selected && !selectedView) {
    setTimeout(() => setSelected(null), 0);
  }

  const fixtureColumnExists = (fixtureId: string, columnName: string): boolean => {
    const f = fixtures.find((x) => x.id === fixtureId);
    if (!f) return false;
    return f.columns.some((c) => c.name === columnName);
  };

  // Rollup broken-ref count across all testcases for the live region.
  const totalBroken = useMemo(() => {
    let total = 0;
    for (const tc of testCases) {
      total += findBrokenRefs(tc, tc.loopBindings ?? [], fixtureColumnExists).length;
    }
    return total;
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [testCases, fixtures]);

  if (testCases.length === 0) {
    return (
      <div className="rounded-lg border border-gray-200 bg-white p-6 text-center">
        <p className="text-xs text-gray-500">No test cases yet. Use the <strong>+ Add</strong> button above to create one.</p>
      </div>
    );
  }

  return (
    <div className="flex flex-col lg:flex-row lg:gap-3 lg:items-start">
      {/* Live region: announces broken-ref rollup to assistive tech. */}
      <span className="sr-only" aria-live="polite">
        {totalBroken === 0
          ? 'All references resolved.'
          : `${totalBroken} broken reference${totalBroken === 1 ? '' : 's'} across the feature.`}
      </span>
      <div className="flex-1 min-w-0 space-y-2">
      {testCases.map((tc) => {
        const isOpen = expanded.has(tc.id);
        const steps = tc.manualSteps ?? [];
        const loops: LoopBinding[] = tc.loopBindings ?? [];
        const broken = findBrokenRefs(tc, loops, fixtureColumnExists);
        const brokenByStep = new Map<string, number>();
        for (const b of broken) {
          brokenByStep.set(b.stepId, (brokenByStep.get(b.stepId) ?? 0) + 1);
        }
        return (
          <div
            key={tc.id}
            className="rounded-lg border border-gray-200 bg-white overflow-hidden"
          >
            {/* Testcase header */}
            <div className="flex items-center justify-between px-3 py-2 hover:bg-gray-50">
              <button
                type="button"
                onClick={() => toggle(tc.id)}
                className="flex items-center gap-1.5 flex-1 min-w-0 text-left"
                aria-expanded={isOpen}
                aria-controls={`tc-steps-${tc.id}`}
              >
                {isOpen ? (
                  <ChevronDownIcon className="w-3 h-3 text-gray-500 shrink-0" />
                ) : (
                  <ChevronRightIcon className="w-3 h-3 text-gray-500 shrink-0" />
                )}
                <div className="flex-1 min-w-0">
                  <div className="text-xs font-semibold text-gray-800 truncate">{tc.title}</div>
                  {tc.description && (
                    <div className="text-[10px] text-gray-500 truncate">{tc.description}</div>
                  )}
                </div>
                <span className="text-[10px] text-gray-400 shrink-0">
                  {steps.length} step{steps.length === 1 ? '' : 's'}
                </span>
              </button>
              <div className="flex items-center gap-1 ml-2 shrink-0">
                {broken.length > 0 && (
                  <span
                    className="px-1 py-0.5 text-[9px] font-semibold bg-red-100 text-red-700 rounded"
                    title={broken.map((b) => b.message).join('\n')}
                  >
                    {broken.length} broken
                  </span>
                )}
                <button
                  type="button"
                  onClick={() => onRefineWithAI(tc, steps.map((s) => s.id))}
                  className="px-1.5 py-0.5 text-[10px] font-semibold text-purple-600 hover:text-purple-800 hover:bg-purple-50 rounded"
                  title="Rewrite title/description from current steps (AI)"
                >
                  ✨
                </button>
                <button
                  type="button"
                  onClick={() => onEdit(tc)}
                  className="p-1 text-gray-500 hover:text-gray-800 hover:bg-gray-100 rounded"
                  aria-label={`Edit ${tc.title}`}
                  title="Edit testcase"
                >
                  <EditIcon className="w-3 h-3" />
                </button>
                <button
                  type="button"
                  onClick={() => onDelete(tc.id)}
                  className="p-1 text-gray-500 hover:text-red-600 hover:bg-red-50 rounded"
                  aria-label={`Delete ${tc.title}`}
                  title="Delete testcase"
                >
                  <DeleteIcon className="w-3 h-3" />
                </button>
              </div>
            </div>

            {isOpen && (
              <>
                <DependencyPicker
                  testCase={tc}
                  allTestCases={testCases}
                  onChange={(parentId) =>
                    onUpdateTestCase(tc.id, { dependsOnTestCaseId: parentId ?? null })
                  }
                />
                <DriverLoopControl
                  testCase={tc}
                  fixtures={fixtures.filter((f) => f.scope === 'project' || f.moduleId === moduleId)}
                  onChange={(loop) => onUpdateTestCase(tc.id, { driverLoop: loop })}
                />
                <div
                  id={`tc-steps-${tc.id}`}
                  className="border-t border-gray-100 bg-gray-50/50"
                >
                  <ManualStepList
                    testCase={tc}
                    steps={steps}
                    activator={activator}
                    projectId={projectId}
                    featureId={featureId}
                    brokenByStep={brokenByStep}
                    selectedStepId={
                      selected && selected.testCaseId === tc.id ? selected.stepId : null
                    }
                    onSelectStep={(stepId) =>
                      setSelected({ testCaseId: tc.id, stepId })
                    }
                  />
                </div>
                <LoopBindingsPanel
                  testCase={tc}
                  fixtures={fixtures.filter((f) => f.scope === 'project' || f.moduleId === moduleId)}
                  activator={activator}
                  projectId={projectId}
                  featureId={featureId}
                />
              </>
            )}
          </div>
        );
      })}
      </div>
      {selectedView && (
        <StepAuthoringPanel
          key={selectedView.step.id}
          testCase={selectedView.tc}
          step={selectedView.step}
          activator={activator}
          projectId={projectId}
          featureId={featureId}
          fixtures={fixtures}
          onClose={() => setSelected(null)}
          onLaunchPicker={() => onPickForStep(selectedView.tc.id, selectedView.step.id)}
        />
      )}
    </div>
  );
}

function DependencyPicker({
  testCase,
  allTestCases,
  onChange,
}: {
  testCase: TestCase;
  allTestCases: TestCase[];
  onChange: (parentId: string | null) => void;
}) {
  const parents = allTestCases.filter((t) => t.id !== testCase.id);
  if (parents.length === 0) return null;
  const current = testCase.dependsOnTestCaseId ?? '';
  return (
    <div className="flex items-center gap-1.5 px-3 py-1.5 border-t border-gray-100 bg-white text-[10px]">
      <label className="text-gray-500" htmlFor={`dep-${testCase.id}`}>
        Runs after
      </label>
      <select
        id={`dep-${testCase.id}`}
        value={current}
        onChange={(e) => onChange(e.target.value || null)}
        className="px-1.5 py-0.5 border border-gray-200 rounded text-[10px] min-w-0 max-w-[60%] truncate"
      >
        <option value="">— independent —</option>
        {parents.map((p) => (
          <option key={p.id} value={p.id}>
            {p.title}
          </option>
        ))}
      </select>
    </div>
  );
}

function DriverLoopControl({
  testCase,
  fixtures,
  onChange,
}: {
  testCase: TestCase;
  fixtures: Fixture[];
  onChange: (loop: DriverLoopBinding | null) => void;
}) {
  const loop = testCase.driverLoop;
  const enabled = !!loop;
  const fixtureId = loop?.fixtureId ?? '';
  const rowFilter = loop?.rowFilter ?? '';
  const stopOnFirstRowFailure = loop?.stopOnFirstRowFailure === true;

  const handleToggle = () => {
    if (enabled) {
      onChange(null);
    } else {
      const first = fixtures[0];
      if (!first) return;
      onChange({ fixtureId: first.id });
    }
  };

  const patch = (next: Partial<DriverLoopBinding>) => {
    if (!loop) return;
    const merged: DriverLoopBinding = { ...loop, ...next };
    if (merged.rowFilter === '') delete merged.rowFilter;
    if (merged.stopOnFirstRowFailure === false) delete merged.stopOnFirstRowFailure;
    onChange(merged);
  };

  const noFixtures = fixtures.length === 0;

  return (
    <div className="flex flex-col gap-1 px-3 py-1.5 border-t border-gray-100 bg-white text-[10px]">
      <div className="flex items-center gap-1.5">
        <input
          id={`dl-${testCase.id}`}
          type="checkbox"
          checked={enabled}
          disabled={!enabled && noFixtures}
          onChange={handleToggle}
          className="accent-orange-500"
        />
        <label htmlFor={`dl-${testCase.id}`} className="text-gray-600">
          Run this testcase and its dependents once per row of…
        </label>
        {noFixtures && !enabled && (
          <span className="text-gray-400 italic">(no fixtures uploaded)</span>
        )}
      </div>
      {enabled && (
        <div className="flex flex-wrap items-center gap-1.5 pl-5">
          <select
            value={fixtureId}
            onChange={(e) => patch({ fixtureId: e.target.value })}
            className="px-1.5 py-0.5 border border-gray-200 rounded text-[10px] min-w-0 max-w-[50%] truncate"
            aria-label="Driver loop fixture"
          >
            {!fixtures.some((f) => f.id === fixtureId) && (
              <option value={fixtureId}>— missing fixture —</option>
            )}
            {fixtures.map((f) => (
              <option key={f.id} value={f.id}>
                {f.filename}
              </option>
            ))}
          </select>
          <input
            value={rowFilter}
            onChange={(e) => patch({ rowFilter: e.target.value })}
            placeholder='Row filter (e.g. role == "admin")'
            className="flex-1 min-w-35 px-1.5 py-0.5 border border-gray-200 rounded text-[10px] focus:outline-none focus:ring-1 focus:ring-orange-300"
            aria-label="Row filter expression"
          />
          <label className="flex items-center gap-1 text-gray-600">
            <input
              type="checkbox"
              checked={stopOnFirstRowFailure}
              onChange={(e) => patch({ stopOnFirstRowFailure: e.target.checked })}
              className="accent-orange-500"
            />
            Stop on first row failure
          </label>
        </div>
      )}
    </div>
  );
}

interface StepListProps {
  testCase: TestCase;
  steps: ManualStep[];
  activator: ActivatorProxy;
  projectId: string;
  featureId: string;
  brokenByStep: Map<string, number>;
  selectedStepId: string | null;
  onSelectStep: (stepId: string) => void;
}

function ManualStepList({
  testCase,
  steps,
  activator,
  projectId,
  featureId,
  brokenByStep,
  selectedStepId,
  onSelectStep,
}: StepListProps) {
  const [addingStep, setAddingStep] = useState(false);
  const [toolName, setToolName] = useState('');
  const [title, setTitle] = useState('');
  const [nlText, setNlText] = useState('');
  const [checkedIds, setCheckedIds] = useState<Set<string>>(new Set());
  const [collapsedGroups, setCollapsedGroups] = useState<Set<string>>(new Set());
  const [dragFromId, setDragFromId] = useState<string | null>(null);
  const browserConnected = useStore((s) => s.session.browserConnected);
  const proposed = useStore((s) =>
    s.proposedManualSteps.find((p) => p.testCaseId === testCase.id),
  );
  const clearProposed = useStore((s) => s.clearProposedManualStep);

  const toggleChecked = (stepId: string) => {
    setCheckedIds((s) => {
      const next = new Set(s);
      if (next.has(stepId)) next.delete(stepId);
      else next.add(stepId);
      return next;
    });
  };

  const bulkDelete = () => {
    for (const id of checkedIds) {
      activator.deleteManualStep(projectId, featureId, testCase.id, id);
    }
    setCheckedIds(new Set());
  };

  const bulkToggleEnabled = (enabled: boolean) => {
    for (const id of checkedIds) {
      activator.updateManualStep(projectId, featureId, testCase.id, id, { enabled });
    }
    setCheckedIds(new Set());
  };

  const toggleGroup = (group: string) => {
    setCollapsedGroups((s) => {
      const next = new Set(s);
      if (next.has(group)) next.delete(group);
      else next.add(group);
      return next;
    });
  };

  const handleDragStart = (stepId: string) => setDragFromId(stepId);
  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };
  const handleDrop = (targetStepId: string) => {
    if (!dragFromId || dragFromId === targetStepId) {
      setDragFromId(null);
      return;
    }
    const srcIdx = steps.findIndex((s) => s.id === dragFromId);
    const dstIdx = steps.findIndex((s) => s.id === targetStepId);
    if (srcIdx < 0 || dstIdx < 0) {
      setDragFromId(null);
      return;
    }
    const next = steps.slice();
    const [item] = next.splice(srcIdx, 1);
    next.splice(dstIdx, 0, item);
    activator.reorderManualSteps(projectId, featureId, testCase.id, next.map((s) => s.id));
    setDragFromId(null);
  };

  // Preserve authored order while collecting into groups.
  const grouped: Array<{ group: string | null; steps: Array<{ step: ManualStep; index: number }> }> = [];
  for (let i = 0; i < steps.length; i++) {
    const s = steps[i];
    const g = s.group ?? null;
    const last = grouped[grouped.length - 1];
    if (last && last.group === g) {
      last.steps.push({ step: s, index: i });
    } else {
      grouped.push({ group: g, steps: [{ step: s, index: i }] });
    }
  }

  // Seed sensible default parameters for common tools so the authoring panel
  // has real fields to edit right after Add — instead of the user having to
  // type parameter names by hand.
  const defaultToolArgsFor = (name: string): Record<string, unknown> => {
    switch (name) {
      case 'browser_launch':      return { preset: 'desktop', url: '' };
      case 'browser_navigate':    return { url: '' };
      case 'browser_resize_preset': return { preset: 'desktop' };
      case 'browser_click':
      case 'browser_double_click':
      case 'browser_right_click':
      case 'browser_hover':
      case 'browser_focus':
      case 'browser_check':
      case 'browser_uncheck':
      case 'browser_scroll_into_view':
      case 'browser_wait_for':    return { selector: '' };
      case 'browser_fill':        return { selector: '', value: '' };
      case 'browser_type':        return { text: '' };
      case 'browser_press_key':   return { key: 'Enter' };
      case 'browser_select_option': return { selector: '', value: '' };
      case 'browser_file_upload': return { selector: '', path: '' };
      case 'browser_wait_for_url': return { pattern: '' };
      case 'wait':                return { duration: 1000 };
      case 'assert_text':         return { selector: '', expected: '' };
      case 'assert_visible':
      case 'assert_enabled':
      case 'assert_checked':      return { selector: '' };
      case 'assert_url':          return { pattern: '' };
      case 'assert_title':        return { expected: '' };
      case 'assert_value':        return { selector: '', expected: '' };
      case 'retain_text':
      case 'retain_value':        return { selector: '' };
      case 'retain_attribute':    return { selector: '', name: '' };
      case 'expect_previous_step_network': return { urlPattern: '', urlMatch: 'contains' };
      case 'run_sandboxed_js':    return { script: '' };
      case 'manual_pause':        return { message: '' };
      default:                    return {};
    }
  };

  const addStepWithTool = (nextToolName: string, titleOverride?: string) => {
    const name = nextToolName.trim();
    if (!name) return;
    const step: ManualStep = {
      id: `mstep_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`,
      toolName: name,
      toolArgs: defaultToolArgsFor(name),
      title: (titleOverride ?? title).trim() || undefined,
      enabled: true,
    };
    activator.addManualStep(projectId, featureId, testCase.id, step);
    setToolName('');
    setTitle('');
    setAddingStep(false);
    onSelectStep(step.id);
  };

  const handleAdd = () => addStepWithTool(toolName);

  const handleDelete = (stepId: string) => {
    activator.deleteManualStep(projectId, featureId, testCase.id, stepId);
  };

  const handleMove = (index: number, dir: -1 | 1) => {
    const target = index + dir;
    if (target < 0 || target >= steps.length) return;
    const next = steps.slice();
    const [item] = next.splice(index, 1);
    next.splice(target, 0, item);
    activator.reorderManualSteps(projectId, featureId, testCase.id, next.map((s) => s.id));
  };

  const handleToggleEnabled = (step: ManualStep) => {
    activator.updateManualStep(projectId, featureId, testCase.id, step.id, {
      enabled: step.enabled === false ? true : false,
    });
  };

  const handleNlSubmit = () => {
    const text = nlText.trim();
    if (!text || !browserConnected) return;
    activator.generateStepFromNL(projectId, featureId, testCase.id, text);
    setNlText('');
  };

  const acceptProposed = () => {
    if (!proposed) return;
    activator.addManualStep(projectId, featureId, testCase.id, proposed.step);
    clearProposed(testCase.id);
    onSelectStep(proposed.step.id);
  };

  const rejectProposed = () => {
    if (!proposed) return;
    clearProposed(testCase.id);
  };

  return (
    <div className="px-2 py-2">
      {/* Natural-language step input (§3.4). Disabled until browser session active. */}
      <div className="mb-2 flex items-center gap-1.5">
        <input
          value={nlText}
          onChange={(e) => setNlText(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') {
              e.preventDefault();
              handleNlSubmit();
            }
          }}
          disabled={!browserConnected}
          placeholder={
            browserConnected
              ? 'Describe a step in plain English (e.g. "click Save in the header")'
              : 'Launch a browser to enable natural-language step input'
          }
          className="flex-1 min-w-0 px-2 py-1 border border-gray-200 rounded text-[11px] focus:outline-none focus:ring-1 focus:ring-orange-300 disabled:bg-gray-50 disabled:text-gray-400"
          aria-label="Natural-language step input"
        />
        <button
          type="button"
          onClick={handleNlSubmit}
          disabled={!browserConnected || !nlText.trim()}
          className="px-2 py-1 text-[10px] font-semibold bg-purple-500 text-white rounded hover:bg-purple-600 disabled:opacity-40"
        >
          ✨ Propose
        </button>
      </div>

      {/* Proposed-step review banner */}
      {proposed && (
        <div className="mb-2 rounded border border-purple-300 bg-purple-50 p-2 text-[11px]">
          <div className="font-semibold text-purple-700 mb-1">
            Proposed step ({proposed.source === 'nl' ? 'natural language' : 'refine'})
          </div>
          <div className="mb-1">
            <span className="font-mono text-[10px] text-orange-600">{proposed.step.toolName}</span>
            {proposed.step.title && <span className="text-gray-700"> — {proposed.step.title}</span>}
          </div>
          <div className="flex items-center gap-1.5">
            <button
              type="button"
              onClick={acceptProposed}
              className="px-2 py-0.5 text-[10px] font-semibold bg-orange-500 text-white rounded hover:bg-orange-600"
            >
              Accept
            </button>
            <button
              type="button"
              onClick={rejectProposed}
              className="px-2 py-0.5 text-[10px] bg-gray-100 text-gray-600 rounded hover:bg-gray-200"
            >
              Reject
            </button>
          </div>
        </div>
      )}

      {/* Bulk action toolbar */}
      {checkedIds.size > 0 && (
        <div className="mb-2 flex items-center gap-1.5 rounded border border-orange-300 bg-orange-50 px-2 py-1 text-[10px]" role="toolbar" aria-label="Bulk step actions">
          <span className="font-semibold text-orange-700" aria-live="polite">
            {checkedIds.size} selected
          </span>
          <div className="flex-1" />
          <button
            type="button"
            onClick={() => bulkToggleEnabled(true)}
            className="px-1.5 py-0.5 bg-white text-gray-700 border border-gray-200 rounded hover:bg-gray-50"
          >
            Enable
          </button>
          <button
            type="button"
            onClick={() => bulkToggleEnabled(false)}
            className="px-1.5 py-0.5 bg-white text-gray-700 border border-gray-200 rounded hover:bg-gray-50"
          >
            Disable
          </button>
          <button
            type="button"
            onClick={bulkDelete}
            className="px-1.5 py-0.5 bg-red-500 text-white rounded hover:bg-red-600"
          >
            Delete
          </button>
          <button
            type="button"
            onClick={() => setCheckedIds(new Set())}
            className="px-1.5 py-0.5 text-gray-500 hover:text-gray-800"
          >
            Clear
          </button>
        </div>
      )}

      {steps.length === 0 ? (
        <p className="text-[11px] text-gray-400 italic px-1 py-2">
          No steps. Add one below to start authoring.
        </p>
      ) : (
        <div className="space-y-1">
          {grouped.map((bucket, bi) => {
            const groupKey = bucket.group ?? `__ungrouped_${bi}`;
            const isCollapsed = bucket.group ? collapsedGroups.has(bucket.group) : false;
            return (
              <div key={groupKey}>
                {bucket.group && (
                  <button
                    type="button"
                    onClick={() => toggleGroup(bucket.group!)}
                    className="w-full flex items-center gap-1 px-1 py-0.5 text-[9px] uppercase tracking-wider text-gray-500 font-semibold hover:text-gray-800"
                    aria-expanded={!isCollapsed}
                  >
                    {isCollapsed ? (
                      <ChevronRightIcon className="w-3 h-3" />
                    ) : (
                      <ChevronDownIcon className="w-3 h-3" />
                    )}
                    {bucket.group} <span className="text-gray-400 normal-case">({bucket.steps.length})</span>
                  </button>
                )}
                {!isCollapsed && (
                  <ol className="space-y-1">
                    {bucket.steps.map(({ step, index: i }) => (
                      <li key={step.id}>
                        <StepRow
                          step={step}
                          index={i}
                          total={steps.length}
                          selected={step.id === selectedStepId}
                          checked={checkedIds.has(step.id)}
                          brokenCount={brokenByStep.get(step.id) ?? 0}
                          onCheck={() => toggleChecked(step.id)}
                          onSelect={() => onSelectStep(step.id)}
                          onMove={(dir) => handleMove(i, dir)}
                          onDelete={() => handleDelete(step.id)}
                          onToggleEnabled={() => handleToggleEnabled(step)}
                          onDragStart={() => handleDragStart(step.id)}
                          onDragOver={handleDragOver}
                          onDrop={() => handleDrop(step.id)}
                        />
                      </li>
                    ))}
                  </ol>
                )}
              </div>
            );
          })}
        </div>
      )}

      {addingStep ? (
        <div className="mt-2 rounded border border-gray-200 bg-white p-2 space-y-1.5">
          <div className="text-[10px] font-semibold text-gray-600">Add step</div>

          <div>
            <div className="text-[9px] uppercase tracking-wider text-gray-500 font-semibold mb-0.5">Action</div>
            <ActionSelector value={toolName} onChange={(n) => setToolName(n)} />
          </div>

          <div>
            <div className="text-[9px] uppercase tracking-wider text-gray-500 font-semibold mb-0.5">Title (optional)</div>
            <input
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="Short label"
              className="w-full px-2 py-1 border border-gray-200 rounded text-[11px] focus:outline-none focus:ring-1 focus:ring-orange-300"
              aria-label="Step title"
            />
          </div>

          <div className="flex items-center gap-1.5 pt-0.5">
            <button
              type="button"
              onClick={handleAdd}
              disabled={!toolName.trim()}
              className="px-2 py-1 text-[10px] font-semibold bg-orange-500 text-white rounded hover:bg-orange-600 disabled:opacity-40"
            >
              Add
            </button>
            <button
              type="button"
              onClick={() => {
                setAddingStep(false);
                setToolName('');
                setTitle('');
              }}
              className="px-2 py-1 text-[10px] bg-gray-100 text-gray-600 rounded hover:bg-gray-200"
            >
              Cancel
            </button>
            <p className="text-[9px] text-gray-400 ml-auto">
              Parameters open in the right-hand panel after Add.
            </p>
          </div>
        </div>
      ) : (
        <div className="mt-2 space-y-1.5">
          {/* Quick-start chips — surfaces the most common tools so a brand-new
              testcase has an obvious first click. Each chip adds the step AND
              opens the authoring panel with pre-seeded parameters. */}
          <div className="flex items-center flex-wrap gap-1 rounded border border-dashed border-gray-200 bg-gray-50/60 px-2 py-1">
            <span className="text-[9px] uppercase tracking-wider text-gray-500 font-semibold mr-1">Quick add</span>
            {[
              { name: 'browser_launch',   label: 'Launch browser' },
              { name: 'browser_navigate', label: 'Navigate' },
              { name: 'browser_click',    label: 'Click' },
              { name: 'browser_fill',     label: 'Fill' },
              { name: 'browser_wait_for', label: 'Wait for' },
              { name: 'assert_visible',   label: 'Assert visible' },
              { name: 'assert_text',      label: 'Assert text' },
              { name: 'retain_text',      label: 'Retain text' },
            ].map((item) => (
              <button
                key={item.name}
                type="button"
                onClick={() => addStepWithTool(item.name, item.label)}
                className="px-1.5 py-0.5 text-[10px] bg-white border border-gray-200 rounded hover:border-orange-300 hover:text-orange-700 text-gray-700"
                title={item.name}
              >
                + {item.label}
              </button>
            ))}
          </div>

          <button
            type="button"
            onClick={() => setAddingStep(true)}
            className="w-full flex items-center justify-center gap-1 px-2 py-1.5 text-[10px] font-medium text-gray-600 border border-dashed border-gray-300 rounded hover:bg-white hover:border-gray-400"
          >
            <PlusCircleIcon className="w-3 h-3" />
            Add step (browse all actions)
          </button>
        </div>
      )}
    </div>
  );
}

interface StepRowProps {
  step: ManualStep;
  index: number;
  total: number;
  selected: boolean;
  checked: boolean;
  brokenCount: number;
  onCheck: () => void;
  onSelect: () => void;
  onMove: (dir: -1 | 1) => void;
  onDelete: () => void;
  onToggleEnabled: () => void;
  onDragStart: () => void;
  onDragOver: (e: React.DragEvent) => void;
  onDrop: () => void;
}

function StepRow({
  step,
  index,
  total,
  selected,
  checked,
  brokenCount,
  onCheck,
  onSelect,
  onMove,
  onDelete,
  onToggleEnabled,
  onDragStart,
  onDragOver,
  onDrop,
}: StepRowProps) {
  const disabled = step.enabled === false;
  const guardPresets: ResolutionPreset[] = step.resolutionGuard?.presets ?? [];
  const borderClass = selected
    ? 'border-orange-300 bg-orange-50/60'
    : disabled
      ? 'border-gray-200 bg-gray-100/60 text-gray-400'
      : 'border-gray-200 bg-white text-gray-700';
  return (
    <div
      draggable
      onDragStart={onDragStart}
      onDragOver={onDragOver}
      onDrop={onDrop}
      className={`flex items-center gap-1.5 px-2 py-1.5 rounded border text-[11px] cursor-grab active:cursor-grabbing ${borderClass}`}
    >
      <input
        type="checkbox"
        checked={checked}
        onChange={onCheck}
        onClick={(e) => e.stopPropagation()}
        className="accent-orange-500 shrink-0"
        aria-label={`Select step ${index + 1} for bulk action`}
      />
      <button
        type="button"
        onClick={onSelect}
        className="shrink-0 w-5 text-right font-mono text-[10px] text-gray-400 hover:text-gray-600"
        aria-label={`Open step ${index + 1} authoring panel`}
      >
        {index + 1}.
      </button>
      <button
        type="button"
        onClick={onSelect}
        className="flex-1 min-w-0 text-left"
        aria-pressed={selected}
      >
        <div className="flex items-center gap-1.5 min-w-0">
          <span className="font-mono text-[10px] text-orange-600 truncate">{step.toolName}</span>
          {step.title && (
            <span className="truncate text-gray-800">— {step.title}</span>
          )}
        </div>
        {(step.isProducer || guardPresets.length > 0 || step.optional || brokenCount > 0) && (
          <div className="flex items-center gap-1 mt-0.5 flex-wrap">
            {brokenCount > 0 && (
              <span
                className="px-1 py-0.5 text-[9px] font-semibold bg-red-100 text-red-700 rounded"
                title={`${brokenCount} broken reference${brokenCount === 1 ? '' : 's'}`}
              >
                {brokenCount} broken
              </span>
            )}
            {step.isProducer && (
              <span
                className="px-1 py-0.5 text-[9px] font-semibold bg-purple-100 text-purple-700 rounded"
                title="This step produces a value that later steps can reference"
              >
                producer
              </span>
            )}
            {step.optional && (
              <span className="px-1 py-0.5 text-[9px] font-semibold bg-yellow-100 text-yellow-700 rounded">
                optional
              </span>
            )}
            {guardPresets.map((p) => (
              <span
                key={p}
                className="px-1 py-0.5 text-[9px] font-medium bg-blue-100 text-blue-700 rounded"
                title={`Runs only on ${p} preset`}
              >
                {p}
              </span>
            ))}
          </div>
        )}
      </button>
      <div className="flex items-center gap-0.5 shrink-0">
        <button
          type="button"
          onClick={() => onMove(-1)}
          disabled={index === 0}
          className="p-0.5 text-gray-400 hover:text-gray-800 disabled:opacity-30 disabled:cursor-not-allowed"
          aria-label="Move step up"
          title="Move up"
        >
          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 15l7-7 7 7" />
          </svg>
        </button>
        <button
          type="button"
          onClick={() => onMove(1)}
          disabled={index === total - 1}
          className="p-0.5 text-gray-400 hover:text-gray-800 disabled:opacity-30 disabled:cursor-not-allowed"
          aria-label="Move step down"
          title="Move down"
        >
          <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" />
          </svg>
        </button>
        <button
          type="button"
          onClick={onToggleEnabled}
          className="px-1 py-0.5 text-[9px] text-gray-500 hover:text-gray-800 rounded"
          aria-label={disabled ? 'Enable step' : 'Disable step'}
          title={disabled ? 'Enable step' : 'Disable step'}
        >
          {disabled ? 'on' : 'off'}
        </button>
        <button
          type="button"
          onClick={onDelete}
          className="p-0.5 text-gray-400 hover:text-red-600"
          aria-label="Delete step"
          title="Delete step"
        >
          <DeleteIcon className="w-3 h-3" />
        </button>
      </div>
    </div>
  );
}
