import { useParams } from 'react-router-dom';
import { useStore } from '../../store/state';
import ComparisonView from './ComparisonView';

export default function FeatureComparison() {
  const { projectId, moduleId, featureId } = useParams<{ projectId: string; moduleId: string; featureId: string }>();
  const project = useStore(s => s.projects.find(p => p.id === projectId));
  const mod = project?.modules.find(m => m.id === moduleId);
  const feature = mod?.features.find(f => f.id === featureId);

  if (!project || !mod || !feature) {
    return (
      <div className="w-full px-4 py-8">
        <div className="rounded-2xl border border-gray-200 bg-white p-8 text-center text-gray-500">Feature not found</div>
      </div>
    );
  }

  return (
    <ComparisonView
      scope={{ projectId: project.id, moduleId: mod.id, featureId: feature.id }}
      title={`Compare — ${feature.name}`}
      subtitle={`Feature-level comparison · ${mod.name}`}
      backTo={`/project/${project.id}/module/${mod.id}/feature/${feature.id}`}
    />
  );
}
