import { useMemo } from 'react';
import { useStore } from '../../../store/state';
import type {
  ChartDiff,
  FormDiff,
  SectionDiff,
  StyleDiff,
  TableDiff,
} from '../../../../activator/engine/comparison/types';

interface Props {
  artifactKey: string;
  runId: string;
  sideLabels: { left: string; right: string };
  onClose: () => void;
}

type AnyDiff = TableDiff | FormDiff | ChartDiff | SectionDiff | StyleDiff;

/**
 * Bottom-sheet modal showing the exact per-row / per-cell / per-header
 * differences for a given diff artifact. It pulls the diff payload from
 * whichever step produced it — the comparison engine records every compare_*
 * tool result under its owning test case, so the detail is already in the
 * store without needing a round-trip.
 */
export default function ComparisonDiffDetailModal({ artifactKey, sideLabels, onClose }: Props) {
  const testCasesByState = useStore((s) => s.comparisonV2TestCasesByState);

  const diff = useMemo<AnyDiff | null>(() => {
    for (const list of Object.values(testCasesByState)) {
      for (const tc of list) {
        for (const step of tc.steps) {
          if (!step.toolName.startsWith('compare_')) continue;
          if ((step.toolArgs as { diffArtifactKey?: string }).diffArtifactKey !== artifactKey) continue;
          const data = unwrapResult(step.result);
          if (data && typeof data === 'object' && 'kind' in data) return data as AnyDiff;
        }
      }
    }
    return null;
  }, [testCasesByState, artifactKey]);

  const handleBackdrop = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) onClose();
  };

  return (
    <div className="fixed inset-0 bg-[rgba(0,0,0,0.5)] flex items-end z-50" onClick={handleBackdrop}>
      <div className="bg-white rounded-t-2xl shadow-xl w-full min-h-[55vh] max-h-[85vh] overflow-hidden flex flex-col">
        <div className="sticky top-0 bg-white border-b border-gray-200 px-4 py-3 shrink-0">
          <div className="w-12 h-1 bg-gray-300 rounded-full mx-auto mb-2" />
          <div className="flex items-center justify-between gap-2">
            <div className="flex items-center gap-2 min-w-0">
              <h2 className="text-sm font-semibold text-gray-800 truncate">
                Diff — <span className="font-mono text-xs">{artifactKey}</span>
              </h2>
              {diff && (
                <span
                  className={`px-1.5 py-0.5 rounded text-[10px] uppercase font-semibold text-white ${
                    diff.verdict === 'match' ? 'bg-green-600' : 'bg-red-600'
                  }`}
                >
                  {diff.verdict}
                </span>
              )}
            </div>
            <button onClick={onClose} className="text-gray-400 hover:text-gray-600 p-1 cursor-pointer shrink-0">
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-4 text-sm">
          {!diff && (
            <p className="text-gray-500">
              Diff data not found in the live run. This happens when the comparison was produced in an earlier run —
              download the Markdown report from the Diffs panel to see the full breakdown.
            </p>
          )}
          {diff?.kind === 'table_diff' && <TableDiffBody diff={diff} labels={sideLabels} />}
          {diff?.kind === 'form_diff' && <FormDiffBody diff={diff} labels={sideLabels} />}
          {diff?.kind === 'chart_diff' && <ChartDiffBody diff={diff} labels={sideLabels} />}
          {diff?.kind === 'section_diff' && <SectionDiffBody diff={diff} labels={sideLabels} />}
          {diff?.kind === 'style_diff' && <StyleDiffBody diff={diff} labels={sideLabels} />}
        </div>
      </div>
    </div>
  );
}

function Section({ title, children }: { title: string; children: React.ReactNode }) {
  return (
    <div>
      <h3 className="text-xs font-semibold text-gray-500 uppercase mb-2">{title}</h3>
      <div className="rounded-lg border border-gray-200 bg-gray-50/60 p-3 space-y-1">{children}</div>
    </div>
  );
}

function unwrapResult(result: unknown): unknown {
  if (!result || typeof result !== 'object') return result;
  const r = result as { success?: unknown; data?: unknown };
  if ('data' in r) return r.data;
  return result;
}

function TableDiffBody({ diff, labels }: { diff: TableDiff; labels: { left: string; right: string } }) {
  return (
    <>
      {diff.titleMismatch && (
        <Section title="Title">
          <p>
            <b>{labels.left}:</b> "{diff.titleMismatch.left}"
          </p>
          <p>
            <b>{labels.right}:</b> "{diff.titleMismatch.right}"
          </p>
        </Section>
      )}

      {diff.headerMismatches.length > 0 && (
        <Section title="Header differences">
          {diff.headerMismatches.map((h, i) => (
            <p key={i}>
              <span className="font-mono text-xs text-gray-500">{h.canonical}:</span> "{h.leftRaw || '(empty)'}" ({labels.left}) vs "
              {h.rightRaw || '(empty)'}" ({labels.right})
            </p>
          ))}
        </Section>
      )}

      {(diff.missingColumnsOnLeft.length > 0 || diff.missingColumnsOnRight.length > 0) && (
        <Section title="Missing columns">
          {diff.missingColumnsOnLeft.length > 0 && (
            <p>
              Missing on <b>{labels.left}:</b> {diff.missingColumnsOnLeft.join(', ')}
            </p>
          )}
          {diff.missingColumnsOnRight.length > 0 && (
            <p>
              Missing on <b>{labels.right}:</b> {diff.missingColumnsOnRight.join(', ')}
            </p>
          )}
        </Section>
      )}

      {diff.rowCountMismatch && (
        <Section title="Row counts">
          <p>
            <b>{labels.left}:</b> {diff.rowCountMismatch.left} rows — <b>{labels.right}:</b> {diff.rowCountMismatch.right} rows
          </p>
        </Section>
      )}

      {(diff.extraRowsOnLeftDetail?.length || diff.extraRowsOnRightDetail?.length) && (
        <Section title="Extra rows — content">
          {diff.extraRowsOnLeftDetail && diff.extraRowsOnLeftDetail.length > 0 && (
            <ExtraRowsTable label={labels.left} rows={diff.extraRowsOnLeftDetail} />
          )}
          {diff.extraRowsOnRightDetail && diff.extraRowsOnRightDetail.length > 0 && (
            <ExtraRowsTable label={labels.right} rows={diff.extraRowsOnRightDetail} />
          )}
        </Section>
      )}

      {diff.rowDiffs.length > 0 && (
        <Section title={`Rows with differences (${diff.rowDiffs.length})`}>
          <RowDiffTable rows={diff.rowDiffs} labels={labels} />
        </Section>
      )}
    </>
  );
}

function formatSources(list?: string[]): string {
  if (!list || list.length === 0) return '';
  return ` [from: ${list.join(', ')}]`;
}

function RowDiffTable({
  rows,
  labels,
}: {
  rows: TableDiff['rowDiffs'];
  labels: { left: string; right: string };
}) {
  return (
    <div className="overflow-x-auto">
      <table className="w-full text-xs border-collapse">
        <thead>
          <tr className="bg-gray-100 text-left">
            <th className="p-1.5 border border-gray-200">Row</th>
            <th className="p-1.5 border border-gray-200">Column</th>
            <th className="p-1.5 border border-gray-200">Kind</th>
            <th className="p-1.5 border border-gray-200">{labels.left}</th>
            <th className="p-1.5 border border-gray-200">{labels.right}</th>
          </tr>
        </thead>
        <tbody>
          {rows.slice(0, 200).flatMap((r) => {
            const label = r.keyLabel || `#${r.index + 1}`;
            const out: React.ReactNode[] = [];
            r.cells.forEach((c, ci) => {
              if (c.visibleMismatch) {
                out.push(
                  <tr key={`${r.index}-${ci}-v`}>
                    <td className="p-1.5 border border-gray-200 font-mono">{label}</td>
                    <td className="p-1.5 border border-gray-200">{c.column}</td>
                    <td className="p-1.5 border border-gray-200">visible</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{c.visibleMismatch.left}{formatSources(c.visibleMismatch.leftSources)}</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{c.visibleMismatch.right}{formatSources(c.visibleMismatch.rightSources)}</td>
                  </tr>,
                );
              }
              if (c.hiddenMismatch) {
                out.push(
                  <tr key={`${r.index}-${ci}-h`}>
                    <td className="p-1.5 border border-gray-200 font-mono">{label}</td>
                    <td className="p-1.5 border border-gray-200">{c.column}</td>
                    <td className="p-1.5 border border-gray-200">hidden</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{c.hiddenMismatch.left}{formatSources(c.hiddenMismatch.leftSources)}</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{c.hiddenMismatch.right}{formatSources(c.hiddenMismatch.rightSources)}</td>
                  </tr>,
                );
              }
              if (c.ariaMismatch) {
                out.push(
                  <tr key={`${r.index}-${ci}-a`}>
                    <td className="p-1.5 border border-gray-200 font-mono">{label}</td>
                    <td className="p-1.5 border border-gray-200">{c.column}</td>
                    <td className="p-1.5 border border-gray-200">aria-label</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{c.ariaMismatch.left}{formatSources(c.ariaMismatch.leftSources)}</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{c.ariaMismatch.right}{formatSources(c.ariaMismatch.rightSources)}</td>
                  </tr>,
                );
              }
              if (c.titleMismatch) {
                out.push(
                  <tr key={`${r.index}-${ci}-t`}>
                    <td className="p-1.5 border border-gray-200 font-mono">{label}</td>
                    <td className="p-1.5 border border-gray-200">{c.column}</td>
                    <td className="p-1.5 border border-gray-200">title</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{c.titleMismatch.left}</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{c.titleMismatch.right}</td>
                  </tr>,
                );
              }
              if (c.altMismatch) {
                out.push(
                  <tr key={`${r.index}-${ci}-al`}>
                    <td className="p-1.5 border border-gray-200 font-mono">{label}</td>
                    <td className="p-1.5 border border-gray-200">{c.column}</td>
                    <td className="p-1.5 border border-gray-200">alt</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{c.altMismatch.left}</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{c.altMismatch.right}</td>
                  </tr>,
                );
              }
              if (c.styleMismatch) {
                for (const [prop, sm] of Object.entries(c.styleMismatch)) {
                  if (!sm) continue;
                  out.push(
                    <tr key={`${r.index}-${ci}-s-${prop}`}>
                      <td className="p-1.5 border border-gray-200 font-mono">{label}</td>
                      <td className="p-1.5 border border-gray-200">{c.column}</td>
                      <td className="p-1.5 border border-gray-200">style: {prop}</td>
                      <td className="p-1.5 border border-gray-200 text-red-700">{sm.left ?? ''}</td>
                      <td className="p-1.5 border border-gray-200 text-red-700">{sm.right ?? ''}</td>
                    </tr>,
                  );
                }
              }
            });
            (r.decorations ?? []).forEach((dec, di) => {
              if (dec.missingOnLeft?.length) {
                out.push(
                  <tr key={`${r.index}-dec-l-${di}`}>
                    <td className="p-1.5 border border-gray-200 font-mono">{label}</td>
                    <td className="p-1.5 border border-gray-200">{dec.column}</td>
                    <td className="p-1.5 border border-gray-200">decoration</td>
                    <td className="p-1.5 border border-gray-200 italic text-gray-500">missing</td>
                    <td className="p-1.5 border border-gray-200">{dec.missingOnLeft.join(', ')}</td>
                  </tr>,
                );
              }
              if (dec.missingOnRight?.length) {
                out.push(
                  <tr key={`${r.index}-dec-r-${di}`}>
                    <td className="p-1.5 border border-gray-200 font-mono">{label}</td>
                    <td className="p-1.5 border border-gray-200">{dec.column}</td>
                    <td className="p-1.5 border border-gray-200">decoration</td>
                    <td className="p-1.5 border border-gray-200">{dec.missingOnRight.join(', ')}</td>
                    <td className="p-1.5 border border-gray-200 italic text-gray-500">missing</td>
                  </tr>,
                );
              }
            });
            return out;
          })}
        </tbody>
      </table>
      {rows.length > 200 && (
        <p className="mt-2 text-[11px] text-gray-500">…and {rows.length - 200} more rows. Download the Markdown report for the full list.</p>
      )}
    </div>
  );
}

function ExtraRowsTable({
  label,
  rows,
}: {
  label: string;
  rows: NonNullable<TableDiff['extraRowsOnLeftDetail']>;
}) {
  // Build a column list from the union of keys across the rows, preserving first-seen order.
  const columns: string[] = [];
  const seen = new Set<string>();
  for (const r of rows) {
    for (const k of Object.keys(r.cells)) {
      if (!seen.has(k)) { seen.add(k); columns.push(k); }
    }
  }
  return (
    <div>
      <p className="text-[11px] text-gray-600 mb-1">
        <b>{label}</b> has {rows.length} row(s) not present on the other side:
      </p>
      <div className="overflow-x-auto">
        <table className="w-full text-xs border-collapse">
          <thead>
            <tr className="bg-gray-100 text-left">
              <th className="p-1.5 border border-gray-200">Row</th>
              {columns.map((c) => (<th key={c} className="p-1.5 border border-gray-200">{c}</th>))}
            </tr>
          </thead>
          <tbody>
            {rows.slice(0, 100).map((r, i) => (
              <tr key={i}>
                <td className="p-1.5 border border-gray-200 font-mono">{r.keyLabel || `#${r.index + 1}`}</td>
                {columns.map((c) => (<td key={c} className="p-1.5 border border-gray-200">{r.cells[c] ?? ''}</td>))}
              </tr>
            ))}
          </tbody>
        </table>
        {rows.length > 100 && (
          <p className="mt-2 text-[11px] text-gray-500">…and {rows.length - 100} more rows. Download the Markdown report for the full list.</p>
        )}
      </div>
    </div>
  );
}

function FormDiffBody({ diff, labels }: { diff: FormDiff; labels: { left: string; right: string } }) {
  return (
    <>
      {diff.titleMismatch && (
        <Section title="Title">
          <p><b>{labels.left}:</b> "{diff.titleMismatch.left}"</p>
          <p><b>{labels.right}:</b> "{diff.titleMismatch.right}"</p>
        </Section>
      )}
      {diff.tabMismatches.length > 0 && (
        <Section title="Tab labels">
          {diff.tabMismatches.map((t, i) => (<p key={i}>{t}</p>))}
        </Section>
      )}
      {(diff.missingFieldsOnLeft.length > 0 || diff.missingFieldsOnRight.length > 0) && (
        <Section title="Missing fields">
          {diff.missingFieldsOnLeft.length > 0 && <p>Missing on <b>{labels.left}:</b> {diff.missingFieldsOnLeft.join(', ')}</p>}
          {diff.missingFieldsOnRight.length > 0 && <p>Missing on <b>{labels.right}:</b> {diff.missingFieldsOnRight.join(', ')}</p>}
        </Section>
      )}
      {diff.fieldDiffs.length > 0 && (
        <Section title={`Field differences (${diff.fieldDiffs.length})`}>
          {diff.fieldDiffs.map((f, i) => (
            <div key={i} className="border border-gray-200 rounded p-2 bg-white">
              <p className="font-semibold text-gray-700">{f.canonical}</p>
              {f.labelMismatch && <p className="mt-1">label: "{f.labelMismatch.left}" ({labels.left}) ≠ "{f.labelMismatch.right}" ({labels.right})</p>}
              {f.valueMismatch && <p className="mt-1">value: "{f.valueMismatch.left}" ({labels.left}) ≠ "{f.valueMismatch.right}" ({labels.right})</p>}
              {f.typeMismatch && <p className="mt-1">type: {f.typeMismatch.left} ({labels.left}) ≠ {f.typeMismatch.right} ({labels.right})</p>}
              {f.requiredMismatch && <p className="mt-1">required: {String(f.requiredMismatch.left)} ({labels.left}) ≠ {String(f.requiredMismatch.right)} ({labels.right})</p>}
              {f.helpTextMismatch && <p className="mt-1">help text differs</p>}
            </div>
          ))}
        </Section>
      )}
    </>
  );
}

function ChartDiffBody({ diff, labels }: { diff: ChartDiff; labels: { left: string; right: string } }) {
  return (
    <>
      {diff.seriesMismatches.length > 0 && (
        <Section title="Series">
          {diff.seriesMismatches.map((s, i) => (<p key={i}>{s}</p>))}
        </Section>
      )}
      {diff.pointDiffs.length > 0 && (
        <Section title={`Point differences (${diff.pointDiffs.length})`}>
          <div className="overflow-x-auto">
            <table className="w-full text-xs border-collapse">
              <thead>
                <tr className="bg-gray-100 text-left">
                  <th className="p-1.5 border border-gray-200">Series</th>
                  <th className="p-1.5 border border-gray-200">x</th>
                  <th className="p-1.5 border border-gray-200">{labels.left}</th>
                  <th className="p-1.5 border border-gray-200">{labels.right}</th>
                  <th className="p-1.5 border border-gray-200">Δ</th>
                </tr>
              </thead>
              <tbody>
                {diff.pointDiffs.slice(0, 200).map((p, i) => (
                  <tr key={i}>
                    <td className="p-1.5 border border-gray-200">{p.series}</td>
                    <td className="p-1.5 border border-gray-200">{String(p.x)}</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{Number.isFinite(p.left) ? p.left : '—'}</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{Number.isFinite(p.right) ? p.right : '—'}</td>
                    <td className="p-1.5 border border-gray-200">{Number.isFinite(p.delta) ? p.delta : '—'}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </Section>
      )}
      {diff.overlayDiffs.length > 0 && (
        <Section title="Overlay markers">
          {diff.overlayDiffs.map((o, i) => (
            <p key={i}>x={String(o.x)}: "{o.leftLabel ?? '(none)'}" ({labels.left}) vs "{o.rightLabel ?? '(none)'}" ({labels.right})</p>
          ))}
        </Section>
      )}
    </>
  );
}

function SectionDiffBody({ diff, labels }: { diff: SectionDiff; labels: { left: string; right: string } }) {
  return (
    <>
      {diff.titleMismatch && (
        <Section title="Title">
          <p><b>{labels.left}:</b> "{diff.titleMismatch.left}"</p>
          <p><b>{labels.right}:</b> "{diff.titleMismatch.right}"</p>
        </Section>
      )}
      {(diff.missingItemsOnLeft.length > 0 || diff.missingItemsOnRight.length > 0) && (
        <Section title="Missing items">
          {diff.missingItemsOnLeft.length > 0 && <p>Missing on <b>{labels.left}:</b> {diff.missingItemsOnLeft.join(', ')}</p>}
          {diff.missingItemsOnRight.length > 0 && <p>Missing on <b>{labels.right}:</b> {diff.missingItemsOnRight.join(', ')}</p>}
        </Section>
      )}
      {diff.itemDiffs.length > 0 && (
        <Section title={`Item value differences (${diff.itemDiffs.length})`}>
          <div className="overflow-x-auto">
            <table className="w-full text-xs border-collapse">
              <thead>
                <tr className="bg-gray-100 text-left">
                  <th className="p-1.5 border border-gray-200">Label</th>
                  <th className="p-1.5 border border-gray-200">{labels.left}</th>
                  <th className="p-1.5 border border-gray-200">{labels.right}</th>
                </tr>
              </thead>
              <tbody>
                {diff.itemDiffs.map((it, i) => (
                  <tr key={i}>
                    <td className="p-1.5 border border-gray-200">{it.label}</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{it.leftValue ?? ''}</td>
                    <td className="p-1.5 border border-gray-200 text-red-700">{it.rightValue ?? ''}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </Section>
      )}
    </>
  );
}

function StyleDiffBody({ diff, labels }: { diff: StyleDiff; labels: { left: string; right: string } }) {
  return (
    <Section title={`Style properties (${diff.differences.length})`}>
      <div className="overflow-x-auto">
        <table className="w-full text-xs border-collapse">
          <thead>
            <tr className="bg-gray-100 text-left">
              <th className="p-1.5 border border-gray-200">Property</th>
              <th className="p-1.5 border border-gray-200">{labels.left}</th>
              <th className="p-1.5 border border-gray-200">{labels.right}</th>
            </tr>
          </thead>
          <tbody>
            {diff.differences.map((p, i) => (
              <tr key={i}>
                <td className="p-1.5 border border-gray-200 font-mono">{p.property}</td>
                <td className="p-1.5 border border-gray-200 text-red-700">{p.left}</td>
                <td className="p-1.5 border border-gray-200 text-red-700">{p.right}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </Section>
  );
}
