interface TokenEntry {
  purpose: string;
  model: string;
  inputTokens: number;
  outputTokens: number;
  cost: number;
  calls: number;
}

interface TokenUsagePanelProps {
  entries: TokenEntry[];
  title?: string;
}

const PURPOSE_LABELS: Record<string, string> = {
  vision: 'Vision',
  testcase_generation: 'Test Case Generation',
  step_execution: 'Step Execution',
  comparison: 'Comparison',
  code_generation: 'Code Generation',
  documentation: 'Documentation',
};

function formatTokens(n: number): string {
  if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
  if (n >= 1_000) return `${(n / 1_000).toFixed(1)}K`;
  return String(n);
}

function formatCost(n: number): string {
  if (n === 0) return '-';
  if (n < 0.01) return `$${n.toFixed(4)}`;
  return `$${n.toFixed(3)}`;
}

export default function TokenUsagePanel({ entries, title }: TokenUsagePanelProps) {
  if (entries.length === 0) return null;

  const totalInput = entries.reduce((s, e) => s + e.inputTokens, 0);
  const totalOutput = entries.reduce((s, e) => s + e.outputTokens, 0);
  const totalCost = entries.reduce((s, e) => s + e.cost, 0);

  return (
    <div className="bg-white rounded-lg border border-gray-200 shadow-sm overflow-hidden">
      {title && (
        <div className="px-3 py-2 bg-gray-50 border-b border-gray-200">
          <h4 className="text-[11px] font-semibold text-gray-600">{title}</h4>
        </div>
      )}
      <table className="w-full text-[11px]">
        <thead>
          <tr className="border-b border-gray-100 text-gray-500">
            <th className="text-left px-3 py-1.5 font-medium">Purpose</th>
            <th className="text-left px-2 py-1.5 font-medium">Model</th>
            <th className="text-right px-2 py-1.5 font-medium">Input</th>
            <th className="text-right px-2 py-1.5 font-medium">Output</th>
            <th className="text-right px-3 py-1.5 font-medium">Cost</th>
          </tr>
        </thead>
        <tbody>
          {entries.map((e, i) => (
            <tr key={i} className="border-b border-gray-50 hover:bg-gray-50">
              <td className="px-3 py-1.5 text-gray-700">{PURPOSE_LABELS[e.purpose] || e.purpose}</td>
              <td className="px-2 py-1.5 text-gray-500 font-mono text-[10px]">{e.model}</td>
              <td className="px-2 py-1.5 text-right text-blue-600">{formatTokens(e.inputTokens)}</td>
              <td className="px-2 py-1.5 text-right text-purple-600">{formatTokens(e.outputTokens)}</td>
              <td className="px-3 py-1.5 text-right text-gray-700">{formatCost(e.cost)}</td>
            </tr>
          ))}
        </tbody>
        <tfoot>
          <tr className="bg-gray-50 font-semibold text-gray-700">
            <td className="px-3 py-1.5" colSpan={2}>Total</td>
            <td className="px-2 py-1.5 text-right text-blue-600">{formatTokens(totalInput)}</td>
            <td className="px-2 py-1.5 text-right text-purple-600">{formatTokens(totalOutput)}</td>
            <td className="px-3 py-1.5 text-right">{formatCost(totalCost)}</td>
          </tr>
        </tfoot>
      </table>
    </div>
  );
}
