import type { LoopBinding, ManualStep, TestCase, ValueRef } from '../types/state.js';

/**
 * Pure reference-analysis helpers extracted from `ReferenceResolver` so the
 * UI bundle can import them without pulling in `FixtureStore` / driver code.
 *
 * These operate on `testCase.manualSteps` — the authored surface — not on
 * `testCase.steps` (which is the AI-mode SavedStep array). The server-side
 * `ReferenceResolver` delegates to the same helpers for consistency.
 */

/**
 * A step is a producer if it declares isProducer:true, or if its tool name
 * implies one (retain_*, store_*, browser_screenshot, run_sandboxed_js,
 * expect_previous_step_network with capture:true).
 */
export function isProducerStep(step: ManualStep): boolean {
  if (step.isProducer) return true;
  const t = step.toolName;
  return (
    t.startsWith('retain_') ||
    t.startsWith('store_') ||
    t === 'run_sandboxed_js' ||
    t === 'browser_screenshot' ||
    (t === 'expect_previous_step_network' && (step.toolArgs as Record<string, unknown>)?.capture === true)
  );
}

/** Walk manualSteps in order and return every producer that precedes `untilStepId` (exclusive). */
export function producersBefore(testCase: TestCase, untilStepId: string): ManualStep[] {
  const out: ManualStep[] = [];
  const steps = testCase.manualSteps ?? [];
  for (const step of steps) {
    if (step.id === untilStepId) break;
    if (isProducerStep(step)) out.push(step);
  }
  return out;
}

/**
 * Return loop bindings whose body contains `stepId`, ordered outermost-first.
 */
export function activeLoopsFor(
  testCase: TestCase,
  stepId: string,
  loops: LoopBinding[],
): LoopBinding[] {
  const steps = testCase.manualSteps ?? [];
  const idx = steps.findIndex((s) => s.id === stepId);
  if (idx < 0) return [];
  const active: LoopBinding[] = [];
  for (const loop of loops) {
    const from = steps.findIndex((s) => s.id === loop.fromStepId);
    const to = steps.findIndex((s) => s.id === loop.toStepId);
    if (from < 0 || to < 0) continue;
    if (idx >= from && idx <= to) active.push(loop);
  }
  active.sort((a, b) => {
    const fa = steps.findIndex((s) => s.id === a.fromStepId);
    const fb = steps.findIndex((s) => s.id === b.fromStepId);
    return fa - fb;
  });
  return active;
}

/** Build a producer-id lookup set for a testcase. */
export function producerIdsOf(testCase: TestCase): Set<string> {
  const out = new Set<string>();
  for (const step of testCase.manualSteps ?? []) {
    if (isProducerStep(step)) out.add(step.id);
  }
  return out;
}

/**
 * Reason a reference is broken at author time. `fixture-column-missing`
 * requires fixture metadata the UI may not have locally — callers pass a
 * `fixtureColumnExists` predicate when they can, otherwise that check is
 * skipped.
 */
export type BrokenRefReason =
  | 'producer-missing'
  | 'producer-not-producer'
  | 'producer-guard-mismatch'
  | 'csv-outside-loop'
  | 'csv-column-missing';

export interface BrokenRef {
  stepId: string;
  paramKey: string;
  ref: ValueRef;
  reason: BrokenRefReason;
  message: string;
}

/**
 * Pure broken-reference scanner. Works on `manualSteps` only. Flags:
 *  - missing producer step
 *  - non-producer tool changed
 *  - producer guard stricter than consumer guard (producer may be skipped)
 *  - csv ref not inside a matching loop scope
 *  - csv column missing (only checked if `fixtureColumnExists` supplied)
 */
export function findBrokenRefs(
  testCase: TestCase,
  loops: LoopBinding[],
  fixtureColumnExists?: (fixtureId: string, columnName: string) => boolean,
): BrokenRef[] {
  const steps = testCase.manualSteps ?? [];
  const stepById = new Map(steps.map((s) => [s.id, s]));
  const broken: BrokenRef[] = [];

  for (const step of steps) {
    if (!step.refs) continue;
    const consumerGuard = new Set(step.resolutionGuard?.presets ?? []);
    const stepLoops = activeLoopsFor(testCase, step.id, loops);
    const stepLoopFixtureIds = new Set(stepLoops.map((l) => l.fixtureId));

    for (const [paramKey, ref] of Object.entries(step.refs)) {
      if (ref.kind === 'step') {
        const producer = stepById.get(ref.stepId);
        if (!producer) {
          broken.push({ stepId: step.id, paramKey, ref, reason: 'producer-missing', message: 'Producer step not found' });
          continue;
        }
        if (!isProducerStep(producer)) {
          broken.push({ stepId: step.id, paramKey, ref, reason: 'producer-not-producer', message: 'Referenced step is no longer a producer' });
          continue;
        }
        const producerGuard = new Set(producer.resolutionGuard?.presets ?? []);
        if (producerGuard.size > 0) {
          if (consumerGuard.size === 0) {
            broken.push({
              stepId: step.id,
              paramKey,
              ref,
              reason: 'producer-guard-mismatch',
              message: 'Consumer has no guard but producer is guarded — producer may be skipped',
            });
            continue;
          }
          for (const preset of consumerGuard) {
            if (!producerGuard.has(preset)) {
              broken.push({
                stepId: step.id,
                paramKey,
                ref,
                reason: 'producer-guard-mismatch',
                message: `Consumer runs on "${preset}" but producer does not`,
              });
              break;
            }
          }
        }
      } else if (ref.kind === 'csv') {
        if (!stepLoopFixtureIds.has(ref.fixtureId)) {
          broken.push({
            stepId: step.id,
            paramKey,
            ref,
            reason: 'csv-outside-loop',
            message: 'CSV column referenced outside its loop scope',
          });
          continue;
        }
        if (fixtureColumnExists && !fixtureColumnExists(ref.fixtureId, ref.columnName)) {
          broken.push({
            stepId: step.id,
            paramKey,
            ref,
            reason: 'csv-column-missing',
            message: 'Fixture or column missing',
          });
        }
      }
    }
  }

  return broken;
}

/** Human-friendly producer label for the reference dropdown. */
export function producerDisplayLabel(step: ManualStep, index: number): string {
  const desc = step.title || step.description || step.toolName;
  return `Step ${index + 1} — ${desc}`;
}
