import { useStore } from '../../../store/state';
import type { SessionState } from '../../../../activator/types/state';
import type { ComparisonSideConfig } from '../../../../activator/types/comparisonPlan';

const EMPTY_SESSIONS: NonNullable<SessionState['browserSessions']> = [];

/**
 * Live list of open browser sessions, paired with the plan's side metadata.
 * Renders each session as a tile with its url, title, active state, and
 * — future iteration — a live screenshot thumbnail.
 *
 * For now we display session metadata; the activator broadcasts
 * `browserSessionsChanged` with url/title from the manager. Live screenshot
 * polling is deferred to a later iteration because it needs a targeted
 * server-side push mechanism (adding it now would require another round of
 * activator changes and feels out of scope for this UI chunk).
 */
export default function BrowserSessionsPanel({ sides }: { sides: ComparisonSideConfig[] }) {
  const sessions = useStore((s) => s.session.browserSessions) ?? EMPTY_SESSIONS;
  const activeId = useStore((s) => s.session.activeBrowserSessionId);

  if (sessions.length === 0) {
    return (
      <div className="rounded-2xl border border-gray-200 bg-white p-4">
        <h3 className="text-sm font-semibold text-gray-800 mb-3">Browsers</h3>
        <p className="text-xs text-gray-400">
          No browser sessions are open yet. Click <strong className="text-orange-600">Start with AI</strong> in the header above to launch them.
          The browsers appear here as they come online — usually within a few seconds. If nothing appears, check the activator log for launch errors.
        </p>
      </div>
    );
  }

  return (
    <div className="rounded-2xl border border-gray-200 bg-white p-4">
      <h3 className="text-sm font-semibold text-gray-800 mb-3">Browsers</h3>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
        {sessions.map((s) => {
          const side = sides.find((x) => x.sessionId === s.id);
          return (
            <div
              key={s.id}
              className={`rounded-lg border p-3 ${s.id === activeId ? 'border-orange-400 bg-orange-50/40' : 'border-gray-200 bg-white'}`}
            >
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <span className="inline-block w-1.5 h-1.5 rounded-full bg-green-500" />
                  <span className="text-sm font-semibold text-gray-800">{side?.label ?? s.id}</span>
                  <span className="text-[10px] uppercase text-gray-400 tracking-wide font-mono">{s.id}</span>
                </div>
                {s.id === activeId && <span className="text-[10px] uppercase text-orange-600 font-semibold">Active</span>}
              </div>
              {s.title && <p className="text-xs text-gray-700 mt-1 truncate">{s.title}</p>}
              {s.url && <p className="text-[11px] text-gray-500 mt-0.5 truncate font-mono">{s.url}</p>}
              <div className="flex items-center gap-3 mt-2 text-[11px] text-gray-500">
                <span>{s.driverType}</span>
                <span>{s.headless ? 'headless' : 'visible'}</span>
                <span>{new Date(s.createdAt).toLocaleTimeString()}</span>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
