import { useNavigate } from 'react-router-dom';
import type { CoverageGapEntry } from '../../../lib/dashboard';

interface Props {
  projectId: string;
  items: CoverageGapEntry[];
}

export default function CoverageGapsTab({ projectId, items }: Props) {
  const navigate = useNavigate();

  if (items.length === 0) {
    return (
      <div className="p-8 text-center">
        <p className="text-sm text-gray-600">Every feature has test cases that have been executed.</p>
      </div>
    );
  }

  const go = (entry: CoverageGapEntry) => {
    navigate(`/project/${projectId}/module/${entry.moduleId}/feature/${entry.featureId}`);
  };

  return (
    <ul className="divide-y divide-gray-100">
      {items.map(entry => (
        <li
          key={`${entry.moduleId}-${entry.featureId}-${entry.kind}`}
          className="p-3 hover:bg-gray-50 flex items-center gap-3"
        >
          <div className="flex-1 min-w-0">
            <div className="text-xs font-semibold text-gray-800 truncate">{entry.featureName}</div>
            <div className="text-[10px] text-gray-400">
              {entry.moduleName} ·{' '}
              {entry.kind === 'no_test_cases' ? 'No test cases yet' : 'Tests exist, never executed'}
            </div>
          </div>
          <button
            onClick={() => go(entry)}
            className="px-2 py-1 text-[10px] font-semibold text-orange-700 bg-orange-50 border border-orange-200 rounded hover:bg-orange-100 focus:outline-none focus:ring-2 focus:ring-orange-300"
          >
            {entry.kind === 'no_test_cases' ? 'Generate test cases' : 'Open feature'}
          </button>
        </li>
      ))}
    </ul>
  );
}
