import { useEffect, useState } from 'react';
import { Navigate, Route, BrowserRouter as Router, Routes, useLocation } from 'react-router-dom';
import Layout from './components/layout';
import ArtifactsPage from './pages/artifacts';
import FeatureComparison from './pages/comparison/FeatureComparison';
import ModuleComparison from './pages/comparison/ModuleComparison';
import Dashboard from './pages/dashboard';
import ExecutionHistoryList from './pages/execution-history';
import FeatureDetail from './pages/feature-detail';
import ModuleDetail from './pages/module-detail';
import ProjectDetail from './pages/project-detail';
import SettingsPage from './pages/settings';
import ModuleTraceability from './pages/traceability/ModuleTraceability';
import ProjectTraceability from './pages/traceability/ProjectTraceability';
import AddProject from './pages/workflow-add';
import EditProject from './pages/workflow-edit';
import FeatureTests from './pages/workflow-tests';
import { AppProvider } from './store/Context';

type ReadinessReason = 'config-missing' | 'missing-credential';

interface ReadinessState {
    ready: boolean;
    reason: ReadinessReason | null;
    missingKeys: string[];
}

/** Checks whether the app has a usable config.json and all credentials for providers in use. */
function useReadiness() {
    const [state, setState] = useState<{ loading: true } | { loading: false; value: ReadinessState }>({ loading: true });
    useEffect(() => {
        fetch('/api/readiness')
            .then((r) => r.json())
            .then((d: ReadinessState) => setState({ loading: false, value: d }))
            .catch(() => setState({ loading: false, value: { ready: true, reason: null, missingKeys: [] } }));
    }, []);
    return state;
}

/** Full-screen spinner shown while we check for .env. */
function SplashLoader() {
    return (
        <div className="min-h-screen bg-[#1e2939] flex items-center justify-center">
            <div className="flex flex-col items-center gap-4">
                <div className="w-10 h-10 border-2 border-orange-400 border-t-transparent rounded-full animate-spin" />
                <span className="text-gray-400 text-sm">Loading…</span>
            </div>
        </div>
    );
}

/** Wraps the whole app and redirects to /settings until the app is ready. */
function AppRoutes() {
    const readiness = useReadiness();
    const location = useLocation();

    if (readiness.loading) return <SplashLoader />;

    const { ready, reason, missingKeys } = readiness.value;

    if (!ready && location.pathname !== '/settings') {
        return <Navigate to="/settings" replace />;
    }

    return (
        <Routes>
            <Route path="/settings" element={<SettingsPage firstRun={!ready} readinessReason={reason} missingKeys={missingKeys} />} />
            <Route path="/" element={<Dashboard />} />
            {/* Project */}
            <Route path="/project/new" element={<AddProject />} />
            <Route path="/project/:id/edit" element={<EditProject />} />
            <Route path="/project/:id/manage" element={<ProjectDetail />} />
            <Route path="/project/:id" element={<Dashboard />} />
            <Route path="/project/:projectId/traceability" element={<ProjectTraceability />} />
            <Route path="/project/:projectId/artifacts" element={<ArtifactsPage />} />
            {/* Module */}
            <Route path="/project/:projectId/module/:moduleId" element={<ModuleDetail />} />
            <Route path="/project/:projectId/module/:moduleId/compare" element={<ModuleComparison />} />
            <Route path="/project/:projectId/module/:moduleId/traceability" element={<ModuleTraceability />} />
            <Route path="/project/:projectId/module/:moduleId/artifacts" element={<ArtifactsPage />} />
            {/* Feature */}
            <Route path="/project/:projectId/module/:moduleId/feature/:featureId" element={<FeatureDetail />} />
            <Route path="/project/:projectId/module/:moduleId/feature/:featureId/tests" element={<FeatureTests />} />
            <Route path="/project/:projectId/module/:moduleId/feature/:featureId/history" element={<ExecutionHistoryList />} />
            <Route path="/project/:projectId/module/:moduleId/feature/:featureId/compare" element={<FeatureComparison />} />
            {/* Fallback */}
            <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
    );
}

function App() {
    return (
        <Router>
            <AppProvider>
                <Layout>
                    <AppRoutes />
                </Layout>
            </AppProvider>
        </Router>
    );
}

export default App;
