import { useNavigate } from 'react-router-dom';
import type { ActivityEntry, ProjectDashboard } from '../../lib/dashboard';
import { formatRelative } from '../../lib/dashboard';

interface Props {
  projectId: string;
  activity: ActivityEntry[];
  live: ProjectDashboard['live'];
  projectName: string;
}

function RunIcon() {
  return (
    <svg className="w-3.5 h-3.5 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-5.197-3.03A1 1 0 008 9v6a1 1 0 001.555.832l5.197-3.03a1 1 0 000-1.664z" />
    </svg>
  );
}

function DiffIcon() {
  return (
    <svg className="w-3.5 h-3.5 text-purple-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 7h13M8 12h13M8 17h13M3 7h.01M3 12h.01M3 17h.01" />
    </svg>
  );
}

export default function ActivityFeed({ projectId, activity, live, projectName }: Props) {
  const navigate = useNavigate();
  const hasLive = !!(live.executionInFlight || live.comparisonInFlight);

  return (
    <div className="rounded-2xl border border-gray-200 bg-white overflow-hidden">
      <div className="px-4 py-3 border-b border-gray-200">
        <h2 className="text-sm font-semibold text-gray-800">Activity</h2>
        <p className="text-[11px] text-gray-400 mt-0.5">Recent runs and comparisons for {projectName}</p>
      </div>

      {hasLive && (
        <div className="bg-orange-50 border-b border-orange-200 px-4 py-3">
          <div className="flex items-center gap-2">
            <span className="relative flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-orange-500 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-orange-600"></span>
            </span>
            <span className="text-[11px] font-semibold uppercase tracking-wide text-orange-700">In progress</span>
          </div>
          {live.executionInFlight && (
            <div className="text-xs text-gray-700 mt-1">Test execution running</div>
          )}
          {live.comparisonInFlight && (
            <div className="text-xs text-gray-700 mt-1">Comparison running</div>
          )}
        </div>
      )}

      {activity.length === 0 ? (
        <div className="p-8 text-center text-xs text-gray-500">No activity yet.</div>
      ) : (
        <ul className="divide-y divide-gray-100">
          {activity.map(entry => {
            if (entry.kind === 'run') {
              return (
                <li
                  key={entry.runId}
                  onClick={() =>
                    navigate(`/project/${projectId}/module/${entry.moduleId}/feature/${entry.featureId}/history`)
                  }
                  className="p-3 hover:bg-gray-50 cursor-pointer flex items-start gap-2 min-w-0"
                >
                  <RunIcon />
                  <div className="flex-1 min-w-0">
                    <div className="text-xs font-semibold text-gray-800 truncate">
                      {entry.mode === 'replay' ? 'Replay run' : 'AI run'} — {entry.featureName}
                    </div>
                    <div className="text-[10px] text-gray-500">
                      <span className="text-green-600">{entry.passed} passed</span>
                      {entry.failed > 0 && <>, <span className="text-red-600">{entry.failed} failed</span></>}
                      {' · '}
                      {formatRelative(entry.startedAt)}
                    </div>
                  </div>
                </li>
              );
            }
            return (
              <li
                key={entry.comparisonId}
                className="p-3 hover:bg-gray-50 flex items-start gap-2"
              >
                <DiffIcon />
                <div className="flex-1 min-w-0">
                  <div className="text-xs font-semibold text-gray-800 truncate">
                    Comparison — {entry.scopeLabel}
                  </div>
                  <div className="text-[10px] text-gray-500">
                    {entry.findingsCount} finding{entry.findingsCount === 1 ? '' : 's'} · {formatRelative(entry.startedAt)}
                  </div>
                </div>
              </li>
            );
          })}
        </ul>
      )}
    </div>
  );
}
