import { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useStore } from '../../store/state';
import { useActivator } from '../../store/Context';
import MultiSelectAutocomplete from '../../components/inputs/MultiSelectAutocomplete';
import FeatureForm from '../workflow-tests/components/FeatureForm';
import type { Feature, JiraTicketRef } from '../../../activator/types/state';
import TestPlanTab from './TestPlanTab';
import SummaryReportTab from './SummaryReportTab';
import ElementPickerModal from '../../components/ElementPickerModal';

export default function ModuleDetail() {
  const { projectId, moduleId } = useParams<{ projectId: string; moduleId: string }>();
  const navigate = useNavigate();
  const activator = useActivator();

  const project = useStore(s => s.projects.find(p => p.id === projectId));
  const mod = project?.modules.find(m => m.id === moduleId);

  // Module editing
  const [editingModule, setEditingModule] = useState(false);
  const [modDescription, setModDescription] = useState('');
  const [modPageUrl, setModPageUrl] = useState('');
  const [modScope, setModScope] = useState('');
  const [modTickets, setModTickets] = useState<Array<{ value: string; label: string; iconUrl?: string }>>([]);
  const [, setModDirty] = useState(false);

  // Feature add
  const [showAddFeature, setShowAddFeature] = useState(false);
  const [addFeatureResetKey, setAddFeatureResetKey] = useState(0);

  // Tabs
  const [activeTab, setActiveTab] = useState<'features' | 'plan' | 'report'>('features');
  const [pickerOpen, setPickerOpen] = useState(false);

  useEffect(() => {
    if (mod) {
      setModDescription(mod.description || '');
      setModPageUrl(mod.pageUrl || '');
      setModScope(mod.scopeSelector || '');
      setModTickets(
        (mod.jiraTickets || []).map(t => ({ value: t.key, label: `${t.key} - ${t.summary}`, iconUrl: t.iconUrl })),
      );
    }
  }, [mod?.id]);

  if (!project || !mod) {
    return (
      <div className="w-full px-4 py-8">
        <div className="rounded-2xl border border-gray-200 bg-white p-8 text-center text-gray-500">Module not found</div>
      </div>
    );
  }

  // --- Jira search ---
  const searchTickets = async (text: string) => {
    try {
      const response = await fetch('/api/issues/picker?query=' + encodeURIComponent(text)).then(r => r.json());
      return response.map((j: any) => ({ value: j.key, label: `${j.key} - ${j.summaryText}`, iconUrl: j.img }));
    } catch {
      return [];
    }
  };

  // --- Module save ---
  const saveModule = () => {
    const jiraTickets: JiraTicketRef[] = modTickets.map(t => ({
      key: t.value,
      summary: t.label.replace(/^[^ ]+ - /, ''),
      iconUrl: t.iconUrl,
    }));
    activator.updateModule(project.id, mod.id, {
      description: modDescription.trim() || undefined,
      pageUrl: modPageUrl.trim() || undefined,
      scopeSelector: modScope.trim() || undefined,
      jiraTickets: jiraTickets.length > 0 ? jiraTickets : undefined,
    });
    setEditingModule(false);
    setModDirty(false);
  };

  // --- Feature CRUD ---
  const submitFeature = (value: { name: string; description: string; jiraTickets: JiraTicketRef[]; swaggerApis: any[]; strategyOverride?: string[]; mode?: 'ai' | 'manual' }) => {
    if (!value.name) return false;
    activator.createFeature(project.id, mod.id, {
      name: value.name,
      description: value.description || undefined,
      jiraTickets: value.jiraTickets.length > 0 ? value.jiraTickets : undefined,
      swaggerApis: value.swaggerApis.length > 0 ? value.swaggerApis : undefined,
      strategyOverride: value.strategyOverride,
      mode: value.mode ?? 'ai',
    });
    return true;
  };

  const handleCreateFeature = (value: Parameters<typeof submitFeature>[0]) => {
    if (submitFeature(value)) setShowAddFeature(false);
  };

  const handleCreateAndAddAnother = (value: Parameters<typeof submitFeature>[0]) => {
    if (submitFeature(value)) setAddFeatureResetKey(k => k + 1);
  };

  const handleDeleteFeature = (featureId: string) => {
    if (confirm('Delete this feature and all its test cases?')) {
      activator.deleteFeature(project.id, mod.id, featureId);
    }
  };

  const statusSummary = (f: Feature) => {
    if (f.testCases.length === 0) return null;
    const passed = f.testCases.filter(tc => tc.status === 'passed').length;
    const failed = f.testCases.filter(tc => tc.status === 'failed').length;
    return (
      <div className="flex items-center gap-2 text-xs">
        <span className="text-gray-400">{f.testCases.length} tests</span>
        {passed > 0 && <span className="text-green-600">{passed} passed</span>}
        {failed > 0 && <span className="text-red-600">{failed} failed</span>}
      </div>
    );
  };

  return (
    <div className="w-full px-4 py-6">
      {/* Header */}
      <div className="rounded-2xl border border-gray-200 bg-white px-5 py-5 mb-5">
        <div className="flex items-center gap-2 mb-3 text-sm">
          <button
            onClick={() => navigate(`/project/${project.id}`)}
            className="inline-flex items-center gap-1 px-2 py-1 text-xs text-gray-600 hover:text-gray-900 hover:bg-gray-100 rounded-md transition"
            title="Back to Project"
          >
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
            Back
          </button>
          <span className="text-gray-300">|</span>
          <button onClick={() => navigate('/')} className="text-gray-400 hover:text-gray-700">Projects</button>
          <span className="text-gray-300">/</span>
          <button onClick={() => navigate(`/project/${project.id}`)} className="text-gray-400 hover:text-gray-700">{project.name}</button>
          <span className="text-gray-300">/</span>
          <span className="font-medium text-gray-800">{mod.name}</span>
        </div>

        <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-3">
          <div className="min-w-0">
            <h1 className="text-xl font-bold text-gray-800">{mod.name}</h1>
            {!editingModule && mod.description && <p className="text-sm text-gray-500 mt-1">{mod.description}</p>}
            {!editingModule && (
              <div className="flex flex-wrap gap-3 mt-1.5 text-xs text-gray-400">
                {mod.pageUrl && <span>{mod.pageUrl}</span>}
                {mod.scopeSelector && <span className="font-mono">Scope: {mod.scopeSelector}</span>}
              </div>
            )}
            {!editingModule && mod.jiraTickets && mod.jiraTickets.length > 0 && (
              <div className="flex flex-wrap gap-1.5 mt-2">
                {mod.jiraTickets.map(t => (
                  <span key={t.key} className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs bg-blue-50 text-blue-700">
                    {t.iconUrl && <img src={t.iconUrl} className="w-3.5 h-3.5" alt="" />}
                    {t.key}
                  </span>
                ))}
              </div>
            )}
          </div>
          {!editingModule && (
            <div className="flex items-center gap-2 shrink-0">
              <button
                onClick={() => navigate(`/project/${project.id}/module/${mod.id}/traceability`)}
                className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-50 transition"
              >
                Traceability
              </button>
              <button
                onClick={() => navigate(`/project/${project.id}/module/${mod.id}/compare`)}
                className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-50 transition"
              >
                Compare UIs
              </button>
              <button
                onClick={() => setEditingModule(true)}
                className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-50 transition"
              >
                Edit Module
              </button>
            </div>
          )}
        </div>

        {/* Module edit form */}
        {editingModule && (
          <div className="mt-4 pt-4 border-t border-gray-100 space-y-4">
            <div>
              <MultiSelectAutocomplete
                label="Jira Epic (module level)"
                onSearch={searchTickets}
                value={modTickets}
                onChange={(v: any[]) => { setModTickets(v); setModDirty(true); }}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Module Prompts / Instructions</label>
              <textarea
                value={modDescription}
                onChange={e => { setModDescription(e.target.value); setModDirty(true); }}
                rows={3}
                className="w-full px-3 py-2 border border-gray-300 rounded-md text-sm resize-y"
                placeholder="Context or instructions specific to this module..."
              />
            </div>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <div>
                <label className="block text-xs text-gray-500 mb-1">Page URL (optional)</label>
                <input
                  value={modPageUrl}
                  onChange={e => { setModPageUrl(e.target.value); setModDirty(true); }}
                  className="w-full px-3 py-2 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-300"
                  placeholder="https://example.com/users"
                />
              </div>
              <div>
                <label className="block text-xs text-gray-500 mb-1">Scope Selector (optional)</label>
                <div className="flex gap-2">
                  <input
                    value={modScope}
                    onChange={e => { setModScope(e.target.value); setModDirty(true); }}
                    className="flex-1 px-3 py-2 border border-gray-200 rounded-lg text-sm font-mono focus:outline-none focus:ring-2 focus:ring-orange-300"
                    placeholder="//div[@id='main-content']"
                  />
                  <button
                    type="button"
                    onClick={() => setPickerOpen(true)}
                    className="px-3 py-2 text-xs font-semibold bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200"
                  >
                    Pick
                  </button>
                </div>
              </div>
            </div>
            <div className="flex gap-2">
              <button onClick={saveModule} className="px-4 py-1.5 text-sm bg-orange-500 text-white rounded-lg hover:bg-orange-600 font-semibold transition">
                Save
              </button>
              <button onClick={() => setEditingModule(false)} className="px-4 py-1.5 text-sm bg-gray-100 text-gray-600 rounded-lg hover:bg-gray-200 transition">
                Cancel
              </button>
            </div>
          </div>
        )}
      </div>

      {/* Tabs */}
      <div className="flex items-center gap-1 border-b border-gray-200 mb-4">
        <button
          onClick={() => setActiveTab('features')}
          className={`px-4 py-2 text-sm font-semibold border-b-2 ${activeTab === 'features' ? 'border-orange-500 text-orange-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
        >
          Features
        </button>
        <button
          onClick={() => setActiveTab('plan')}
          className={`px-4 py-2 text-sm font-semibold border-b-2 ${activeTab === 'plan' ? 'border-orange-500 text-orange-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
        >
          Test Plan
        </button>
        <button
          onClick={() => setActiveTab('report')}
          className={`px-4 py-2 text-sm font-semibold border-b-2 ${activeTab === 'report' ? 'border-orange-500 text-orange-600' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
        >
          Summary Report
        </button>
      </div>

      {activeTab === 'plan' && <TestPlanTab projectId={project.id} moduleId={mod.id} />}
      {activeTab === 'report' && <SummaryReportTab projectId={project.id} moduleId={mod.id} />}

      {activeTab === 'features' && (
      <>
      {/* Features */}
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-base font-semibold text-gray-800">Features ({mod.features.length})</h2>
        {!showAddFeature && (
          <button
            onClick={() => setShowAddFeature(true)}
            className="px-3 py-1.5 text-xs font-semibold bg-orange-500 text-white rounded-lg hover:bg-orange-600 transition"
          >
            + Add Feature
          </button>
        )}
      </div>

      {/* Add Feature Form */}
      {showAddFeature && (
        <div className="rounded-xl border border-gray-200 bg-white p-4 mb-4">
          <h3 className="text-sm font-semibold text-gray-800 mb-3">Add Feature</h3>
          <FeatureForm
            key={addFeatureResetKey}
            submitLabel="Add Feature"
            showModeField
            onSubmit={handleCreateFeature}
            onCancel={() => setShowAddFeature(false)}
            projectDefaultStrategies={project.defaultStrategies}
            secondaryAction={{
              label: 'Save & Add Another',
              onSubmit: handleCreateAndAddAnother,
              className: 'px-4 py-2 bg-white text-orange-600 border border-orange-200 rounded-md text-sm font-medium hover:bg-orange-50 transition cursor-pointer',
            }}
          />
        </div>
      )}

      {mod.features.length === 0 && !showAddFeature && (
        <div className="rounded-2xl border border-gray-200 bg-white p-10 text-center">
          <h3 className="text-lg font-semibold text-gray-800 mb-1">No features yet</h3>
          <p className="text-sm text-gray-500 mb-4">Add features to define what you want to test in this module.</p>
          <button
            onClick={() => setShowAddFeature(true)}
            className="px-5 py-2 bg-orange-500 text-white rounded-lg hover:bg-orange-600 font-semibold text-sm transition"
          >
            + Add Feature
          </button>
        </div>
      )}

      <div className="space-y-3">
        {mod.features.map(feature => {
          const hasRuns = (feature.testRuns?.length ?? 0) > 0;
          const primaryTarget = `/project/${project.id}/module/${mod.id}/feature/${feature.id}/tests`;
          return (
            <div
              key={feature.id}
              className="rounded-xl border border-gray-100 bg-white hover:border-gray-300 hover:shadow-sm transition-all cursor-pointer"
              onClick={() => navigate(primaryTarget)}
            >
              <div className="p-4 flex items-center justify-between">
                <div className="min-w-0">
                  <h3 className="text-sm font-semibold text-gray-800">{feature.name}</h3>
                  {feature.description && <p className="text-xs text-gray-500 mt-0.5 line-clamp-1">{feature.description}</p>}
                  <div className="mt-1.5">
                    {statusSummary(feature)}
                    <div className="flex flex-wrap gap-2 mt-1 text-xs text-gray-400">
                      {feature.jiraTickets && feature.jiraTickets.length > 0 && (
                        <span>{feature.jiraTickets.length} Jira ticket{feature.jiraTickets.length > 1 ? 's' : ''}</span>
                      )}
                      {feature.swaggerApis && feature.swaggerApis.length > 0 && (
                        <span>{feature.swaggerApis.length} API{feature.swaggerApis.length > 1 ? 's' : ''}</span>
                      )}
                      {hasRuns && (
                        <span>{feature.testRuns!.length} run{feature.testRuns!.length > 1 ? 's' : ''}</span>
                      )}
                    </div>
                  </div>
                </div>
                <div className="flex items-center gap-1 ml-3">
                  {hasRuns && (
                    <button
                      onClick={(e) => { e.stopPropagation(); navigate(`/project/${project.id}/module/${mod.id}/feature/${feature.id}/history`); }}
                      className="p-1.5 text-gray-400 hover:text-amber-500 rounded hover:bg-amber-50 transition"
                      title="View execution history"
                    >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                    </button>
                  )}
                  <button
                    onClick={(e) => { e.stopPropagation(); navigate(`/project/${project.id}/module/${mod.id}/feature/${feature.id}`); }}
                    className="p-1.5 text-gray-400 hover:text-blue-500 rounded hover:bg-blue-50 transition"
                    title="Edit feature"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>
                  </button>
                  <button
                    onClick={(e) => { e.stopPropagation(); handleDeleteFeature(feature.id); }}
                    className="p-1.5 text-gray-400 hover:text-red-500 rounded hover:bg-red-50 transition"
                    title="Delete"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                  </button>
                  <svg className="w-4 h-4 text-gray-300 ml-1" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      </>
      )}

      <ElementPickerModal
        open={pickerOpen}
        initialUrl={modPageUrl || undefined}
        context="module"
        onResult={({ xpath, url }) => {
          setModScope(xpath);
          setModDirty(true);
          if (!modPageUrl) setModPageUrl(url);
        }}
        onClose={() => setPickerOpen(false)}
      />
    </div>
  );
}
