import React, { useEffect, useState } from 'react';
import { ChevronDownIcon } from '../../../styles/Icons';
import Popover from './Popover';
import { Item } from './types';

interface MultiSelectDropdownProps {
    value: string[];
    onChange: (selectedKeys: string[]) => void;
    onSearch: (query: string) => Promise<Item[]>;
    placeholder?: string;
    allItems: Item[];
}

const SwaggerMultiSelectDropdown: React.FC<MultiSelectDropdownProps> = ({
    value,
    onChange,
    onSearch,
    placeholder = 'Select items...',
    allItems,
}) => {
    const [isOpen, setIsOpen] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const [items, setItems] = useState<Item[]>([]);
    const [selectedKeys, setSelectedKeys] = useState<string[]>(value);

    useEffect(() => {
        setSelectedKeys(value);
    }, [value]);

    useEffect(() => {
        if (isOpen && searchQuery) {
            onSearch(searchQuery).then(setItems);
        } else if (isOpen) {
            setItems(allItems);
        }
    }, [isOpen, searchQuery, onSearch, allItems]);

    const handleSave = () => {
        onChange(selectedKeys);
        setIsOpen(false);
    };

    const handleClose = () => {
        setSelectedKeys(value);
        setIsOpen(false);
        setSearchQuery('');
    };

    const getDisplayText = () => {
        if (selectedKeys.length === 0) return placeholder;
        if (selectedKeys.length === 1) {
            const item = allItems.find((item) => item.key === selectedKeys[0]);
            return item ? `${item.action} ${item.summary}` : selectedKeys[0];
        }
        return `${selectedKeys.length} items selected`;
    };

    return (
        <>
            <div
                className="relative w-full border border-gray-300 rounded-lg px-3 py-2 bg-white cursor-pointer hover:border-gray-400 transition-colors"
                onClick={() => setIsOpen(true)}
            >
                <div className="flex items-center justify-between">
                    <span className="text-sm text-gray-700 truncate">{getDisplayText()}</span>
                    <ChevronDownIcon className="text-gray-400 flex-shrink-0 w-4 h-4" />
                </div>
            </div>

            <Popover
                isOpen={isOpen}
                onClose={handleClose}
                onSave={handleSave}
                items={items}
                selectedKeys={selectedKeys}
                onSelectionChange={setSelectedKeys}
                onSearch={onSearch}
                searchQuery={searchQuery}
                onSearchChange={setSearchQuery}
            />
        </>
    );
};

export default SwaggerMultiSelectDropdown;
