import React, { useEffect, useState } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import { useStore } from '../../store/state';
import { useActivator } from '../../store/Context';

function EditProject() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const activator = useActivator();

  const project = useStore(s => s.projects.find(p => p.id === id));

  const [form, setForm] = useState({
    name: '',
    category: '',
    description: '',
  });

  useEffect(() => {
    if (project) {
      setForm({
        name: project.name,
        category: project.category,
        description: project.description,
      });
    }
  }, [project?.id]);

  if (!project) {
    return <div className="p-6 text-gray-500">Project not found</div>;
  }

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    activator.updateProject({
      id: project.id,
      name: form.name,
      category: form.category,
      description: form.description,
    });
    navigate(`/project/${project.id}`);
  };

  return (
    <div className="mx-auto px-3 py-4">
      <div className="w-full max-w-2xl mx-auto">
        <div className="flex items-center gap-2 mb-3">
          <button
            onClick={() => navigate(`/project/${id}`)}
            className="inline-flex items-center gap-1 px-2 py-1 text-xs text-gray-600 hover:text-gray-900 hover:bg-gray-100 rounded-md transition"
            title="Back to project"
          >
            <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
            Back
          </button>
        </div>
        <h1 className="text-lg font-bold text-[#1e2939] mb-4">Edit Project</h1>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Name *</label>
            <input
              name="name"
              value={form.name}
              onChange={handleChange}
              required
              className="w-full px-3 py-2 border border-gray-300 rounded-md text-sm"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Category *</label>
            <input
              name="category"
              value={form.category}
              onChange={handleChange}
              required
              className="w-full px-3 py-2 border border-gray-300 rounded-md text-sm"
            />
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Description / General Instructions</label>
            <textarea
              name="description"
              value={form.description}
              onChange={handleChange}
              rows={4}
              className="w-full px-3 py-2 border border-gray-300 rounded-md text-sm resize-y"
            />
          </div>

          <div className="flex gap-3 pt-2">
            <button
              type="submit"
              className="px-4 py-2 bg-orange-500 text-white rounded-md text-sm font-medium hover:bg-orange-600"
            >
              Save Changes
            </button>
            <button
              type="button"
              onClick={() => navigate(`/project/${id}`)}
              className="px-4 py-2 bg-gray-200 text-gray-700 rounded-md text-sm font-medium hover:bg-gray-300"
            >
              Cancel
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default EditProject;
