import { useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { buildTraceability, countByStatus, rowsToCsv, rowsToMarkdown, type TraceabilityRow } from '../../lib/traceability';
import { useStore } from '../../store/state';

interface Props {
  projectId?: string;
  moduleId?: string;
  title: string;
  subtitle: string;
  backTo: string;
}

type StatusFilter = 'all' | 'passed' | 'failed' | 'pending' | 'never';

export default function TraceabilityMatrix({ projectId, moduleId, title, subtitle, backTo }: Props) {
  const navigate = useNavigate();
  const projects = useStore(s => s.projects);

  const [statusFilter, setStatusFilter] = useState<StatusFilter>('all');
  const [search, setSearch] = useState('');
  const [onlyWithFindings, setOnlyWithFindings] = useState(false);

  const allRows = useMemo(
    () => buildTraceability({ projects, projectId, moduleId }),
    [projects, projectId, moduleId],
  );

  const rows = useMemo(() => {
    const q = search.trim().toLowerCase();
    return allRows.filter(r => {
      if (onlyWithFindings && r.findings.length === 0) return false;
      if (statusFilter !== 'all') {
        if (statusFilter === 'passed' && r.latestStatus !== 'passed') return false;
        if (statusFilter === 'failed' && r.latestStatus !== 'failed') return false;
        if (statusFilter === 'never' && r.latestStatus !== 'never') return false;
        if (statusFilter === 'pending' && (r.latestStatus === 'passed' || r.latestStatus === 'failed' || r.latestStatus === 'never')) {
          return false;
        }
      }
      if (q) {
        const hay = [
          r.jiraKey,
          r.jiraSummary ?? '',
          r.projectName,
          r.moduleName,
          r.featureName,
          r.testCaseTitle,
          r.testCaseStrategy ?? '',
        ]
          .join(' ')
          .toLowerCase();
        if (!hay.includes(q)) return false;
      }
      return true;
    });
  }, [allRows, statusFilter, search, onlyWithFindings]);

  const counts = useMemo(() => countByStatus(allRows), [allRows]);

  const download = (content: string, filename: string, mime: string) => {
    const blob = new Blob([content], { type: mime });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleDownloadCsv = () => download(rowsToCsv(rows), `traceability-${Date.now()}.csv`, 'text/csv');
  const handleDownloadMd = () => download(rowsToMarkdown(rows, title), `traceability-${Date.now()}.md`, 'text/markdown');

  const statusPill = (status: TraceabilityRow['latestStatus']) => {
    const colors: Record<string, string> = {
      passed: 'bg-green-50 text-green-700 border-green-200',
      failed: 'bg-red-50 text-red-700 border-red-200',
      pending: 'bg-gray-50 text-gray-600 border-gray-200',
      running: 'bg-blue-50 text-blue-700 border-blue-200',
      paused: 'bg-yellow-50 text-yellow-700 border-yellow-200',
      skipped: 'bg-gray-50 text-gray-500 border-gray-200',
      never: 'bg-gray-50 text-gray-400 border-gray-200',
    };
    return (
      <span className={`inline-block px-2 py-0.5 rounded-full text-[10px] font-medium border ${colors[status] || colors.pending}`}>
        {status.toUpperCase()}
      </span>
    );
  };

  return (
    <div className="w-full px-2 sm:px-4 py-3 sm:py-6">
      {/* Top-left back button */}
      <div className="flex items-center gap-2 mb-3 flex-wrap">
        <button
          onClick={() => navigate(backTo)}
          className="inline-flex items-center gap-1 px-2 py-1 text-xs text-gray-600 hover:text-gray-900 hover:bg-gray-100 rounded-md transition"
          title="Back"
        >
          <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
          Back
        </button>
      </div>

      {/* Header */}
      <div className="flex items-start justify-between gap-3 mb-4 flex-wrap">
        <div className="min-w-0">
          <h1 className="text-base sm:text-xl font-bold text-gray-800 truncate">{title}</h1>
          <p className="text-xs sm:text-sm text-gray-500 mt-1 truncate">{subtitle}</p>
        </div>
        <div className="flex gap-2 shrink-0 flex-wrap">
          <button
            onClick={handleDownloadCsv}
            className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-50 transition"
          >
            Download CSV
          </button>
          <button
            onClick={handleDownloadMd}
            className="px-3 py-1.5 text-xs font-semibold bg-white text-gray-700 border border-gray-200 rounded-lg hover:bg-gray-50 transition"
          >
            Download Markdown
          </button>
        </div>
      </div>

      {/* Counts */}
      <div className="grid grid-cols-2 sm:grid-cols-5 gap-3 mb-5">
        <div className="rounded-xl border border-gray-200 bg-white p-3 text-center">
          <p className="text-xs text-gray-500">Total</p>
          <p className="text-xl font-bold text-gray-800">{counts.total}</p>
        </div>
        <div className="rounded-xl border border-gray-200 bg-white p-3 text-center">
          <p className="text-xs text-green-700">Passed</p>
          <p className="text-xl font-bold text-green-700">{counts.passed}</p>
        </div>
        <div className="rounded-xl border border-gray-200 bg-white p-3 text-center">
          <p className="text-xs text-red-700">Failed</p>
          <p className="text-xl font-bold text-red-700">{counts.failed}</p>
        </div>
        <div className="rounded-xl border border-gray-200 bg-white p-3 text-center">
          <p className="text-xs text-gray-500">Pending</p>
          <p className="text-xl font-bold text-gray-600">{counts.pending}</p>
        </div>
        <div className="rounded-xl border border-gray-200 bg-white p-3 text-center">
          <p className="text-xs text-gray-400">Never run</p>
          <p className="text-xl font-bold text-gray-400">{counts.never}</p>
        </div>
      </div>

      {/* Filters */}
      <div className="rounded-xl border border-gray-200 bg-white p-3 mb-4 flex flex-wrap items-center gap-3">
        <input
          value={search}
          onChange={e => setSearch(e.target.value)}
          placeholder="Search by Jira key, feature, test case, strategy..."
          className="flex-1 min-w-64 px-3 py-1.5 border border-gray-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-orange-300"
        />
        <select
          value={statusFilter}
          onChange={e => setStatusFilter(e.target.value as StatusFilter)}
          className="px-3 py-1.5 border border-gray-200 rounded-lg text-sm bg-white"
        >
          <option value="all">All statuses</option>
          <option value="passed">Passed</option>
          <option value="failed">Failed</option>
          <option value="pending">Pending / running</option>
          <option value="never">Never run</option>
        </select>
        <label className="flex items-center gap-2 text-sm text-gray-700">
          <input
            type="checkbox"
            checked={onlyWithFindings}
            onChange={e => setOnlyWithFindings(e.target.checked)}
            className="accent-orange-500"
          />
          Only with findings
        </label>
      </div>

      {/* Matrix */}
      {rows.length === 0 ? (
        <div className="rounded-2xl border border-gray-200 bg-white p-10 text-center">
          <p className="text-sm text-gray-500">No rows match the current filters.</p>
        </div>
      ) : (
        <div className="rounded-xl border border-gray-200 bg-white overflow-hidden">
          <div className="overflow-x-auto">
            <table className="w-full text-sm">
              <thead className="bg-gray-50 text-gray-600">
                <tr>
                  <th className="px-3 py-2 text-left font-semibold">Jira</th>
                  <th className="px-3 py-2 text-left font-semibold">Module</th>
                  <th className="px-3 py-2 text-left font-semibold">Feature</th>
                  <th className="px-3 py-2 text-left font-semibold">Test Case</th>
                  <th className="px-3 py-2 text-left font-semibold">Strategy</th>
                  <th className="px-3 py-2 text-left font-semibold">Status</th>
                  <th className="px-3 py-2 text-left font-semibold">Findings</th>
                </tr>
              </thead>
              <tbody>
                {rows.map((r, i) => (
                  <tr
                    key={`${r.jiraKey}_${r.featureId}_${r.testCaseId}_${i}`}
                    className="border-t border-gray-100 hover:bg-gray-50 cursor-pointer"
                    onClick={() =>
                      navigate(
                        `/project/${r.projectId}/module/${r.moduleId}/feature/${r.featureId}${r.testCaseId === '__no_tests__' ? '' : '/tests'}`,
                      )
                    }
                  >
                    <td className="px-3 py-2 align-top">
                      {r.jiraKey === '__untraced__' ? (
                        <span className="text-xs text-gray-400">—</span>
                      ) : (
                        <span className="inline-flex items-center gap-1 text-xs text-blue-700">
                          {r.jiraIconUrl && <img src={r.jiraIconUrl} className="w-3.5 h-3.5" alt="" />}
                          {r.jiraKey}
                        </span>
                      )}
                      {r.jiraSummary && <div className="text-[11px] text-gray-500 line-clamp-1 max-w-48">{r.jiraSummary}</div>}
                    </td>
                    <td className="px-3 py-2 align-top text-xs text-gray-700">{r.moduleName}</td>
                    <td className="px-3 py-2 align-top">
                      <div className="text-xs text-gray-800 font-medium">{r.featureName}</div>
                      {r.featureType === 'comparison' && (
                        <span className="inline-block mt-0.5 px-1.5 py-0.5 rounded-full text-[10px] font-medium bg-purple-50 text-purple-700 border border-purple-200">
                          comparison
                        </span>
                      )}
                    </td>
                    <td className="px-3 py-2 align-top">
                      {r.testCaseId === '__no_tests__' ? (
                        <span className="text-[11px] text-gray-400 italic">no test cases</span>
                      ) : (
                        <>
                          <div className="text-xs text-gray-800">{r.testCaseTitle}</div>
                          {r.testCasePriority && (
                            <span className="text-[10px] text-gray-400 uppercase">{r.testCasePriority}</span>
                          )}
                        </>
                      )}
                    </td>
                    <td className="px-3 py-2 align-top text-[11px] text-gray-600">{r.testCaseStrategy ?? ''}</td>
                    <td className="px-3 py-2 align-top">{statusPill(r.latestStatus)}</td>
                    <td className="px-3 py-2 align-top text-xs text-gray-700">{r.findings.length}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}
