import { useStore } from '../store/state';
import { useActivator } from '../store/Context';

export default function ManualPauseDialog() {
  const pause = useStore(s => s.manualPause);
  const activator = useActivator();

  if (!pause) return null;

  const respond = (confirmed: boolean) => {
    activator.pauseForConfirmation(pause.projectId, pause.featureId, pause.testCaseId, pause.stepId, confirmed);
    useStore.getState().setManualPause(null);
  };

  return (
    <div
      className="fixed inset-0 bg-black/60 flex items-center justify-center z-50"
      role="dialog"
      aria-modal="true"
      aria-labelledby="manual-pause-title"
      onKeyDown={(e) => {
        if (e.key === 'Escape') respond(false);
        if (e.key === 'Enter') respond(true);
      }}
    >
      <div className="bg-gray-800 rounded-lg p-6 max-w-lg w-full mx-4 border border-gray-600 shadow-xl">
        <div className="flex items-center gap-2 mb-4">
          <span className="text-blue-400 text-xl">⏸</span>
          <h2 id="manual-pause-title" className="text-lg font-semibold text-white">
            Manual Confirmation Required
          </h2>
        </div>

        <p className="text-gray-300 text-sm mb-3">
          Execution is paused at a manual confirmation step. Review the browser state, then
          continue or abort the run.
        </p>

        {pause.message && (
          <div className="bg-gray-900 rounded p-3 mb-4 text-gray-200 text-sm">
            {pause.message}
          </div>
        )}

        <div className="flex gap-3 justify-end">
          <button
            onClick={() => respond(false)}
            className="px-4 py-2 bg-gray-700 text-white rounded hover:bg-gray-600 text-sm"
          >
            Abort run
          </button>
          <button
            onClick={() => respond(true)}
            autoFocus
            className="px-4 py-2 bg-blue-500 text-white rounded hover:bg-blue-600 text-sm"
          >
            Continue
          </button>
        </div>
      </div>
    </div>
  );
}
